/*****************************************************************************************************
Program:		owp_BatchFINSTAT0053aSubTotalSTAAllProviders
				(based on owp_BatchFINSTAT0053SubTotalSTAAllProviders by A Groves on 13/11/2012)

Description:	This produces FINSTATS 0053a for all providers.

Amendment History			
-----------------

Date		Who				Description				
----		---				-----------		

*****************************************************************************************************/

CREATE   PROCEDURE [dbo].[owp_BatchFINSTAT0053aSubTotalSTAAllProviders]
AS
BEGIN
	SET NOCOUNT ON;

	SELECT
		 CASE WHEN Product = 'TALA' THEN 1 END AS FileNumber
		,CaseID
		,ProviderRef AS ProviderRef
		,InitPeriod
		,MonthsPaid AS ExpiredIP
		,InitPeriod - MonthsPaid AS RemainingIP
		,Freq AS Frequency
		,Product AS Product
		,Provider AS Provider
		,IRD
		,FirstDueDate
		,FinStatTot7FC AS CommissionsToDate
		,SUM	(	Month01Com + Month02Com + Month03Com + Month04Com + Month05Com + Month06Com + Month07Com + Month08Com + Month09Com + Month10Com + Month11Com + Month12Com 
				+	Month13Com + Month14Com + Month15Com + Month16Com + Month17Com + Month18Com + Month19Com + Month20Com + Month21Com + Month22Com + Month23Com + Month24Com 
				+	Month25Com + Month26Com + Month27Com + Month28Com + Month29Com + Month30Com + Month31Com + Month32Com + Month33Com + Month34Com + Month35Com + Month36Com 
				+	Month37Com + Month38Com + Month39Com + Month40Com + Month41Com + Month42Com + Month43Com + Month44Com + Month45Com + Month46Com + Month47Com + Month48Com 
				+	Month49Com + Month50Com + Month51Com + Month52Com + Month53Com + Month54Com + Month55Com + Month56Com + Month57Com + Month58Com + Month59Com + Month60Com
				) AS CommissionsSTA
		,Month01Com ,Month02Com ,Month03Com ,Month04Com ,Month05Com ,Month06Com ,Month07Com ,Month08Com ,Month09Com ,Month10Com ,Month11Com ,Month12Com 
		,Month13Com ,Month14Com ,Month15Com ,Month16Com ,Month17Com ,Month18Com ,Month19Com ,Month20Com ,Month21Com ,Month22Com ,Month23Com ,Month24Com 
		,Month25Com ,Month26Com ,Month27Com ,Month28Com ,Month29Com ,Month30Com ,Month31Com ,Month32Com ,Month33Com ,Month34Com ,Month35Com ,Month36Com 
		,Month37Com ,Month38Com ,Month39Com ,Month40Com ,Month41Com ,Month42Com ,Month43Com ,Month44Com ,Month45Com ,Month46Com ,Month47Com ,Month48Com 
		,Month49Com ,Month50Com ,Month51Com ,Month52Com ,Month53Com ,Month54Com ,Month55Com ,Month56Com ,Month57Com ,Month58Com ,Month59Com ,Month60Com
	FROM	dbo.owhot_FinanceFutureExpectations
	WHERE	Basis = 'Accrual'
	AND		Product IN ('ZGUA', 'TALA')
	AND		IRD IS NOT NULL
	GROUP BY
		 CASE WHEN Product = 'TALA' THEN 1 END
		,CaseID
		,ProviderRef
		,InitPeriod
		,MonthsPaid
		,InitPeriod - MonthsPaid
		,Freq
		,Product
		,Provider
		,IRD
		,FirstDueDate
		,FinStatTot7FC
		,Month01Com ,Month02Com ,Month03Com ,Month04Com ,Month05Com ,Month06Com ,Month07Com ,Month08Com ,Month09Com ,Month10Com ,Month11Com ,Month12Com 
		,Month13Com ,Month14Com ,Month15Com ,Month16Com ,Month17Com ,Month18Com ,Month19Com ,Month20Com ,Month21Com ,Month22Com ,Month23Com ,Month24Com 
		,Month25Com ,Month26Com ,Month27Com ,Month28Com ,Month29Com ,Month30Com ,Month31Com ,Month32Com ,Month33Com ,Month34Com ,Month35Com ,Month36Com 
		,Month37Com ,Month38Com ,Month39Com ,Month40Com ,Month41Com ,Month42Com ,Month43Com ,Month44Com ,Month45Com ,Month46Com ,Month47Com ,Month48Com 
		,Month49Com ,Month50Com ,Month51Com ,Month52Com ,Month53Com ,Month54Com ,Month55Com ,Month56Com ,Month57Com ,Month58Com ,Month59Com ,Month60Com
	HAVING	SUM	(	Month01Com + Month02Com + Month03Com + Month04Com + Month05Com + Month06Com + Month07Com + Month08Com + Month09Com + Month10Com + Month11Com + Month12Com 
				+	Month13Com + Month14Com + Month15Com + Month16Com + Month17Com + Month18Com + Month19Com + Month20Com + Month21Com + Month22Com + Month23Com + Month24Com 
				+	Month25Com + Month26Com + Month27Com + Month28Com + Month29Com + Month30Com + Month31Com + Month32Com + Month33Com + Month34Com + Month35Com + Month36Com 
				+	Month37Com + Month38Com + Month39Com + Month40Com + Month41Com + Month42Com + Month43Com + Month44Com + Month45Com + Month46Com + Month47Com + Month48Com 
				+	Month49Com + Month50Com + Month51Com + Month52Com + Month53Com + Month54Com + Month55Com + Month56Com + Month57Com + Month58Com + Month59Com + Month60Com
				) > 0;
END
GO
