/*****************************************************************************************************
  	 Program:  	owp_BatchFINSTAT0053SubTotalSTAAllProviders				
	  Author:	A Groves
Date created:	13/11/2012							
											
Description:	This procedure automates the following manually created FINSTATS:
				0053a
				0053b
				0053c
				for all providers.

				It is called as follows:
					exec owp_BatchFINSTAT0053SubTotalSTAAllProviders 'Openwork','BatchFINSTAT','BATCHFINSTAT'

				The output file is written to the location defined by the SCANS.ini 
				parameter passed in as @Location.
				
				The report recipient is: Jayne Howells (Finance). No email required as it will be 
				created as part of the 1st day of the month reporting suite.
									
Amendment History								
-----------------								
											
Date		Who				Description				
----		---				-----------			
*****************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_BatchFINSTAT0053SubTotalSTAAllProviders]
	@Client		varchar(50),
	@Module		varchar(50),
	@Location	varchar(50)
AS

declare @cmd						varchar(8000),
		@Today						varchar(8), 
		@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@delimiter					varchar(1),
		@FilePath					varchar(500),
		@FileNamePrefix				varchar(500),
		@FileNameSuffix				varchar(50),
		@FullFilePathAndName		varchar(4000),
		@Database					varchar(100),
		@Server						varchar(100),
		@Environ					varchar(50),
		@SourceSystem				varchar(50),		
		@ExcelRows					int,
		@RowCount					int,		
		@FileDateSuffix				nvarchar(8)


/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/


set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @Process		= object_name(@@procid)
set @SourceSystem	= 'Swift'


/****************************************************************************

	Log start																
																		
****************************************************************************/


exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


/****************************************************************************

	Set program parameters																
																		
****************************************************************************/

exec owp_GetDatabaseDetails @Client, @SourceSystem, @Database output,
				@Server output, @Environ output

exec owp_GetFileLocation @Location, @FilePath output

set @delimiter					= ','
set @FileDateSuffix				= convert(varchar(8),getdate(),112)

set @FileNamePrefix			= 'BatchFinstat0053 Subtotalled v7 All Providers ' + @FileDateSuffix 
set @FileNameSuffix			= '.xls'
set @FullFilePathAndName	= @FilePath + @FileNamePrefix + @FileNameSuffix

/****************************************************************************

	Select report data																
																		
****************************************************************************/


--BatchFinstat0053 Subtotalled v6

--New BatchFINSTAT0053
select	Null as FileNumber,	
		CaseID,	
		ProviderRef,	
		InitPeriod,	
		MonthsPaid as ExpiredIP,
		(InitPeriod-MonthsPaid) as RemainingIP,	
		Freq as Frequency,	
		Product,	
		Provider,
		(case when IRD is null then '1900-01-01' else IRD end) as IRD, 
		FirstDueDate,
		FinStatTot7FC as CommissionsToDate,	
		Null as CommissionsSTA,
		Month01 * ComRate as Month01Com,	Month02 * ComRate as Month02Com,
		Month03 * ComRate as Month03Com,	Month04 * ComRate as Month04Com,
		Month05 * ComRate as Month05Com,	Month06 * ComRate as Month06Com,
		Month07 * ComRate as Month07Com,	Month08 * ComRate as Month08Com,
		Month09 * ComRate as Month09Com,	Month10 * ComRate as Month10Com,
		Month11 * ComRate as Month11Com,	Month12 * ComRate as Month12Com,
		Month13 * ComRate as Month13Com,	Month14 * ComRate as Month14Com,
		Month15 * ComRate as Month15Com,	Month16 * ComRate as Month16Com,
		Month17 * ComRate as Month17Com,	Month18 * ComRate as Month18Com,
		Month19 * ComRate as Month19Com,	Month20 * ComRate as Month20Com,
		Month21 * ComRate as Month21Com,	Month22 * ComRate as Month22Com,
		Month23 * ComRate as Month23Com,	Month24 * ComRate as Month24Com,
		Month25 * ComRate as Month25Com,	Month26 * ComRate as Month26Com,
		Month27 * ComRate as Month27Com,	Month28 * ComRate as Month28Com,
		Month29 * ComRate as Month29Com,	Month30 * ComRate as Month30Com,
		Month31 * ComRate as Month31Com,	Month32 * ComRate as Month32Com,
		Month33 * ComRate as Month33Com,	Month34 * ComRate as Month34Com,
		Month35 * ComRate as Month35Com,	Month36 * ComRate as Month36Com,
		Month37 * ComRate as Month37Com,	Month38 * ComRate as Month38Com,
		Month39 * ComRate as Month39Com,	Month40 * ComRate as Month40Com,
		Month41 * ComRate as Month41Com,	Month42 * ComRate as Month42Com,
		Month43 * ComRate as Month43Com,	Month44 * ComRate as Month44Com,
		Month45 * ComRate as Month45Com,	Month46 * ComRate as Month46Com,
		Month47 * ComRate as Month47Com,	Month48 * ComRate as Month48Com,
		Month49 * ComRate as Month49Com,	Month50 * ComRate as Month50Com,
		Month51 * ComRate as Month51Com,	Month52 * ComRate as Month52Com,
		Month53 * ComRate as Month53Com,	Month54 * ComRate as Month54Com,
		Month55 * ComRate as Month55Com,	Month56 * ComRate as Month56Com,
		Month57 * ComRate as Month57Com,	Month58 * ComRate as Month58Com,
		Month59 * ComRate as Month59Com,	Month60 * ComRate as Month60Com
into 	#tempFINSTAT0053
from	owhot_FinanceFutureExpectations with (nolock)
where	Basis = 'Accrual'
--and		Provider = 'Zurich New'		ALL PROVIDERS!!!!
and		isnull(IRD,'') <> ''

update	tmp
	set FileNumber =
			case when product = 'ZALP' then 6
				when product = 'TALA' then 1
				when product = 'LS' then 2
				when product = 'IPP' then 3
				when product = 'DMC' then 4
				when product = 'DMCP' then 4
				when product = 'ATP' then 5
				when product = 'LPP' then 5
			end
from #tempFINSTAT0053 tmp


select	FileNumber,		
		CaseID,		
		ProviderRef,		
		InitPeriod,		
		ExpiredIP,
		RemainingIP,		
		Frequency,		
		Product,		
		Provider,
		substring(convert(varchar(25),ird,113),4,8) as IRD, 
		FirstDueDate,
		CommissionsToDate,
		sum (Month01Com + Month02Com + Month03Com + Month04Com + Month05Com + Month06Com + Month07Com + Month08Com + Month09Com + Month10Com + Month11Com + Month12Com + Month13Com + Month14Com + Month15Com + Month16Com + Month17Com + Month18Com + Month19Com + Month20Com + Month21Com + Month22Com + Month23Com + Month24Com + Month25Com + Month26Com + Month27Com + Month28Com + Month29Com + Month30Com + Month31Com + Month32Com + Month33Com + Month34Com + Month35Com + Month36Com + Month37Com + Month38Com + Month39Com + Month40Com + Month41Com + Month42Com + Month43Com + Month44Com + Month45Com + Month46Com + Month47Com + Month48Com + Month49Com + Month50Com + Month51Com + Month52Com + Month53Com + Month54Com + Month55Com + Month56Com + Month57Com + Month58Com + Month59Com + Month60Com) as CommissionsSTA,
		Month01Com, Month02Com, Month03Com, Month04Com, Month05Com, Month06Com, Month07Com, 
		Month08Com, Month09Com, Month10Com, Month11Com, Month12Com, Month13Com, Month14Com, 
		Month15Com, Month16Com, Month17Com, Month18Com, Month19Com, Month20Com, Month21Com, 
		Month22Com, Month23Com, Month24Com, Month25Com, Month26Com, Month27Com, Month28Com, 
		Month29Com, Month30Com, Month31Com, Month32Com, Month33Com, Month34Com, Month35Com, 
		Month36Com, Month37Com, Month38Com, Month39Com, Month40Com, Month41Com, Month42Com, 
		Month43Com, Month44Com, Month45Com, Month46Com, Month47Com, Month48Com, Month49Com, 
		Month50Com, Month51Com, Month52Com, Month53Com, Month54Com, Month55Com, Month56Com, 
		Month57Com, Month58Com, Month59Com, Month60Com
into	#tempFINSTAT0053a
from	#tempFINSTAT0053
where	Product in ('ZGUA', 'TALA')
group by FileNumber, CaseID, ProviderRef, InitPeriod, ExpiredIP, RemainingIP, Frequency, Product, 
		Provider, IRD, FirstDueDate, CommissionsToDate,
		Month01Com, Month02Com, Month03Com, Month04Com, Month05Com, Month06Com, Month07Com, 
		Month08Com, Month09Com, Month10Com, Month11Com, Month12Com, Month13Com, Month14Com, 
		Month15Com, Month16Com, Month17Com, Month18Com, Month19Com, Month20Com, Month21Com, 
		Month22Com, Month23Com, Month24Com, Month25Com, Month26Com, Month27Com, Month28Com, 
		Month29Com, Month30Com, Month31Com, Month32Com, Month33Com, Month34Com, Month35Com, 
		Month36Com, Month37Com, Month38Com, Month39Com, Month40Com, Month41Com, Month42Com, 
		Month43Com, Month44Com, Month45Com, Month46Com, Month47Com, Month48Com, Month49Com, 
		Month50Com, Month51Com, Month52Com, Month53Com, Month54Com, Month55Com, Month56Com, 
		Month57Com, Month58Com, Month59Com, Month60Com

set @RowCount = @@rowcount


select	FileNumber,		
		CaseID,		
		ProviderRef,
		InitPeriod,
		ExpiredIP,
		RemainingIP,
		Frequency,
		Product,
		Provider,
		substring(convert(varchar(25),ird,113),4,8) as IRD, 
		FirstDueDate,
		CommissionsToDate,
