/*****************************************************************************************************
Program:		owp_BatchFINSTAT0054bSubTotalSTAAllProviders
				(based on owp_BatchFINSTAT0054SubTotalSTAAllProviders by A Groves on 13/11/2012)

Description:	This produces FINSTATS 0054b for all providers.

Amendment History			
-----------------

Date		Who				Description				
----		---				-----------		

*****************************************************************************************************/

CREATE   PROCEDURE [dbo].[owp_BatchFINSTAT0054bSubTotalSTAAllProviders]
AS
BEGIN
	SET NOCOUNT ON;

	SELECT
		 CASE Product 
			WHEN 'ZALP' THEN 6 
			WHEN 'LS' THEN 2 
			WHEN 'IPP' THEN 3 
			WHEN 'DMC' THEN 4 
			WHEN 'DMCP' THEN 4 
			WHEN 'ATP' THEN 5 
			WHEN 'LPP' THEN 5 
		 END AS FileNumber
		,CaseID
		,ProviderRef
		,InitPeriod
		,MonthsPaid AS ExpiredIP
		,InitPeriod - MonthsPaid AS RemainingIP
		,Freq AS Frequency
		,Product
		,Provider
		,SUBSTRING(CONVERT(VARCHAR(25),IRD,113),4,8) AS IRD
		,FirstDueDate
		,FinStatTot1inPeriod AS CommissionsToDate
		,SUM	(	Month01 + Month02 + Month03 + Month04 + Month05 + Month06 + Month07 + Month08 + Month09 + Month10 + Month11 + Month12 
				+	Month13 + Month14 + Month15 + Month16 + Month17 + Month18 + Month19 + Month20 + Month21 + Month22 + Month23 + Month24 
				+	Month25 + Month26 + Month27 + Month28 + Month29 + Month30 + Month31 + Month32 + Month33 + Month34 + Month35 + Month36 
				+	Month37 + Month38 + Month39 + Month40 + Month41 + Month42 + Month43 + Month44 + Month45 + Month46 + Month47 + Month48 
				+	Month49 + Month50 + Month51 + Month52 + Month53 + Month54 + Month55 + Month56 + Month57 + Month58 + Month59 + Month60
				) AS CommissionsSTA
		,Month01 AS Month01DA, Month02 AS Month02DA, Month03 AS Month03DA, Month04 AS Month04DA, Month05 AS Month05DA, Month06 AS Month06DA
		,Month07 AS Month07DA, Month08 AS Month08DA, Month09 AS Month09DA, Month10 AS Month10DA, Month11 AS Month11DA, Month12 AS Month12DA
		,Month13 AS Month13DA, Month14 AS Month14DA, Month15 AS Month15DA, Month16 AS Month16DA, Month17 AS Month17DA, Month18 AS Month18DA
		,Month19 AS Month19DA, Month20 AS Month20DA, Month21 AS Month21DA, Month22 AS Month22DA, Month23 AS Month23DA, Month24 AS Month24DA
		,Month25 AS Month25DA, Month26 AS Month26DA, Month27 AS Month27DA, Month28 AS Month28DA, Month29 AS Month29DA, Month30 AS Month30DA
		,Month31 AS Month31DA, Month32 AS Month32DA, Month33 AS Month33DA, Month34 AS Month34DA, Month35 AS Month35DA, Month36 AS Month36DA
		,Month37 AS Month37DA, Month38 AS Month38DA, Month39 AS Month39DA, Month40 AS Month40DA, Month41 AS Month41DA, Month42 AS Month42DA
		,Month43 AS Month43DA, Month44 AS Month44DA, Month45 AS Month45DA, Month46 AS Month46DA, Month47 AS Month47DA, Month48 AS Month48DA
		,Month49 AS Month49DA, Month50 AS Month50DA, Month51 AS Month51DA, Month52 AS Month52DA, Month53 AS Month53DA, Month54 AS Month54DA
		,Month55 AS Month55DA, Month56 AS Month56DA, Month57 AS Month57DA, Month58 AS Month58DA, Month59 AS Month59DA, Month60 AS Month60DA
	FROM	dbo.owhot_FinanceFutureExpectations
	WHERE	Basis = 'Accrual'
	AND		Product NOT IN ('ZGUA', 'TALA')
	AND		IRD IS NOT NULL
	GROUP BY
		 CASE Product 
			WHEN 'ZALP' THEN 6 
			WHEN 'LS' THEN 2 
			WHEN 'IPP' THEN 3 
			WHEN 'DMC' THEN 4 
			WHEN 'DMCP' THEN 4 
			WHEN 'ATP' THEN 5 
			WHEN 'LPP' THEN 5 
		 END
		,CaseID
		,ProviderRef
		,InitPeriod
		,MonthsPaid
		,InitPeriod - MonthsPaid
		,Freq
		,Product
		,Provider
		,SUBSTRING(CONVERT(VARCHAR(25),IRD,113),4,8)
		,FirstDueDate
		,FinStatTot1inPeriod
		,Month01, Month02, Month03, Month04, Month05, Month06, Month07, Month08, Month09, Month10, Month11, Month12 
		,Month13, Month14, Month15, Month16, Month17, Month18, Month19, Month20, Month21, Month22, Month23, Month24 
		,Month25, Month26, Month27, Month28, Month29, Month30, Month31, Month32, Month33, Month34, Month35, Month36 
		,Month37, Month38, Month39, Month40, Month41, Month42, Month43, Month44, Month45, Month46, Month47, Month48 
		,Month49, Month50, Month51, Month52, Month53, Month54, Month55, Month56, Month57, Month58, Month59, Month60
	HAVING	SUM	(	Month01 + Month02 + Month03 + Month04 + Month05 + Month06 + Month07 + Month08 + Month09 + Month10 + Month11 + Month12 
				+	Month13 + Month14 + Month15 + Month16 + Month17 + Month18 + Month19 + Month20 + Month21 + Month22 + Month23 + Month24 
				+	Month25 + Month26 + Month27 + Month28 + Month29 + Month30 + Month31 + Month32 + Month33 + Month34 + Month35 + Month36 
				+	Month37 + Month38 + Month39 + Month40 + Month41 + Month42 + Month43 + Month44 + Month45 + Month46 + Month47 + Month48 
				+	Month49 + Month50 + Month51 + Month52 + Month53 + Month54 + Month55 + Month56 + Month57 + Month58 + Month59 + Month60
				) > 0;
END
