/*****************************************************************************************************
  	 Program:  	owp_BatchFINSTAT0054SubTotalSTAAllProviders				
	  Author:	A Groves
Date created:	14/11/2012							
											
Description:	This procedure automates the following manually created FINSTATS:
				0054a
				0054b
				for all providers.

				It is called as follows:
					exec owp_BatchFINSTAT0054SubTotalSTAAllProviders 'Openwork','BatchFINSTAT','BATCHFINSTAT'

				The output file is written to the location defined by the SCANS.ini 
				parameter passed in as @Location.
				
				The report recipient is: Jayne Howells (Finance). No email required as it will be 
				created as part of the 1st day of the month reporting suite.
									
Amendment History								
-----------------								
											
Date		Who				Description				
----		---				-----------			
*****************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_BatchFINSTAT0054SubTotalSTAAllProviders]
	@Client		varchar(50),
	@Module		varchar(50),
	@Location	varchar(50)
AS

declare @cmd						varchar(8000),
		@Today						varchar(8), 
		@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@delimiter					varchar(1),
		@FilePath					varchar(500),
		@FileNamePrefix				varchar(500),
		@FileNameSuffix				varchar(50),
		@FullFilePathAndName		varchar(4000),
		@Database					varchar(100),
		@Server						varchar(100),
		@Environ					varchar(50),
		@SourceSystem				varchar(50),		
		@ExcelRows					int,
		@RowCount					int,		
		@FileDateSuffix				nvarchar(8)


/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/


set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @Process		= object_name(@@procid)
set @SourceSystem	= 'Swift'


/****************************************************************************

	Log start																
																		
****************************************************************************/


exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


/****************************************************************************

	Set program parameters																
																		
****************************************************************************/

exec owp_GetDatabaseDetails @Client, @SourceSystem, @Database output,
				@Server output, @Environ output

exec owp_GetFileLocation @Location, @FilePath output

set @delimiter					= ','
set @FileDateSuffix				= convert(varchar(8),getdate(),112)

set @FileNamePrefix			= 'BatchFinstat0054 Subtotalled v6 All Providers ' + @FileDateSuffix 
set @FileNameSuffix			= '.xls'
set @FullFilePathAndName	= @FilePath + @FileNamePrefix + @FileNameSuffix

/****************************************************************************

	Select report data																
																		
****************************************************************************/


--BatchFinstat0053 Subtotalled v6

--New BatchFINSTAT0054
select	Null as FileNumber,
		CaseID,	ProviderRef,
		InitPeriod,	
		MonthsPaid as ExpiredIP,
		(InitPeriod-MonthsPaid) as RemainingIP,	
		Freq as Frequency,	
		Product,	
		Provider,
		(case when IRD is null then '1900-01-01' else IRD end) as IRD, 
		FirstDueDate,
		FinStatTot1inPeriod as CommissionsToDate,	
		Null as CommissionsSTA,
		Month01 as Month01DA,	Month02 as Month02DA,	Month03 as Month03DA,	Month04 as Month04DA,
		Month05 as Month05DA,	Month06 as Month06DA,	Month07 as Month07DA,	Month08 as Month08DA,
		Month09 as Month09DA,	Month10 as Month10DA,	Month11 as Month11DA,	Month12 as Month12DA,
		Month13 as Month13DA,	Month14 as Month14DA,	Month15 as Month15DA,	Month16 as Month16DA,
		Month17 as Month17DA,	Month18 as Month18DA,	Month19 as Month19DA,	Month20 as Month20DA,
		Month21 as Month21DA,	Month22 as Month22DA,	Month23 as Month23DA,	Month24 as Month24DA,
		Month25 as Month25DA,	Month26 as Month26DA,	Month27 as Month27DA,	Month28 as Month28DA,
		Month29 as Month29DA,	Month30 as Month30DA,	Month31 as Month31DA,	Month32 as Month32DA,
		Month33 as Month33DA,	Month34 as Month34DA,	Month35 as Month35DA,	Month36 as Month36DA,
		Month37 as Month37DA,	Month38 as Month38DA,	Month39 as Month39DA,	Month40 as Month40DA,
		Month41 as Month41DA,	Month42 as Month42DA,	Month43 as Month43DA,	Month44 as Month44DA,
		Month45 as Month45DA,	Month46 as Month46DA,	Month47 as Month47DA,	Month48 as Month48DA,
		Month49 as Month49DA,	Month50 as Month50DA,	Month51 as Month51DA,	Month52 as Month52DA,
		Month53 as Month53DA,	Month54 as Month54DA,	Month55 as Month55DA,	Month56 as Month56DA,
		Month57 as Month57DA,	Month58 as Month58DA,	Month59 as Month59DA,	Month60 as Month60DA
into	#tempFINSTAT0054
from	owhot_FinanceFutureExpectations with(nolock)
where	Basis = 'Accrual'
--	and Provider = 'Zurich New'		ALL PROVIDERS!!!!
and		isnull(IRD,'') <> ''


update	tmp
	set FileNumber =
			case when product = 'ZALP' then 6
				when product = 'TALA' then 1
				when product = 'LS' then 2
				when product = 'IPP' then 3
				when product = 'DMC' then 4
				when product = 'DMCP' then 4
				when product = 'ATP' then 5
				when product = 'LPP' then 5
			end
from #tempFINSTAT0054 tmp


select	FileNumber,		
		CaseID,		
		ProviderRef,
		InitPeriod,
		ExpiredIP,
		RemainingIP,
		Frequency,
		Product,
		Provider,
		substring(convert(varchar(25),ird,113),4,8) as IRD, 
		FirstDueDate,
		CommissionsToDate,
		sum (Month01DA + Month02DA + Month03DA + Month04DA + Month05DA + Month06DA + Month07DA + Month08DA + Month09DA + Month10DA + Month11DA + Month12DA + Month13DA + Month14DA + Month15DA + Month16DA + Month17DA + Month18DA + Month19DA + Month20DA + Month21DA + Month22DA + Month23DA + Month24DA + Month25DA + Month26DA + Month27DA + Month28DA + Month29DA + Month30DA + Month31DA + Month32DA + Month33DA + Month34DA + Month35DA + Month36DA + Month37DA + Month38DA + Month39DA + Month40DA + Month41DA + Month42DA + Month43DA + Month44DA + Month45DA + Month46DA + Month47DA + Month48DA + Month49DA + Month50DA + Month51DA + Month52DA + Month53DA + Month54DA + Month55DA + Month56DA + Month57DA + Month58DA + Month59DA + Month60DA) as CommissionsSTA,
		Month01DA,		Month02DA,		Month03DA,		Month04DA,
		Month05DA,		Month06DA,		Month07DA,		Month08DA,
		Month09DA,		Month10DA, 		Month11DA,		Month12DA,
		Month13DA,		Month14DA,		Month15DA,		Month16DA,
		Month17DA,		Month18DA,		Month19DA,		Month20DA,
		Month21DA,		Month22DA,		Month23DA,		Month24DA,
		Month25DA,		Month26DA,		Month27DA,		Month28DA,
		Month29DA,		Month30DA,		Month31DA,		Month32DA,
		Month33DA,		Month34DA,		Month35DA,		Month36DA,
