/*****************************************************************************************************
Program:		owp_BatchFINSTAT0055
				(based on owp_BatchFINSTAT0055To0058SubTotal by A Groves on 02/11/2012)

Description:	This produces FINSTATS 0055

Amendment History			
-----------------

Date		Who				Description				
----		---				-----------		

*****************************************************************************************************/

CREATE   PROCEDURE [dbo].[owp_BatchFINSTAT0055]
AS
BEGIN
	SET NOCOUNT ON;

	SELECT 	
		 LEFT(CONVERT(VARCHAR(20),fe.ird, 112),4) AS IRDYear
		,LEFT(CONVERT(VARCHAR(20),fe.ird, 110),2) AS IRDMonth
		,fe.Provider AS Provider
		,ISNULL(sh.Description, '') AS CommissionShape
		,fe.Product AS Product
		,SUM(fe.FinStatTot1inPeriod) AS FinStatTot1inPeriod
	FROM		dbo.owhot_FinanceFutureExpectations fe
	LEFT JOIN	dbo.msit_CodeCommissionShape sh ON sh.ID = fe.ShapeId
	WHERE	fe.Basis = 'IT'
	AND		fe.ird IS NOT NULL
	GROUP BY
		 LEFT(CONVERT(VARCHAR(20),fe.ird, 112),4)
		,LEFT(CONVERT(VARCHAR(20),fe.ird, 110),2)
		,fe.Provider
		,ISNULL(sh.Description, '')
		,fe.Product
	ORDER BY
		 LEFT(CONVERT(VARCHAR(20),fe.ird, 112),4)
		,LEFT(CONVERT(VARCHAR(20),fe.ird, 110),2)
		,fe.Provider
		,ISNULL(sh.Description, '')
		,fe.Product
		;
END
GO
