/*****************************************************************************************************
  	 Program:  	owp_BatchFINSTAT0055To0058SubTotal					
	  Author:	A Groves
Date created:	02/11/2012							
											
Description:	This procedure automates the following manually created FINSTATS:
				0055
				0056
				0057
				0058

				It is called as follows:
					exec owp_BatchFINSTAT0055To0058SubTotal 'Openwork','BatchFINSTAT','BATCHFINSTAT'

				The output file is written to the location defined by the SCANS.ini 
				parameter passed in as @Location.
				
				The report recipient is: Jayne Howells (Finance). No email required as it will be 
				created as part of the 1st day of the month reporting suite.
									
Amendment History								
-----------------								
											
Date		Who				Description				
----		---				-----------			
*****************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_BatchFINSTAT0055To0058SubTotal]
	@Client		varchar(50),
	@Module		varchar(50),
	@Location	varchar(50)
AS

declare @cmd						varchar(8000),
		@Today						varchar(8), 
		@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@delimiter					varchar(1),
		@FilePath					varchar(500),
		@FileNamePrefix				varchar(500),
		@FileNameSuffix				varchar(50),
		@FullFilePathAndName		varchar(4000),
		@Database					varchar(100),
		@Server						varchar(100),
		@Environ					varchar(50),
		@SourceSystem				varchar(50),		
		@ExcelRows					int,
		@RowCount					int,		
		@FileDateSuffix				nvarchar(8)


/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/


set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @Process		= object_name(@@procid)
set @SourceSystem	= 'Swift'


/****************************************************************************

	Log start																
																		
****************************************************************************/


exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


/****************************************************************************

	Set program parameters																
																		
****************************************************************************/

exec owp_GetDatabaseDetails @Client, @SourceSystem, @Database output,
				@Server output, @Environ output

exec owp_GetFileLocation @Location, @FilePath output

set @delimiter					= ','
set @FileDateSuffix				= convert(varchar(8),getdate(),112)

set @FileNamePrefix			= 'BatchFinstats0055to0058 Subtotalled v4 ' + @FileDateSuffix 
set @FileNameSuffix			= '.xls'
set @FullFilePathAndName	= @FilePath + @FileNamePrefix + @FileNameSuffix

/****************************************************************************

	Select report data																
																		
****************************************************************************/


--New BatchFINSTAT0058
select	Provider,
		Product,
 		isnull(left(convert(varchar(20),IRD, 112),4),'') as IRDYear,
		sh.description as CommissionShape,
		isnull(left(convert(varchar(20),IRD, 110),2),'') as IRDMonth,
		SUM(FinStatTot1inPeriod) as FinStatTot1inPeriod
into	#FINSTAT0058
from	owhot_FinanceFutureExpectations fe with (nolock)
		left outer join msit_CodeCommissionShape sh  with (nolock) on sh.id = fe.shapeid
where	fe.Basis = 'Accrual'
and		fe.Provider = 'STERLING'
and		isnull(fe.IRD,'') <> ''
Group by	isnull(left(convert(varchar(20),IRD,112),4),''), 
			isnull(left(convert(varchar(20),IRD, 110),2),''), 
			Provider, 
			sh.description, 
			Product

set @RowCount = @@rowcount


--New BatchFINSTAT0057
select	Provider,
		Product,
		isnull(left(convert(varchar(20),IRD, 112),4),'') as IRDYear,
		sh.description as CommissionShape,
		isnull(left(convert(varchar(20),IRD, 110),2),'') as IRDMonth,
		SUM(FinStatTot1inPeriod) as FinStatTot1inPeriod
into	#FINSTAT0057
from	owhot_FinanceFutureExpectations fe with (nolock)
		left outer join msit_CodeCommissionShape sh with (nolock) on sh.id = fe.shapeid
where	fe.Basis = 'Accrual'
and		fe.Provider = 'SIML'
and		isnull(fe.IRD,'') <> ''
Group by	isnull(left(convert(varchar(20),IRD,112),4),''), 
			isnull(left(convert(varchar(20),IRD, 110),2),''), 
			Provider, 
			sh.description, 
			Product

set @RowCount = @Rowcount + @@rowcount


--New BatchFINSTAT0056
select	Provider,
		Product,
		isnull(left(convert(varchar(20),IRD, 112),4),'') as IRDYear,
		sh.description as CommissionShape,
		isnull(left(convert(varchar(20),IRD, 110),2),'') as IRDMonth,
		SUM(FinStatTot1inPeriod) as FinStatTot1inPeriod
into	#FINSTAT0056
from	owhot_FinanceFutureExpectations fe with (nolock)
		left outer join msit_CodeCommissionShape sh with (nolock) on sh.id = fe.shapeid
where	fe.Basis = 'Accrual'
and		fe.Provider in ('SCOT EQ','SCOT EQINT')
and		isnull(fe.IRD,'') <> ''
Group by	isnull(left(convert(varchar(20),IRD,112),4),''), 
			isnull(left(convert(varchar(20),IRD, 110),2),''), 
			Provider, 
			sh.description, 
			Product

set @RowCount = @Rowcount + @@rowcount


--New BatchFINSTAT0055
Select 	isnull(left(convert(varchar(20),IRD, 112),4),'') as IRDYear,
		isnull(left(convert(varchar(20),IRD, 110),2),'') as IRDMonth,
		Provider,
		sh.description as CommissionShape,
		Product,
		SUM(FinStatTot1inPeriod) as FinStatTot1inPeriod
into	#FINSTAT0055
from	owhot_FinanceFutureExpectations fe with(nolock)
		left outer join mstt_ProductHierarchy ph with(nolock) on fe.product = ph.productcode 
		left outer join msit_CodeCommissionShape sh with(nolock) on sh.id = fe.shapeid
where	basis = 'IT'
and		isnull(fe.IRD,'') <> ''
Group by	isnull(left(convert(varchar(20),IRD,112),4),''), 
			isnull(left(convert(varchar(20),IRD, 110),2),''), 
			Provider, 
			sh.description, 
			Product

set @RowCount = @Rowcount + @@rowcount

select * from #FINSTAT0055
GO
