/****** Object:  StoredProcedure [dbo].[owp_BatchFINSTAT0060_ExpensesReimbursedEXCEL]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*****************************************************************************************************
  	 Program:  	owp_BatchFINSTAT0060_ExpensesReimbursedEXCEL						
	  Author:	A Groves
Date created:	05/07/2013							
											
Description:	This procedure has been created to run the Expenses Reimbursed report for Finance.
				It used to be run from the BI Button on the portal until the BI Buton was 
				decommissioned in January 2013.

				It is called as follows:

					declare @LastDayOfPrevMth varchar(8)
					select @LastDayOfPrevMth = dbo.owf_LastDayOfPrevMth(getdate())
					exec owp_BatchFINSTAT0060_ExpensesReimbursedEXCEL 'Openwork', 'BatchFINSTAT', 
							'BATCHFINSTAT', '20060101',  @LastDayOfPrevMth, @rc output, @EmailBody output

				The output file is written to the location defined by the SCANS.ini 
				parameter passed in as @Location.
				
				The report recipient is the following in Finance:
				Jonathan Wain 
				
				This Stored proc calls stored proc "usp_ExecuteSSISPackage" in the DBManagement database 
				that creates a self-deleting SQL Agent job that executes an SSIS package to produce an 
				Excel file.
				NOTE: for Excel files that have multiple worksheets, the vWorksheetNames attribute in 
				the @xVar variable MUST be delimited with a ^ character (that is the symbol above the 
				6 key).

Amendment History			
-----------------
											
Date		Who				Description				
----		---				-----------		

*****************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_BatchFINSTAT0060_ExpensesReimbursedEXCEL]
	@Client		varchar(50),
	@Module		varchar(50),
	@Location	varchar(50),
	@StartDate	varchar(10),
	@EndDate	varchar(10),
	@RowCount	int				output,
	@EmailBody	nvarchar(4000)	output
AS

declare @cmd						varchar(8000),
		@Today						varchar(8), 
		@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@FilePath					varchar(500),
		@FileNamePrefix				varchar(500),
		@FileNameSuffix				varchar(50),
		@FullFilePathAndName		varchar(4000),
		@Database					varchar(100),
		@Server						varchar(100),
		@Environ					varchar(50),				
		@FileDateSuffix				nvarchar(8),
		@SSISFileSystem				varchar(500)


/****************************************************************************

	Set initial parameters
																					
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @Process		= object_name(@@procid)
set @StartDate		= convert(varchar(10),convert(datetime,@StartDate,112),103)
set @EndDate		= convert(varchar(10),convert(datetime,@EndDate,112),103)

/****************************************************************************

	Log start

****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Set program parameters

****************************************************************************/

exec owp_GetFileLocation 'SSISFileSystem', @SSISFileSystem output

exec owp_GetDatabaseDetails @Client, 'Swift', @Database output,
				@Server output, @Environ output

exec owp_GetFileLocation @Location, @FilePath output

set @FileDateSuffix				= convert(varchar(8),getdate(),112)

set @FileNamePrefix			= 'BatchFINSTAT0060_ExpensesReimbursed_' + @FileDateSuffix 
set @FileNameSuffix			= '.xls'  
set @FullFilePathAndName	= @FilePath + @FileNamePrefix + @FileNameSuffix
set @EmailBody				= @FullFilePathAndName

/****************************************************************************

	Clear old tables
																		
****************************************************************************/

truncate table dbo.RPT_ExpensesReimbursed

/****************************************************************************

	Select report data																									
****************************************************************************/

set dateformat dmy
insert	into dbo.RPT_ExpensesReimbursed
(
	[Standing Order],
	[Enterprise Code],
	[Enterprise Name],
	[Gross Amount],
	[VAT],
	[Net Amount],
	[Error]
)
exec cscp_ExpensesReimbursed '', @StartDate, @EndDate

set @RowCount = @@rowcount


/****************************************************************************

	Output data
																		
****************************************************************************/

declare @ExcelStructure varchar(8000)
-- vExcelWorkbookName is the physical name of the file created in C:\Temp on MIDB.
-- The final step of the process copies the file from C:\Temp to what has been
-- defined in @FullFilePathAndName.
set @ExcelStructure = 
		'<package name="\' + @SSISFileSystem + '\ReportToExcel" notifyMethod="Email" notifyOperator="SQL Server Admin" 
						owner="sa" > 
					<variable name="vWorkingTableQueries" value="select * from dbo.RPT_ExpensesReimbursed"/> 
					<variable name="vWorkSheetNames" value="ExpensesReimbursed"/>
					<variable name="vExcelWorkbookName" value="ExpensesReimbursed"/>
					<variable name="vTableName" value="RPT_ExpensesReimbursed"/>
					<variable name="vExcelVersion" value=".xls"/>
				</package>' 

if @RowCount > 0
	BEGIN
		DECLARE @xVar XML 
		SET @xVar = @ExcelStructure
		exec [DBManagement].[dbo].[usp_ExecuteSSISPackage] @xVar, @FileName = @FullFilePathAndName
	END

/****************************************************************************

	E N D	
		
****************************************************************************/


set @ProcessMessage = @Process + '. Number of rows = ' + convert(varchar(20),@RowCount)

exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client




GO
