/****************************************************************************
Program:  	    owp_CaseSelectionversusInsightPanelList
Author:	        Mike Cawood
Date Created:	  06/09/2010							
											
Description:	

This procedure lists all Cases created on Insight on or after the Extract Date 
together with key details about the Seller including the current Panel flag.

It is called as follows:
		exec owp_CaseSelectionversusInsightPanelList '0'

			
Amendment History								
-----------------								
											
Date  		    Who		    	  Description				
----	    	  --- 			    -----------			
15/10/2010    M Cawood      Amend Panel derivation on SWIFT Comm Shape to align with
                            codes and descriptions set up on Insight.

****************************************************************************/
CREATE PROCEDURE [dbo].[owp_CaseSelectionversusInsightPanelList]
	@Days     int = 0
AS

declare @Yesterday datetime;
set @Yesterday = dateadd(dd,-1,datediff(dd,0,getdate()))

declare @ExtractDate datetime;
set @ExtractDate = (select dbo.owf_CalcDateNWorkingDaysEarlierthanDate(@Yesterday,@Days))

Select CASE_CASEReference as Opportunity,
max(Case when RFC_Description like '%replace%' then 1 else 0 end) as Replace,
max(Case when RFC_Description like '%switch%' then 1 else 0 end) as Switch
into #Type
from sa_insight_SalesCase 
LEFT OUTER JOIN sa_insight_BasicPolicy ON sa_insight_BasicPolicy.BPOL_ParentID = sa_insight_SalesCase.CASE_ID 
LEFT OUTER JOIN sa_insight_SalesCaseRFC 
	ON sa_insight_SalesCaseRFC.SCRFC_SalesCaseID = sa_insight_SalesCase.CASE_ID AND sa_insight_SalesCaseRFC.SCRFC_Status = 1
LEFT OUTER JOIN sa_insight_RFC RFC on RFC_ID = SCRFC_RFCID
Where RFC_Description like '%switch%' or RFC_Description like '%replace%'
Group by CASE_CASEReference

select DISTINCT
Opportunity         = CASE_CASEReference,
CaseFromOBPDate     = CASE_SubmitDate,
CaseCreatedDate     = CASE_CreatedDate,
PolicyName          = BPOL_Name,
CaseID              = BP.BPOL_BackOfficeID,
ProductName         = VP.ProductName,
RFCType             = RFC_Description,
RFCGroup            = RFC_Group,
ReplonOpp           = Case when T1.Replace = 1 then 'Yes' end,
SwitchonOpp         = Case when T1.Switch = 1 then 'Yes' end,
DateCompleted       = cast(floor(cast(bqf.BQ_CompletedDate as float)) as datetime),
--Panel               = UPS_Section,                            --MPC: 15/10/2010
Panel               = isnull(CD2.Code_Description,'Unknown'),   --MPC: 15/10/2010
UserRole            = isnull(CD1.Code_Description,'Unknown'),   --MPC: 15/10/2010
AdviserID           = coalesce(adviserid, '0000000'),
AgentName           = ltrim(rtrim(AG.DESCN)),
Enterprise          = A2.CODE,
EnterpriseName      = ltrim(rtrim(isnull(A2.TradingName,A2.DESCN)))
FROM sa_insight_salescase
inner join sa_insight_basicpolicy BP on bpol_parentid = case_id
left join (select bq_parentid,min(bq_CheckDate) as FirstCheck,max(bq_CheckDate) as LastCheck
           from sa_insight_businessquality 
           where bq_status <> 8
           group by bq_parentid ) bqdate on bqdate.bq_parentid = case_Id
left join sa_insight_businessquality bq1 on bq1.bq_parentid = case_id and bq1.bq_checkdate = bqdate.FirstCheck
left join sa_insight_businessquality bqf on bqf.bq_parentid = case_id and bqf.bq_checkdate = bqdate.LastCheck and case_checkingcomplete = 1
left join sa_insight_salescaserfc on scrfc_salescaseid = case_id and scrfc_status = 1
left join sa_insight_RFC on RFC_ID = SCRFC_RFCID
left join #Type T1 on T1.Opportunity = CASE_CASEReference
inner join sa_insight_userposition UPS on ups_id = case_userpositionid
left join (select bqr_caseid, bqr_businessqualityid, max(cfq_questioncode % 5) as Reason from sa_insight_businessqualityresult inner join sa_insight_complianceformquestion on cfq_id = bqr_questionid and cfq_questioncode between 157 and 161 and bqr_code = 101 group by bqr_caseid, bqr_businessqualityid) reason on bqr_caseid = case_id and bqr_businessqualityid = bq1.bq_id
left join sa_insight_Staff SC on SC.STAF_UserId = CASE_CreatedBy
left join sa_insight_Staff SC2 on SC2.STAF_UserId = CASE_UpdatedBy
left join sa_insight_Staff SC3 on SC3.STAF_UserId = bq1.BQ_CheckedBy
left join sa_insight_Staff SC4 on SC4.STAF_UserId = bq1.BQ_CreatedBy
left join sa_insight_Staff SC5 on SC5.STAF_UserId = isnull(bqf.BQ_UpdatedBy,bq1.BQ_UpdatedBy)
left join sa_insight_Staff SC6 on SC6.STAF_UserId = isnull(bqf.BQ_CompletedBy,bq1.BQ_CompletedBy)
left join dds_d_qualityadviser on adviserid = ups_externalid
left join dds_d_product vp on vp.producttype = bpol_producttype
left outer join sa_obpmi_Opportunity O on O.Clientfacingopportunityid = CASE_CASEReference
inner join (Select BPOL_ID,BPOL_BackOfficeID as BOID from sa_insight_basicpolicy where len(BPOL_BackOfficeID) <= 9 and isnumeric(BPOL_BackOfficeID)  = 1) BPOL on BPOL.BPOL_ID = BP.BPOL_ID
left join mstt_Policies PO on PO.Policyref = BPOL.BOID
left join mstt_Agents AG on AG.CODE = coalesce(adviserid, '0000000')
left join mstt_Agents A2 on A2.CODE = AG.FIRM and A2.AgentType in (2,46,49)
left join sa_insight_UserDetails UD ON UD.USR_ID = UPS_UserId
left join sa_insight_CodeDescription CD1 on CD1.Code_SystemID = 200 and CD1.Code_CodeType = 11 and CD1.Code_Code = UPS_UserType     --User Type     --MPC: 15/10/2010
left join sa_insight_CodeDescription CD2 on CD2.Code_SystemID = 200 and CD2.Code_CodeType = 53 and CD2.Code_Code = UPS_Section      --Section       --MPC: 15/10/2010
where CASE_CreatedDate >= @ExtractDate
Order by 1,5,7

drop table #Type;
GO
/****** Object:  StoredProcedure [dbo].[owp_CheckDataMatches]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_CheckDataMatches](@RunId     int,
                                          @JobId     smallint,
                                          @StepId    smallint,
                                          @DebugMode bit = 0)
as
begin
  set nocount on;

	--Declare variables
  declare @CR                 varchar(2);
  declare @SQL                nvarchar(max);
  declare @ErrCode            int;
  declare @Message            varchar(2000);
  declare @ProcedureName      nvarchar(128);

  declare @Line               nvarchar(max);
  declare @LineLen            int;
  declare @MaxColLen          int;
  declare @MaxPKColLen        int;
  declare @FirstPKColName     nvarchar(128);
  declare @i                  int;
  declare @j                  int;
  declare @Unmatched          xml
  
  declare @CmpDataSource1     varchar(128);
  declare @CmpDataSource2     varchar(128);
  declare @CmpDifferenceTable varchar(128);
  declare @CmpCommand         varchar(max);
  
  declare @TableDef table(ColumnId      smallint not null,
                          ColumnName    nvarchar(128) not null,
                          TypeConvert   nvarchar(177) not null,
                          IsNullable    nvarchar(9) not null,
                          IsPKColumn    bit not null,
                          PKPosition    smallint null,
                          PKName        nvarchar(128) null,
                          PKDesc        varchar(12) null,
                          primary key clustered (ColumnId));
  begin try
    -----------------------------------------------------------------------------------------------
    --Initialize
    -----------------------------------------------------------------------------------------------
    --Set variables
    set @CR            = char(13)+char(10);
    set @ErrCode       = 0;
    set @ProcedureName = object_name(@@procid);

    -----------------------------------------------------------------------------------------------
    --Check and calculate initial data                                 
    -----------------------------------------------------------------------------------------------
    select @CmpDataSource1     = nullif(rtrim(object_name(object_id(d.CmpDataSource1))), ''),
           @CmpDataSource2     = nullif(rtrim(object_name(object_id(d.CmpDataSource2))), ''),
           @CmpDifferenceTable = nullif(rtrim(d.CmpDifferenceTable), ''),
           @CmpCommand         = nullif(rtrim(d.CmpCommand), '')
    from dbo.owt_JobDefinitionDetails d
    where d.JobId       = @JobId and
          d.StepId      = @StepId and
          d.CmpIsActive = 1 and
          d.IsActive    = 1;

    if (@CmpDataSource1 is null or @CmpDataSource2 is null or @CmpDifferenceTable is null) and 
       (@CmpDifferenceTable is null or @CmpCommand is null)
    begin
      set @Message = 'There is no active data comparision defined in dbo.owt_JobDefinitionDetails table '+
                     'for JobId = '+convert(varchar(18), @JobId)+' and StepId = '+convert(varchar(18), @StepId)+'.';
      raiserror(@Message, 16, 10);
    end;

    --Read history details
    select @RunId  = d.RunId,
           @JobId  = d.JobId,
           @StepId = d.StepId
    from dbo.owt_JobRunHistoryDetails d
    where d.RunId       = @RunId and
          d.JobId       = @JobId and
          d.StepId      = @StepId;

    --Compare datasets
    if @CmpCommand is not null
    begin
      set @SQL = @CmpCommand;
      
      if isnull(@DebugMode, 0) = 1
      begin
        --Print @CmpCommand
        print(@CR+'-------- SQL -------->');

        set @j = 1;
        set @i = charindex(@CR, @SQL, @j);
        
        --Print line by line
        while @i > 0
        begin
          set @Line = substring(@SQL, @j, @i - @j);
          print(@Line);
          set @j = @i + 2;
          set @i = charindex(@CR, @SQL, @j);
        end;
      
        --Print last line
        if @j < len(@SQL)
        begin
          set @Line = substring(@SQL, @j, len(@SQL) - @j + 1);
          print(@Line);
        end;
        print('-------- SQL --------<'+@CR+@CR);
      end;

      --Compare tables
      exec dbo.sp_executesql @stmt   = @SQL,
                             @params = N'@RunId int',
                             @RunId  = @RunId;
                             
      --Check rows affected
      print(convert(varchar(19), getdate(), 121)+' - '+convert(varchar(18), isnull(@@rowcount, 0))+' row(s) different.');
    end
    else
    begin
      --Populate @TableDef table
      -----------------------------
      insert into @TableDef(ColumnId,
                            ColumnName,
                            TypeConvert,
                            IsNullable,
                            IsPKColumn,
                            PKPosition,
                            PKName,
                            PKDesc)
      select ColumnId      = c.colid,
             ColumnName    = rtrim(c.name),
             TypeConvert   = case when t.name = 'image' then 'varbinary(max)'
                                  when t.name = 'text'  then 'varchar(max)'
                                  when t.name = 'ntext' then 'nvarchar(max)'
                                  when t.name = 'xml'   then 'nvarchar(max)'
                                  when t.name = 'float' then 'decimal(28, 6)'
                                  else rtrim(t.name)
                             end+
                             case when t.name in ('decimal', 'numeric') then '('+convert(varchar(18), c.prec)+', '+convert(varchar(18), c.scale)+')'
                                  when t.name in ('binary', 'char', 'nchar') then '('+convert(varchar(18), c.prec)+')'
                                  when t.name in ('varbinary', 'varchar', 'nvarchar') then '('+case when c.length < 0 then 'max' else convert(varchar(18), c.prec) end+')'
                                  else ''
                             end,
             IsNullable    = case when c.isnullable = 1 then ' null' else ' not null' end,
             IsPKColumn    = convert(bit, case when ik.keyno is null then 0 else 1 end),
             PKPosition    = ik.keyno,
             PKName        = i.name,
             PKDesc        = case when (i.status & 0x10) = 0x10 then 'clustered' else 'nonclustered' end
      from dbo.sysobjects o
           inner join dbo.syscolumns c on o.id = c.id
           inner join dbo.systypes t on c.xtype = t.xtype and
                                        c.xtype = t.xusertype
           left outer join dbo.sysindexes i on o.id              = i.id and
                                               (i.status & 0x800) = 0x800  --primary key
           left outer join dbo.sysindexkeys ik on i.id    = ik.id and
                                                  i.indid = ik.indid and
                                                  c.id    = ik.id and
                                                  c.colid = ik.colid
      where o.xtype = 'U' and
            o.id    = object_id(@CmpDataSource1);

      --Get max primary key column length and the first column name, defining primary key
      select @MaxPKColLen    = max(len(d.ColumnName)),
             @FirstPKColName = max(case when d.PKPosition = 1 then d.ColumnName else '' end)
      from @TableDef d
      where d.IsPKColumn = 1;

      if @FirstPKColName is null
      begin
        set @Message = 'Error reading primary key details for '+@CmpDataSource1+' table. PK may not be created.';
        raiserror(@Message, 16, 10);
      end;
      
      --Get max column length
      select @MaxColLen = max(len(d.ColumnName))
      from @TableDef d;

      --Check if difference table exists
      if object_id(@CmpDifferenceTable) is null
      begin
        --Create Difference table
        --------------------------
        set @Line = 'create table dbo.'+quotename(@CmpDifferenceTable)+'(';
        set @Linelen = len(@Line);
        
        set @Line = @Line+quotename('RunId')+space(@MaxColLen-len('RunId')+5)+'int not null';

        --Build column list
        select @Line = isnull(@Line+','+@CR+space(@LineLen), '') + 
                       quotename('DS1_'+d.ColumnName)+space(@MaxColLen-len(d.ColumnName)+1)+d.TypeConvert+' null,'+@CR+space(@LineLen)+
                       quotename('DS2_'+d.ColumnName)+space(@MaxColLen-len(d.ColumnName)+1)+d.TypeConvert+' null'
        from @TableDef d
        order by d.ColumnID;    

        set @SQL = @Line+');';
        
        if isnull(@DebugMode, 0) = 1
        begin
          --Print SQL

          print(@CR+'-------- SQL -------->');
          set @j = 1;
          set @i = charindex(@CR, @SQL, @j);
          
          --Print line by line
          while @i > 0
          begin
            set @Line = substring(@SQL, @j, @i - @j);
            print(@Line);
            set @j = @i + 2;
            set @i = charindex(@CR, @SQL, @j);
          end;
        
          --Print last line
          if @j < len(@SQL)
          begin
            set @Line = substring(@SQL, @j, len(@SQL) - @j + 1);
            print(@Line);
          end;
          print('-------- SQL --------<'+@CR+@CR);
        end;
        
        --Create table
        exec(@SQL);
        
        if object_id(@CmpDifferenceTable) is not null
          print(convert(varchar(19), getdate(), 121)+' - Table '''+@CmpDifferenceTable+''' has been created.');
      end;

      if object_id(@CmpDifferenceTable) is null
      begin
        set @Message = 'Table '''+@CmpDifferenceTable+''' does not exists.';
        raiserror(@Message, 16, 10);
      end
      
      --Compare data
      ---------------------
      set @SQL = '';
      
      --Insert
      set @Line = 'insert into dbo.'+quotename(@CmpDifferenceTable)+'(';
      set @Linelen = len(@Line);
      
      set @Line = @Line+quotename('RunId');

      --Build column list
      select @Line = isnull(@Line+','+@CR+space(@LineLen), '') + 
                     quotename('DS1_'+d.ColumnName)+','+@CR+space(@LineLen)+
                     quotename('DS2_'+d.ColumnName)
      from @TableDef d
      order by d.ColumnID;    

      set @SQL = @Line+')'+@CR;

      --First select
      set @Line = 'select ';
      set @LineLen = len(@Line)+1;
      set @SQL = @SQL + @Line;
      
      --Build column list
      set @Line = quotename('RunId')+space(@MaxColLen-len('RunId')+5)+'= convert(int, @RunId)';
      select @Line = isnull(@Line+','+@CR+space(@LineLen), '') + 
                     quotename('DS1_'+d.ColumnName)+space(@MaxColLen-len(d.ColumnName)+1)+
                     '= convert('+d.TypeConvert+', s.'+quotename(d.ColumnName)+'),'+@CR+
                     space(@LineLen)+quotename('DS2_'+d.ColumnName)+space(@MaxColLen-len(d.ColumnName)+1)+
                     '= convert('+d.TypeConvert+', t.'+quotename(d.ColumnName)+')'
      from @TableDef d
      order by d.ColumnID;
      
      set @SQL = @SQL + @Line + @CR;
      
      set @Line = 'from (select ';
      set @LineLen = len(@Line)+1;
      set @SQL = @SQL + @Line;

      --Internal select list
      set @Line = null;
      select @Line = isnull(@Line+','+@CR+space(@LineLen), '') +
                     quotename(d.ColumnName)+space(@MaxPKColLen-len(d.ColumnName)+1)+'= coalesce(convert('+TypeConvert+', xs.'+quotename(d.ColumnName)+'), convert('+TypeConvert+', xt.'+quotename(d.ColumnName)+'))'
      from @TableDef d
      where d.IsPKColumn = 1
      order by d.PKPosition;

      set @SQL = @SQL + @Line+@CR;
      set @SQL = @SQL + '      from dbo.'+quotename(@CmpDataSource1)+' xs'+@CR;
      set @Line = space(11)+'full outer join dbo.'+quotename(@CmpDataSource2)+' xt on ';
      set @LineLen = len(@Line)+1;
      set @SQL = @SQL + @Line;
      
      --Build PK column list
      set @Line = null;
      select @Line = isnull(@Line+' and'+@CR+space(@LineLen), '') +
                     case when d.IsNullable = ' not null' or d.PKPosition = 1 then 'convert('+TypeConvert+', xs.'+quotename(d.ColumnName)+') = convert('+TypeConvert+', xt.'+quotename(d.ColumnName)+')'
                          else '(isnull(xs.'+quotename(d.ColumnName)+', xt.'+quotename(d.ColumnName)+') is null or convert('+TypeConvert+', xs.'+quotename(d.ColumnName)+') = convert('+TypeConvert+', xt.'+quotename(d.ColumnName)+'))'
                     end
      from @TableDef d
      order by d.ColumnId;

      set @SQL = @SQL + @Line + @CR;
      
      set @SQL = @SQL + space(6)+'where xs.'+quotename(@FirstPKColName)+' is null or'+@CR+
                        space(12)+'xt.'+quotename(@FirstPKColName)+' is null'+@CR;

      set @Line = space(6)+'group by ';
      set @LineLen = len(@Line)+1;
      set @SQL = @SQL + @Line;

      --Internal select list
      set @Line = null;
      select @Line = isnull(@Line+','+@CR+space(@LineLen), '') +
                     'coalesce(convert('+TypeConvert+', xs.'+quotename(d.ColumnName)+'), convert('+TypeConvert+', xt.'+quotename(d.ColumnName)+'))'
      from @TableDef d
      where d.IsPKColumn = 1
      order by d.PKPosition;

      set @SQL = @SQL + @Line + ') as x' + @CR;
      
      set @Line = space(5)+'left outer join dbo.'+quotename(@CmpDataSource1)+' s on ';
      set @LineLen = len(@Line)+1;
      set @SQL = @SQL + @Line;
      
      set @Line = null;
      select @Line = isnull(@Line+' and'+@CR+space(@LineLen), '') +
                     'convert('+TypeConvert+', x.'+quotename(d.ColumnName)+')'+space(@MaxPKColLen-len(d.ColumnName)+1)+'= convert('+TypeConvert+', s.'+quotename(d.ColumnName)+')'
      from @TableDef d
      where d.IsPKColumn = 1
      order by d.PKPosition;

      set @SQL = @SQL + @Line + @CR;

      set @Line = space(5)+'left outer join dbo.'+quotename(@CmpDataSource2)+' t on ';
      set @LineLen = len(@Line)+1;
      set @SQL = @SQL + @Line;
      
      set @Line = null;
      select @Line = isnull(@Line+' and'+@CR+space(@LineLen), '') +
                     'convert('+TypeConvert+', x.'+quotename(d.ColumnName)+')'+space(@MaxPKColLen-len(d.ColumnName)+1)+'= convert('+TypeConvert+', t.'+quotename(d.ColumnName)+')'
      from @TableDef d
      where d.IsPKColumn = 1
      order by d.PKPosition;

      set @SQL = @SQL + @Line + @CR+'option (maxdop 1);';

      if isnull(@DebugMode, 0) = 1
      begin
        --Print SQL
        print(@CR+'-------- SQL -------->');
        set @j = 1;
        set @i = charindex(@CR, @SQL, @j);
        
        --Print line by line
        while @i > 0
        begin
          set @Line = substring(@SQL, @j, @i - @j);
          print(@Line);
          set @j = @i + 2;
          set @i = charindex(@CR, @SQL, @j);
        end;
      
        --Print last line
        if @j < len(@SQL)
        begin
          set @Line = substring(@SQL, @j, len(@SQL) - @j + 1);
          print(@Line);
        end;
        print('-------- SQL --------<'+@CR+@CR);
      end;

      --Compare tables
      exec dbo.sp_executesql @stmt   = @SQL,
                             @params = N'@RunId int',
                             @RunId  = @RunId;

      print(convert(varchar(19), getdate(), 121)+' - '+convert(varchar(18), isnull(@@rowcount, 0))+' row(s) different.');
    end;
  end try
  begin catch
    set @Message = 'Error in line '+ convert(varchar(18), error_line())+
                   ' of '+isnull(quotename(error_procedure())+' procedure:', ' ad-hoc query in '+quotename(@ProcedureName))+' procedure:'+@CR+
                   isnull(error_message(), '');    
    print(@Message);
    raiserror(@Message, 16, 10);
  end catch;  
end;
GO
/****** Object:  StoredProcedure [dbo].[owp_CommissionStatement_RV]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_CommissionStatement_RV]
 -- @Client   varchar(50),            --MPC:21/01/2010
 --- @Module   varchar(50),            --MPC:21/01/2010
--  @StartDate  varchar(10)           --MPC:21/01/2010		--MPC:08/08/2012
 --- @StartDate  datetime				--MPC:08/08/2012    
AS

Declare
  @Mode       varchar(4),    --'FULL' or 'MOVE'
  @DistributionAllowance float,
  @DefaultStandingOrderCode     int,
  @DefaultStandingOrderDesc     nvarchar(255)


Set @Mode = 'MOVE'
Set @DistributionAllowance = 0.0
set @DefaultStandingOrderCode = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'StandingOrderCode')
set @DefaultStandingOrderDesc = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'StandingOrderDesc')   

/******************************************************************************************************************************

  BEGIN PROCESSING  - Temp Table #CommissionStatement

****************************************************************************************************************************/

Drop table #AGMFILChanges2;
Drop table #Frequency;
Drop table #msit_CommissionStatement;
Drop table #Margins2;
Drop table #Comm;
Drop table #TotPaid;
Drop table #Totdue;
drop table #TransExcept;
drop table #TransExcept2; 
drop table #TransExcept3;
drop table #Expectations4; 
drop table #Expectations5; 
drop table #Expectations6; 
drop table #PP;
drop table #FranchiseName;
drop table #PolicyNumber;
drop table #ClientNames; 
drop table #CommRate; 
drop table #CommRate1;
 

/*===========================================================================================
    IDENTIFY S_AGMFIL Rows to be Processed based on @Mode and @MovementStartDate
===========================================================================================*/

--MPC 21/01/2010 Start of Identify Payment Movements processing

CREATE TABLE #AGMFILChanges2 (ID int)
CREATE INDEX #X ON #AGMFILCHANGES2 (ID)

IF @Mode = 'FULL'	--FULL Reload of Table
BEGIN

	Insert INTO #AGMFILCHANGES2
	Select Distinct ID 
	from sa_swift_S_AGMFIL 


END	--@Mode = 'FULL'

IF @Mode = 'MOVE'	--Process Movements only
BEGIN

	Insert	INTO #AGMFILCHANGES2
	Select	DISTINCT PKID 
	FROM	owt_TransformationMovements
	Where	DriverTableName = 'sa_swift_S_AGMFIL'
	and		CommissionStatement = 'Y'				-- AG 30/03/2010

END		--@Mode = 'MOVE'

--MPC 21/01/2010 End of Identify Payment Movements processing

/*===========================================================================================
    PROCESS S_AGMFIL Rows selected based on @Mode and @MovementStartDate
===========================================================================================*/

--All columns except ID selected onto #msit_CommissionStatement as Primary Key defined on Insert

CREATE TABLE #msit_CommissionStatement
(
	[AgentCode] [varchar](7) NULL,
	[PaymentType] [varchar](100) NULL,
	[StandingOrderCode] [varchar](8) NULL,
	[StandingOrderDesc] [varchar](255) NULL,
	[StandingOrderText] [varchar](255) NULL,
	[CommissionType] [int] NULL,
	[ReportingClassCode] [varchar](10) NULL,
	[ReportingClassDesc] [varchar](100) NULL,
	[BusinessCode] [varchar](7) NULL,
	[SellerName] [varchar](255) NULL,
	[FranchiseName] [varchar](255) NULL,
	[CommProviderCode] [varchar](10) NULL,
	[CommProviderDesc] [varchar](100) NULL,
	[PaymentDate] [datetime] NULL,
	[PaymentStatus] [varchar](10) NULL,
	[Amount] [float] NULL,
	[DebitCredit] [varchar](1) NULL,
	[ExtPolicyNumber] [varchar](25) NULL,
	[ClientSurname] [varchar](60) NULL,
	[ClientForenames] [varchar](60) NULL,
	[ProductCode] [varchar](8) NULL,
	[StartDate] [datetime] NULL,
	[FrequencyCode] [tinyint] NULL,
	[FrequencyDesc] [varchar](20) NULL,
	[Premium] [float] NULL,
	[CommissionRate] [float] NULL,
