-- insert details from sa_swift_AgentPayments, mstt_PaymentsPending & mstt_Agents 
 
insert into #msit_CommissionStatement
select DISTINCT						--MPC 21/01/2010
 PP.Agent_Code [AgentCode], 
 AP.PaymentType [PaymentType], 
 PP.StandingOrderCode * 1 [StandingOrderCode], 
 PP.Notes [StandingOrderDesc], 
 '' [StandingOrderText], 
 PP.TYPE [CommissionType], 
 '' [ReportingClassCode], 
 '' [ReportingClassDesc], 
AG.FIRM [BusinessCode], 
 rtrim(AG.Descn) [SellerName], 
 '' [FranchiseName], 
 '' [CommProviderCode], 
 '' [CommProviderDesc], 
 convert(datetime,coalesce(AP.PaymentDate,PP.CreateDateTime,'1901-01-01'),103) [PaymentDate],
 case 
 when AP.Export_Date is null then 'Pending' 
 else 'Paid' end [PaymentStatus], 
 isnull(AP.Amount, PP.Amount) [Amount], 
 case 
 when PP.Amount < '0' then 'D' 
 else 'C' end [DebitCredit], 
 '' [ExtPolicyNumber],
 '' [ClientSurname], 
 '' [ClientForenames], 
 '' [ProductCode], 
 '' [StartDate], 
 '' [FrequencyCode], 
 '' [FrequencyDesc], 
 '' [Premium], 
 '' [CommissionRate], 
 '' [InitialPeriod], 
 [FranchiseUpliftRate] = case
                          when PP.Type in ('4','10','15','16','18','19') then '100'
                          else isnull(PP.FranchiseUpliftPercent, 0.0)
                         end,
 '' [PayBasisCode], 
 '' [PayBasisDesc], 
 0  [CommSacrificeAmt],			--MPC: 22/03/2010 
 0  [CommSacrificePct],			--MPC: 22/03/2010
 [AgentSplit] = isnull(PP.AGENT_PERC, 0.0),
 '' [FranchiseSplit], 
 PP.Type [CommFeeCode], 
 case
 when isnull(PH.ProductCode,'') in ('OWADHOC') and PP.Type in ('1','2','17') then 'Ad Hoc'		--MPC: 21/11/2012 - SR191818
 when PP.Type in ('1','2','17') and sh.CommShapePrefix = 'ADH'  then 'Ad Hoc'						--MPC: 21/11/2012 - SR191818
 when isnull(PH.RDRType,'') <> '' and PP.Type in ('1','2','17') then 'Upfront'					--MPC: 21/11/2012 - SR191818
 when isnull(PH.RDRType,'') <> '' and PP.Type in ('4','10','15','16','18','19') then 'Ongoing'	--MPC: 21/11/2012 - SR191818
 when isnull(PH.RDRType,'') <> '' then 'Fee'		--MPC: 03/05/2012 - SR153273 
 when PP.Type in ('1','2','17') then 'IC' 
 when PP.Type = '3' then 'Agt'																--MPC: 03/05/2012 - SR153273 
 when PP.Type in ('4','15','18') then 'RC' 
 when PP.Type in ('10','16','19') then 'Trail' 
 when PP.Type in ('11','12') then 'Adj' 
 when PP.Type = '13' then 'Fee' 
 when PP.Type in ('15','16') then 'Claw' 
 else 'Oth' end [CommFeeType], 
 case 
 when PP.Type in ('1','2','17') and sh.CommShapePrefix = 'ADH'  then 'Fee Net VAT'					--MPC: 21/11/2012 - SR191818
 when PP.Type in ('1','2','17') and sh.CommShapePrefix = 'UA'   then 'U&A Fee'						--MPC: 21/11/2012 - SR191818
 when PP.Type in ('1','2','17') and sh.CommShapePrefix = 'FEE'  then 'A&I Fee'						--MPC: 21/11/2012 - SR191818
 when PP.Type in ('1','2','17') and sh.CommShapePrefix = 'IMP'  then 'A&I Fee XChg'					--MPC: 21/11/2012 - SR191818
 when PP.Type in ('1','2','17') and isnull(PH.RDRType,'') <> '' then 'Upfront Fee'					--MPC: 21/11/2012 - SR191818
 when PP.Type in ('4','10','15','16','18','19') and isnull(PH.RDRType,'') <> '' then 'Ongoing Fee'	--MPC: 21/11/2012 - SR191818
-- when isnull(PH.RDRType,'') in ('DIRECT','OFPLAT','ONPLAT') then 'Fee' --MPC: 03/05/2012 - SR153273
 when PP.Type in ('1','4','10','13') then 'New' 
 when PP.Type in ('2','15','16') then 'Claw' 
 else 'Adj' end [CommReason], 
 '' [TotDue], 
 '' [FirstID], 
 '' [LastID], 
 '' [ExpectCount], 
 '' [TotPaid], 
 '' [AccruedToDate], 
 [BaseAmount] = case
                 when PP.Amount < 0 and PP.BaseAmount > 0 then PP.BaseAmount * -1
                 when PP.Amount > 0 and PP.BaseAmount < 0 then PP.BaseAmount * -1			-- PR 13/9/08
                 when PP.BaseAmount is NULL and PP.Type in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                           when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                           else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                          end > 100 then round(PP.Amount / (0.01 * case -- FranchiseUpliftRate
                                                                                                                                    when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                                                                    else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                   end),2)
                 when PP.BaseAmount is NULL and PP.Type in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                           when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                           else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                          end <= 100 then PP.Amount
                 else PP.BaseAmount
                end,
 [UpliftAmount] = case
                   when PP.Amount < 0 and PP.UpliftAmount > 0 then PP.UpliftAmount * -1
                   when PP.UpliftAmount is NULL and PP.Type in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                               when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                               else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                              end > 100 then PP.Amount - case -- BaseAmount
                                                                                                                          when PP.Amount < 0 and PP.BaseAmount > 0 then PP.BaseAmount * -1
                                                                                                                          when PP.Amount > 0 and PP.BaseAmount < 0 then PP.BaseAmount * -1    --  PR 13/9/08
                                                                                                                          when PP.BaseAmount is NULL and PP.Type in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                                                                                                                                    when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                                                                                                                                    else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                                                                                   end > 100 then round(PP.Amount / (0.01 * case -- FranchiseUpliftRate
                                                                                                                                                                                                                                             when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                                                                                                                                                                             else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                                                                                                                            end),2)
                                                                                                                          when PP.BaseAmount is NULL and PP.Type in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                                                                                                                                    when PP.Type in ('4','10','15','16','18','19') then '100'
                                                                                                                                                                                                    else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                                                                                   end <= 100 then PP.Amount
                                                                                                                          else PP.BaseAmount
                                                                                                                         end
                   else PP.UpliftAmount
                  end,
 '' [INIssued], 
 '' [INAccrued], 
 '' [INIndemnity], 
 case
 when PP.Due_Date < '2006-01-01' then PP.PaymentDueDate
 else PP.Due_Date end [DueDate], 
 PP.AuthorisedDate [AuthDate], 
 AP.PaymentDate [PaidListDate], 
 AP.ID [AgentPaymentsID], 
 PP.ID [PendingPaymentID], 
 PP.PACC_ID [ExpectationID], 
 PP.TransactionID [TransactionID], 
 '' [PolicyID], 
 '' [ClientID], 
 '' [CommissionsID], 
---- PP.StandingOrderId [AgtStandingOrderID], ---MF 23/02/2024 Tech Debt: StandingOrderID for mstt_PaymentsPending replaced by AGMFIL's StandingOrderCode
 PP.StandingOrderCode [AgtStandingOrderID],
 '' [CaseID],
 '' [APE],  --From mstt_PolicyTransactions, linked via TransactionID :MF 16/02/24,
	case 
		when 	PP.Type = 21	-- RH CR229 mortgage early payment test added			and PP.Amount < 0
			and PP.PaymentDueDate is not null 
		then	convert(datetime,convert(varchar,PP.PaymentDueDate,106)) -- RH convert to whole date (not sure if needed but CreateDateTime below had similar treatment
										 -- Use 106 as totally unambiguous ie "10 Jan 2007" and not 1/10, ... 10/1 etc
		else	convert(datetime,convert(varchar,PP.CreateDateTime,106)) -- RH tidied up existing ungainly processing to convert to whole date
	end 
	[CreateDate],
 '' [Month],
 '' [ProviderName],
 '' [ProviderCode],
 '' [SuspendComm],
 '' [CommShapeID],		-- WI260
 '' [LastAccrualinMonth],	-- WI260
 case when AG.FIRM is null then 'No FIRM' else 'Valid' end [OAStatus], 	--MPC:16/04/08 SR9
 '' [SchemeNum]
from sa_swift_S_AGMFIL PP					-- AG 24/02/2010
 Inner Join #AGMFILChanges2 X ON X.ID = PP.ID		--MPC 21/01/2010 Select Daily Movements only
 Inner Join Sa_Swift_Policytransactions pt on pt.ID = PP.TransactionID  ---MF 16/02/2024 Added to join pt.CommProductCode  
 inner join sa_swift_S_AGENTS AG on PP.AGENT_CODE = AG.Code 
-- left outer join mstt_AgentPayments AP on PP.id = AP.agmid	--MPC 21/01/2010
 left outer join sa_swift_S_AGMPAY AP on PP.id = AP.agmid		--MF 16/02/2024 Replace mstt_Agents 
 left join mstt_ProductHierarchy PH on PH.ProductCode collate SQL_Latin1_General_CP1_CI_AS = pt.CommProductCode	---MF 16/02/2024 Replace pp.tranproduct with pt.CommProductCode
 left join (select pt.id as TranId,substring(sh.description,1,3) as CommShapePrefix				--MPC: 21/11/2012 - SR191818
			from Sa_Swift_Policytransactions pt														--MPC: 21/11/2012 - SR191818
			inner join (Select pp.Transactionid													--MPC: 21/11/2012 - SR191818
						from sa_swift_S_AGMFIL PP												--MPC: 21/11/2012 - SR191818
						inner join #AGMFILChanges2 X ON X.ID = PP.ID								--MPC: 21/11/2012 - SR191818
						group by pp.Transactionid) Y on Y.Transactionid = pt.id					--MPC: 21/11/2012 - SR191818
			inner join mstt_ProductHierarchy ph on ph.productcode collate SQL_Latin1_General_CP1_CI_AS = pt.commproductcode			--MPC: 21/11/2012 - SR191818
			inner join sa_swift_CodeCommissionShape sh on sh.id = pt.CodeCommissionShapeId		--MPC: 21/11/2012 - SR191818
			where ph.RDRType is not null														--MPC: 21/11/2012 - SR191818
			group by pt.id,substring(sh.description,1,3)) sh on sh.TranId = pp.Transactionid	--MPC: 21/11/2012 - SR191818

where 
	-- RH CR226 include Authorised test and rephrased "where" clause to match spec
	AG.Agt_Type in ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55') 	--MPC:19/02/2008
	and isnull(PP.Due_Date,'1901-01-01') < getdate() -- MWA 03/09/2006 Change Requested by MC
	and not (
			PP.Type in ('0','7','14','20','21') 
			and (
				isnull(PP.AuthorisedDate,'1901-01-01') = '1901-01-01'
				or PP.Authorised<>0
			)
			and ap.id is null
		)
create index rt1 on #msit_CommissionStatement(TransactionID,AgentCode)				--MPC 21/01/2010
create index rt2 on #msit_CommissionStatement(PendingPaymentID)		
