--Set the SplitMargin

select isnull(cs.TransactionID, -99) as TransactionId, co.GrossOrNet, co.FixedAmount, co.AGENT_PERC, sum(co.FixedAmount) as Margin
into #Margins2 
from #msit_commissionstatement cs
inner join sa_Swift_S_AGTCOM co on co.TransactionID = cs.TransactionID
where co.GrossOrNet = 'N'
and co.FixedAmount <> 0
and co.CommissionType = 1  --MPC:25/01/10
group by cs.TransactionID, co.GrossOrNet, co.Agent_perc, co.FixedAmount

