-- Insert Policy Transaction details 
---Sel #3

update cs
set 
 ProductCode = PT.CommProductCode, 
 StartDate = PT.StartDate, 
 FrequencyCode = PT.Frequency, 
 FrequencyDesc = f.Description, 
 ---MortgageAmount = CASE WHEN ph.ProductGroupCode = '3' THEN ABS(pt.Amount) ELSE NULL END AS MortgageAmount
 Premium = case when PT.Amount > 0 then PT.Amount 
           WHEN ph.ProductGroupCode = '3' THEN ABS(pt.Amount) ELSE NULL end, 
 InitialPeriod = PT.CommInitialPeriod, 
 PayBasisCode = PT.CommType,
PayBasisDesc = case
when PT.CommType = 'F' then 'Accr' 
 when PT.CommType = 'T' then 'IT' 
 when PT.CommType = 'L' then 'Level' 
 end
from 
#msit_CommissionStatement cs
inner join sa_swift_PolicyTransactions PT on PT.ID = cs.TransactionID
