--Upd #16
update 
 #msit_commissionstatement
set 
 CommissionsID = t1.ID
from sa_swift_S_AGTCOM CO                     --- Tech Debt Modification: Replaced mstt_Commissions with S_AGTCOM - MF 20/02/2024
inner join #Comm t1 on CO.Agent_code = t1.Agent_Code and CO.TransactionID = t1.TransactionID
and (case when CO.CommissionType in ('2','17') then '1' when CO.CommissionType in ('15','18') then '4'
     when CO.CommissionType in ('16','19') then '10' else CO.CommissionType end) = t1.CommissionType
inner join #msit_commissionstatement cs on cs.Agentcode collate SQL_Latin1_General_CP1_CI_AS = t1.Agent_Code and Cs.TransactionID = t1.TransactionID
and (case when Cs.CommissionType in ('2','17') then '1' when Cs.CommissionType in ('15','18') then '4'
     when Cs.CommissionType in ('16','19') then '10' else Cs.CommissionType end) = t1.CommissionType

--Upd #17
update
 #msit_CommissionStatement
set
-- CommissionsID = CO.ID,	-- Ticket 108
-- AgentSplit = CO.Agent_Perc,	-- Ticket 108													--SR174877: MPC 17/08/2012
 AgentSplit = case when isnull(#msit_CommissionStatement.AgentSplit,0) = 0 then CO.AGENT_PERC else #msit_CommissionStatement.AgentSplit end,		--SR174877: MPC 17/08/2012
 
/* FranchiseSplit = case when DistributionAllowance = '0' then '0'    ----MF 29/02/2024: Incorrect calculation/formula removed.
				 else CO.FixedAmount /DistributionAllowance 
				 end, */
	
/******  Note: Formula for caluclating FranchiseSplit************************	
 DA = pt.CommExpectedUplift * pt.CommBaseAmount or pt.CommCalculateAmount
 FranchiseSplit =	co.FixedAmount/DA 
***************************************************************************/
 FranchiseSplit =  CO.FixedAmount/NULLIF(isnull(pt.CommCalculatedAmount,0),0),
 
 FranchiseUpliftRate = case
-- Ticket143            when mstt_CommissionStatement.FranchiseUpliftRate = 0 then case when CommProviderCode = 'MORTGAGE' then CO.FranchiseUpliftPercent - 20 else CO.FranchiseUpliftPercent end
-- Ticket143            else case when CommProviderCode = 'MORTGAGE' then mstt_CommissionStatement.FranchiseUpliftRate - 20 else mstt_CommissionStatement.FranchiseUpliftRate end
---MF 20/02/24          Tech Debt Mod: Replaced CO.ProductGroupCode with ph.ProductGroupCode
                        when #msit_CommissionStatement.FranchiseUpliftRate = 0 then case when PH.ProductGroupCode = 3 then CO.FranchiseUpliftPercent - 20 
																						 when CO.CommissionType = 1 and isnull(ph.RDRType,'') <> '' then CO.FranchiseUpliftPercent - isnull(PH.RetentionRateFactor,20)	--MPC: 03/05/2012 - SR153273	--MPC: 30/05/2012 - SR153273
																						 else CO.FranchiseUpliftPercent end	--Ticket143
						else case when PH.ProductGroupCode = 3 then #msit_CommissionStatement.FranchiseUpliftRate - 20 
								  when CO.CommissionType = 1 and isnull(ph.RDRType,'') <> '' then #msit_CommissionStatement.FranchiseUpliftRate - isnull(PH.RetentionRateFactor,20)	--MPC: 03/05/2012 - SR153273	--MPC: 30/05/2012 - SR153273
								  else #msit_CommissionStatement.FranchiseUpliftRate end			--Ticket143
                       end
from
 sa_swift_S_AGTCOM CO
 left outer join sa_swift_PolicyTransactions pt on CO.TransactionID = pt.ID
  left join #Margins2 m2 on m2.TransactionID = co.TransactionID
 left outer join sa_swift_S_POLMAI p on pt.PolicyID = p.POL_NUM
 left join mstt_ProductHierarchy ph on coalesce(pt.CommProductCode, p.ProductCode) collate SQL_Latin1_General_CP1_CI_AS = ph.ProductCode    --From mstt_Policies, linked via PolicyID
 ----left join mstt_ProductHierarchy PH on PH.ProductCode = CO.ProductCode	--MPC: 03/05/2012 - SR153273
where CO.ID = CommissionsID	-- Ticket 108

