select 
 EX.TransactionID, 
 EX.ID, 
 EX.Date_Due, 
-- Amount_Due = case when EX.Adjust in ('1', '2') then EX.Amount_Rec else EX.Amount_Due end,		--:MPC 29/02/2008 (1)
 Amount_Due = case when EX.Status in ('2', '3') and EX.TYPE = 1 then EX.Amount_Rec 		--:MPC 29/02/2008 (1)
		   when EX.Status in ('2', '3') and EX.TYPE = 17 then -1*ABS(EX.Amount_Rec)		--:MPC 29/02/2008 (1)
		   else EX.Amount_Due end,								--:MPC 29/02/2008 (1)
 EX.Status, 
 EX.Adjust,
 EX.Type,
 'N' [Count] 
into 
 #TransExcept 
from 
 sa_swift_S_PACC EX 
where 
 EX.Type = '1'
 OR											--:MPC 29/02/2008 (1)B
 (EX.TYPE = '17' and STATUS in ('2','3'))	--:MPC 29/02/2008 (1)B
order by 
 EX.TransactionID,							--:MPC 29/02/2008 (1)B
 EX.Date_Due, 
 EX.ID 
 
