-- EX.Type = '1'												--:MPC 29/02/2008 (1)B
where															-- PR 13/9/2008
	--EX.Type not in ('4', '15','18','10', '16', '19')			-- PR 13/9/2008
	EX.Type not in ('4', '5','6','15','18','10', '16', '19')    -- PR 4/3/2009
group by 
 EX.TransactionID, 
 EX.Date_Due 
 
