 [Count] = case when #TransExcept.TYPE = 1 then 'Y' else 'A' end	--:MPC 29/02/2008 (1)B
from 
 #TransExcept2 TE2 
where 
 #TransExcept.TransactionID = TE2.TransactionID and 
 #TransExcept.Date_Due = TE2.Date_Due and 
 #TransExcept.ID = TE2.ID

