 TotDue = 
		case																		----- MF 23/02/2024: Amended from Amount to EX.Amount_Due to enable TotDue Calculation
				when #msit_CommissionStatement.productcode = 'ISA' and  #msit_CommissionStatement.FrequencyCode = '2' then #msit_CommissionStatement.Amount * 60 
				else #msit_CommissionStatement.Amount * FranchiseSplit * (AgentSplit / 100)
			end     
			/*case 
