/*===============================================================================================
		Month Processing
==================================================================================================
 Mike Cawood - 13 October 2010
  UPD#53a Override Month for Commission Payments created on 12 October that were included in the
          SWIFT BACS rerun on 12 October to backdate to September 2010 (Month = '1 Oct 2010').
  UPD#53b Override Month for BACS Payments made in 12 October rerun following 11 October failure
          on SWIFT to backdate to September 2010 (Month = '1 Oct 2010').
================================================================================================== */

--Upd #53a  --MPC: 2010/10/13
update cs
   set month = '1 oct 2010'   -- September 2010
   from #msit_CommissionStatement cs
   inner join dbo.sa_swift_S_AGMPAY PAY on PAY.ID = cs.AgentPaymentsId
   where isnull(cs.reportingclasscode,0) not in (4)   -- Commission Payment
     and pay.Exported = 'T'  -- Exported via BACS
     and pay.Export_Date = '2010-10-12 17:40:34.000'
     and cs.Month > '1 oct 2010'

