where
 #msit_CommissionStatement.PolicyId = PQ.PolicyId and
 #msit_CommissionStatement.ReportingClassCode = '1' and
 #msit_CommissionStatement.AgentPaymentsID is null and
 PQ.SuspendCommission = '1'
 ---------------------------------------------------------------------

----Insert APE 

--APE
update cs
set APE = case
 WHEN ExpectationId = FirstId then
		abs(case when f.type = 6 then pt.Amount/10  --'S' (Single)       --:MF 19/02/24 ---- APE reverse engineered into IB (OWL) from mstt_Policytransaction proc
		when f.Type = 2 then pt.Amount * 12 --'M (Montly)
		when f.Type = 5 then pt.Amount    --'A (Annually) 
		when f.Type = 4 then pt.Amount * 2  --'B' (Half-Yearly)
		when f.type = 3 then pt.Amount * 4 --'Q' (Quarterly)
	else '0' end) 
-----'Update APE to ZERO for Non-APE products'
 ELSE 0 end
---else '0' end 
from #msit_CommissionStatement cs
inner join sa_swift_PolicyTransactions PT on PT.ID = cs.TransactionID
left join mstt_ProductHierarchy PH on PH.ProductCode collate SQL_Latin1_General_CP1_CI_AS = PT.CommProductCode  
left Join #Frequency f ON f.Type = PT.Frequency

