/****** Object:  StoredProcedure [dbo].[owp_Comms_AutoConfiguration]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*******************************************************************************************************************

Program:		owp_Comms_AutoConfiguration					
Author:			Alan Groves
Date created:	23/08/2022
											
Description:
===========

This proc is used for auto creating config for the "Comms" (OpenAccess automated emails) process. It will only 
create config rows on table "dbo.owt_Comms_ConfigAdviser" for active enterprises that already exist on table 
"dbo.owt_Comms_ConfigEnterprise" and active activities that already exist on table "dbo.owt_Comms_ConfigActivity". 
This proc will run daily and will create new adviser config rows if they are missing and the adviser is active. 
Note that if any advisers leave (go out of contract) or transfer, then the adviser config is de-activated 
(Active is set to 0) and all ETL and emails are stopped for that adviser.

Notes
=====
1) Tables "dbo.owt_Comms_ConfigEnterprise" and "dbo.owt_Comms_ConfigActivity" need to be loaded via a script.

This proc is called as follows:
	
	exec dbo.owp_Comms_AutoConfiguration 

AMENDMENT HISTORY				
=================								

Date		Author			Description
----		------			-----------
20/10/2022	A Groves		Previously, this proc handled terminations, but not transfers. Transfers are now handled 
							by the merge "when not matched by source" statement.
22/11/2022	A Groves		Correction to the MERGE statement in the WHEN MATCHED condition that was previously causing
							any leaver with Active=0 status to have Active=0 set in every run. This caused the 
							LastUpdatedReason and DateLastUpdated to be updated every day.
********************************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_AutoConfiguration]

AS

set nocount on

declare		@PhaseStart					varchar(50),
			@PhaseEnd					varchar(50),
			@PhaseError					varchar(50),
			@PhaseLog					varchar(50),
			@ProcName					varchar(100),
			@RowCount					int,
			@ErrMsg						nvarchar(4000),
			@Message					varchar(100),
			@ErrMsgBrief				nvarchar(100),
			@LogMessage					varchar(100),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@ErrState					int,
			@Client						varchar(50),
			@Module						varchar(50),
			@AdviserName				nvarchar(50),
			@BusinessName				nvarchar(255),
			@DateLastUpdated			datetime,
			@TodayStr					varchar(10)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Client						= 'Openwork'
set @Module						= 'Automated Emails'
set @ProcName					= object_name(@@procid)
set @PhaseStart					= 'START'
set @PhaseEnd					= 'END'
set @PhaseError					= 'ERROR'
set @PhaseLog					= 'LOG'
set @ErrNum						= 0	
set @DateLastUpdated			= getdate()
set @TodayStr					= convert(varchar(10),@DateLastUpdated,103)

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Start																
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Get the AdviserUID from the most recently added Adviser Config row.
		This adviser will be the template for any new config rows to be added.
																		
	****************************************************************************/

	select	EnterpriseUID, ActivityID, max(DateInserted) as MaxDateInserted
	into	#MostRecentlyAddedConfig 
	from	dbo.owt_Comms_ConfigAdviser
	group	by EnterpriseUID, ActivityID

	select	adv.EnterpriseUID, adv.ActivityID, max(adv.AdviserUID) as AdviserUID
	into	#MostRecentlyAddedAdviser
	from	dbo.owt_Comms_ConfigAdviser adv
			inner join #MostRecentlyAddedConfig config
						on config.EnterpriseUID = adv.EnterpriseUID
						and config.ActivityID = adv.ActivityID
						and config.MaxDateInserted = adv.DateInserted
	group	by adv.EnterpriseUID, adv.ActivityID

	/****************************************************************************

		Create temp table to populate from a mixture of source (new rows) and
		destination (existing rows).
																		
	****************************************************************************/

	CREATE TABLE #ConfigAdviser
	(
		EnterpriseUID varchar(7) NOT NULL,
		AdviserUID varchar(7) NOT NULL,
		ActivityID int NOT NULL,
		Active bit NULL,
		ActiveSwitchingEnabled bit NULL,
		RecipientsToEnabled bit NULL,
		RecipientsTo varchar(4000) NULL,
		RecipientsCCEnabled bit NULL,
		RecipientsCC varchar(4000) NULL,
		RecipientsToOverrideEnabled bit NULL,
		RecipientsToOverride varchar(4000) NULL,
		DateInserted datetime NULL,
		DateLastUpdated datetime NULL,
		LastUpdatedReason varchar(4000) NULL,
		Notes varchar(4000) NULL,
		AutoAdviserConfigEnabled bit null,
		EnterpriseActive bit null,
		ActivityActive bit null,
		EnterpriseCompetentStatus tinyint null,
		AdviserCompetentStatus tinyint null
	)

	/****************************************************************************

		Get all the adviser data for each enterprise being processed.
		NOTES:
		1) If the adviser already exists on dbo.owt_Comms_ConfigAdviser then get existing values
		2) If the adviser is new then use the #MostRecentlyAddedAdviser to clone the columns
		3) Store these values for the MERGE to decide what - if anything - to do:
			a) AutoAdviserConfigEnabled
			b) EnterpriseActive
			c) ActivityActive
			d) EnterpriseCompetentStatus
			e) AdviserCompetentStatus
																		
	****************************************************************************/

	insert into #ConfigAdviser
	(
		EnterpriseUID,
		AdviserUID,
		ActivityID,
		Active,
		ActiveSwitchingEnabled,
		RecipientsToEnabled,
		RecipientsTo,
		RecipientsCCEnabled,
		RecipientsCC,
		RecipientsToOverrideEnabled,
		RecipientsToOverride,
		DateInserted,
		DateLastUpdated,
		LastUpdatedReason,
		Notes,
		AutoAdviserConfigEnabled,
		EnterpriseActive,
		ActivityActive,
		EnterpriseCompetentStatus,
		AdviserCompetentStatus
	)
	select	ce.EnterpriseUID as EnterpriseUID,
			ag.Code as AdviseUID,
			ca.ActivityID as ActivityID,
			case when existing.AdviserUID is not null
				then existing.Active
				else case when clone.AdviserUID is not null then clone.Active else 1 end
			end as Active,
			case when existing.AdviserUID is not null
				then existing.ActiveSwitchingEnabled
				else case when clone.AdviserUID is not null then clone.ActiveSwitchingEnabled else 1 end 
			end as ActiveSwitchingEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsToEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsToEnabled else 1 end
			end as RecipientsToEnabled,
			cd.CD_email as RecipientsTo,	--MERGE will either insert or update this
			case when existing.AdviserUID is not null
				then existing.RecipientsCCEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsCCEnabled else null end
			end as RecipientsCCEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsCC
				else case when clone.AdviserUID is not null then clone.RecipientsCC else null end
			end as RecipientsCC,
			case when existing.AdviserUID is not null
				then existing.RecipientsToOverrideEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsToOverrideEnabled else null end
			end as RecipientsToOverrideEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsToOverride
				else case when clone.AdviserUID is not null then clone.RecipientsToOverride else null end
			end as RecipientsToOverride,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated,
			case when existing.AdviserUID is not null
				then existing.LastUpdatedReason
				else @TodayStr + ': Inserted by Auto Config; ' 
			end as LastUpdatedReason,
			case when existing.AdviserUID is not null
				then existing.Notes
				else null	--Notes are not cloned 
			end as Notes,
			ce.AutoAdviserConfigEnabled as AutoAdviserConfigEnabled,
			ce.Active as EnterpriseActive,
			ca.Active as ActivityActive,
			firm.CompetentStatus as EnterpriseCompetentStatus,
			ag.CompetentStatus as AdviserCompetentStatus
	from	dbo.owt_Comms_ConfigActivity ca
			inner join dbo.owt_Comms_ConfigEnterprise ce on ce.ActivityID = ca.ActivityID
			inner join mstt_Agents firm on firm.CODE = ce.EnterpriseUID
			inner join mstt_Agents ag on ag.Firm = ce.EnterpriseUID and ag.GivesAdvice = 'Y'
			inner join sa_insight_UserDetails ud on ud.USR_ExternalID = ag.Code
			inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
			inner join sa_insight_ContactDetails cd on cd.CD_ParentID = s.STAF_ID
			left join #MostRecentlyAddedAdviser mraa
						on  mraa.EnterpriseUID = ce.EnterpriseUID
						and mraa.ActivityID = ce.ActivityID
			left join dbo.owt_Comms_ConfigAdviser clone
						on  clone.EnterpriseUID = ce.EnterpriseUID
						and clone.AdviserUID = mraa.AdviserUID
						and clone.ActivityID = ca.ActivityID
			left join dbo.owt_Comms_ConfigAdviser existing
						on  existing.EnterpriseUID = ce.EnterpriseUID
						and existing.AdviserUID = ag.Code
						and existing.ActivityID = ca.ActivityID

	set @RowCount = @@rowcount

	set @LogMessage = 'New and existing adviser config selected. RowCount = ' + convert(varchar(20),@RowCount)
	exec msp_ProcessLog @PhaseLog, @LogMessage, null, @Module, @Client

	/****************************************************************************

		MERGE the selected data
		Notes:
		1) Update if RecipientsTo has changed or firm is inactive or adviser has transferred or left and AutoAdviserConfigEnabled = 1
		2) Insert if EnterpriseUID/AdviserUID/ActivityID combination doesn't already exist and both firm and adviser are active and AutoAdviserConfigEnabled = 1
 																
	****************************************************************************/

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Comms_ConfigAdviser as trg
	using	#ConfigAdviser as src
	on		trg.EnterpriseUID = src.EnterpriseUID
	and		trg.AdviserUID = src.AdviserUID
	and		trg.ActivityID = src.ActivityID
	when	matched 
	and		src.ActivityActive = 1																					--Activity is active
	and		src.EnterpriseActive = 1																				--Enterprise is active
	and		src.AutoAdviserConfigEnabled = 1																		--Enterprise enabled for auto adviser config
	and		(isnull(src.RecipientsTo,'') <> isnull(trg.RecipientsTo,'')												--Recipient email address has been updated
			or		((src.EnterpriseCompetentStatus = 2 or src.AdviserCompetentStatus = 2) and trg.Active = 1 and src.ActiveSwitchingEnabled = 1)		--Enterprise CompetentStatus 2 = Left; Adviser CompetentStatus 2 = Left
			or		(src.EnterpriseCompetentStatus = 1 and src.AdviserCompetentStatus = 1 and trg.Active = 0 and src.ActiveSwitchingEnabled = 1))		--Enterprise CompetentStatus 1 = Active; Adviser CompetentStatus 1 = Active
	then	update 
				set trg.RecipientsTo = src.RecipientsTo,
					trg.Active = case	when (src.EnterpriseCompetentStatus = 2 or src.AdviserCompetentStatus = 2) and src.ActiveSwitchingEnabled = 1 then 0	--Note: Ent or Adv
										when (src.EnterpriseCompetentStatus = 1 and src.AdviserCompetentStatus = 1) and src.ActiveSwitchingEnabled = 1 then 1	--Note: Ent and Adv
										else trg.Active 
								 end,
					trg.LastUpdatedReason = isnull(trg.LastUpdatedReason,'') 
											+ case 
												when isnull(src.RecipientsTo,'') <> isnull(trg.RecipientsTo,'') then @TodayStr + ': Change of RecipientsTo; '
												when src.AdviserCompetentStatus = 2 and src.ActiveSwitchingEnabled = 1 then @TodayStr + ': Change of Active, Adviser Left; ' 
												when src.EnterpriseCompetentStatus = 2 and src.ActiveSwitchingEnabled = 1 then  @TodayStr + ': Change of Active, Enterprise Left; '
												when src.AdviserCompetentStatus = 1 and src.EnterpriseCompetentStatus = 1 and src.ActiveSwitchingEnabled = 1 then @TodayStr + ': Change of Active, Adviser Active; ' 
												else ''
											  end,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by source
	and		trg.Active = 1
	then	update 
				set trg.Active = 0,	--Note this is forced to zero (off) even if ActiveSwitchingEnabled is off as it is inappropriate to continue sending emails to a transferred adviser.
					trg.LastUpdatedReason = isnull(trg.LastUpdatedReason,'') +  @TodayStr + ': Adviser Transferred; ',
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	and		src.ActivityActive = 1					--Activity is active
	and		src.EnterpriseActive = 1				--Enterprise is active
	and		src.AutoAdviserConfigEnabled = 1		--Enterprise enabled for auto adviser config
	and		src.EnterpriseCompetentStatus = 1		--Enterprise CompetentStatus 1 = Active
	and		src.AdviserCompetentStatus = 1			--Adviser CompetentStatus 1 = Active
	then	insert
			(
				EnterpriseUID,
				AdviserUID,
				ActivityID,
				Active,
				ActiveSwitchingEnabled,
				RecipientsToEnabled,
				RecipientsTo,
				RecipientsCCEnabled,
				RecipientsCC,
				RecipientsToOverrideEnabled,
				RecipientsToOverride,
				DateInserted,
				DateLastUpdated,
				LastUpdatedReason,
				Notes
			)		
			values
			(
				src.EnterpriseUID,
				src.AdviserUID,
				src.ActivityID,
				src.Active,
				src.ActiveSwitchingEnabled,
				src.RecipientsToEnabled,
				src.RecipientsTo,
				src.RecipientsCCEnabled,
				src.RecipientsCC,
				src.RecipientsToOverrideEnabled,
				src.RecipientsToOverride,
				@DateLastUpdated,
				@DateLastUpdated,
				src.LastUpdatedReason,
				src.Notes
			)				
	output $action into @SummaryOfChanges;	--Merge statements must have a ;

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @Message = 'owt_Comms_ConfigAdviser (insert) = ' + convert(varchar(20), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Message, null, @Module, @Client

	select	@RowCount = COUNT(*)	--This covers the updates for MATCHED and NOT MATCHED BY SOURCE
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @Message = 'owt_Comms_ConfigAdviser (update) = ' + convert(varchar(20), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Message, null, @Module, @Client

	/****************************************************************************

		End of processing
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd,  @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = @ErrMsg + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

	T H E   E N D														

****************************************************************************/

return @ErrNum
GO
/****** Object:  StoredProcedure [dbo].[owp_Comms_AutoConfiguration_Backup20221020AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*******************************************************************************************************************

Program:		owp_Comms_AutoConfiguration					
Author:			Alan Groves
Date created:	23/08/2022
											
Description:
===========

This proc is used for auto creating config for the "Comms" (OpenAccess automated emails) process. It will only 
create config rows on table "dbo.owt_Comms_ConfigAdviser" for active enterprises that already exist on table 
"dbo.owt_Comms_ConfigEnterprise" and active activities that already exist on table "dbo.owt_Comms_ConfigActivity". 
This proc will run daily and will create new adviser config rows if they are missing and the adviser is active. 
Note that if any advisers leave (go out of contract) or transfer, then the adviser config is de-activated 
(Active is set to 0) and all ETL and emails are stopped for that adviser.

Notes
=====
1) Tables "dbo.owt_Comms_ConfigEnterprise" and "dbo.owt_Comms_ConfigActivity" need to be loaded via a script.

This proc is called as follows:
	
	exec dbo.owp_Comms_AutoConfiguration 

AMENDMENT HISTORY				
=================								

Date		Author			Description
----		------			-----------

********************************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_AutoConfiguration_Backup20221020AG]

AS

set nocount on

declare		@PhaseStart					varchar(50),
			@PhaseEnd					varchar(50),
			@PhaseError					varchar(50),
			@PhaseLog					varchar(50),
			@ProcName					varchar(100),
			@RowCount					int,
			@ErrMsg						nvarchar(4000),
			@Message					varchar(100),
			@ErrMsgBrief				nvarchar(100),
			@LogMessage					varchar(100),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@ErrState					int,
			@Client						varchar(50),
			@Module						varchar(50),
			@AdviserName				nvarchar(50),
			@BusinessName				nvarchar(255),
			@DateLastUpdated			datetime,
			@TodayStr					varchar(10)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Client						= 'Openwork'
set @Module						= 'Automated Emails'
set @ProcName					= object_name(@@procid)
set @PhaseStart					= 'START'
set @PhaseEnd					= 'END'
set @PhaseError					= 'ERROR'
set @PhaseLog					= 'LOG'
set @ErrNum						= 0	
set @DateLastUpdated			= getdate()
set @TodayStr					= convert(varchar(10),@DateLastUpdated,103)

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Start																
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Get the AdviserUID from the most recently added Adviser Config row.
		This adviser will be the template for any new config rows to be added.
																		
	****************************************************************************/

	select	EnterpriseUID, ActivityID, max(DateInserted) as MaxDateInserted
	into	#MostRecentlyAddedConfig 
	from	dbo.owt_Comms_ConfigAdviser
	group	by EnterpriseUID, ActivityID

	select	adv.EnterpriseUID, adv.ActivityID, max(adv.AdviserUID) as AdviserUID
	into	#MostRecentlyAddedAdviser
	from	dbo.owt_Comms_ConfigAdviser adv
			inner join #MostRecentlyAddedConfig config
						on config.EnterpriseUID = adv.EnterpriseUID
						and config.ActivityID = adv.ActivityID
						and config.MaxDateInserted = adv.DateInserted
	group	by adv.EnterpriseUID, adv.ActivityID

	/****************************************************************************

		Create temp table to populate from a mixture of source (new rows) and
		destination (existing rows).
																		
	****************************************************************************/

	CREATE TABLE #ConfigAdviser
	(
		EnterpriseUID varchar(7) NOT NULL,
		AdviserUID varchar(7) NOT NULL,
		ActivityID int NOT NULL,
		Active bit NULL,
		ActiveSwitchingEnabled bit NULL,
		RecipientsToEnabled bit NULL,
		RecipientsTo varchar(4000) NULL,
		RecipientsCCEnabled bit NULL,
		RecipientsCC varchar(4000) NULL,
		RecipientsToOverrideEnabled bit NULL,
		RecipientsToOverride varchar(4000) NULL,
		DateInserted datetime NULL,
		DateLastUpdated datetime NULL,
		LastUpdatedReason varchar(4000) NULL,
		Notes varchar(4000) NULL,
		AutoAdviserConfigEnabled bit null,
		EnterpriseActive bit null,
		ActivityActive bit null,
		EnterpriseCompetentStatus tinyint null,
		AdviserCompetentStatus tinyint null
	)

	/****************************************************************************

		Get all the adviser data for each enterprise being processed.
		NOTES:
		1) If the adviser already exists on dbo.owt_Comms_ConfigAdviser then get existing values
		2) If the adviser is new then use the #MostRecentlyAddedAdviser to clone the columns
		3) Store these values for the MERGE to decide what - if anything - to do:
			a) AutoAdviserConfigEnabled
			b) EnterpriseActive
			c) ActivityActive
			d) EnterpriseCompetentStatus
			e) AdviserCompetentStatus
																		
	****************************************************************************/

	insert into #ConfigAdviser
	(
		EnterpriseUID,
		AdviserUID,
		ActivityID,
		Active,
		ActiveSwitchingEnabled,
		RecipientsToEnabled,
		RecipientsTo,
		RecipientsCCEnabled,
		RecipientsCC,
		RecipientsToOverrideEnabled,
		RecipientsToOverride,
		DateInserted,
		DateLastUpdated,
		LastUpdatedReason,
		Notes,
		AutoAdviserConfigEnabled,
		EnterpriseActive,
		ActivityActive,
		EnterpriseCompetentStatus,
		AdviserCompetentStatus
	)
	select	ce.EnterpriseUID as EnterpriseUID,
			ag.Code as AdviseUID,
			ca.ActivityID as ActivityID,
			case when existing.AdviserUID is not null
				then existing.Active
				else case when clone.AdviserUID is not null then clone.Active else 1 end
			end as Active,
			case when existing.AdviserUID is not null
				then existing.ActiveSwitchingEnabled
				else case when clone.AdviserUID is not null then clone.ActiveSwitchingEnabled else 1 end 
			end as ActiveSwitchingEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsToEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsToEnabled else 1 end
			end as RecipientsToEnabled,
			cd.CD_email as RecipientsTo,	--MERGE will either insert or update this
			case when existing.AdviserUID is not null
				then existing.RecipientsCCEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsCCEnabled else null end
			end as RecipientsCCEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsCC
				else case when clone.AdviserUID is not null then clone.RecipientsCC else null end
			end as RecipientsCC,
			case when existing.AdviserUID is not null
				then existing.RecipientsToOverrideEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsToOverrideEnabled else null end
			end as RecipientsToOverrideEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsToOverride
				else case when clone.AdviserUID is not null then clone.RecipientsToOverride else null end
			end as RecipientsToOverride,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated,
			case when existing.AdviserUID is not null
				then existing.LastUpdatedReason
				else @TodayStr + ': Inserted by Auto Config; ' 
			end as LastUpdatedReason,
			case when existing.AdviserUID is not null
				then existing.Notes
				else null	--Notes are not cloned 
			end as Notes,
			ce.AutoAdviserConfigEnabled as AutoAdviserConfigEnabled,
			ce.Active as EnterpriseActive,
			ca.Active as ActivityActive,
			firm.CompetentStatus as EnterpriseCompetentStatus,
			ag.CompetentStatus as AdviserCompetentStatus
	from	dbo.owt_Comms_ConfigActivity ca
			inner join dbo.owt_Comms_ConfigEnterprise ce on ce.ActivityID = ca.ActivityID
			inner join mstt_Agents firm on firm.CODE = ce.EnterpriseUID
			inner join mstt_Agents ag on ag.Firm = ce.EnterpriseUID and ag.GivesAdvice = 'Y'
			inner join sa_insight_UserDetails ud on ud.USR_ExternalID = ag.Code
			inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
			inner join sa_insight_ContactDetails cd on cd.CD_ParentID = s.STAF_ID
			left join #MostRecentlyAddedAdviser mraa
						on  mraa.EnterpriseUID = ce.EnterpriseUID
						and mraa.ActivityID = ce.ActivityID
			left join dbo.owt_Comms_ConfigAdviser clone
						on  clone.EnterpriseUID = ce.EnterpriseUID
						and clone.AdviserUID = mraa.AdviserUID
						and clone.ActivityID = ca.ActivityID
			left join dbo.owt_Comms_ConfigAdviser existing
						on  existing.EnterpriseUID = ce.EnterpriseUID
						and existing.AdviserUID = ag.Code
						and existing.ActivityID = ca.ActivityID

	set @RowCount = @@rowcount

	set @LogMessage = 'New and existing adviser config selected. RowCount = ' + convert(varchar(20),@RowCount)
	exec msp_ProcessLog @PhaseLog, @LogMessage, null, @Module, @Client

	/****************************************************************************

		MERGE the selected data
		Notes:
		1) Update if RecipientsTo has changed or firm is inactive or adviser has transferred or left and AutoAdviserConfigEnabled = 1
		2) Insert if EnterpriseUID/AdviserUID/ActivityID combination doesn't already exist and both firm and adviser are active and AutoAdviserConfigEnabled = 1
 																
	****************************************************************************/

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Comms_ConfigAdviser as trg
	using	#ConfigAdviser as src
	on		trg.EnterpriseUID = src.EnterpriseUID
	and		trg.AdviserUID = src.AdviserUID
	and		trg.ActivityID = src.ActivityID
	when	matched 
	and		src.ActivityActive = 1																					--Activity is active
	and		src.EnterpriseActive = 1																				--Enterprise is active
	and		src.AutoAdviserConfigEnabled = 1																		--Enterprise enabled for auto adviser config
	and		(isnull(src.RecipientsTo,'') <> isnull(trg.RecipientsTo,'')												--Recipient email address has been updated
			or		(src.EnterpriseCompetentStatus = 2 and trg.Active = 1 and src.ActiveSwitchingEnabled = 1)		--Enterprise CompetentStatus 2 = Left
			or		(src.AdviserCompetentStatus = 2 and trg.Active = 1 and src.ActiveSwitchingEnabled = 1)			--Adviser CompetentStatus 2 = Left
			or		(src.EnterpriseCompetentStatus = 1 and trg.Active = 0 and src.ActiveSwitchingEnabled = 1)		--Enterprise CompetentStatus 1 = Active
			or		(src.AdviserCompetentStatus = 1 and trg.Active = 0 and src.ActiveSwitchingEnabled = 1))			--Adviser CompetentStatus 1 = Active
	then	update 
				set trg.RecipientsTo = src.RecipientsTo,
					trg.Active = case	when (src.EnterpriseCompetentStatus = 2 or src.AdviserCompetentStatus = 2) and src.ActiveSwitchingEnabled = 1 then 0	--Note: Ent or Adv
										when (src.EnterpriseCompetentStatus = 1 and src.AdviserCompetentStatus = 1) and src.ActiveSwitchingEnabled = 1 then 1	--Note: Ent and Adv
										else trg.Active 
								 end,
					trg.LastUpdatedReason = isnull(trg.LastUpdatedReason,'') 
											+ case 
												when isnull(src.RecipientsTo,'') <> isnull(trg.RecipientsTo,'') then @TodayStr + ': Change of RecipientsTo; '
												when src.AdviserCompetentStatus = 2 and src.ActiveSwitchingEnabled = 1 then @TodayStr + ': Change of Active, Adviser Left; ' 
												when src.EnterpriseCompetentStatus = 2 and src.ActiveSwitchingEnabled = 1 then  @TodayStr + ': Change of Active, Enterprise Left; '
												when src.AdviserCompetentStatus = 1 and src.EnterpriseCompetentStatus = 1 and src.ActiveSwitchingEnabled = 1 then @TodayStr + ': Change of Active, Adviser Active; ' 
												else ''
											  end,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	and		src.ActivityActive = 1					--Activity is active
	and		src.EnterpriseActive = 1				--Enterprise is active
	and		src.AutoAdviserConfigEnabled = 1		--Enterprise enabled for auto adviser config
	and		src.EnterpriseCompetentStatus = 1		--Enterprise CompetentStatus 1 = Active
	and		src.AdviserCompetentStatus = 1			--Adviser CompetentStatus 1 = Active
	then	insert
			(
				EnterpriseUID,
				AdviserUID,
				ActivityID,
				Active,
				ActiveSwitchingEnabled,
				RecipientsToEnabled,
				RecipientsTo,
				RecipientsCCEnabled,
				RecipientsCC,
				RecipientsToOverrideEnabled,
				RecipientsToOverride,
				DateInserted,
				DateLastUpdated,
				LastUpdatedReason,
				Notes
			)		
			values
			(
				src.EnterpriseUID,
				src.AdviserUID,
				src.ActivityID,
				src.Active,
				src.ActiveSwitchingEnabled,
				src.RecipientsToEnabled,
				src.RecipientsTo,
				src.RecipientsCCEnabled,
				src.RecipientsCC,
				src.RecipientsToOverrideEnabled,
				src.RecipientsToOverride,
				@DateLastUpdated,
				@DateLastUpdated,
				src.LastUpdatedReason,
				src.Notes
			)				
	output $action into @SummaryOfChanges;	--Merge statements must have a ;

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @Message = 'owt_Comms_ConfigAdviser (insert) = ' + convert(varchar(20), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Message, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @Message = 'owt_Comms_ConfigAdviser (update) = ' + convert(varchar(20), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Message, null, @Module, @Client

	/****************************************************************************

		End of processing
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd,  @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = @ErrMsg + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

	T H E   E N D														

****************************************************************************/

return @ErrNum
GO
/****** Object:  StoredProcedure [dbo].[owp_Comms_AutoConfiguration_Backup20221122AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*******************************************************************************************************************

Program:		owp_Comms_AutoConfiguration					
Author:			Alan Groves
Date created:	23/08/2022
											
Description:
===========

This proc is used for auto creating config for the "Comms" (OpenAccess automated emails) process. It will only 
create config rows on table "dbo.owt_Comms_ConfigAdviser" for active enterprises that already exist on table 
"dbo.owt_Comms_ConfigEnterprise" and active activities that already exist on table "dbo.owt_Comms_ConfigActivity". 
This proc will run daily and will create new adviser config rows if they are missing and the adviser is active. 
Note that if any advisers leave (go out of contract) or transfer, then the adviser config is de-activated 
(Active is set to 0) and all ETL and emails are stopped for that adviser.

Notes
=====
1) Tables "dbo.owt_Comms_ConfigEnterprise" and "dbo.owt_Comms_ConfigActivity" need to be loaded via a script.

This proc is called as follows:
	
	exec dbo.owp_Comms_AutoConfiguration 

AMENDMENT HISTORY				
=================								

Date		Author			Description
----		------			-----------
20/10/2022	A Groves		Previously, this proc handled terminations, but not transfers. Transfers are now handled 
							by the merge "when not matched by source" statement.
********************************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_AutoConfiguration_Backup20221122AG]

AS

set nocount on

declare		@PhaseStart					varchar(50),
			@PhaseEnd					varchar(50),
			@PhaseError					varchar(50),
			@PhaseLog					varchar(50),
			@ProcName					varchar(100),
			@RowCount					int,
			@ErrMsg						nvarchar(4000),
			@Message					varchar(100),
			@ErrMsgBrief				nvarchar(100),
			@LogMessage					varchar(100),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@ErrState					int,
			@Client						varchar(50),
			@Module						varchar(50),
			@AdviserName				nvarchar(50),
			@BusinessName				nvarchar(255),
			@DateLastUpdated			datetime,
			@TodayStr					varchar(10)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Client						= 'Openwork'
set @Module						= 'Automated Emails'
set @ProcName					= object_name(@@procid)
set @PhaseStart					= 'START'
set @PhaseEnd					= 'END'
set @PhaseError					= 'ERROR'
set @PhaseLog					= 'LOG'
set @ErrNum						= 0	
set @DateLastUpdated			= getdate()
set @TodayStr					= convert(varchar(10),@DateLastUpdated,103)

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Start																
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Get the AdviserUID from the most recently added Adviser Config row.
		This adviser will be the template for any new config rows to be added.
																		
	****************************************************************************/

	select	EnterpriseUID, ActivityID, max(DateInserted) as MaxDateInserted
	into	#MostRecentlyAddedConfig 
	from	dbo.owt_Comms_ConfigAdviser
	group	by EnterpriseUID, ActivityID

	select	adv.EnterpriseUID, adv.ActivityID, max(adv.AdviserUID) as AdviserUID
	into	#MostRecentlyAddedAdviser
	from	dbo.owt_Comms_ConfigAdviser adv
			inner join #MostRecentlyAddedConfig config
						on config.EnterpriseUID = adv.EnterpriseUID
						and config.ActivityID = adv.ActivityID
						and config.MaxDateInserted = adv.DateInserted
	group	by adv.EnterpriseUID, adv.ActivityID

	/****************************************************************************

		Create temp table to populate from a mixture of source (new rows) and
		destination (existing rows).
																		
	****************************************************************************/

	CREATE TABLE #ConfigAdviser
	(
		EnterpriseUID varchar(7) NOT NULL,
		AdviserUID varchar(7) NOT NULL,
		ActivityID int NOT NULL,
		Active bit NULL,
		ActiveSwitchingEnabled bit NULL,
		RecipientsToEnabled bit NULL,
		RecipientsTo varchar(4000) NULL,
		RecipientsCCEnabled bit NULL,
		RecipientsCC varchar(4000) NULL,
		RecipientsToOverrideEnabled bit NULL,
		RecipientsToOverride varchar(4000) NULL,
		DateInserted datetime NULL,
		DateLastUpdated datetime NULL,
		LastUpdatedReason varchar(4000) NULL,
		Notes varchar(4000) NULL,
		AutoAdviserConfigEnabled bit null,
		EnterpriseActive bit null,
		ActivityActive bit null,
		EnterpriseCompetentStatus tinyint null,
		AdviserCompetentStatus tinyint null
	)

	/****************************************************************************

		Get all the adviser data for each enterprise being processed.
		NOTES:
		1) If the adviser already exists on dbo.owt_Comms_ConfigAdviser then get existing values
		2) If the adviser is new then use the #MostRecentlyAddedAdviser to clone the columns
		3) Store these values for the MERGE to decide what - if anything - to do:
			a) AutoAdviserConfigEnabled
			b) EnterpriseActive
			c) ActivityActive
			d) EnterpriseCompetentStatus
			e) AdviserCompetentStatus
																		
	****************************************************************************/

	insert into #ConfigAdviser
	(
		EnterpriseUID,
		AdviserUID,
		ActivityID,
		Active,
		ActiveSwitchingEnabled,
		RecipientsToEnabled,
		RecipientsTo,
		RecipientsCCEnabled,
		RecipientsCC,
		RecipientsToOverrideEnabled,
		RecipientsToOverride,
		DateInserted,
		DateLastUpdated,
		LastUpdatedReason,
		Notes,
		AutoAdviserConfigEnabled,
		EnterpriseActive,
		ActivityActive,
		EnterpriseCompetentStatus,
		AdviserCompetentStatus
	)
	select	ce.EnterpriseUID as EnterpriseUID,
			ag.Code as AdviseUID,
			ca.ActivityID as ActivityID,
			case when existing.AdviserUID is not null
				then existing.Active
				else case when clone.AdviserUID is not null then clone.Active else 1 end
			end as Active,
			case when existing.AdviserUID is not null
				then existing.ActiveSwitchingEnabled
				else case when clone.AdviserUID is not null then clone.ActiveSwitchingEnabled else 1 end 
			end as ActiveSwitchingEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsToEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsToEnabled else 1 end
			end as RecipientsToEnabled,
			cd.CD_email as RecipientsTo,	--MERGE will either insert or update this
			case when existing.AdviserUID is not null
				then existing.RecipientsCCEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsCCEnabled else null end
			end as RecipientsCCEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsCC
				else case when clone.AdviserUID is not null then clone.RecipientsCC else null end
			end as RecipientsCC,
			case when existing.AdviserUID is not null
				then existing.RecipientsToOverrideEnabled
				else case when clone.AdviserUID is not null then clone.RecipientsToOverrideEnabled else null end
			end as RecipientsToOverrideEnabled,
			case when existing.AdviserUID is not null
				then existing.RecipientsToOverride
				else case when clone.AdviserUID is not null then clone.RecipientsToOverride else null end
			end as RecipientsToOverride,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated,
			case when existing.AdviserUID is not null
				then existing.LastUpdatedReason
				else @TodayStr + ': Inserted by Auto Config; ' 
			end as LastUpdatedReason,
			case when existing.AdviserUID is not null
				then existing.Notes
				else null	--Notes are not cloned 
			end as Notes,
			ce.AutoAdviserConfigEnabled as AutoAdviserConfigEnabled,
			ce.Active as EnterpriseActive,
			ca.Active as ActivityActive,
			firm.CompetentStatus as EnterpriseCompetentStatus,
			ag.CompetentStatus as AdviserCompetentStatus
	from	dbo.owt_Comms_ConfigActivity ca
			inner join dbo.owt_Comms_ConfigEnterprise ce on ce.ActivityID = ca.ActivityID
			inner join mstt_Agents firm on firm.CODE = ce.EnterpriseUID
			inner join mstt_Agents ag on ag.Firm = ce.EnterpriseUID and ag.GivesAdvice = 'Y'
			inner join sa_insight_UserDetails ud on ud.USR_ExternalID = ag.Code
			inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
			inner join sa_insight_ContactDetails cd on cd.CD_ParentID = s.STAF_ID
			left join #MostRecentlyAddedAdviser mraa
						on  mraa.EnterpriseUID = ce.EnterpriseUID
						and mraa.ActivityID = ce.ActivityID
			left join dbo.owt_Comms_ConfigAdviser clone
						on  clone.EnterpriseUID = ce.EnterpriseUID
						and clone.AdviserUID = mraa.AdviserUID
						and clone.ActivityID = ca.ActivityID
			left join dbo.owt_Comms_ConfigAdviser existing
						on  existing.EnterpriseUID = ce.EnterpriseUID
						and existing.AdviserUID = ag.Code
						and existing.ActivityID = ca.ActivityID

	set @RowCount = @@rowcount

	set @LogMessage = 'New and existing adviser config selected. RowCount = ' + convert(varchar(20),@RowCount)
	exec msp_ProcessLog @PhaseLog, @LogMessage, null, @Module, @Client

	/****************************************************************************

		MERGE the selected data
		Notes:
		1) Update if RecipientsTo has changed or firm is inactive or adviser has transferred or left and AutoAdviserConfigEnabled = 1
		2) Insert if EnterpriseUID/AdviserUID/ActivityID combination doesn't already exist and both firm and adviser are active and AutoAdviserConfigEnabled = 1
 																
	****************************************************************************/

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Comms_ConfigAdviser as trg
	using	#ConfigAdviser as src
	on		trg.EnterpriseUID = src.EnterpriseUID
	and		trg.AdviserUID = src.AdviserUID
	and		trg.ActivityID = src.ActivityID
	when	matched 
	and		src.ActivityActive = 1																					--Activity is active
	and		src.EnterpriseActive = 1																				--Enterprise is active
	and		src.AutoAdviserConfigEnabled = 1																		--Enterprise enabled for auto adviser config
	and		(isnull(src.RecipientsTo,'') <> isnull(trg.RecipientsTo,'')												--Recipient email address has been updated
			or		(src.EnterpriseCompetentStatus = 2 and trg.Active = 1 and src.ActiveSwitchingEnabled = 1)		--Enterprise CompetentStatus 2 = Left
			or		(src.AdviserCompetentStatus = 2 and trg.Active = 1 and src.ActiveSwitchingEnabled = 1)			--Adviser CompetentStatus 2 = Left
			or		(src.EnterpriseCompetentStatus = 1 and trg.Active = 0 and src.ActiveSwitchingEnabled = 1)		--Enterprise CompetentStatus 1 = Active
			or		(src.AdviserCompetentStatus = 1 and trg.Active = 0 and src.ActiveSwitchingEnabled = 1))			--Adviser CompetentStatus 1 = Active
	then	update 
				set trg.RecipientsTo = src.RecipientsTo,
					trg.Active = case	when (src.EnterpriseCompetentStatus = 2 or src.AdviserCompetentStatus = 2) and src.ActiveSwitchingEnabled = 1 then 0	--Note: Ent or Adv
										when (src.EnterpriseCompetentStatus = 1 and src.AdviserCompetentStatus = 1) and src.ActiveSwitchingEnabled = 1 then 1	--Note: Ent and Adv
										else trg.Active 
								 end,
					trg.LastUpdatedReason = isnull(trg.LastUpdatedReason,'') 
											+ case 
												when isnull(src.RecipientsTo,'') <> isnull(trg.RecipientsTo,'') then @TodayStr + ': Change of RecipientsTo; '
												when src.AdviserCompetentStatus = 2 and src.ActiveSwitchingEnabled = 1 then @TodayStr + ': Change of Active, Adviser Left; ' 
												when src.EnterpriseCompetentStatus = 2 and src.ActiveSwitchingEnabled = 1 then  @TodayStr + ': Change of Active, Enterprise Left; '
												when src.AdviserCompetentStatus = 1 and src.EnterpriseCompetentStatus = 1 and src.ActiveSwitchingEnabled = 1 then @TodayStr + ': Change of Active, Adviser Active; ' 
												else ''
											  end,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by source
	and		trg.Active = 1
	then	update 
				set trg.Active = 0,	--Note this is forced to zero (off) even if ActiveSwitchingEnabled is off as it is inappropriate to continue sending emails to a transferred adviser.
					trg.LastUpdatedReason = isnull(trg.LastUpdatedReason,'') +  @TodayStr + ': Adviser Transferred; ',
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	and		src.ActivityActive = 1					--Activity is active
	and		src.EnterpriseActive = 1				--Enterprise is active
	and		src.AutoAdviserConfigEnabled = 1		--Enterprise enabled for auto adviser config
	and		src.EnterpriseCompetentStatus = 1		--Enterprise CompetentStatus 1 = Active
	and		src.AdviserCompetentStatus = 1			--Adviser CompetentStatus 1 = Active
	then	insert
			(
				EnterpriseUID,
				AdviserUID,
				ActivityID,
				Active,
				ActiveSwitchingEnabled,
				RecipientsToEnabled,
				RecipientsTo,
				RecipientsCCEnabled,
				RecipientsCC,
				RecipientsToOverrideEnabled,
				RecipientsToOverride,
				DateInserted,
				DateLastUpdated,
				LastUpdatedReason,
				Notes
			)		
			values
			(
				src.EnterpriseUID,
				src.AdviserUID,
				src.ActivityID,
				src.Active,
				src.ActiveSwitchingEnabled,
				src.RecipientsToEnabled,
				src.RecipientsTo,
				src.RecipientsCCEnabled,
				src.RecipientsCC,
				src.RecipientsToOverrideEnabled,
				src.RecipientsToOverride,
				@DateLastUpdated,
				@DateLastUpdated,
				src.LastUpdatedReason,
				src.Notes
			)				
	output $action into @SummaryOfChanges;	--Merge statements must have a ;

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @Message = 'owt_Comms_ConfigAdviser (insert) = ' + convert(varchar(20), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Message, null, @Module, @Client

	select	@RowCount = COUNT(*)	--This covers the updates for MATCHED and NOT MATCHED BY SOURCE
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @Message = 'owt_Comms_ConfigAdviser (update) = ' + convert(varchar(20), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Message, null, @Module, @Client

	/****************************************************************************

		End of processing
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd,  @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = @ErrMsg + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

	T H E   E N D														

****************************************************************************/

return @ErrNum
GO
