/*********************************************************************************************************

Name:	owp_Comms_InsertCommsHistory

Author:	A Groves

Date:	09/06/2022

Description:	This proc is a generic proc for inserting into table "owt_Comms_History". Only
				inserts should happen to this table, there should never be updates or deletes.

Notes:			SSIS variables cannot hold the database NULL value so they are passed into SSIS
				as empty strings and when the variables are passed into this proc any empty
				strings are then converted to NULL for the database.

Execution:		declare	@EnterpriseUID varchar(7) = '1001734'
						@AdviserUID varchar(7) = null,
						@ActivityID int = 1,
						@Dispatched bit = 1,
						@DispatchedDateTime = getdate(),
						@StartPeriod datetime = '2022-02-01',
						@EndPeriod datetime = '2022-02-01',
						@QuarterMonth = '2022-04-01',
						@Access varchar(200) = '1234567',
						@Sender nvarchar(4000) = 'alan.groves@theopenworkpartnership.com'
						@RecipientsTo nvarchar(4000) = 'alan.groves@theopenworkpartnership.com',
						@RecipientsCC nvarchar(4000) = null,
						@MessageSubject nvarchar(250) = 'Openwork Statements',
						@MessageContent nvarchar(max) = null,
						@FileAttachments nvarchar(max) = '\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\SupremeFinancialSolutionsOrangeWords189x57px.png;\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\TheOpenworkPartnershipLogo.png'
				exec dbo.owp_Comms_InsertCommsHistory @EnterpriseUID, @AdviserUID, @ActivityID, @Dispatched, @DispatchedDateTime, @StartPeriod, 
							@EndPeriod, @QuarterMonth, @Access, @Sender, @RecipientsTo, @RecipientsCC, @MessageSubject, @MessageContent, @FileAttachments

AMENDMENT HISTORY
=================

Date		Author		Description
----		------		-----------
18/08/2022	A Groves	Columns StartMonth & EndMonth changed to StartPeriod and EndPeriod to
						reflect generic use of this proc.
28/12/2022	A Groves	Added new parameter @FileAttachments to proc "dbo.owp_Comms_InsertCommsHistory".
**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_InsertCommsHistory]
	@EnterpriseUID varchar(7),
	@AdviserUID varchar(7) = null,
	@ActivityID int,
	@Dispatched bit = 1,
	@DispatchedDateTime datetime = null,
	@StartPeriod datetime = null,
	@EndPeriod datetime = null,
	@QuarterMonth datetime = null,
	@Access varchar(200) = null,
	@Sender nvarchar(400) = null,
	@RecipientsTo nvarchar(4000) = null,
	@RecipientsCC nvarchar(4000) = null,
	@MessageSubject nvarchar(250) = null,
	@MessageContent nvarchar(max) = null,
	@FileAttachments nvarchar(max) = null
as

declare @CurrentDateTime datetime = getdate()

insert into dbo.owt_Comms_History
(
	EnterpriseUID,
	AdviserUID,
	ActivityID,
	CommsDateTime,
	Dispatched,
	DispatchedDateTime,
	StartPeriod,
	EndPeriod,
	QuarterMonth,
	Access,
	Sender,
	RecipientsTo,
	RecipientsCC,
	MessageSubject,
	MessageContent,
	FileAttachments
)
values
(
	@EnterpriseUID,
	@AdviserUID,
	@ActivityID,
	@CurrentDateTime,						--CommsDateTime
	isnull(@Dispatched,0),
	case when isnull(@Dispatched,0) = 1 and @DispatchedDateTime is null then @CurrentDateTime else nullif(@DispatchedDateTime,'') end,
	nullif(@StartPeriod,''),
	nullif(@EndPeriod,''),
	nullif(@QuarterMonth,''),
	nullif(@Access,''),
	nullif(@Sender,''),
	nullif(@RecipientsTo,''),
	nullif(@RecipientsCC,''),
	nullif(@MessageSubject,''),
	nullif(@MessageContent,''),
	nullif(@FileAttachments,'')
)

GO
