CREATE PROCEDURE [dbo].[owp_Comms_InsertCommsHistory_Backup20230126AG]
	@EnterpriseUID varchar(7),
	@AdviserUID varchar(7) = null,
	@ActivityID int,
	@Dispatched bit = 1,
	@DispatchedDateTime datetime = null,
	@StartPeriod datetime = null,
	@EndPeriod datetime = null,
	@QuarterMonth datetime = null,
	@Access varchar(200) = null,
	@Sender nvarchar(400) = null,
	@RecipientsTo nvarchar(4000) = null,
	@RecipientsCC nvarchar(4000) = null,
	@MessageSubject nvarchar(250) = null,
	@MessageContent nvarchar(max) = null

as

declare @CurrentDateTime datetime = getdate()

insert into dbo.owt_Comms_History
(
	EnterpriseUID,
	AdviserUID,
	ActivityID,
	CommsDateTime,
	Dispatched,
	DispatchedDateTime,
	StartPeriod,
	EndPeriod,
	QuarterMonth,
	Access,
	Sender,
	RecipientsTo,
	RecipientsCC,
	MessageSubject,
	MessageContent
)
values
(
	@EnterpriseUID,
	@AdviserUID,
	@ActivityID,
	@CurrentDateTime,						--CommsDateTime
	isnull(@Dispatched,0),
	case when isnull(@Dispatched,0) = 1 and @DispatchedDateTime is null then @CurrentDateTime else nullif(@DispatchedDateTime,'') end,
	nullif(@StartPeriod,''),
	nullif(@EndPeriod,''),
	nullif(@QuarterMonth,''),
	nullif(@Access,''),
	nullif(@Sender,''),
	nullif(@RecipientsTo,''),
	nullif(@RecipientsCC,''),
	nullif(@MessageSubject,''),
	nullif(@MessageContent,'')
)




GO
/****** Object:  StoredProcedure [dbo].[owp_Comms_OpenAccess_AdvisersToProcess]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/***********************************************************************************************

Name:	owp_Comms_OpenAccess_AdvisersToProcess

Author:	A Groves

Date:	12/08/2022

Description:	This proc is used by SSIS script "Comms_OpenAccess_ProcessAdvisers.dtsx" to get the
				list of advisers to be processed for OpenAccess emailed reports in the current run.
				Table "owt_Comms_ConfigAdviser" contains the list of advisers to be processed
				and function "owf_RunNow" is used to determine if the enterprise and therefore all
				of its advisers should be processed now. 

				Notes: 

				1) At the time of writing there are two reports to be produced and emailed to each adviser
				for Colin Trigg's Supreme Financial Solutions AR business. They are:
				a) OpenAccess Pipeline on a Monday
				b) OpenAccess Issued Business on a Wednesday

				2) SSIS variables can't hold NULL values. NULL is allowed in data flow columns, but not 
				in variables, this is a limitation of the underlying COM objects used by SSIS. Thus this
				proc returns the empty string if a NULL is possible and this is reverted to NULL when 
				writing to the dbo.owt_Comms_History table.

				3) When concatenating multiple file attachments, do not insert a space between file
				paths as msdb.dbo.sp_send_dbmail thinks the space is part of the file path name and 
				the SSIS script will error-abort.

				4) The complex derivation of MessageContent in the final SELECT statement is to remove
				the two HTML <IMG> markups used for the brand logos (the enterprise's and Openwork's) if
				the recipient email addresses are NOT in the Openwork domain as these will cause the logos
				to be shown twice in the Apple Email app (Safari). However, Openwork email domains mean 
				Outlook is used and unless these <IMG> are present, then it causes the Email client to bump
				them to the top of the email like they're document attachments. So, in summry, this trickey 
				attempts to keep the logos in the email footer.
				
Execution:		exec dbo.owp_Comms_OpenAccess_AdvisersToProcess

AMENDMENT HISTORY
=================
Date	Author		Description
----	------		-----------

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_OpenAccess_AdvisersToProcess]

AS

declare @Today datetime = convert(date,getdate())
declare @TodayStr varchar(10) = convert(varchar(10),@Today,103)	
declare @StartPeriod datetime = @Today-7
declare @EndPeriod datetime = @Today-1

;with AdviserSetCTE as
(
	select	cce.ActivityID,
			cce.EnterpriseUID,
			ccadv.AdviserUID,
			@StartPeriod as StartPeriod, 
			@EndPeriod as EndPeriod,
			isnull(case when isnull(cce.Sender,'') <> '' then cce.Sender else cca.Sender end,'') as Sender,
			isnull(case when isnull(cce.ReplyTo,'') <> '' then cce.ReplyTo else cca.ReplyTo end,'') as ReplyTo,
			case when ccadv.RecipientsToOverrideEnabled = 1 and isnull(ccadv.RecipientsToOverride,'') <> ''
				then ccadv.RecipientsToOverride
				else case when ccadv.RecipientsToEnabled = 1 and isnull(ccadv.RecipientsTo,'') <> '' then ccadv.RecipientsTo else '' end 
			end as RecipientsTo,
			case when ccadv.RecipientsToOverrideEnabled = 1 and isnull(ccadv.RecipientsToOverride,'') <> ''
				then ''
				else case when ccadv.RecipientsCCEnabled = 1 and isnull(ccadv.RecipientsCC,'') <> '' then ccadv.RecipientsCC else '' end 
			end as RecipientsCC,
			isnull(	case when isnull(cce.MessageSubject,'') <> '' 
						then replace(cce.MessageSubject,'dd/mm/yyyy',@TodayStr)
						else replace(cca.MessageSubject,'dd/mm/yyyy',@TodayStr)
					end,'') as MessageSubject,
			isnull( case when isnull(cce.MessageContent,'') <> '' 
						then cce.MessageContent 
						else cca.MessageContent
					end,'') as MessageContent,
			case when cce.IncludeOpenworkLogo = 1
				then isnull(cce.FileAttachments,'') + case when LEN(cce.FileAttachments) > 0 then ';' else '' end + owlogo.[Path]
				else isnull(cce.FileAttachments,'')
			end as FileAttachments,
			cca.RunOrder
	from	dbo.owt_Comms_ConfigActivity cca 
			inner join dbo.owt_Comms_ConfigEnterprise cce on cce.ActivityID = cca.ActivityID
			inner join dbo.owt_Comms_ConfigAdviser ccadv
						on  ccadv.ActivityID = cce.ActivityID
						and ccadv.EnterpriseUID = cce.EnterpriseUID
			left join dbo.mst_DataImportConfiguration owlogo
						on	owlogo.Client = 'Openwork'
						and	owlogo.Module = 'TheOpenworkPartnershipTransparentLogo'
						and	owlogo.Name = 'OPWLOGO'
	where	1 = dbo.owf_RunNow(getdate(),cce.RunStartDate,cce.RunEndDate,cce.RunDaily,cce.RunDailyExcWeekend,cce.RunWeekDay,cce.RunWeekInterval,cce.RunMonthDay,cce.RunMonthInterval)
	and		cca.Active = 1
	and		cce.Active = 1
	and		ccadv.Active = 1
	and		cca.ActivityName in ('OpenAccess - Pipeline','OpenAccess - Issued')
	and		case when ccadv.RecipientsToOverrideEnabled = 1 and isnull(ccadv.RecipientsToOverride,'') <> ''
				then ccadv.RecipientsToOverride
				else case when ccadv.RecipientsToEnabled = 1 and isnull(ccadv.RecipientsTo,'') <> '' then ccadv.RecipientsTo else '' end 
			end <> '' --There must always be a RecipientsTo, although there may - or may not - be a RecipientsCC
)
select	ActivityID,
		EnterpriseUID,
		AdviserUID,
		StartPeriod,
		EndPeriod,
		Sender,
		ReplyTo,
		RecipientsTo,	
		RecipientsCC,
		MessageSubject,
		case when patindex('%<img %',MessageContent) > 1 and patindex('%@theopenworkpartnership.com%',RecipientsTo) = 0 and patindex('%@openwork.uk.com%',RecipientsTo) = 0 and patindex('%@owlfinancial.co.uk%',RecipientsTo) = 0
			then LEFT(MessageContent,patindex('%<img %',MessageContent)-1)	--Remove the <IMG> tags
			else MessageContent
		end as MessageContent,
		FileAttachments
from	AdviserSetCTE
order	by RunOrder asc


GO
