				proc is:
				1) Call the stored proc for the required OpenAccess report
				2) Call the generic proc that sends the email
				3) Log the email in the Comms History table

				Note:

				1) When concatenating multiple file attachments, do not insert a space between file
				paths as msdb.dbo.sp_send_dbmail thinks the space is part of the file path name and 
				will error.

Execution:		declare @ActivityID int = 2,
						@EnterpriseUID varchar(7) = '2018100',
						@AdviserUID varchar(7) = '4021656',
						@RecipientsTo nvarchar(4000) = 'alan.groves@theopenworkpartnership.com',
						@RecipientsCC nvarchar(4000) = 'alan.groves@theopenworkpartnership.com',
						@Sender nvarchar(400) = 'generalinformationDONOTREPLY@theopenworkpartnership.com',
						@ReplyTo nvarchar(400) = 'alan.groves@theopenworkpartnership.com',
						@StartPeriod datetime = '2022-08-12',
						@EndPeriod datetime = '2022-08-18',
						@MessageSubject nvarchar(250) = 'Email Subject', 
						@MessageContent nvarchar(max) = 'Email Body Content',
						@FileAttachments nvarchar(max) = '\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\SupremeFinancialSolutionsOrangeWords189x57px.png;\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\TheOpenworkPartnershipLogo.png'
				exec owp_Comms_OpenAccess_ExecuteReport @ActivityID, @EnterpriseUID, @AdviserUID, @RecipientsTo, @RecipientsCC, @Sender,
														@ReplyTo, @StartPeriod, @EndPeriod, @MessageSubject, @MessageContent, @FileAttachments

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
28/12/2022	A Groves	Added new parameter @FileAttachments to proc "dbo.owp_Comms_InsertCommsHistory".
**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_OpenAccess_ExecuteReport]
	@ActivityID int,
	@EnterpriseUID varchar(7),
	@AdviserUID varchar(7),
	@RecipientsTo nvarchar(4000),
	@RecipientsCC nvarchar(4000),
	@Sender nvarchar(400),
	@ReplyTo nvarchar(400),
	@StartPeriod datetime,
	@EndPeriod datetime,
	@MessageSubject nvarchar(250), 
	@MessageContent nvarchar(max),
	@FileAttachments nvarchar(max)
AS

if @ActivityID = 2
	exec dbo.owp_Comms_OpenAccess_PipelineReport @EnterpriseUID, @AdviserUID, @MessageContent output
else if @ActivityID = 3
	exec dbo.owp_Comms_OpenAccess_IssuedReport @EnterpriseUID, @AdviserUID, @MessageContent output

exec dbo.owp_Comms_OpenAccess_SendEmail @RecipientsTo, @RecipientsCC, @MessageSubject, @MessageContent, 'HTML', @Sender, @ReplyTo, @FileAttachments

exec dbo.owp_Comms_InsertCommsHistory @EnterpriseUID, @AdviserUID, @ActivityID, 1, null, @StartPeriod, @EndPeriod, null, null, 
										@Sender, @RecipientsTo, @RecipientsCC, @MessageSubject, @MessageContent, @FileAttachments

GO
