/*******************************************************************************************************************

Program:		owp_Comms_OpenAccess_IssuedReport					
Author:			Alan Groves
Date created:	10/08/2022
											
Description:
===========

This proc will create an OpenAccess Issued business HTML email. Just the Email Subject and Email Body are created.
These are then returned by the proc as output parameters to the calling module which sends the email.

Note:	There will be text in HTML format passed into this proc via @MessageContent similar to the following (it is enterprise specific):

			Please email me at admin@supremefinancialsolutions.co.uk if you have any queries.

			Kind regards,

			Colin Trigg
			Practice Principal
			Supreme Financial Solutions Ltd

			Supreme Financial Solutions Limited is an Appointed Representative of The Openwork Partnership, a trading style of Openwork Limited, which is authorised and regulated by the Financial Conduct Authority.

			If you wish to view the Openwork email disclaimer, please click here.

		This proc then embeds the report table data above this text and passes the whole lot out of the proc via the @MessageContent output parameter.

This proc is called as follows:
	
	declare @BusinessCode varchar(7) = '2018100',
			@AdviserCode varchar(7) = '4021656',
			@MessageContent nvarchar(max)
	exec dbo.owp_Comms_OpenAccess_IssuedReport @BusinessCode, @AdviserCode, @MessageSubject output, @MessageContent output

AMENDMENT HISTORY				
=================								

Date		Author			Description
----		------			-----------

********************************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_OpenAccess_IssuedReport]
	@BusinessCode varchar(7),
	@AdviserCode varchar(7),
	@MessageContent nvarchar(max) output

AS

set nocount on

declare		@RowCount					int,
			@AdviserName				nvarchar(50),
			@BusinessName				nvarchar(255),
			@WeekCommencingDate			varchar(10),
			@FirstName					varchar(60),
			@LastName					varchar(60),
			@Salutation					varchar(100),
			@TableHeading				varchar(200),
			@Today						datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Today		= CONVERT(date,getdate())
set @WeekCommencingDate = convert(varchar(10),DATEADD(wk,DATEDIFF(wk,0,@Today),0),103)

/****************************************************************************

	Select the OpenAccess Issued data for the adviser
																		
****************************************************************************/

select	row_number() over (order by subqry.Provider,subqry.ClientName,subqry.Policy,subqry.PaidDate) as Item,
		subqry.*
into	#Issued
from	(
		select	PaidDate		= convert(varchar(10),BACSDate,103),
				Provider		= Provider,
				ClientName		= dbo.owf_MaskText(ClientForename + ' ' + ClientSurname),
				Policy			= isnull(Policy,''),							--PolicyNumber
				CaseId			= isnull(CaseId,''),
				ProdType		= ProdType,
				StartDate		= convert(varchar(10),StartDate,103),
				Premium			= convert(decimal(12,2),isnull(Premium,0)),		--Premium/Inv/MortLoadAmt
				InitialPeriod	= InitialPeriod,
				PayBasis		= PayBasis,
				APE				= convert(decimal(12,2),isnull(APE,0))
		from	msit_OpenWorkAdviserListing
		where	BusinessCode = @BusinessCode
		and		SellerCode = @AdviserCode
		and		Source in ('Openwork 2005','Openwork 2006')
		and		BACSDate between @Today-7 and @Today-1 
		and		(isnull(TotDue_Base,0.00) <> 0 
				or isnull(Accrued_Base,0.00) <> 0
				or isnull(StillToAccr_Base,0.00) <> 0
				or isnull(ITAdvanced_Base,0.00) <> 0
				or isnull(TotDue_Enhd,0.00) <> 0
				or isnull(Accrued_Enhd,0.00) <> 0
				or isnull(StillToAccr_Enhd,0.00) <> 0
				or isnull(ITAdvanced_Enhd,0.00) <> 0
				or isnull(TotalPayment, 0.0) <> 0
				or isnull(APE,0.00) <> 0)
		) subqry

set @RowCount = @@rowcount

insert into #Issued
(
	Item,
	PaidDate,
	Provider,
	ClientName,
	Policy,
	CaseId,
	ProdType,
	StartDate,
	Premium,
	InitialPeriod,
	PayBasis,
	APE
)
select	(select max(Item)+1 from #Issued) as Item,
		'' as PaidDate,
		'' as Provider,
		'' as ClientName,
		'' as Policy,
		'' as CaseId,
		'' as ProdType,
		'' as StartDate,
		0 as Premium,
		'' as InitialPeriod,
		'TOTAL' as PayBasis,
		(select sum(APE) from #Issued) as APE

/****************************************************************************

	Fetch info needed for email
																		
****************************************************************************/

select	@FirstName = dbo.owf_FirstWord(adv.FirstNames),
		@LastName = ltrim(rtrim(adv.Name))
from	mstt_Agents adv
where	adv.CODE = @AdviserCode

set @Salutation = 'Dear ' + @FirstName + ','

set @TableHeading =	@FirstName + 
					' ' + 
					@LastName + 
					' (' + convert(varchar(20),@RowCount) +
					case when @RowCount = 1 then ' case)' else ' cases)' end

/****************************************************************************

	Build the HTML email body
																		
****************************************************************************/

if @RowCount > 0
begin
	set @MessageContent =
		N'<style>' + 
			N'table, td, th {border: 1px solid black; border-collapse: collapse; padding: 4px};' + 
			N'th {background:#E8E8E8};' +
			N'</style>' +
		N'</head>' +
		N'<body>' +		
		N'</br>' +
		@Salutation +
		N'</br>' +
		N'</br>' +
		N'Please find below your OpenAccess Issued Report for week commencing ' + @WeekCommencingDate + N'.' +
		N'</br>' +
		N'</br>' +
		N'<b>' +
		@TableHeading +
		N'</b>' +
		N'</br>' +
		N'</br>' +
		N'<table>' +
		N'<tr>' +
			N'<th>Item</th>' +
			N'<th>PaidDate</th>' +
			N'<th>Provider</th>' +
			N'<th>Client Name</th>' +
			N'<th>Policy Number</th>' +
			N'<th>Case ID</th>' +
			N'<th>Prod Type</th>' +
			N'<th>Start Date</th>' +
			N'<th>Prem / Invest / MLA</th>' +
			N'<th>Init Period</th>' +
			N'<th>Pay Basis</th>' +
			N'<th>APE</th>' +
		N'</tr>' +
		cast ( (
				select	"td/@align" = 'right', td = Item, '',
						"td/@align" = 'center', td = PaidDate, '',
						td = Provider, '',
						td = ClientName, '',
						td = Policy, '',
						td = CaseID, '',
						td = ProdType, '',
						td = StartDate, '',
						"td/@align" = 'right', td = Premium, '',
						"td/@align" = 'right', td = InitialPeriod, '',
						td = PayBasis, '',
						"td/@align" = 'right', td = APE, ''
				from
				(
					select	case when Item > @RowCount then '' else convert(varchar(10),Item) end as Item,
							PaidDate,
							Provider,
							ClientName,
							Policy,
							CaseID,
							ProdType,
							StartDate,
							case when Item > @RowCount then '' else convert(varchar(20),Premium) end as Premium,
							case when Item > @RowCount then '' else convert(varchar(10),InitialPeriod) end as InitialPeriod,
							PayBasis,
							convert(varchar(20),APE) as APE,
							Item as SortOrder
					from	#Issued
				) a
				order by SortOrder										
				FOR XML PATH('tr')
				) AS NVARCHAR(MAX) ) +
		N'</table>' +
		N'</br>' +
		N'</br>' +
		@MessageContent +
		N'</br>' +
		N'</br>' +
		N'</body>' 
end
else
begin
	set @MessageContent = 
		N'<head>' +
		N'<style>' + 
			N'table, td, th {border: 1px solid black; border-collapse: collapse; padding: 4px};' + 
			N'th {background:#E8E8E8};' +
		N'</style>' +
		N'</head>' +
		N'<body>' +	
		N'</br>' +
		@Salutation +
		N'</br>' +
		N'</br>' +
		N'Please find below your OpenAccess Issued Report for week commencing ' + @WeekCommencingDate + N'.' +
		N'</br>' +
		N'</br>' +
		N'</br></br>No Issued data to report.' +
		N'</br>' +
		N'</br>' +
		N'</br>' +
		N'</br>' +
		@MessageContent +
		N'</br>' +
		N'</body>' 
end

/****************************************************************************

	T H E   E N D														

****************************************************************************/


GO
