CREATE PROCEDURE [dbo].[owp_Comms_OpenAccess_PipelineReport]
	@BusinessCode varchar(7),
	@AdviserCode varchar(7),
	@MessageContent nvarchar(max) output

AS

set nocount on

declare		@RowCount					int,
			@AdviserName				nvarchar(50),
			@BusinessName				nvarchar(255),
			@WeekCommencingDate			varchar(10),
			@FirstName					varchar(60),
			@LastName					varchar(60),
			@Salutation					varchar(100),
			@TableHeading				varchar(200),
			@Today						datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Today = CONVERT(date,getdate())
set @WeekCommencingDate = convert(varchar(10),DATEADD(wk,DATEDIFF(wk,0,@Today),0),103)

/****************************************************************************

	Select the OpenAccess Pipeline data for the adviser
																		
****************************************************************************/

select	row_number() over (order by subqry.PipelineDays, subqry.Provider, subqry.ClientName, subqry.CaseID) as Item,
		subqry.*
into	#Pipeline
from	(
		select	convert(varchar(10),PipelineStartDate,103) as SubmissionDate,
				PipelineDays,
				isnull(pp.ProductProviderName,'N/A') as Provider,
				case when cpg.StructuredProduct = 'Y' then 'Structured' else COALESCE(cpg.ProductGroupName,'Unknown') end as ProductGroup,
				dbo.owf_MaskText(p.ClientName) as ClientName,
				isnull(p.PolicyNumber,'') as PolicyNumber,
				isnull(p.CaseID,'') as CaseID,
				p.Basis as PayBasis,
				p.StatusDesc as Status
		from	owoa_Pipeline p
				left outer join head_office_systems.dbo.owoa_pipelineNPW npw on p.proptranid = npw.proptranid
				left outer join mstt_producthierarchy cpg on cpg.ProductCode = p.ProductCode
				left outer join mstt_ProductProviders pp on pp.ProductProviderCode = p.ProviderCode	
		where	p.BusinessCode = @BusinessCode
		and		p.SellerCode = @AdviserCode
		and		npw.PropTranID is null
		) subqry

set @RowCount = @@rowcount

/****************************************************************************

	Fetch info needed for email
																		
****************************************************************************/

select	@FirstName = dbo.owf_FirstWord(adv.FirstNames),
		@LastName = ltrim(rtrim(adv.Name))
from	mstt_Agents adv
where	adv.CODE = @AdviserCode

set @Salutation = 'Dear ' + @FirstName + ','

set @TableHeading =	@FirstName + 
					' ' + 
					@LastName + 
					' (' + convert(varchar(20),@RowCount) +
					case when @RowCount = 1 then ' case)' else ' cases)' end

/****************************************************************************

	Build the HTML email body
																		
****************************************************************************/

if @RowCount > 0
begin
	set @MessageContent =
		N'<head>' +
		N'<style>' + 
			N'table, td, th {border: 1px solid black; border-collapse: collapse; padding: 4px};' + 
			N'th {background:#E8E8E8};' +
		N'</style>' +
		N'</head>' +
		N'<body>' +		
		N'</br>' +
		@Salutation +
		N'</br>' +
		N'</br>' +
		N'Please find below your OpenAccess Pipeline Report for week commencing ' + @WeekCommencingDate + N'.' +
		N'</br>' +
		N'</br>' +
		N'<b>' +
		@TableHeading +
		N'</b>' +
		N'</br>' +
		N'</br>' +
		N'<table>' +
		N'<tr>' +
			N'<th>Item</th>' +
			N'<th>Submission Date</th>' +
			N'<th>Days in P/Line</th>' +
			N'<th>Provider</th>' +
			N'<th>Product Group</th>' +
			N'<th>Client Name</th>' +
			N'<th>Policy Number</th>' +
			N'<th>Case ID</th>' +
			N'<th>Pay Basis</th>' +
			N'<th>Status</th>' +
		N'</tr>' +
		cast ( (
				select	"td/@align" = 'right', td = Item, '',
						"td/@align" = 'center', td = SubmissionDate, '',
						"td/@align" = 'right', td = PipelineDays, '',
						td = Provider, '',
						td = ProductGroup, '',
						td = ClientName, '',
						td = PolicyNumber, '',
						td = CaseID, '',
						td = PayBasis, '',
						td = Status, ''
				from
				(
					select	Item,
							SubmissionDate,
							PipelineDays,
							Provider,
							ProductGroup,
							ClientName,
							PolicyNumber,
							CaseID,
							PayBasis,
							Status
					from	#Pipeline
				) a
				order by Item										
				FOR XML PATH('tr')
				) AS NVARCHAR(MAX) ) +
		N'</table>' +
		N'</br>' +
		N'</br>' +
		@MessageContent +
		N'</br>' +
		N'</br>' +
		N'</body>' 
end
else
begin
	set @MessageContent = 
		N'<head>' +
		N'<style>' + 
			N'table, td, th {border: 1px solid black; border-collapse: collapse; padding: 4px};' + 
			N'th {background:#E8E8E8};' +
		N'</style>' +
		N'</head>' +
		N'<body>' +	
		N'</br>' +
		@Salutation +
		N'</br>' +
		N'</br>' +
		N'Please find below your OpenAccess Pipeline Report for week commencing ' + @WeekCommencingDate + N'.' +
		N'</br>' +
		N'</br>' +
		N'</br></br>No Pipeline data to report.' +
		N'</br>' +
		N'</br>' +
		N'</br>' +
		N'</br>' +
		@MessageContent +
		N'</br>' +
		N'</body>' 
end

/****************************************************************************

	T H E   E N D														

****************************************************************************/



GO
