/***********************************************************************************************

Name:	owp_Comms_OpenAccess_SendEmail

Author:	A Groves

Date:	10/08/2022

Description:	This proc is a wrapper for Microsoft stored proc sp_send_dbmail. It exists to:
				1) Add in the Openwork Logo 
				2) Set the @reply_to parameter

Execution:		declare @RecipientsTo varchar(max) = 'alan.groves@theopenworkpartnership.com',
						@RecipientsCC varchar(max) = null,
						@Subject nvarchar(255) = 'OpenAccess Report',
						@MessageContent nvarchar(max) = 'Please find attached your Openwork statements for the latest period.',
						@EmailFormat varchar(20) = 'HTML',
						@Sender varchar(max) = 'generalinformationDONOTREPLY@theopenworkpartnership.com',
						@ReplyTo varchar(max) = 'alan.groves@theopenworkpartnership.com',
						@FileAttachments nvarchar(max) = '\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\TheOpenworkPartnershipLogo.png'
				exec dbo.owp_Comms_OpenAccess_SendEmail @RecipientsTo, @RecipientsCC, @Subject, @MessageContent,
														@EmailFormat, @Sender, @ReplyTo, @FileAttachments

AMENDMENT HISTORY
=================
Date	Author		Description
----	------		-----------

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_OpenAccess_SendEmail]
	@RecipientsTo varchar(max),
	@RecipientsCC varchar(max),
	@Subject nvarchar(255),
	@MessageContent nvarchar(max),
	@EmailFormat varchar(20),
	@Sender varchar(max),
	@ReplyTo varchar(max),
	@FileAttachments nvarchar(max)
AS

/****************************************************************************

	Set NULL where an empty string can occur																
																		
****************************************************************************/

set @RecipientsCC = nullif(@RecipientsCC,'')
set @FileAttachments = nullif(@FileAttachments,'')

/****************************************************************************

	Send the email																
																		
****************************************************************************/

exec msdb.dbo.sp_send_dbmail
		@recipients = @RecipientsTo,
		@copy_recipients = @RecipientsCC,
		@subject = @Subject,
		@body = @MessageContent,
		@body_format = @EmailFormat,
		@from_address = @Sender,
		@file_attachments = @FileAttachments,
		@reply_to = @ReplyTo

/****************************************************************************

	T H E   E N D														

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Comms_TermStmts_EnterprisesToProcess]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/***********************************************************************************************

Name:	owp_Comms_TermStmts_EnterprisesToProcess

Author:	A Groves

Date:	09/06/2022

Description:	This proc is used by SSIS script "TermStmts_ProcessEnterprises.dtsx" to get the
				list of enterprises to be processed for terminated statements in the current run.
				Table "owt_CommsConfigEnterprise" contains the list of enterprises to be processed
				and function "owf_RunNow" is used to determine if the enterprise should be processed
				now. Most enterprises are processed quarterly, but some are processed monthly.

				Notes: 
				1) The StartMonth and EndMonth span is determined by the execution frequency given 
				by column "RunWeekInterval" on table "owt_CommsConfigEnterprise". Where the value is
				1, this means monthly processed, where it is 3, this means it is quarterly processed
				(every three months).

				2) EnterpriseFileID is a reversible 6 digit hash code that is generated for each 
				enterprise and pre-pended to the report files generated to ensure there is no confusion 
				over which firm is the recipient. This is used because typically the report files are 
				zipped and password protected with the BUID. So it is important that the BUID is not 
				used in the file names.

				3) SSIS variables can't hold NULL values. NULL is allowed in data flow columns, but not 
				in variables, this is a limitation of the underlying COM objects used by SSIS. Thus this
				proc returns the empty string if a NULL is possible and this is reverted to NULL when 
				writing to the dbo.owt_Comms_History table.

Execution:		exec dbo.owp_Comms_TermStmts_EnterprisesToProcess

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
29/12/2022	A Groves	1) Added "ReplyTo" and "FileAttachments" to the results set.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_TermStmts_EnterprisesToProcess]

AS

declare @MY varchar(20) = ' ' + datename(mm,getdate()) + ' ' + CONVERT(varchar(4),year(getdate()))	--Format: July 2022 with leading space

select	cce.ActivityID,
		cce.EnterpriseUID,
		dbo.owf_HashForwardUID(cce.EnterpriseUID) as EnterpriseFileID,
		StrtPrd.Month as StartMonth, 
		EndPrd.Month as EndMonth,
		case when QtrComms.EnterpriseUID is null
			then PrevQtr.MaxQuarterMonth
			else '1900-01-01'
		end as QuarterMonth,
		case when QtrComms.EnterpriseUID is null
			then 'Quarter ' + datename(qq,dateadd(dd,-1,PrevQtr.MaxQuarterMonth)) + ' ' + dateName(yyyy,dateadd(dd,-1,PrevQtr.MaxQuarterMonth))
			else ''
		end as QuarterName,
		case when QtrComms.EnterpriseUID is null
			then left(datename(mm,dateadd(mm,-3,PrevQtr.MaxQuarterMonth)),3) + ' ' + right(datename(yyyy,dateadd(mm,-3,PrevQtr.MaxQuarterMonth)),2)
			else ''
		end as QuarterMonth1Name,
		case when QtrComms.EnterpriseUID is null
			then left(datename(mm,dateadd(mm,-2,PrevQtr.MaxQuarterMonth)),3) + ' ' + right(datename(yyyy,dateadd(mm,-2,PrevQtr.MaxQuarterMonth)),2)
			else ''
		end as QuarterMonth2Name,
		case when QtrComms.EnterpriseUID is null
			then left(datename(mm,dateadd(mm,-1,PrevQtr.MaxQuarterMonth)),3) + ' ' + right(datename(yyyy,dateadd(mm,-1,PrevQtr.MaxQuarterMonth)),2)
			else ''
		end as QuarterMonth3Name,
		isnull(case when isnull(cce.Override,'') <> '' then cce.Override else ltrim(rtrim(isnull(cce.Prefix,'') + cce.EnterpriseUID + isnull(cce.Suffix,''))) end,'') as Access,
		isnull(case when isnull(cce.Sender,'') <> '' then cce.Sender else cca.Sender end,'') as Sender,
		isnull(cce.RecipientsTo,'') as RecipientsTo,
		isnull(cce.RecipientsCC,'') as RecipientsCC,
		isnull(	case when isnull(cce.MessageSubject,'') <> '' 
					then cce.MessageSubject + @MY 
					else cca.MessageSubject + @MY 
				end,'') as MessageSubject,
		isnull( case when isnull(cce.MessageContent,'') <> '' 
					then replace(cce.MessageContent,'XXXEntNameXXX',ltrim(rtrim(ag.Descn))) 
					else replace(cca.MessageContent,'XXXEntNameXXX',ltrim(rtrim(ag.Descn)))
				end,'') as MessageContent,
		isnull(case when isnull(cce.ReplyTo,'') <> '' then cce.ReplyTo else cca.ReplyTo end,'') as ReplyTo,
		case when cce.IncludeOpenworkLogo = 1
				then isnull(cce.FileAttachments,'') + case when LEN(cce.FileAttachments) > 0 then ';' else '' end + owlogo.[Path]
				else isnull(cce.FileAttachments,'')
			end as FileAttachments
from	dbo.owt_Comms_ConfigActivity cca 
		inner join dbo.owt_Comms_ConfigEnterprise cce on cce.ActivityID = cca.ActivityID
		inner join dbo.mstt_Agents ag on ag.CODE = cce.EnterpriseUID
		cross join (select	max(PeriodEndDate) as MaxPeriodEndDate
					 from	dbo.msit_CommissionStatementPeriods
					 where	PeriodEndDate < convert(date,getdate())
					 ) PrevPrd 
		cross join (select	max(Month) as MaxQuarterMonth
					 from	dbo.msit_FeesNonSWIFTRenewalListing
					 ) PrevQtr
		inner join dbo.msit_CommissionStatementPeriods EndPrd on EndPrd.PeriodEndDate = PrevPrd.MaxPeriodEndDate
		inner join dbo.msit_CommissionStatementPeriods StrtPrd on StrtPrd.Month = dateadd(mm,-(isnull(cce.RunMonthInterval,1)-1),EndPrd.Month)
		left join (select	EnterpriseUID, ActivityID, MAX(QuarterMonth) as MaxQuarterMonth
					from	dbo.owt_Comms_History
					--where	1=2
					group	by EnterpriseUID, ActivityID
					) QtrComms
					on QtrComms.EnterpriseUID = cce.EnterpriseUID
					and QtrComms.ActivityID = cca.ActivityID	
					and QtrComms.MaxQuarterMonth = PrevQtr.MaxQuarterMonth
		left join dbo.mst_DataImportConfiguration owlogo
					on	owlogo.Client = 'Openwork'
					and	owlogo.Module = 'TheOpenworkPartnershipTransparentLogo'
					and	owlogo.Name = 'OPWLOGO'
where	cca.ActivityName = 'Terminated Statements'
and		1 = dbo.owf_RunNow(getdate(),RunStartDate,RunEndDate,RunDaily,RunDailyExcWeekend,RunWeekDay,RunWeekInterval,RunMonthDay,RunMonthInterval)
and		cca.Active = 1
and		cce.Active = 1


GO
