CREATE PROCEDURE [dbo].[owp_Comms_TermStmts_GetRunConfig]

AS

select	wp.[Path] as DestinationFolder, lg.[Path] as LogFolder, arc.[Path] as ArchiveFolder
from	dbo.mst_DataImportConfiguration wp
		inner join dbo.mst_DataImportConfiguration lg
						on  lg.Client = wp.Client
						and lg.Module = wp.Module
						and lg.Name = 'LOG'
		inner join dbo.mst_DataImportConfiguration arc
						on  arc.Client = wp.Client
						and arc.Module = wp.Module
						and arc.Name = 'ARCHIVE'
where	wp.Client = 'Openwork'
and		wp.Module = 'TerminatedStatements'
and		wp.Name = 'COMMS'
