/****** Object:  StoredProcedure [dbo].[owp_Comms_TermStmts_SendAndLogEmail]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Name:	dbo.owp_Comms_TermStmts_SendAndLogEmail

Author:	A Groves

Date:	29/12/2022

Description:	This proc is used by SSIS script "TermStmts_PopulateReport.dtsx". The job of this
				proc is:
				1) Call the generic proc that sends the email
				2) Log the email in the Comms History table

				Note:

				1) When concatenating multiple file attachments, do not insert a space between file
				paths as msdb.dbo.sp_send_dbmail thinks the space is part of the file path name and 
				will error.
				2) Ensure there is no leading or trailing ; character in @FileAttachments, or 
				msdb.dbo.sp_send_dbmail will fail.

Execution:		declare @ActivityID int = 2,
						@EnterpriseUID varchar(7) = '2018100',
						@RecipientsTo nvarchar(4000) = 'alan.groves@theopenworkpartnership.com',
						@RecipientsCC nvarchar(4000) = 'alan.groves@theopenworkpartnership.com',
						@Sender nvarchar(400) = 'StatementsDONOTREPLY@theopenworkpartnership.com',
						@ReplyTo nvarchar(400) = 'feesandpayments@theopenworkpartnership.com',
						@StartPeriod datetime = '2022-08-12',
						@EndPeriod datetime = '2022-08-18',
						@QuarterMonth datetime = '2022-10-01',
						@Access varchar(200) = '2018100',
						@MessageSubject nvarchar(250) = 'Email Subject', 
						@MessageContent nvarchar(max) = 'Email Body Content',
						@FileAttachments nvarchar(max) = '\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\SupremeFinancialSolutionsOrangeWords189x57px.png;\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\TheOpenworkPartnershipLogo.png'
				exec dbo.owp_Comms_TermStmts_SendAndLogEmail @ActivityID, @EnterpriseUID, @RecipientsTo, @RecipientsCC, @Sender, @ReplyTo, @StartPeriod,
																@EndPeriod, @QuarterMonth, @Access, @MessageSubject, @MessageContent, @FileAttachments

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_TermStmts_SendAndLogEmail]
	@ActivityID int,
	@EnterpriseUID varchar(7),
	@RecipientsTo nvarchar(4000),
	@RecipientsCC nvarchar(4000),
	@Sender nvarchar(400),
	@ReplyTo nvarchar(400),
	@StartPeriod datetime,
	@EndPeriod datetime,
	@QuarterMonth datetime,
	@Access varchar(200) = null,
	@MessageSubject nvarchar(250), 
	@MessageContent nvarchar(max),
	@FileAttachments nvarchar(max)

as

--Remove any leading or trailing spaces
set @FileAttachments = ltrim(rtrim(@FileAttachments))

--Remove leading ; character if there is one
if left(@FileAttachments,1) = ';'
	set @FileAttachments = substring(@FileAttachments,2,len(@FileAttachments))

--Remove trailing ; character if there is one
if right(@FileAttachments,1) = ';'
	set @FileAttachments = substring(@FileAttachments,1,len(@FileAttachments)-1)

