exec dbo.owp_Comms_InsertCommsHistory @EnterpriseUID, null, @ActivityID, 1, null, @StartPeriod, @EndPeriod, @QuarterMonth, @Access, 
										@Sender, @RecipientsTo, @RecipientsCC, @MessageSubject, @MessageContent, @FileAttachments

