Name:	owp_Comms_TermStmts_SendEmail

Author:	A Groves

Date:	15/07/2022

Description:	This proc is a wrapper for Microsoft stored proc sp_send_dbmail. It exists to:
				1) Add in the Openwork Logo 
				2) Set the @reply_to parameter

Execution:		declare @RecipientsTo varchar(max) = 'alan.groves@theopenworkpartnership.com',
						@RecipientsCC varchar(max) = null,
						@Subject nvarchar(255) = 'Openwork - OpenAccess Statements - July 2022',
						@MessageContent nvarchar(max) = 'Please find attached your Openwork statements for the latest period.',
						@EmailFormat varchar(20) = 'HTML',
						@Sender varchar(max) = 'alan.groves@theopenworkpartnership.com',
						@FileAttachments nvarchar(max) = '\\uat-openwork.local\midb\MIDATA\HeadOfficeSystems\SSIS\IMAGES\TheOpenworkPartnershipLogo.png'
				exec dbo.owp_Comms_TermStmts_SendEmail @RecipientsTo, @RecipientsCC, @Subject, @MessageContent,
														@EmailFormat, @Sender, @FileAttachments

AMENDMENT HISTORY
=================
Date	Author		Description
----	------		-----------

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Comms_TermStmts_SendEmail_Backup20230126AG]
	@RecipientsTo varchar(max),
	@RecipientsCC varchar(max),
	@Subject nvarchar(255),
	@MessageContent nvarchar(max),
	@EmailFormat varchar(20),
	@Sender varchar(max),
	@FileAttachments nvarchar(max)
AS

declare @OWLogoFilePath varchar(255)

select	@OWLogoFilePath = owlogo.[Path]
from	dbo.mst_DataImportConfiguration owlogo
where	owlogo.Client = 'Openwork'
and		owlogo.Module = 'TheOpenworkPartnershipTransparentLogo'
and		owlogo.Name = 'OPWLOGO'

set @RecipientsCC = nullif(@RecipientsCC,'')
set @FileAttachments = isnull(@FileAttachments,'') + case when isnull(@FileAttachments,'') = '' then '' else ';' end + @OWLogoFilePath

exec msdb.dbo.sp_send_dbmail
		@recipients = @RecipientsTo,
		@copy_recipients = @RecipientsCC,
		@subject = @Subject,
		@body = @MessageContent,
		@body_format = @EmailFormat,
		@from_address = @Sender,
		@file_attachments = @FileAttachments,
		@reply_to = @Sender
GO
