/*********************************************************************************************************

Name:	owp_Comms_TermStmts_SSISRpt_OWAccountStatement
Author:	A Groves
Date:	27/05/2022

Description:	Openwork Account Statement for the automated Terminated Statements process.

				Note: This stored proc is called by SSIS package "TermStmts - PopulateExcel.dtsx".

The proc is called as follows:

exec dbo.owp_Comms_TermStmts_SSISRpt_OWAccountStatement '1001734', '2022-04-01', '2022-04-01' 

Amendment History
-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE procedure [dbo].[owp_Comms_TermStmts_SSISRpt_OWAccountStatement]
	@EnterpriseUID nvarchar(20),
	@StartMonth datetime,
	@EndMonth datetime

as

declare @OwOpeningBalanceAmount float,
		@OwOpeningBalanceTxnDate datetime

declare @AccountStatement table
(
	Id int identity(1,1),
	TxnDate nvarchar(10),
	Description nvarchar(255),
	Credits float,
	Debits float,
	Amount float,
	Notes nvarchar(255),
	Source nvarchar(13),
	TotalType int
)

Insert into @AccountStatement
(
	TxnDate,
	Description,
	Credits,
	Debits,
	Amount,
	Notes,
	Source,
	TotalType
)
select	TxnDate = convert(varchar(10),TransactionDate,103),
		Description = TransactionType,
		Credits         = case when Amount > 0 then Amount
								else 0
						   end,
		Debits          = case when Amount < 0 then Amount
								else 0
						   end,
		Amount,
		Notes = case when TransactionType in ('Opening Balance','Closing Balance') then Source else Description + ' ' + isnull(Notes,'') end,
		Source,
		TotalType
from	dbo.msit_OpenworkBankDetails
where	BusinessCode = @EnterpriseUID 
and		[Month] <= @EndMonth              
and		[Month] >= @StartMonth              
and		Source in ('Openwork 2005','Openwork 2006')
order	by	Source,
			[Month],
			SortCode,
			TransactionDate,
			[Sequence],
			TotalType,
			PaymentType,
			Provider desc


select	@OwOpeningBalanceAmount = sum(Amount),
		@OwOpeningBalanceTxnDate = min(TransactionDate)
from	dbo.msit_OpenworkBankDetails a
		join (select	source,min(month) as month
			  from		dbo.msit_OpenworkBankDetails
			  where		BusinessCode = @EnterpriseUID
			  and		[Month] <= @EndMonth
			  and		[Month] >= @StartMonth
			  and		source in ('Openwork 2005','Openwork 2006')
			  and		PaymentType = 0
			  group by source
			) b on a.source = b.source and a.month = b.month
where	BusinessCode = @EnterpriseUID  
and		a.source in ('Openwork 2005','Openwork 2006')
and		PaymentType = 0


select	Code as EnterpriseUID,
		Descn as EnterpriseName,
		OscarAgentPrefix + OscarAgentSerial + OscarAgentSuffix as Oscar,
		case when @StartMonth = @EndMonth
			then cspStart.MonthName 
			else cspStart.MonthName + ' - ' + cspEnd.MonthName
		end as StatementPeriod,
		convert(varchar(10),cspStart.PeriodStartDate,103) as StmtFromDate,
		convert(varchar(10),cspEnd.PeriodEndDate,103) as StmtToDate,
		case when cspEnd.PeriodEndDate < convert(date,getdate()) then 'Paid' else 'Awaiting Payment' end as Status,
		isnull(@OwOpeningBalanceAmount,0.0) as OwOpeningBalanceAmount,
		case when @OwOpeningBalanceTxnDate is null then convert(varchar(10),cspStart.PeriodStartDate,103) else convert(varchar(10),@OwOpeningBalanceTxnDate,103) end as OwOpeningBalanceTxnDate
from	dbo.mstt_Agents
		inner join dbo.msit_CommissionStatementPeriods cspStart on cspStart.Month = @StartMonth
		inner join dbo.msit_CommissionStatementPeriods cspEnd on cspEnd.Month = @EndMonth
where	Code = @EnterpriseUID


select	TxnDate,
		Description,
		isnull(Credits,0.0) as Credits,
		isnull(Debits,0.0) as Debits,
		Notes,
		TotalType
from	@AccountStatement
where	TotalType is not null	--TotalType should never be null, but just in case....
order	by ID


GO
