Name:	owp_Comms_TermStmts_SSISRpt_OWCommissionListing
		(templated from dbo.owoa_OpenworkAdviserListingRange - unknown author and date)
Author:	A Groves
Date:	16/06/2022

Description:	Openwork Commission Listing for the automated Terminated Statements process.

				Note: This stored proc is called by SSIS package "TermStmts - PopulateExcel.dtsx".

The proc is called as follows:

exec dbo.owp_Comms_TermStmts_SSISRpt_OWCommissionListing '1001734', '2022-04-01', '2022-04-01' 
        
Amendment History
-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE procedure [dbo].[owp_Comms_TermStmts_SSISRpt_OWCommissionListing]
	@EnterpriseUID nvarchar(20),
	@StartMonth datetime,
	@EndMonth datetime

as

select	Code as EnterpriseUID,
		Descn as EnterpriseName,
		OscarAgentPrefix + OscarAgentSerial + OscarAgentSuffix as Oscar,
		case when @StartMonth = @EndMonth
			then cspStart.MonthName 
			else cspStart.MonthName + ' - ' + cspEnd.MonthName
		end as StatementPeriod,
		convert(varchar(10),cspStart.PeriodStartDate,103) as StmtFromDate,
		convert(varchar(10),cspEnd.PeriodEndDate,103) as StmtToDate,
		case when cspEnd.PeriodEndDate < convert(date,getdate()) then 'Paid' else 'Awaiting Payment' end as Status
from	dbo.mstt_Agents
		inner join dbo.msit_CommissionStatementPeriods cspStart on cspStart.Month = @StartMonth
		inner join dbo.msit_CommissionStatementPeriods cspEnd on cspEnd.Month = @EndMonth
where	Code = @EnterpriseUID


select	SellerName         = SellerName,
		Provider           = Provider,
		PaidDate           = case when BACSDate = '1901-01-01' or BACSDate >= getdate() then NULL
										else substring(convert(nvarchar(11), BACSDate, 103), 1, 2) + '-' + upper(substring(convert(nvarchar(11), BACSDate), 1, 3)) + '-' + substring(convert(nvarchar(11), BACSDate), 10, 2)
									end,
		ClientName         = Client,
		PolicyNumber       = case when DistributorRef is not null and charindex(' ', DistributorRef) > 0 then Policy + ' : ' + DistributorRef
								else Policy
							 end,
		CaseId             = CaseId,
		ProdType           = ProdType,
		StartDate          = upper(substring(convert(nvarchar(11), StartDate), 1, 3)) + '-' + substring(convert(nvarchar(11), StartDate), 10, 2),
		Freq               = Frequency,
		Premium            = case when Premium = 0 then NULL
								else Premium
							 end,            
		CommRate           = CommRate,
		InitialPeriod      = case when InitialPeriod = 0 then NULL
								   else InitialPeriod
							 end,
		AccruedBase        = isnull(Accrued_Base,0),
		EnhancementRate    = isnull(EnhancementRate,0),
		AccruedEnhd        = isnull(Accrued_Enhd,0),
		TotalPayment       = isnull(TotalPayment,0),
		PayBasis           = PayBasis,
		TotalCommSacrifice = Sacrifice,    
		Split              = case when AgentSplit = 0 then NULL
									else AgentSplit
								end,   
		CommType           = FeeType,					
		Remarks            = Remarks
from	dbo.msit_OpenWorkAdviserListing a
where	BusinessCode = @EnterpriseUID 
and		[Month] <= @EndMonth              
and		[Month] >= @StartMonth              
and		Source in ('Openwork 2005','Openwork 2006')
and		( isnull(TotDue_Base,0.00) <> 0 or
		  isnull(Accrued_Base,0.00) <> 0 or
		  isnull(StillToAccr_Base,0.00) <> 0 or
		  isnull(ITAdvanced_Base,0.00) <> 0 or
		  isnull(TotDue_Enhd,0.00) <> 0 or
		  isnull(Accrued_Enhd,0.00) <> 0 or
		  isnull(StillToAccr_Enhd,0.00) <> 0 or
		  isnull(ITAdvanced_Enhd,0.00) <> 0 or
		  isnull(TotalPayment, 0.0) <> 0 or
		  isnull(APE,0.00) <> 0 or
		  isnull(Elite_Points,0.00) <> 0)
order	by SellerName,
		Provider,
		SchemeNum Desc,
		ClientSurname,
		Client,
		Policy,
		BACSDate,
		PaymentDate


GO
