/*********************************************************************************************************

Name:	owp_Comms_TermStmts_SSISRpt_QuarterlyRenewals
Author:	A Groves
Date:	13/06/2022

Description:	Openwork or ZAN Quarterly Renewals for the automated Terminated Statements process.

				Notes: 
				1) This stored proc is called by SSIS package "TermStmts - PopulateExcel.dtsx".
				2) The parameter @OpenworkInd will be set to "Y" for Openwork and "N" for ZAN.

The proc is called as follows:

exec dbo.owp_Comms_TermStmts_SSISRpt_QuarterlyRenewals '1001734', '2021-01-01', 'Y' 

Amendment History
-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE procedure [dbo].[owp_Comms_TermStmts_SSISRpt_QuarterlyRenewals]
	@EnterpriseUID nvarchar(20),
	@Period datetime,
	@OpenworkInd nvarchar(5)

as

select	Code as EnterpriseUID,
		Descn as EnterpriseName,
		OscarAgentPrefix + OscarAgentSerial + OscarAgentSuffix as Oscar
from	dbo.mstt_Agents
where	Code = @EnterpriseUID


select	rl.SellerName as Seller,
		rl.Client as Client,
		rl.Policy as Policy,
		convert(varchar(10),rl.StartDate,103) as StartDate,
		rl.Frequency as Frequency,
		isnull(rl.Premium,0.0) as Premium,
		isnull(rl.CommRateStd,0.0) as RFRate,
		isnull(rl.Value1*isnull(ai.RC_RIGHTS_M1,1),0.0) as AccruedMth1,
		isnull(rl.Value2*isnull(ai.RC_RIGHTS_M2,1),0.0) as AccruedMth2,
		isnull(rl.Value3*isnull(ai.RC_RIGHTS_M3,1),0.0) as AccruedMth3,
		rl.RemarksString as Remarks
from	dbo.msit_FeesNonSWIFTRenewalListing rl with (index(IX_msit_FeesNonSwiftRenewalListing_SwiftFranchise))  
        left outer join dbo.msit_AgentInfo ai on ai.MAIN_SERIAL = rl.FranchiseSerial  
where	rl.SWIFTFranchise = @EnterpriseUID 
and		isnull(@OpenworkInd,'N') = isnull(OpenworkInd,'N')
and		rl.Month = @Period   
order	by	Seller,
			Client,
			Policy,
			StartDate


GO
