/****************************************************************************
Program:  	    owp_CommShapePanelMismatchtoInsightPanel
Author:	        Mike Cawood
Date Created:	  06/09/2010							
											
Description:	

This procedure compares the Panel marker of Transactions created on SWIFT with the
source OBP or OBP Manual with the Panel flag on Insight for the selling agent as at
the transaction Proposal Date.

It is called as follows:
		exec owp_CommShapePanelMismatchtoInsightPanel '0'

			
Amendment History								
-----------------								
											
Date		    Who		    		Description				
----		    --- 			  	-----------			
28/09/2010  M Cawood      Match on 1st 3 chars of Panel description on Insight as
                          derived by Function.
15/10/2010  M Cawood      Amend Panel derivation on SWIFT Comm Shape to align with
                          codes and descriptions set up on Insight.                          

****************************************************************************/
CREATE PROCEDURE [dbo].[owp_CommShapePanelMismatchtoInsightPanel]
	@Days     int = 0
AS

declare @Yesterday datetime;
set @Yesterday = dateadd(dd,-1,datediff(dd,0,getdate()))

declare @ExtractDate datetime;
set @ExtractDate = (select dbo.owf_CalcDateNWorkingDaysEarlierthanDate(@Yesterday,@Days))

select 
PolicyNumber    = PO.CONT_NUM,
CaseID          = PO.PolicyRef,
Source          = OS.Description,
ProductCode     = PT.CommProductCode,
CommShapeId     = PT.CodeCommissionShapeId,
CommissionShape = CSH.Description,
ProposalDate    = PT.ProposalDate,
CommShapePanel  = isnull(CD2.Code_Description,'Not Set'),   --MPC: 15/10/2010,
InsightPanel    = isnull(PANEL,'Not Set'),
InsightEffFrom  = PANEL.EffFrom,
InsightEffTo    = PANEL.EffTo,
PanelOnInsight  = CASE 
                    WHEN LAST.InsightAgentUID is not null THEN 'Yes' 
                    ELSE 'No'
                  END,
PanelDateMatch  = CASE 
                    WHEN PANEL.InsightAgentUID is not null THEN 'Yes' 
                    ELSE 'No'
                  END,                  
ClientName      = rtrim(ltrim(CL.FirstNames)) + ' ' + rtrim(ltrim(CL.NAME)),
AgentCode       = PT.AgentCode,
AgentName       = rtrim(ltrim(AG.DESCN)),
Enterprise      = CASE 
                    WHEN LEN(AG.FIRM) = 7 THEN AG.FIRM
                  END,
EnterpriseName  = rtrim(ltrim(isnull(AE.TradingName,AE.DESCN)))
from dbo.mstt_PolicyTransactions PT
inner join dbo.mstt_Policies PO 
  on PO.POL_NUM = PT.PolicyId
left join dbo.mstt_Clients CL
  on CL.CLIENT_NUM = PO.CLIENT_NUM
left join dbo.mstt_Agents AG
  on AG.CODE = PT.AgentCode
left join dbo.mstt_Agents AE
  on AE.CODE = CASE WHEN LEN(AG.FIRM) = 7 THEN AG.FIRM END
left join (Select InsightAgentUID, Max(EffFrom) as EffFrom
           from dbo.f_Insight_ListPanelHistoryOfAllSellers()
           Where EffFrom <= @ExtractDate
           Group by InsightAgentUID) LAST
  on PT.AgentCode = LAST.InsightAgentUID 
left join dbo.f_Insight_ListPanelHistoryOfAllSellers() PANEL 
  on PT.AgentCode = PANEL.InsightAgentUID and LAST.EffFrom = PANEL.EffFrom
     and PT.ProposalDate between isnull(PANEL.EffFrom,'1 Jan 1899') and Isnull(PANEL.EffTo,'31 Dec 2999')
left join dbo.sa_swift_CodeCommissionShape CSH 
  on CSH.ID = PT.CodeCommissionShapeId
inner join dbo.sa_swift_CodeOriginatingSources OS
  on OS.ID = PO.OriginatingSource
inner join dbo.sa_insight_CodeType CT2                --MPC: 15/10/2010
    on CT2.CT_CODE = 53 --Section                     --MPC: 15/10/2010
left join dbo.sa_insight_CodeDescription CD2          --MPC: 15/10/2010
    on CD2.Code_CodeType = CT2.CT_CODE  and           --MPC: 15/10/2010
       CASE WHEN Isnumeric(Substring(CD2.Code_Description,1,3)) = 1 THEN Substring(CD2.Code_Description,1,3)      --MPC: 15/10/2010
            ELSE 0                  --MPC: 15/10/2010
       END                          --MPC: 15/10/2010
       = CASE                       --MPC: 15/10/2010
          WHEN Isnumeric(Substring(CSH.Description,1,3)) = 1 and Substring(CSH.Description,1,3) < 250     --MPC: 15/10/2010
          THEN Substring(CSH.Description,1,3)    --MPC: 15/10/2010
          ELSE 0                    --MPC: 15/10/2010
         END                        --MPC: 15/10/2010
where isnull(PT.CodeCommissionShapeId,0) > 0
and OS.Description like '%OBP%'
and PT.CreateDateTime >= @ExtractDate
--and CASE WHEN Isnumeric(Substring(CSH.Description,1,3)) = 1 THEN Substring(CSH.Description,1,3) ELSE 0 END      --MPC: 15/10/2010
--    <> CASE WHEN Isnumeric(Substring(PANEL,1,3)) = 1 THEN Substring(PANEL,1,3) ELSE 0 END                       --MPC: 15/10/2010
and isnull(CD2.Code_Description,'Not Set') <> isnull(PANEL.PANEL,'Not Set')                                       --MPC: 15/10/2010
Order by PO.PolicyRef,PT.CreateDateTime;
GO
