/****************************************************************************
  	 Program:  	owp_CrossTab						
	  Author:	A Harrison
Date created:	18/02/09							
											
Description:	This program enables a crosstab query within SQL.  Used for Recruitment Manager Bonus report

				This proc would be called as follows:

	exec owp_CrossTab
		'SELECT FieldName, FieldName2 FROM [tablename] ', 
		'[FieldName(ColumnHeading)]', 
		'Sum(FieldName2)[]',
		'FieldName2'

OR (following example untested!!):

	exec owp_CrossTab
		'SELECT FieldName, FieldName2 FieldName3FROM [tablename] ', 
		'[FieldName(ColumnHeading)]', 
		'Sum(FieldName2 ELSE 0)[FieldName2], MAX(FieldName3 ELSE 0)[FieldName3]',
		'FieldName2'


	Amendment History								
	-----------------								
											
	Date		Who			Description				
	----		---			-----------			
	
****************************************************************************/

/****************************************************************************
DESCRIPTION OF PARAMETERS:

* Select - SQL statement/table querying, ie. any valid SELECT statement with 
JOINS, WHERE clauses, TOP, etc; anything you can cut/paste into query analyser.
* PivotCol - column (valid expression) you wish to pivot on.
* Summaries - Summaries of column/multiple columns as required.
* GroupBy - list of non-pivot columns you wish to group by and return, 
separated by commas
* OtherCols(optional) - Any other columns to return that you're not grouping
by, also separated by commas.  Don't include references to columns not being 
summarised/grouped
****************************************************************************/



CREATE PROCEDURE [dbo].[owp_CrossTab]	
	(
	@Select		varchar(1000),
	@PivotCol	varchar(100),
	@Summaries	varchar(100),
	@GroupBy	varchar(100),
	@OtherCols	varchar(100),
	@Debug		varchar(1) = 'N'
	)

as

set nocount on
set ansi_warnings off

declare @sql varchar(8000)
declare @Vals	varchar(8000);

set @Vals = '';

Set @OtherCols = isNull(' ' + @OtherCols,'')

--create table #temp  (Pivot varchar(100))

--set @sql = 'select distinct convert(varchar(100),' + @PivotCol + ') as Pivot FROM (' + @Select + ') A'
if @debug = 'Y' PRINT @SQL

insert into #temp
exec (@sql)

--select @Vals = @Vals + ', ' + 
--    replace(replace(@Summaries,'(','(CASE WHEN ' + @PivotCol + '=''' + 
--            Pivot +  ''' THEN '),')[', ' END) as [' + Pivot )

--from #Temp 
--order by Pivot

drop table #Temp

set @Sql = 'select ' + isnull(@GroupBy, '') + @OtherCols + @Vals + 
       ' from (' + @Select + ') A GROUP BY ' + isnull(@GroupBy,'')

if @debug = 'Y' PRINT @SQL

exec (@sql)



set nocount off
set ansi_warnings on


GO
/****** Object:  StoredProcedure [dbo].[owp_DataFixLoadMissingPaymentsIntoOpenAccess]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Program:		owp_DataFixLoadMissingPaymentsIntoOpenAccess						
Author:			Alan Groves
Date created:	04/08/2014							
											
Description
===========

This proc can be used to feed missing Openwork (not OMS) payments into OpenAccess. Note that 
it can only be used for this purpose. It will not fix duplicate payments - so it must not be 
used if duplicates have occurred.

Note that this data fix will:
Add payments into tables:
1) msit_CommissionStatement
2) msit_OpenworkAdviserListing
and commission splits into this table:
1) mstt_Commissions

which will make these payments viewable on the "Openwork Commission Listing" in OpenAccess.

This fix can be run during office hours because it runs in incremental mode which is quick
and no data is removed prior to loading. It is therefore very similar to the non-Swift
Month End load processes which also run during office hours.

To make the "Payments To Bank" show on the OpenAccess "Account Statement" then proc
"msp_OpenworkBankDetailsSwift" must run. However, this proc has never been incrementalised
(because it runs fairly quickly) and the way it works is to delete all the Swift-sourced rows 
on table "msit_OpenworkBankDetails" and reload them from table "msit_CommissionStatement".
This process is too destructive to run during office hours so we must wait for the overnight
batch to do this. After running this data fix, proc "msp_OpenworkBankDetailsSwift" should pick
up the "Payments To Bank" automatically without any further data fixing.

This proc is called as follows:
	declare @rc int
	exec @rc = dbo.owp_DataFixLoadMissingPaymentsIntoOpenAccess
	select @rc
									
Amendment History								
-----------------								

Date		Amended By	Change Details
==========	==========  ==============

*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_DataFixLoadMissingPaymentsIntoOpenAccess]
AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseLog				varchar(50),
			@PhaseError				varchar(50),
			@ProcName				varchar(100),
			@Process				varchar(100),
			@RowCount				int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@Client					varchar(50),
			@Module					Varchar(50)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/


set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @ErrNum				= 0	
set @Client				= 'Openwork'
set @Module				= 'OpenAccess - Data Fix'

-- We want this logging irrespective of whether or not there is a rollback
exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client


/****************************************************************************

	Populate the table																
																		
****************************************************************************/

BEGIN TRY

	BEGIN TRANSACTION
	
	TRUNCATE TABLE owt_TransformationMovements

	-- Find the missing payments for the OpenAccess "Openwork Commission Listing"
	INSERT INTO owt_TransformationMovements
	Select  DISTINCT agm.ID as PKID,
			'sa_swift_S_AGMFIL' as DriverTable,
			getdate() as LoadDate,
			'sa_swift_S_AGENTS (Agent)' as SourceTable,
			'N' as CommissionSplits,
			'Y' as PendingPayments,
			'Y' as CommissionStatement,
			'Y' as AdviserListing
	FROM	sa_swift_S_AGMFIL agm
			inner join sa_swift_S_AGENTS a on a.Code = agm.AGENT_CODE  
			left join mstt_PaymentsPending pp on pp.ID = agm.ID
			left join msit_CommissionStatement cs on cs.PendingPaymentId = agm.ID 
	Where	a.Agt_Type in ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55') 
	and		cs.PendingPaymentId is null


	-- Log the count of missing commission listing payments 	
	select @RowCount = @@rowcount
	set @Process = 'sa_swift_S_AGMFIL. Rowcount = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Process, null, @Module, @Client


	-- Find the missing "Payments To Bank" for the OpenAccess "Openwork Account Statement"
	INSERT INTO owt_TransformationMovements	
	Select  Distinct BAC.ID as PKID,
			'sa_swift_ReportBACSExport' as DriverTable,
			getdate() as LoadDate,
			'sa_swift_ReportBACSExport' as SourceTable,
			'N' as CommissionSplits,
			'N' as PendingPayments,
			'Y' as CommissionStatement,
			'N' as AdviserListing
	from	sa_swift_ReportBACSExport BAC
			left join msit_CommissionStatement cs 
					on  cs.BACSExportId = BAC.ID  
					and cs.ReportingClassCode = '4'
	where	cs.BACSExportId is null

	-- Log the count of missing "Payments To Bank".
	select @RowCount = @@rowcount
	set @Process = 'sa_swift_ReportBACSExport. Rowcount = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Process, null, @Module, @Client


	-- This section must run after ALL the S_AGMFIL movements have been identified.
	-- Log all the IDs that will need to be deleted on msit_OpenworkAdviserListing
	-- while we still know what they are, because as soon as msit_CommissionStatement
	-- is updated, then this information is lost. 
	-- In theory this step should not be needed, but it is a fail-safe in case this
	-- proc is re-run as it will prevent duplicates on table msit_OpenworkAdviserListing 
	INSERT INTO owt_TransformationMovements
	Select DISTINCT CS.ID as PKID,
		'msit_CommissionStatement' as DriverTable,
		getdate() as LoadDate,
		'owt_TransformationMovements' as SourceTable,
		'N' as CommissionSplits,  -- All 'N' as this has special meaning in msp_OpenworkAdviserListingSwift
		'N' as PendingPayments,
		'N' as CommissionStatement,
		'Y' as AdviserListing
	From  owt_TransformationMovements T
		inner join msit_CommissionStatement CS on CS.PendingPaymentID = T.PKID
	where T.DriverTableName = 'sa_swift_S_AGMFIL'
	and   T.AdviserListing = 'Y'

	-- Log the count of adviser listing rows that must be deleted prior to re-load to avoid dupes.
	select @RowCount = @@rowcount
	set @Process = 'msit_CommissionStatement. Rowcount = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Process, null, @Module, @Client


	-- Find the missing commission split data rows. Mark Jayna is main user for SMT reporting
	INSERT INTO owt_TransformationMovements
	Select  Distinct agt.ID,
			'sa_swift_S_AGTCOM' as DriverTable,
			getdate() as LoadDate,
			'sa_swift_S_AGTCOM' as SourceTable,
			'Y' as CommissionSplits,
			'N' as PendingPayments,
			'N' as CommissionStatement,
			'N' as AdviserListing
	from	sa_swift_S_AGTCOM agt
			left join mstt_Commissions com on com.ID = agt.ID
	where	com.ID is null

	-- Log the count commission split data rows 
	select @RowCount = @@rowcount
	set @Process = 'sa_swift_S_AGTCOM. Rowcount = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @Process, null, @Module, @Client


	-- Now call the three procs that are in the batch in incremental mode to drive the data in
	exec dbo.mstp_Commissions 'Openwork', 'PrimaryTransformationSalesComm - Data Fix', 'MOVE'
	exec dbo.mstp_PaymentsPending 'Openwork', 'PrimaryTransformationPart2 - Data Fix', 'MOVE'
	exec dbo.msp_CommissionStatement 'Openwork', 'OpenAccessPart1 - Data Fix', 'MOVE' 
	exec dbo.msp_OpenworkAdviserListingSwift 'Openwork', 'OpenAccessPart2 - Data Fix', 'MOVE' 
	exec dbo.owp_PaymentMarginSplits 'Openwork', 'SecondaryTransformationPart2 - Data Fix', 'MOVE'


	-- Log that this data fix has now completed
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	COMMIT TRANSACTION      

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION	  

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

return @ErrNum



GO
/****** Object:  StoredProcedure [dbo].[owp_editextract_wh]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[owp_editextract_wh] AS

set nocount on

Select 
edh.Statementid as Statement,edc.policynumber as policynumber,edc.policytype as EDIType,
edc.commissiontype as EDICommType,edc.paymenttype as EDIPayType,
edc.PremiumType as EDIPremTyp,edc.PremiumAmount as EDIPremium,
edc.IFAReference as EDIAgentCode,edc.IFAReferenceNumber as EDIRefNo,
edc.AmountReceived as AmountReceived,
case 
when edc.amountreceived < 0 then 'Negative'
when edc.amountreceived >= 0 and edc.amountreceived < 10 then 'Less Than 10'
when edc.amountreceived >= 10 and edc.amountreceived < 100 then 'Less Than 100' 
when edc.amountreceived >= 100 and edc.amountreceived < 500 then 'Less Than 500'
when edc.amountreceived >= 500 and edc.amountreceived < 1000 then 'Less Than 1000'
when edc.amountreceived >= 1000 then 'More Than 1000'
end as ValueBand,
edc.commissionduedate as DueDate,edc.id as EdiID,
edh.datereceived as HeaderRecDate,
edc.commissionreceiveddate as EDIRecDate,
case datepart(mm,edc.commissionreceiveddate)
when 01 then 'JAN'
when 02 then 'FEB'
when 03 then 'MAR'
when 04 then 'APR'
when 05 then 'MAY'
when 06 then 'JUN'
when 07 then 'JUL'
when 08 then 'AUG'
when 09 then 'SEP'
when 10 then 'OCT'
when 11 then 'NOV'
when 12 then 'DEC'
end as EDIRecMonth,
ex.comp_code as Provider,
ex.type as Type,ex.status as Status,ex.amount_due as AmtDue,ex.amount_rec as AmtRec,
ex.unallocatedreasoncode as UnallocReason,ex.transactionid as TxnID,
su.amount as SuspAmt,
e2.type as MatchType,e2.status as MatchStatus,e2.amount_due as MatchDue,e2.amount_rec as MatchRec,
e2.transactionid as Matchid
--,*

from msit_edifactcommissionstatementcontents edc
left outer join msit_edifactcommissionstatementheader edh on edh.id = edc.statementheaderid
--inner join msit_s_stmtct st on st.statement = edh.statementid
left outer join msit_s_pacc ex on ex.id = edc.pacc_id
left outer join msit_s_paccsu su on su.susp_id = ex.id
left outer join msit_s_pacc e2 on e2.id = su.init_id

--where su.susp_id is null and ex.transactionid <> 0 and ex.type in (5,6)

order by edc.id,edh.statementid,edc.pacc_id

GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_AccessBusiness_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_AccessBusiness_History						
	  Author:	A Groves
Date created:	19/03/2018

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_AccessBusiness from the staging table. 
				
				This proc is part of the 2018/Q1 sweep up to put the straggler scans into Logi
				with the end game being to decomm all the old-style scans in favour of the 
				Finance Logi app. This table replaces Finstat0038.
				
				It is called as follows:

				exec dbo.owp_Finance_AccessBusiness_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_AccessBusiness_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(15,2),
		@SmallNegativeNumber		decimal(8,2),
		@FinancialPeriodEndDate		date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -999999999.00
set @SmallNegativeNumber		= -99999.00
set @FinancialPeriodEndDate		= dateadd(month, datediff(month, 0, getdate())-1, 0) - 1
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert expectation changes to the Finance Expectation table.

	****************************************************************************/

	insert into dbo.owt_Finance_AccessBusiness
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		BusinessCode,
		AgentType,
		SubTotal,
		Description,
		ReportType,
		ProdType,
		ProductGroupName,
		PayBasis,
		FeeType,
		Frequency,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,
			stag.BusinessCode,
			stag.AgentType,
			stag.SubTotal,
			stag.Description,
			stag.ReportType,
			stag.ProdType,
			stag.ProductGroupName,
			stag.PayBasis,
			stag.FeeType,
			stag.Frequency,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	dbo.sa_Finance_AccessBusiness stag				--Select from the staging table
			left join dbo.owt_Finance_AccessBusiness hist	--Check if the row is already known
					on  hist.BusinessCode = stag.BusinessCode
					and hist.Description = stag.Description
					and hist.ReportType = stag.ReportType
					and isnull(hist.ProdType,'') = isnull(stag.ProdType,'')
					and isnull(hist.ProductGroupName,'') = isnull(stag.ProductGroupName,'')
					and isnull(hist.PayBasis,'') = isnull(stag.PayBasis,'')
					and isnull(hist.FeeType,'') = isnull(stag.FeeType,'')
					and isnull(hist.Frequency,'') = isnull(stag.Frequency,'')
					and stag.FinancialPeriodFromDate
							between hist.FinancialPeriodFromDate	--This will ensure just one row is joined			
							and hist.FinancialPeriodToDate			--...but not joined if it has previously ended		
	where	hist.BusinessCode is null								--There's no existing row for this item so add it
	or		isnull(stag.AgentType,0) <> isnull(hist.AgentType,0)
	or		isnull(stag.SubTotal,@LargeNegativeNumber) <> isnull(hist.SubTotal,@LargeNegativeNumber)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
										then @FinancialPeriodEndDate								-- Then close it with the last day of last month
										else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,					-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated	-- Update the audit info
	from	dbo.owt_Finance_AccessBusiness old
			inner join dbo.owt_Finance_AccessBusiness new 
							on  new.BusinessCode = old.BusinessCode
							and new.Description = old.Description
							and new.ReportType = old.ReportType
							and isnull(new.ProdType,'') = isnull(old.ProdType,'')
							and isnull(new.ProductGroupName,'') = isnull(old.ProductGroupName,'')
							and isnull(new.PayBasis,'') = isnull(old.PayBasis,'')
							and isnull(new.FeeType,'') = isnull(old.FeeType,'')
							and isnull(new.Frequency,'') = isnull(old.Frequency,'')
							and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
							and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_AccessBusiness new
	where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = @FinancialPeriodEndDate,	-- Not present this month so close off as at the end of last month
			DateLastUpdated = @DateLastUpdated					-- Update the audit info
	from	dbo.owt_Finance_AccessBusiness hist
			left join dbo.sa_Finance_AccessBusiness stag 
						on  stag.BusinessCode = hist.BusinessCode
						and stag.Description = hist.Description
						and stag.ReportType = hist.ReportType
						and isnull(stag.ProdType,'') = isnull(hist.ProdType,'')
						and isnull(stag.ProductGroupName,'') = isnull(hist.ProductGroupName,'')
						and isnull(stag.PayBasis,'') = isnull(hist.PayBasis,'')
						and isnull(stag.FeeType,'') = isnull(hist.FeeType,'')
						and isnull(stag.Frequency,'') = isnull(hist.Frequency,'')						
	where	hist.FinancialPeriodToDate = @FinancialPeriodToDate	-- Active row - this excludes any rows already de-activated
	and		stag.BusinessCode is null
	
	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_AccessBusiness_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_AccessBusiness_Staging						
	  Author:	A Groves
Date created:	15/03/2018

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_AccessBusiness. This is the staging table
				for table dbo.owt_Finance_AccessBusiness which is populated by another stored proc.
				
				This proc is part of the 2018/Q1 sweep up to put the straggler scans into Logi
				with the end game being to decomm all the old-style scans in favour of the 
				Finance Logi app. This table replaces Finstat0038a.

				Notes:
				
				(1)	OAL - Openwork Access Ltd
					AFML - Zurich Access Franchise Mgtmt Ltd 
					
				(2) Jacinta Magee asked for the new Finstat38 to ignore AFML business as this was 
					no longer of interest to the Finance Team
				
				(2)	Pat Thompson advised on 19/03/2018 that the mstt_Agents.MCVDate was set to the 
					year in which the enterprise joined Zurich. To determine whether an enterprise 
					is OAL or AFML, this proc must check the MCV Indicator is set to 3 (MCV taken) 
					and the msttAgents.MCVStatusDate must be 01-June-2005 or later. However, for 
					Access agents, the mstt_Agents.MCVDate is checked.
				
				(3)	The numbers don't exactly reconcile to the old Finstat38. Usually this occurs
					where payments for a case span the MCV date. The approach taken here is to 
					assume that the partner received all payments for a case up to the MCV date
					- but not beyond - and it is the beyond MCV payments that this proc pulls. 
					
					See example below:
					
					select	sum(case when CreateDate >= '2010-04-21' then TotalPayment else 0 end) as TotalPaymentSinceMCV, 
							sum(case when CreateDate < '2010-04-21' then TotalPayment else 0 end) as TotalPaymentPriorToMCV
					from msit_OpenworkAdviserListing
					where Source = 'Openwork 2006'
					and BusinessCode = '1001504'
					and ProdType = 'ISA'
					and PayBasis = 'Level'
					and FeeType = 'Trail'
					and Frequency = 'M'
					 
				
				The proc is called as follows:

				exec owp_Finance_AccessBusiness_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_AccessBusiness_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()
      
/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_AccessBusiness
	
	/****************************************************************************
	
		Insert standing order rows to the staging table.

	****************************************************************************/

	insert into sa_Finance_AccessBusiness
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		BusinessCode,
		AgentType,
		SubTotal,
		Description,
		ReportType,
		ProdType,
		ProductGroupName,
		PayBasis,
		FeeType,
		Frequency,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,										-- Must be zero - will be toggled later
			oal.BusinessCode,
			a.AgentType,
			sum(round(oal.TotalPayment,2)) as SubTotal,
			'Commission Accrual' as Description,
			'Agency Period Sales' as ReportType,
			oal.ProdType,
			p.ProductGroupName,
			oal.PayBasis,
			m.Description as FeeType,
			oal.Frequency,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated			
	from	msit_openworkadviserlisting oal
			inner join mstt_Agents a on a.code = oal.BusinessCode
			inner join msit_CommissionStatement cs on cs.id = oal.SourceID
			inner join msit_MIWarehouseCodesAndDescriptions m 
							on	m.code = cs.CommissionType
							and	m.Columnname = 'CommissionType'
			inner join mstt_PolicyTransactions pt on pt.ID = oal.TransactionID
			inner join mstt_ProductHierarchy p on  p.ProductCode =  
							case
								when oal.ProdType = 'MORTGAGE' then 'NBI_MTG'
								when oal.ProdType is null then oal.ProdType
								when oal.ProdType <> 'MORTGAGE' then oal.ProdType
								else oal.ProdType
							end
	where	oal.source = 'Openwork 2006'
	and		((a.AgentType = 46 and CompetentStatus in (1,2)			--Agency period sales			
			and a.MCVDate >= '1 Jun 2005' and oal.CreateDate >= a.MCVDate)
			or
			(a.AgentType in (2,49) and CompetentStatus in (1,2)		--Practice Asset Unwind
			and	a.MCVStatusDate >= '1 Jun 2005'	and	a.MCVIndicator = 3 and oal.CreateDate >= a.MCVStatusDate)) 
--	and		oal.BusinessCode = '1001504'
	group	by oal.BusinessCode,
			a.AgentType,
			oal.ProdType,
			p.ProductGroupName,
			oal.PayBasis,
			m.Description,
			oal.Frequency


	insert into sa_Finance_AccessBusiness
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		BusinessCode,
		AgentType,
		SubTotal,
		Description,
		ReportType,
		ProdType,
		ProductGroupName,
		PayBasis,
		FeeType,
		Frequency,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,										-- Must be zero - will be toggled later
			obd.BusinessCode,
			a.AgentType,		--Equivalent to ReportType
			sum(round(obd.Amount,2)) as SubTotal,
			obd.TransactionType as Description,
			'Agency Period Sales' as ReportType,
			null as ProdType,
			null as ProductGroupName,
			null as PayBasis,
			null as FeeType,
			null as Frequency,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated			
	from	msit_OpenworkBankDetails obd
			inner join mstt_agents a on a.code = obd.BusinessCode
	where	obd.source in ('Openwork 2006')
	and		obd.PaymentType not in ('0','90','99')	
	and		((a.AgentType = 46 and CompetentStatus in (1,2)			--Agency period sales			
			and a.MCVDate >= '1 Jun 2005' and obd.TransactionDate >= a.MCVDate)
			or
			(a.AgentType in (2,49) and CompetentStatus in (1,2)		--Practice Asset Unwind
			and	a.MCVStatusDate >= '1 Jun 2005'	and	a.MCVIndicator = 3 and obd.TransactionDate >= a.MCVStatusDate)) 
--	and		obd.BusinessCode = '1001504'
	group	by obd.BusinessCode,
			a.AgentType,
			obd.TransactionType
			

	insert into sa_Finance_AccessBusiness
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		BusinessCode,
		AgentType,
		SubTotal,
		Description,
		ReportType,
		ProdType,
		ProductGroupName,
		PayBasis,
		FeeType,
		Frequency,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,										-- Must be zero - will be toggled later	
			BusinessCode,
			AgentType,
			Sum(SubTotal)*-1.0 as SubTotal,
			'Closing Balance' as Description,
			ReportType,
			null as ProdType,
			null as ProductGroupName,
			null as PayBasis,
			null as FeeType,
			null as Frequency,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from  sa_Finance_AccessBusiness
	group by BusinessCode, AgentType, ReportType

				
	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
