/************************************************************************************************
  	 Program:  	owp_Finance_AccountBalance_Staging						
	  Author:	A Groves
Date created:	29/11/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_AccountBalance. This is the staging table
				for table dbo.owt_Finance_AccountBalance which is populated by another stored proc.
				
				It is called as follows:

				exec dbo.owp_Finance_AccountBalance_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_AccountBalance_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriod			date,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateInserted				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateInserted				= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_AccountBalance
	
	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	;with CTE_AccountBalance as
	(
		select	sum(case when agmf.CommissionType in (1,4,17,18,10,19) and (agmp.ID is null or agmp.EXPORT_DATE is null) then agmf.amount else 0 end) as InitialCommissionPaid,
				sum(case when agmf.CommissionType in (2,15,16) and (agmp.ID is null or agmp.EXPORT_DATE is null) then agmf.amount else 0 end) as ClawbackPaid,
				sum(case when agmf.CommissionType = 8 and (agmp.ID is null or agmp.EXPORT_DATE is null) then agmf.amount else 0 end) as SOPaymentsPaid,
				sum(case when agmf.CommissionType = 14 and (agmp.ID is null or agmp.EXPORT_DATE is null) then agmf.amount else 0 end) as TTPaymentsPaid,
				sum(case when agmf.CommissionType = 20 and (agmp.ID is null or agmp.EXPORT_DATE is null) then agmf.amount else 0 end) as BonusPaymentsPaid,
				sum(case when agmf.CommissionType in (3,5,6,7,9,11,12,13,21,0) and (agmp.ID is null or agmp.EXPORT_DATE is null) then agmf.amount else 0 end) as OtherPaid,
				sum(case when agmf.CommissionType in (1,4,17,18,10,19) and (agmp.ID is not null or agmp.EXPORT_DATE is not null) then agmf.amount else 0 end) as InitialCommissionPaid2,
				sum(case when agmf.CommissionType in (2,15,16) and (agmp.ID is not null or agmp.EXPORT_DATE is not null)  then agmf.amount else 0 end) as ClawbackPaid2,
				sum(case when agmf.CommissionType = 8 and (agmp.ID is not null or agmp.EXPORT_DATE is not null)  then agmf.amount else 0 end) as SOPaymentsPaid2,
				sum(case when agmf.CommissionType = 14 and (agmp.ID is not null or agmp.EXPORT_DATE is not null)  then agmf.amount else 0 end) as TTPaymentsPaid2,
				sum(case when agmf.CommissionType = 20 and (agmp.ID is not null or agmp.EXPORT_DATE is not null)  then agmf.amount else 0 end) as BonusPaymentsPaid2,
				sum(case when agmf.CommissionType in (3,5,6,7,9,11,12,13,21,0) and (agmp.ID is not null or agmp.EXPORT_DATE is not null) then agmf.amount else 0 end) as OtherPaid2,
				isnull(agmf.Firm, agmf.franchiseagentcode) as BUID
		from	mstt_PaymentsPending agmf
				left join mstt_AgentPayments agmp on agmp.AGMID = agmf.Id
		where	agmf.AGENT_CODE != '1006886'
		group	by isnull(agmf.Firm, agmf.franchiseagentcode)
	)
	insert into dbo.sa_Finance_AccountBalance
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		BusinessCode,
		BusinessName,
		InitialPaid,
		ClawbackPaid,
		SOPaid,
		TTPaid,
		BonusPaid,
		OtherPaid,
		TotalPaid,
		InitialNotPaid,
		ClawbackNotPaid,
		SONotPaid,
		TTNotPaid,
		BonusNotPaid,
		OtherNotPaid,
		TotalToPay,
		DateInserted,
		DateLastUpdated	
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			BUID as BusinessCode,
			agt.DESCN as BusinessName,
			sum(round(InitialCommissionPaid2,2)) as InitialPaid,
			sum(round(ClawbackPaid2,2)) as ClawbackPaid,
			sum(round(SOPaymentsPaid2,2)) as SOPaid,
			sum(round(TTPaymentsPaid2,2)) as TTPaid,
			sum(round(BonusPaymentsPaid2,2)) as BonusPaid,
			sum(round(OtherPaid2,2)) as OtherPaid,
			sum(round(InitialCommissionPaid2+ClawbackPaid2+SOPaymentsPaid2+TTPaymentsPaid2+BonusPaymentsPaid2+OtherPaid2,2)) as TotalPaid,
			sum(round(initialcommissionpaid,2))as InitialNotPaid,
			sum(round(ClawbackPaid,2)) as ClawbackNotPaid,
			sum(round(SOPaymentsPaid,2)) as SONotPaid,
			sum(round(TTPaymentsPaid,2)) as TTNotPaid,
			sum(round(BonusPaymentsPaid,2)) as BonusNotPaid,
			sum(round(OtherPaid,2)) as OtherNotPaid,
			sum(round(InitialCommissionPaid+ClawbackPaid+SOPaymentsPaid+TTPaymentsPaid+BonusPaymentsPaid+OtherPaid,2)) as TotalToPay,
			@DateInserted as DateInserted,
			@DateInserted as DateLastUpdated
	from	CTE_AccountBalance ab
			inner join mstt_Agents agt on agt.CODE = ab.BUID 
	Group	by BUID,agt.DESCN

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_BacsAmounts_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	dbo.owp_Finance_BacsAmounts_1Off
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_BacsAmounts from table
				logi.FinstatReporting13GrossAmtTypeDateByDate the original proof-of-concept table.
				
				It is called as follows:

				exec dbo.owp_Finance_BacsAmounts_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_BacsAmounts_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @FromDate		= '01-JAN-2006'
set @ToDate			= dateadd(dd,0,datediff(dd,0,getdate()));

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,1,'20168','2016-08-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_BacsAmounts
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				Type,
				BacsDate,
				BacsAmount,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					Type,
					BacsDate,
					BacsAmount,
					GrossAmtPayable,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting13GrossAmtTypeDateByDate old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_BacsAmounts
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				Type,
				BacsDate,
				BacsAmount,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.Type,
					old.BacsDate,
					old.BacsAmount,
					old.GrossAmtPayable,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting13GrossAmtTypeDateByDate old
					left join dbo.owt_Finance_BacsAmounts new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Type,-1) = isnull(new.Type,-1)
									and isnull(old.BacsDate,0) = isnull(new.BacsDate,0)
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.Type is null						--There's no existing row for this item so add it
			or		isnull(old.BacsAmount,-999999999) <> isnull(new.BacsAmount,-999999999)
			or		isnull(old.GrossAmtPayable,-999999999) <> isnull(new.GrossAmtPayable,-999999999)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_BacsAmounts old
					inner join dbo.owt_Finance_BacsAmounts new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Type,-1) = isnull(new.Type,-1)
									and isnull(old.BacsDate,0) = isnull(new.BacsDate,0)
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_BacsAmounts new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_BacsAmounts new
					left join logi.FinstatReporting13GrossAmtTypeDateByDate old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Type,-1) = isnull(new.Type,-1)
									and isnull(old.BacsDate,0) = isnull(new.BacsDate,0)
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			--and		new.LatestRowInd = 1	-- Should always be 1 if FinancialPeriodToDate = '9999-12-31'
			and		old.Type is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_BacsAmounts_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_BacsAmounts_History
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_BacsAmounts from staging table 
				dbo.sa_Finance_BacsAmounts which is populated by another stored proc.

				It is called as follows:

				exec dbo.owp_Finance_BacsAmounts_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_BacsAmounts_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_BacsAmounts
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Type,
		BacsDate,
		BacsAmount,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.Type,
			stag.BacsDate,
			stag.BacsAmount,
			stag.GrossAmtPayable,
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_BacsAmounts stag
			left join dbo.owt_Finance_BacsAmounts hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.Type,-1) = isnull(hist.Type,-1)
							and isnull(stag.BacsDate,0) = isnull(hist.BacsDate,0)
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.Type is null						--There's no existing row for this item so add it
	or		isnull(stag.BacsAmount,-999999999) <> isnull(hist.BacsAmount,-999999999)
	or		isnull(stag.GrossAmtPayable,-999999999) <> isnull(hist.GrossAmtPayable,-999999999)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_BacsAmounts old
			inner join dbo.owt_Finance_BacsAmounts new 
							on  isnull(new.Type,-1) = isnull(old.Type,-1)
							and isnull(new.BacsDate,0) = isnull(old.BacsDate,0)
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_BacsAmounts new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_BacsAmounts hist
			left join dbo.sa_Finance_BacsAmounts stag	-- Don't join on a column that can change such as some sort of financial amount!!!	
							on  isnull(stag.Type,-1) = isnull(hist.Type,-1)
							and isnull(stag.BacsDate,0) = isnull(hist.BacsDate,0)
	where	hist.FinancialPeriodToDate = '9999-12-31'	-- Active row - this excludes any rows already de-activated
	and		stag.Type is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

