/****** Object:  StoredProcedure [dbo].[owp_Finance_BacsAmounts_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_BacsAmounts_Staging						
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_BacsAmounts. This is the staging table
				for table dbo.owt_Finance_BacsAmounts which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_BacsAmounts_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
01/10/2016	A Groves	Stripped off the time element on the BacsDate column. The original 
						proof-of-concept table converted it to a text date to resolve the 
						same problem.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_BacsAmounts_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_BacsAmounts
	
	/****************************************************************************
	
		Insert S_PACC (expectation) rows to the staging table.

	****************************************************************************/

	insert into dbo.sa_Finance_BacsAmounts
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Type,
		BacsDate,
		BacsAmount,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate AS FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			agmf.Type,
			--tbeh.CreatedOn as BacsDate,								  AG 01/10/2016
			dateadd(dd,0,datediff(dd,0,tbeh.CreatedOn)) as BacsDate,	--AG 01/10/2016
			round(sum(tbeh.Amount),2) BacsAmount, 
			round(sum(	case isnull(fipa.PaccID,-1) 
							when -1 then null
							else tbeh.Amount 
						end),2) as GrossAmtPayable,      
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from    dbo.sa_swift_TempBACSExportHistory tbeh
			inner join dbo.sa_swift_S_AGMPAY agmp on agmp.ID = tbeh.S_AGMPAY_ID
			inner join dbo.sa_swift_S_AGMFIL agmf on agmp.AGMID = agmf.ID
			left join dbo.owt_Finance_S_PACC fipa 
							on fipa.PaccId = agmf.PACC_ID
							and @FinancialPeriodFromDate 
								between fipa.FinancialPeriodFromDate 
								and fipa.FinancialPeriodToDate
	group	by dateadd(dd,0,datediff(dd,0,tbeh.CreatedOn)), agmf.Type	--AG 01/01/2016

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_BacsPreMay2008_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_BacsPreMay2008_1Off
	  Author:	A Groves
Date created:	03/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_BacsPreMay2008 from table
				logi.FinstatReporting16BacsPreMay2008 the original proof-of-concept table.
				
				It is called as follows:

				exec dbo.owp_Finance_BacsPreMay2008_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_BacsPreMay2008_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit,
		@LargeNegativeNumber		decimal(16,2)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @LargeNegativeNumber	= -999999999.00

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,0,'20168','2016-08-01'
	union all
	select 10,0,1,'20169','2016-09-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_BacsPreMay2008
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				AgentCode,
				DateStarted,
				DateLeaving,
				AgentAmountDueNotAuthorised,
				AgentAmountDueAuthorised,
				NoAgmAmt,
				AgentAmountPaidNotExported,
				AgentAmountPaidExported,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					AgentCode,
					DateStarted,
					DateLeaving,
					AgentAmountDueNotAuthorised,
					AgentAmountDueAuthorised,
					NoAgmAmt,
					AgentAmountPaidNotExported,
					AgentAmountPaidExported,
					GrossAmtPayable,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting16BacsPreMay2008 old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_BacsPreMay2008
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				AgentCode,
				DateStarted,
				DateLeaving,
				AgentAmountDueNotAuthorised,
				AgentAmountDueAuthorised,
				NoAgmAmt,
				AgentAmountPaidNotExported,
				AgentAmountPaidExported,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.AgentCode,
					old.DateStarted,
					old.DateLeaving,
					old.AgentAmountDueNotAuthorised,
					old.AgentAmountDueAuthorised,
					old.NoAgmAmt,
					old.AgentAmountPaidNotExported,
					old.AgentAmountPaidExported,
					old.GrossAmtPayable,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting16BacsPreMay2008 old
					left join dbo.owt_Finance_BacsPreMay2008 new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.AgentCode,'') = isnull(new.AgentCode,'')
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.ID is null						--There's no existing row for this item so add it
			or		isnull(old.AgentAmountDueNotAuthorised,@LargeNegativeNumber) <> isnull(new.AgentAmountDueNotAuthorised,@LargeNegativeNumber)
			or		isnull(old.AgentAmountDueAuthorised,@LargeNegativeNumber) <> isnull(new.AgentAmountDueAuthorised,@LargeNegativeNumber)
			or		isnull(old.NoAgmAmt,@LargeNegativeNumber) <> isnull(new.NoAgmAmt,@LargeNegativeNumber)
			or		isnull(old.AgentAmountPaidNotExported,@LargeNegativeNumber) <> isnull(new.AgentAmountPaidNotExported,@LargeNegativeNumber)
			or		isnull(old.AgentAmountPaidExported,@LargeNegativeNumber) <> isnull(new.AgentAmountPaidExported,@LargeNegativeNumber)
			or		isnull(old.GrossAmtPayable,@LargeNegativeNumber) <> isnull(new.GrossAmtPayable,@LargeNegativeNumber)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_BacsPreMay2008 old
					inner join dbo.owt_Finance_BacsPreMay2008 new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.AgentCode,'') = isnull(new.AgentCode,'')
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_BacsPreMay2008 new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_BacsPreMay2008 new
					left join logi.FinstatReporting16BacsPreMay2008 old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.AgentCode,'') = isnull(new.AgentCode,'')
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			--and		new.LatestRowInd = 1	-- Should always be 1 if FinancialPeriodToDate = '9999-12-31'
			and		old.FinancialPeriod is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_BacsPreMay2008_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_BacsPreMay2008_History
	  Author:	A Groves
Date created:	03/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_BacsPreMay2008 from staging table 
				dbo.sa_Finance_BacsPreMay2008 which is populated by another stored proc.

				It is called as follows:

				exec dbo.owp_Finance_BacsPreMay2008_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_BacsPreMay2008_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2)
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @LargeNegativeNumber	= -999999999.00

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_BacsPreMay2008
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		AgentCode,
		DateStarted,
		DateLeaving,
		AgentAmountDueNotAuthorised,
		AgentAmountDueAuthorised,
		NoAgmAmt,
		AgentAmountPaidNotExported,
		AgentAmountPaidExported,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.AgentCode,
			stag.DateStarted,
			stag.DateLeaving,
			stag.AgentAmountDueNotAuthorised,
			stag.AgentAmountDueAuthorised,
			stag.NoAgmAmt,
			stag.AgentAmountPaidNotExported,
			stag.AgentAmountPaidExported,
			stag.GrossAmtPayable,
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_BacsPreMay2008 stag
			left join dbo.owt_Finance_BacsPreMay2008 hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.AgentCode,'') = isnull(hist.AgentCode,'')
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.ID is null						--There's no existing row for this item so add it
	or		isnull(stag.AgentAmountDueNotAuthorised,@LargeNegativeNumber) <> isnull(hist.AgentAmountDueNotAuthorised,@LargeNegativeNumber)
	or		isnull(stag.AgentAmountDueAuthorised,@LargeNegativeNumber) <> isnull(hist.AgentAmountDueAuthorised,@LargeNegativeNumber)
	or		isnull(stag.NoAgmAmt,@LargeNegativeNumber) <> isnull(hist.NoAgmAmt,@LargeNegativeNumber)
	or		isnull(stag.AgentAmountPaidNotExported,@LargeNegativeNumber) <> isnull(hist.AgentAmountPaidNotExported,@LargeNegativeNumber)
	or		isnull(stag.AgentAmountPaidExported,@LargeNegativeNumber) <> isnull(hist.AgentAmountPaidExported,@LargeNegativeNumber)
	or		isnull(stag.GrossAmtPayable,@LargeNegativeNumber) <> isnull(hist.GrossAmtPayable,@LargeNegativeNumber)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_BacsPreMay2008 old
			inner join dbo.owt_Finance_BacsPreMay2008 new 
							on  isnull(new.AgentCode,'') = isnull(old.AgentCode,'')
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_BacsPreMay2008 new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_BacsPreMay2008 hist
			left join dbo.sa_Finance_BacsPreMay2008 stag	-- Don't join on a column that can change such as some sort of financial amount!!!	
							on isnull(stag.AgentCode,'') = isnull(hist.AgentCode,'')
	where	hist.FinancialPeriodToDate = '9999-12-31'	-- Active row - this excludes any rows already de-activated
	and		stag.ID is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

