****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_BacsPreMay2008
	
	/****************************************************************************
	
		Insert rows into the temp table

	****************************************************************************/

	select 	fipa.AgentCode,
			case agmf.STATUS 
					when 'F' THEN	case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
