										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmf.AMOUNT 
									end 
					else 0 
			end as AgentAmountDueNotAuthorised,
			case agmf.STATUS 
					when 'T' THEN	case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmf.AMOUNT 
									end 
					else 0 
			end as AgentAmountDueAuthorised,
			case ISNULL(agmf.PACC_ID,0) 
					when 0 then case fipa.PayType 
									when 5 then 0
									when 6 then fipa.RecAmt 
									else fipa.RecAmt 
								end 
					else 0 
			end as NoAgmAmt,
			case agmp.EXPORTED 
					when 'F' THEN case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmp.AMOUNT 
									end 
					else 0 
			end as AgentAmountPaidNotExported,
			case agmp.EXPORTED 
					when 'T' THEN case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmp.AMOUNT 
									end 
					else 0 
			end as AgentAmountPaidExported,
			tbeh.Amount as GrossAmtPayable
	into	#S_PACC
	from	dbo.owt_Finance_S_PACC fipa
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = fipa.PaccId	--00:03:05
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID		--00:04:22
			left join dbo.sa_swift_TempBACSExportHistory tbeh on tbeh.S_AGMPAY_ID = agmp.ID --00:05:26
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
	and		tbeh.PaymentCreatedDate is null

	exec msp_ProcessLog @PhaseLog, 'Temp Table Created.', null, @Module, @Client

	/****************************************************************************

			Insert rows into the staging table
																		
	****************************************************************************/

	insert into dbo.sa_Finance_BacsPreMay2008
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		AgentCode,
		DateStarted,
		DateLeaving,
		AgentAmountDueNotAuthorised,
		AgentAmountDueAuthorised,
		NoAgmAmt,
		AgentAmountPaidNotExported,
		AgentAmountPaidExported,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			pac.AgentCode,
			agen.DateStarted,
			agen.DateLeaving,
			sum(pac.AgentAmountDueNotAuthorised) as AgentAmountDueNotAuthorised,
			sum(pac.AgentAmountDueAuthorised) as AgentAmountDueAuthorised,
			sum(pac.NoAgmAmt) as NoAgmAmt,
			sum(pac.AgentAmountPaidNotExported) as AgentAmountPaidNotExported,
			sum(pac.AgentAmountPaidExported) as AgentAmountPaidExported,
			round(sum(pac.GrossAmtPayable),2) as GrossAmtPayable,
			@DateInserted as DateInserted,
			@DateInserted as DateLastUpdated
	from	#S_PACC pac
			inner join dbo.sa_swift_S_AGENTS agen on agen.CODE = pac.AgentCode
	group	by pac.AgentCode, agen.DateStarted, agen.DateLeaving

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

