/****** Object:  StoredProcedure [dbo].[owp_Finance_BacsYearAndType_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_BacsYearAndType_Staging						
	  Author:	A Groves
Date created:	10/10/2016

		Type:	Financial Reporting 2016 - Finstat 29 Bacs Amount by Bacs Year + Commission Type
		
 Description:   This proc populates table dbo.sa_Finance_BacsYearAndType. This is the staging table
				for table dbo.owt_Finance_BacsYearAndType which is populated by another stored proc.
				
				It is called as follows:

				exec dbo.owp_Finance_BacsYearAndType_Staging 'Openwork', 'Finance 2016'
						
				Note:
					BacsAmount			- Includes standing orders
					GrossAmtPayable		- Does not include standing orders

Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
09/08/2022	A Groves	Due to an operational error, the Finance Month End ran on 02/03/2022
						instead of on 01/03/2022. This caused the fortnightly pay run for 
						01/03/2022 to be incorrectly included. To further confound the problem,
						none of the payments to bank were lodged on table 
						"dbo.sa_swift_TempBACSExportHistory" by Swift. This table was identified 
						as a transient table by Sam Campbell and Richard Abbott and therefore 
						should never have been used in the Finstat processing.					
						The Finance Team did not want the transient table removed, they just
						wanted the £3.1m of missing income to be included on the Finance 
						locked down table (dbo.owt_Finance_BacsYearAndType). Given the above
						background, this code was changed to pull in the missing £3.1m from 
						S_AGMPAY, but continues to use the transient table for all other payments.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_BacsYearAndType_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriod			date,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_BacsYearAndType
	
	/****************************************************************************
	
		Insert rows into the staging table

		The second part of the UNION ALL is the data fix introduced on 
		09/08/2022.

	****************************************************************************/

	insert into dbo.sa_Finance_BacsYearAndType
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Type,
		BacsYear,
		BacsAmount,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			merged.Type,
			year(merged.CreatedOn) as BacsYear,
			round(sum(merged.Amount),2) BacsAmount, 
			round(sum(	case isnull(merged.PaccID,-1) 
							when -1 then null
							else merged.Amount 
						end),2) as GrossAmtPayable,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	(
			select	agmf.Type,
					tbeh.CreatedOn as CreatedOn,
					tbeh.Amount as Amount, 
					fipa.PaccID
			from    dbo.sa_swift_TempBACSExportHistory tbeh
					inner join dbo.sa_swift_S_AGMPAY agmp on agmp.ID = tbeh.S_AGMPAY_ID
					inner join dbo.sa_swift_S_AGMFIL agmf on agmp.AGMID   = agmf.ID
					left join dbo.owt_Finance_S_PACC fipa 
									on  fipa.PaccId = agmf.PACC_ID
									and @FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
			union all
			select	agmf.Type,
					agmp.EXPORT_DATE as CreatedOn,
					agmp.AMOUNT as Amount, 
					fipa.PaccID
			from    dbo.sa_swift_S_AGMPAY agmp 
					inner join dbo.sa_swift_S_AGMFIL agmf on agmp.AGMID   = agmf.ID
					left join dbo.owt_Finance_S_PACC fipa 
									on  fipa.PaccId = agmf.PACC_ID
									and @FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
			where	agmp.EXPORTED = 'T' and convert(date,agmp.EXPORT_DATE) = '2022-03-01'
			) merged
	group by year(merged.CreatedOn),merged.Type

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
