/************************************************************************************************
  	 Program:  	owp_Finance_CommExpByAgent_Staging						
	  Author:	A Groves
Date created:	30/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_CommExpByAgent. This is the staging table
				for table dbo.owt_Finance_CommExpByAgent which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_CommExpByAgent_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
22/07/2022	A Groves	Due to an operational error, the Finance Month End ran on 02/03/2022
						instead of on 01/03/2022. This caused the fortnightly pay run for 
						01/03/2022 to be incorrectly included. To further confound the problem,
						none of the payments to bank were lodged on table 
						"dbo.sa_swift_TempBACSExportHistory" by Swift. This table was identified 
						as a transient table by Sam Campbell and Richard Abbott and therefore 
						should never have been used in the Finstat processing.					
						The Finance Team did not want the transient table removed, they just
						wanted the £3.1m of missing income to be included on the Finance 
						locked down table (dbo.owt_Finance_CommExpByAgent). Given the above
						background, this code was changed to pull in the missing £3.1m from 
						S_AGMPAY, but continues to use the transient table for all other payments.
16/01/2023	A Groves	Added new pot code '1012561' (Defined Benefit Transfer Fee).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_CommExpByAgent_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_CommExpByAgent
	
	/****************************************************************************
	
		Insert rows into the temp table

	****************************************************************************/

	--00:09:52	36,624,504
	select 	fipa.AgentCode,
			case agmf.STATUS 
					when 'F' THEN	case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmf.AMOUNT 
									end 
					else 0 
			end as AgentAmountDueNotAuthorised,
			case agmf.STATUS 
					when 'T' THEN	case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmf.AMOUNT 
									end 
					else 0 
			end as AgentAmountDueAuthorised,
			case ISNULL(agmf.PACC_ID,0) 
					when 0 then case fipa.PayType 
									when 5 then 0
									when 6 then fipa.RecAmt 
									else fipa.RecAmt 
								end 
					else 0 
			end as NoAgmAmt,
			case agmp.EXPORTED 
					when 'F' THEN case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmp.AMOUNT 
									end 
					else 0 
			end as AgentAmountPaidNotExported,
			case agmp.EXPORTED 
					when 'T' THEN case agmf.AGENT_CODE 
										when '1011543' then 0
										when '10002' then 0
										when '10004' then 0
										when '10005' then 0
										when '1006124' then 0
										when '1006886' then 0
										when '1011542' then 0
										when '1011587' then 0
										when '1011623' then 0
										when '1011629' then 0
										when '1011630' then 0
										when '1011631' then 0
										when '1011632' then 0
										when '1011633' then 0
										when '1011634' then 0
										when '1011635' then 0
										when '1012045' then 0	--AG 28/06/2019
										when '1012561' then 0	--AG 16/01/2023
										else agmp.AMOUNT 
									end 
					else 0 
			end as AgentAmountPaidExported,
			case when agmp.EXPORTED = 'T' and convert(date,agmp.EXPORT_DATE) = '2022-03-01'		--AG 22/07/2022
				then agmp.AMOUNT 
				else tbeh.Amount
			end as GrossAmtPayable
			--tbeh.Amount as GrossAmtPayable	AG 22/07/2022
	into	#S_PACC
	from	dbo.owt_Finance_S_PACC fipa
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = fipa.PaccId	--00:03:05
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID		--00:04:22
			left join dbo.sa_swift_TempBACSExportHistory tbeh on tbeh.S_AGMPAY_ID = agmp.ID --00:05:26
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate

	exec msp_ProcessLog @PhaseLog, 'Temp Table Created.', null, @Module, @Client

	/****************************************************************************

		Insert rows into the staging table		
																		
	****************************************************************************/

	--00:00:33
	insert into dbo.sa_Finance_CommExpByAgent
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		AgentCode,
		DateStarted,
		DateLeaving,
		AgentAmountDueNotAuthorised,
		AgentAmountDueAuthorised,
		NoAgmAmt,
		AgentAmountPaidNotExported,
		AgentAmountPaidExported,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate AS FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			pac.AgentCode,
			agen.DateStarted,
			agen.DateLeaving,
			sum(pac.AgentAmountDueNotAuthorised) as AgentAmountDueNotAuthorised,
			sum(pac.AgentAmountDueAuthorised) as AgentAmountDueAuthorised,
			sum(pac.NoAgmAmt) as NoAgmAmt,
			sum(pac.AgentAmountPaidNotExported) as AgentAmountPaidNotExported,
			sum(pac.AgentAmountPaidExported) as AgentAmountPaidExported,
			round(sum(pac.GrossAmtPayable),2) as GrossAmtPayable,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	#S_PACC pac
			left join dbo.sa_swift_S_AGENTS agen on agen.CODE = pac.AgentCode
	group	by pac.AgentCode, agen.DateStarted, agen.DateLeaving

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

