CREATE PROCEDURE [dbo].[owp_Finance_MoniesInSuspense_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @FromDate		= '01-JAN-2006'
set @ToDate			= dateadd(dd,0,datediff(dd,0,getdate()));

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,1,'20168','2016-08-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_MoniesInSuspense
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				PayType,
				Statement,
				StatementDate,
				COMP_CODE,
				ProductCode,
				RecAmt,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					PayType,
					Statement,
					StatementDate,
					COMP_CODE,
					ProductCode,
					RecAmt,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting5MoniesInSuspense susp
			where	susp.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_MoniesInSuspense
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				PayType,
				Statement,
				StatementDate,
				COMP_CODE,
				ProductCode,
				RecAmt,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.PayType,
					old.Statement,
					old.StatementDate,
					old.COMP_CODE,
					old.ProductCode,
					old.RecAmt,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting5MoniesInSuspense old
					left join dbo.owt_Finance_MoniesInSuspense new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and isnull(old.StatementDate,0) = isnull(new.StatementDate,0)
									and isnull(old.COMP_CODE,'') = isnull(new.COMP_CODE,'')
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									--and new.LatestRowInd = 1	--This will ensure you join to just one row
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.Statement is null						--There's no existing row for this item so add it
			or		isnull(old.PayType,-1) <> isnull(new.PayType,-1)
			or		isnull(old.Statement,-1) <> isnull(new.Statement,-1)
			or		isnull(old.StatementDate,0) <> isnull(new.StatementDate,0)
			or		isnull(old.COMP_CODE,'') <> isnull(new.COMP_CODE,'')
			or		isnull(old.ProductCode,'') <> isnull(new.ProductCode,'')
			or		isnull(old.RecAmt,-999999999) <> isnull(new.RecAmt,-999999999)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_MoniesInSuspense old
					inner join dbo.owt_Finance_MoniesInSuspense new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and isnull(old.StatementDate,0) = isnull(new.StatementDate,0)
									and isnull(old.COMP_CODE,'') = isnull(new.COMP_CODE,'')
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_MoniesInSuspense new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_MoniesInSuspense new
					left join logi.FinstatReporting5MoniesInSuspense old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and isnull(old.StatementDate,0) = isnull(new.StatementDate,0)
									and isnull(old.COMP_CODE,'') = isnull(new.COMP_CODE,'')
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			--and		new.LatestRowInd = 1	-- Should always be 1 if FinancialPeriodToDate = '9999-12-31'
			and		old.Statement is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_MoniesInSuspense_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_MoniesInSuspense_History						
	  Author:	A Groves
Date created:	20/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_MoniesInSuspense from staging table 
				dbo.sa_Finance_MoniesInSuspense which is populated by another stored proc.

				It is called as follows:

				exec owp_Finance_MoniesInSuspense_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
21/09/2016	A Groves	Correct coding used for last day of previous period.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_MoniesInSuspense_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_MoniesInSuspense
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		PayType,
		Statement,
		StatementDate,
		COMP_CODE,
		ProductCode,
		RecAmt,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.PayType,
			stag.Statement,
			stag.StatementDate,
			stag.COMP_CODE,
			stag.ProductCode,
			stag.RecAmt,
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_MoniesInSuspense stag
			left join dbo.owt_Finance_MoniesInSuspense hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.PayType,-1) = isnull(hist.PayType,-1)
							and isnull(stag.Statement,-1) = isnull(hist.Statement,-1)
							and isnull(stag.StatementDate,0) = isnull(hist.StatementDate,0)
							and isnull(stag.COMP_CODE,'') = isnull(hist.COMP_CODE,'')
							and isnull(stag.ProductCode,'') = isnull(hist.ProductCode,'')
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.Statement is null						--There's no existing row for this item so add it
	or		isnull(stag.PayType,-1) <> isnull(hist.PayType,-1)
	or		isnull(stag.Statement,-1) <> isnull(hist.Statement,-1)
	or		isnull(stag.StatementDate,0) <> isnull(hist.StatementDate,0)
	or		isnull(stag.COMP_CODE,'') <> isnull(hist.COMP_CODE,'')
	or		isnull(stag.ProductCode,'') <> isnull(hist.ProductCode,'')
	or		isnull(stag.RecAmt,-999999999) <> isnull(hist.RecAmt,-999999999)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_MoniesInSuspense old
			inner join dbo.owt_Finance_MoniesInSuspense new 
							on  isnull(new.PayType,-1) = isnull(old.PayType,-1)
							and isnull(new.Statement,-1) = isnull(old.Statement,-1)
							and isnull(new.StatementDate,0) = isnull(old.StatementDate,0)
							and isnull(new.COMP_CODE,'') = isnull(old.COMP_CODE,'')
							and isnull(new.ProductCode,'') = isnull(old.ProductCode,'')
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_MoniesInSuspense new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_MoniesInSuspense hist
			left join dbo.sa_Finance_MoniesInSuspense stag	-- Don't join on a column that can change such as some sort of financial amount!!!	
						on  isnull(hist.PayType,-1) = isnull(stag.PayType,-1)
						and isnull(hist.Statement,-1) = isnull(stag.Statement,-1)
						and isnull(hist.StatementDate,0) = isnull(stag.StatementDate,0)
						and isnull(hist.COMP_CODE,'') = isnull(stag.COMP_CODE,'')
						and isnull(hist.ProductCode,'') = isnull(stag.ProductCode,'')
	where	hist.FinancialPeriodToDate = '9999-12-31'	-- Active row - this excludes any rows already de-activated
	and		stag.Statement is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_MoniesInSuspense_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_MoniesInSuspense_Staging						
	  Author:	A Groves
Date created:	19/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_MoniesInSuspense. This is the staging table
				for table dbo.owt_Finance_MoniesInSuspense which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_MoniesInSuspense_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_MoniesInSuspense_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_MoniesInSuspense
	
	/****************************************************************************
	
		Insert S_PACC (expectation) rows to the staging table.

	****************************************************************************/

	insert into dbo.sa_Finance_MoniesInSuspense
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		PayType,
		Statement,
		StatementDate,
		COMP_CODE,
		ProductCode,
		RecAmt,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate AS FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			fipa.PayType,
			fipa.Statement,
			stmt.STMNT_DATE as StatmentDate,
			stmt.COMP_CODE,
			polm.ProductCode,
			sum(fipa.RecAmt) as RecAmt,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	dbo.owt_Finance_S_PACC fipa
			join dbo.sa_swift_S_PACCUN paccun on paccun.PACC_ID = fipa.PaccId
			left join dbo.sa_swift_S_POLMAI polm   
							on polm.CONT_NUM  = paccun.POLICY
							and polm.POL_NUM = (select MAX(pol_num) 
												from   dbo.sa_swift_S_POLMAI polm1   
												where  polm1.CONT_NUM  = paccun.POLICY) 
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement
			left join [dbo].[mstt_ProductProviders] prpr on prpr.ProductProviderCode = fipa.ProviderCode
	where	Fipa.PayType = 5 
	and		(Fipa.MatchInd = 'N' or fipa.MatchedToType = 5)
	and		Fipa.Init_Id is null
	and		@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
	group	by fipa.Statement,
				stmt.COMP_CODE,
				stmt.STMNT_DATE,
				polm.ProductCode,
				fipa.PayType
	having	ISNULL(sum(fipa.RecAmt),0) <> 0      


	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

