-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_MortgageDetail_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriod			date,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime,
		@FROM_DATE					DATETIME,
		@TO_DATE					DATETIME

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()
SET @FROM_DATE					= '01-JAN-2006'
SET @TO_DATE					= dateadd(dd,0,datediff(dd,0,getdate()))

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_MortgageDetail
	
	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_MortgageDetail
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		PolicyID, 
		CaseId,
		START_DATE,
		InternalProductID,
		PolicyNum,
		PLAN_CODE,
		COMP_CODE,
		ProductCode,
		ProductSubGroupCode,
		ProductSubGroupName,
		DisplayName,
		MortgageCategory,
		amount_rec,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			isnull(potr.PolicyID,-1) as PolicyID,	-- Must be a non-null value for the owt table.
			poli.PolicyID as CaseId,
			polm.START_DATE as SubmissionDate,
			poli.InternalProductID,
			polm.CONT_NUM,
			polm.PLAN_CODE,
			polm.COMP_CODE,
			polm.ProductCode,
			prhi.ProductSubGroupCode,
			prhi.ProductSubGroupName,
			mopr.DisplayName,
			case when (mpsu.MortgageCategoryID = 8866  OR olmpsu.MortgageCategoryId = 8866 ) 
					then 'Buy To Let'
					else 'Residential' 
			end as MortgageCategory,
			sum(pacc.amount_rec *	case pacc.type 
										when 2 then -1 
										when 15 then -1
										when 16 then -1  
										when 17 then -1
										when 19 then -1
										else 1 
									end) as amount_rec,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated		
	from	dbo.sa_swift_S_PACC pacc
			left join dbo.sa_swift_PolicyTransactions potr on pacc.transactionId = potr.Id
			left join dbo.sa_swift_S_POLMAI polm on polm.POL_NUM = potr.PolicyID
			left join dbo.mstt_ProductHierarchy prhi on polm.ProductCode = prhi.ProductCode
			left join dbo.sa_swift_S_PACCSU paccsu on pacc.ID = paccsu.SUSP_ID
			left join dbo.sa_swift_S_PACC pacc_to on pacc_to.ID = paccsu.INIT_ID
			left join dbo.sa_ows_Policies poli on  poli.PolicyID = polm.PolicyRef
			left join Policy.sa_ows_MortgageProductSummary mpsu on mpsu.PolicyID = polm.PolicyRef
			left join PolicyOneLink.sa_ows_MortgageProductSummary olmpsu on olmpsu.PolicyId = polm.PolicyRef
			left join Policy.sa_ows_MortgageProduct mopr on mopr.InternalProductID = poli.InternalProductID
	where	pacc.DATE_RECV between @FROM_DATE and @TO_DATE
	and		pacc.type not in (6)
	and		prhi.ProductSubGroupName = 'Mortgage'
	group	by	potr.PolicyID, 
				polm.START_DATE,
				poli.InternalProductID,
				polm.CONT_NUM,
				polm.PLAN_CODE,
				polm.COMP_CODE,
				polm.ProductCode,
				prhi.ProductSubGroupCode,
				prhi.ProductSubGroupName,
				mopr.DisplayName,
				case when (mpsu.MortgageCategoryID = 8866  OR olmpsu.MortgageCategoryId = 8866 ) 
					then 'Buy To Let'
					else 'Residential' 
				end,
				poli.PolicyID 
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_PotCodes_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	dbo.owp_Finance_PotCodes_1Off						
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_PotCodes from table
				logi.FinstatReporting11PotCodes the original proof-of-concept table.
				
				It is called as follows:

				exec owp_Finance_PotCodes_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_PotCodes_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @FromDate		= '01-JAN-2006'
set @ToDate			= dateadd(dd,0,datediff(dd,0,getdate()));

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,1,'20168','2016-08-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_PotCodes
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				ProviderCode,
				ProductProviderName,
				ProductSubGroupName,
				ProductBasisCode,
				ProductBasisDescr,
				ProductCode,
				PayType,
				CommDescription,
				RecAmt,
				OpenWorkAmountDue1011543,
				OpenWorkAmountDue10002,
				OpenWorkAmountDue10004,
				OpenWorkAmountDue10005,
				OpenWorkAmountDue1006124,
				OpenWorkAmountDue1006886,
				OpenWorkAmountDue1011542,
				OpenWorkAmountDue1011587,
				OpenWorkAmountDue1011623,
				OpenWorkAmountDue1011629,
				OpenWorkAmountDue1011630,
				OpenWorkAmountDue1011631,
				OpenWorkAmountDue1011632,
				OpenWorkAmountDue1011633,
				OpenWorkAmountDue1011634,
				OpenWorkAmountDue1011635,
				DateInserted,
				DateLastUpdated				
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					ProviderCode,
					ProductProviderName,
					ProductSubGroupName,
					ProductBasisCode,
					ProductBasisDescr,
					ProductCode,
					PayType,
					CommDescription,
					RecAmt,
					OpenWorkAmountDue1011543,
					OpenWorkAmountDue10002,
					OpenWorkAmountDue10004,
					OpenWorkAmountDue10005,
					OpenWorkAmountDue1006124,
					OpenWorkAmountDue1006886,
					OpenWorkAmountDue1011542,
					OpenWorkAmountDue1011587,
					OpenWorkAmountDue1011623,
					OpenWorkAmountDue1011629,
					OpenWorkAmountDue1011630,
					OpenWorkAmountDue1011631,
					OpenWorkAmountDue1011632,
					OpenWorkAmountDue1011633,
					OpenWorkAmountDue1011634,
					OpenWorkAmountDue1011635,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting11PotCodes old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_PotCodes
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				ProviderCode,
				ProductProviderName,
				ProductSubGroupName,
				ProductBasisCode,
				ProductBasisDescr,
				ProductCode,
				PayType,
				CommDescription,
				RecAmt,
				OpenWorkAmountDue1011543,
				OpenWorkAmountDue10002,
				OpenWorkAmountDue10004,
				OpenWorkAmountDue10005,
				OpenWorkAmountDue1006124,
				OpenWorkAmountDue1006886,
				OpenWorkAmountDue1011542,
				OpenWorkAmountDue1011587,
				OpenWorkAmountDue1011623,
				OpenWorkAmountDue1011629,
				OpenWorkAmountDue1011630,
				OpenWorkAmountDue1011631,
				OpenWorkAmountDue1011632,
				OpenWorkAmountDue1011633,
				OpenWorkAmountDue1011634,
				OpenWorkAmountDue1011635,
				DateInserted,
				DateLastUpdated				
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.ProviderCode,
					old.ProductProviderName,
					old.ProductSubGroupName,
					old.ProductBasisCode,
					old.ProductBasisDescr,
					old.ProductCode,
					old.PayType,
					old.CommDescription,
					old.RecAmt,
					old.OpenWorkAmountDue1011543,
					old.OpenWorkAmountDue10002,
					old.OpenWorkAmountDue10004,
					old.OpenWorkAmountDue10005,
					old.OpenWorkAmountDue1006124,
					old.OpenWorkAmountDue1006886,
					old.OpenWorkAmountDue1011542,
					old.OpenWorkAmountDue1011587,
					old.OpenWorkAmountDue1011623,
					old.OpenWorkAmountDue1011629,
					old.OpenWorkAmountDue1011630,
					old.OpenWorkAmountDue1011631,
					old.OpenWorkAmountDue1011632,
					old.OpenWorkAmountDue1011633,
					old.OpenWorkAmountDue1011634,
					old.OpenWorkAmountDue1011635,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting11PotCodes old
					left join dbo.owt_Finance_PotCodes new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
									and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
									and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
									and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
									and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.PayType is null						--There's no existing row for this item so add it
			or		isnull(old.RecAmt,-999999999) <> isnull(new.RecAmt,-999999999)
			or		isnull(old.OpenWorkAmountDue1011543,-999999999) <> isnull(new.OpenWorkAmountDue1011543,-999999999)
			or		isnull(old.OpenWorkAmountDue10002,-999999999) <> isnull(new.OpenWorkAmountDue10002,-999999999)
			or		isnull(old.OpenWorkAmountDue10004,-999999999) <> isnull(new.OpenWorkAmountDue10004,-999999999)
			or		isnull(old.OpenWorkAmountDue10005,-999999999) <> isnull(new.OpenWorkAmountDue10005,-999999999)
			or		isnull(old.OpenWorkAmountDue1006124,-999999999) <> isnull(new.OpenWorkAmountDue1006124,-999999999)
			or		isnull(old.OpenWorkAmountDue1006886,-999999999) <> isnull(new.OpenWorkAmountDue1006886,-999999999)
			or		isnull(old.OpenWorkAmountDue1011542,-999999999) <> isnull(new.OpenWorkAmountDue1011542,-999999999)
			or		isnull(old.OpenWorkAmountDue1011587,-999999999) <> isnull(new.OpenWorkAmountDue1011587,-999999999)
			or		isnull(old.OpenWorkAmountDue1011623,-999999999) <> isnull(new.OpenWorkAmountDue1011623,-999999999)
			or		isnull(old.OpenWorkAmountDue1011629,-999999999) <> isnull(new.OpenWorkAmountDue1011629,-999999999)
			or		isnull(old.OpenWorkAmountDue1011630,-999999999) <> isnull(new.OpenWorkAmountDue1011630,-999999999)
			or		isnull(old.OpenWorkAmountDue1011631,-999999999) <> isnull(new.OpenWorkAmountDue1011631,-999999999)
			or		isnull(old.OpenWorkAmountDue1011632,-999999999) <> isnull(new.OpenWorkAmountDue1011632,-999999999)
			or		isnull(old.OpenWorkAmountDue1011633,-999999999) <> isnull(new.OpenWorkAmountDue1011633,-999999999)
			or		isnull(old.OpenWorkAmountDue1011634,-999999999) <> isnull(new.OpenWorkAmountDue1011634,-999999999)
			or		isnull(old.OpenWorkAmountDue1011635,-999999999) <> isnull(new.OpenWorkAmountDue1011635,-999999999)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_PotCodes old
					inner join dbo.owt_Finance_PotCodes new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
									and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
									and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
									and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
									and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_PotCodes new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_PotCodes new
					left join logi.FinstatReporting11PotCodes old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
									and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
									and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
									and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
									and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			and		old.PayType is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_PotCodes_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_PotCodes_History
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_PotCodes from staging table 
				dbo.sa_Finance_PotCodes which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_PotCodes_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).	
16/01/2023	A Groves	1) Added new pot code '1012561' (Defined Benefit Transfer Fee).
						2) Introduced @LargeNegativeNumber to improve code safety.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_PotCodes_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @LargeNegativeNumber	= -999999999.00

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_PotCodes
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		ProviderCode,
		ProductProviderName,
		ProductSubGroupName,
		ProductBasisCode,
		ProductBasisDescr,
		ProductCode,
		PayType,
		CommDescription,
		RecAmt,
		OpenWorkAmountDue1011543,
		OpenWorkAmountDue10002,
		OpenWorkAmountDue10004,
		OpenWorkAmountDue10005,
		OpenWorkAmountDue1006124,
		OpenWorkAmountDue1006886,
		OpenWorkAmountDue1011542,
		OpenWorkAmountDue1011587,
		OpenWorkAmountDue1011623,
		OpenWorkAmountDue1011629,
		OpenWorkAmountDue1011630,
		OpenWorkAmountDue1011631,
		OpenWorkAmountDue1011632,
		OpenWorkAmountDue1011633,
		OpenWorkAmountDue1011634,
		OpenWorkAmountDue1011635,
		OpenWorkAmountDue1012045,	--AG 28/06/2019
		OpenWorkAmountDue1012561,	--AG 16/01/2023
		DateInserted,
		DateLastUpdated	
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.ProviderCode,
			stag.ProductProviderName,
			stag.ProductSubGroupName,
			stag.ProductBasisCode,
			stag.ProductBasisDescr,
			stag.ProductCode,
			stag.PayType,
			stag.CommDescription,
			stag.RecAmt,
			stag.OpenWorkAmountDue1011543,
			stag.OpenWorkAmountDue10002,
			stag.OpenWorkAmountDue10004,
			stag.OpenWorkAmountDue10005,
			stag.OpenWorkAmountDue1006124,
			stag.OpenWorkAmountDue1006886,
			stag.OpenWorkAmountDue1011542,
			stag.OpenWorkAmountDue1011587,
			stag.OpenWorkAmountDue1011623,
			stag.OpenWorkAmountDue1011629,
			stag.OpenWorkAmountDue1011630,
			stag.OpenWorkAmountDue1011631,
			stag.OpenWorkAmountDue1011632,
			stag.OpenWorkAmountDue1011633,
			stag.OpenWorkAmountDue1011634,
			stag.OpenWorkAmountDue1011635,
			stag.OpenWorkAmountDue1012045,	--AG 28/06/2019
			stag.OpenWorkAmountDue1012561,	--AG 16/01/2023
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_PotCodes stag
			left join dbo.owt_Finance_PotCodes hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.ProviderCode,'') = isnull(hist.ProviderCode,'')
							and isnull(stag.ProductProviderName,'') = isnull(hist.ProductProviderName,'')
							and isnull(stag.ProductSubGroupName,'') = isnull(hist.ProductSubGroupName,'')
							and isnull(stag.ProductBasisCode,'') = isnull(hist.ProductBasisCode,'')
							and isnull(stag.ProductBasisDescr,'') = isnull(hist.ProductBasisDescr,'')									
							and isnull(stag.ProductCode,'') = isnull(hist.ProductCode,'')
							and isnull(stag.PayType,-1) = isnull(hist.PayType,-1)
							and isnull(stag.CommDescription,'') = isnull(hist.CommDescription,'')
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.PayType is null						--There's no existing row for this item so add it
	or		isnull(stag.RecAmt,@LargeNegativeNumber) <> isnull(hist.RecAmt,@LargeNegativeNumber)
	or		isnull(stag.OpenWorkAmountDue1011543,@LargeNegativeNumber) <> isnull(hist.OpenWorkAmountDue1011543,@LargeNegativeNumber)
	or		isnull(stag.OpenWorkAmountDue10002,@LargeNegativeNumber) <> isnull(hist.OpenWorkAmountDue10002,@LargeNegativeNumber)
