	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.ProviderCode,
			stag.ProductProviderName,
			stag.ProductSubGroupName,
			stag.ProductBasisCode,
			stag.ProductBasisDescr,
			stag.ProductCode,
			stag.PayType,
			stag.CommDescription,
			stag.RecAmt,
			stag.OpenWorkAmountDue1011543,
			stag.OpenWorkAmountDue10002,
			stag.OpenWorkAmountDue10004,
			stag.OpenWorkAmountDue10005,
			stag.OpenWorkAmountDue1006124,
			stag.OpenWorkAmountDue1006886,
			stag.OpenWorkAmountDue1011542,
			stag.OpenWorkAmountDue1011587,
			stag.OpenWorkAmountDue1011623,
			stag.OpenWorkAmountDue1011629,
			stag.OpenWorkAmountDue1011630,
			stag.OpenWorkAmountDue1011631,
			stag.OpenWorkAmountDue1011632,
			stag.OpenWorkAmountDue1011633,
			stag.OpenWorkAmountDue1011634,
			stag.OpenWorkAmountDue1011635,
			stag.OpenWorkAmountDue1012045,	--AG 28/06/2019
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_PotCodes stag
			left join dbo.owt_Finance_PotCodes hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.ProviderCode,'') = isnull(hist.ProviderCode,'')
							and isnull(stag.ProductProviderName,'') = isnull(hist.ProductProviderName,'')
							and isnull(stag.ProductSubGroupName,'') = isnull(hist.ProductSubGroupName,'')
							and isnull(stag.ProductBasisCode,'') = isnull(hist.ProductBasisCode,'')
							and isnull(stag.ProductBasisDescr,'') = isnull(hist.ProductBasisDescr,'')									
							and isnull(stag.ProductCode,'') = isnull(hist.ProductCode,'')
							and isnull(stag.PayType,-1) = isnull(hist.PayType,-1)
							and isnull(stag.CommDescription,'') = isnull(hist.CommDescription,'')
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.PayType is null						--There's no existing row for this item so add it
	or		isnull(stag.RecAmt,-999999999) <> isnull(hist.RecAmt,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011543,-999999999) <> isnull(hist.OpenWorkAmountDue1011543,-999999999)
	or		isnull(stag.OpenWorkAmountDue10002,-999999999) <> isnull(hist.OpenWorkAmountDue10002,-999999999)
	or		isnull(stag.OpenWorkAmountDue10004,-999999999) <> isnull(hist.OpenWorkAmountDue10004,-999999999)
	or		isnull(stag.OpenWorkAmountDue10005,-999999999) <> isnull(hist.OpenWorkAmountDue10005,-999999999)
	or		isnull(stag.OpenWorkAmountDue1006124,-999999999) <> isnull(hist.OpenWorkAmountDue1006124,-999999999)
	or		isnull(stag.OpenWorkAmountDue1006886,-999999999) <> isnull(hist.OpenWorkAmountDue1006886,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011542,-999999999) <> isnull(hist.OpenWorkAmountDue1011542,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011587,-999999999) <> isnull(hist.OpenWorkAmountDue1011587,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011623,-999999999) <> isnull(hist.OpenWorkAmountDue1011623,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011629,-999999999) <> isnull(hist.OpenWorkAmountDue1011629,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011630,-999999999) <> isnull(hist.OpenWorkAmountDue1011630,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011631,-999999999) <> isnull(hist.OpenWorkAmountDue1011631,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011632,-999999999) <> isnull(hist.OpenWorkAmountDue1011632,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011633,-999999999) <> isnull(hist.OpenWorkAmountDue1011633,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011634,-999999999) <> isnull(hist.OpenWorkAmountDue1011634,-999999999)
	or		isnull(stag.OpenWorkAmountDue1011635,-999999999) <> isnull(hist.OpenWorkAmountDue1011635,-999999999)
	or		isnull(stag.OpenWorkAmountDue1012045,-999999999) <> isnull(hist.OpenWorkAmountDue1012045,-999999999)	--AG 28/06/2019

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of last month
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_PotCodes old
			inner join dbo.owt_Finance_PotCodes new		-- Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
							and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
							and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
							and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
							and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
							and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
							and isnull(old.PayType,-1) = isnull(new.PayType,-1)
							and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update new
		set LatestRowInd = 1
	from	dbo.owt_Finance_PotCodes new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of last month
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_PotCodes hist
			left join dbo.sa_Finance_PotCodes stag	-- Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.ProviderCode,'') = isnull(hist.ProviderCode,'')
							and isnull(stag.ProductProviderName,'') = isnull(hist.ProductProviderName,'')
							and isnull(stag.ProductSubGroupName,'') = isnull(hist.ProductSubGroupName,'')
							and isnull(stag.ProductBasisCode,'') = isnull(hist.ProductBasisCode,'')
							and isnull(stag.ProductBasisDescr,'') = isnull(hist.ProductBasisDescr,'')									
							and isnull(stag.ProductCode,'') = isnull(hist.ProductCode,'')
							and isnull(stag.PayType,-1) = isnull(hist.PayType,-1)
							and isnull(stag.CommDescription,'') = isnull(hist.CommDescription,'')
	where	hist.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
	and		stag.PayType is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_PotCodes_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_PotCodes_Staging				
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_PotCodes. This is the staging table
				for table dbo.owt_Finance_PotCodes which is populated by another stored proc.
				
				NOTE:
				You will notice the SQL has been split up into a number of tiny steps. This was
				needed to aid performance. When the SQL was combined into fewer statements,
				performance was very poor.
				
				It is called as follows:

				exec owp_Finance_PotCodes_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
16/01/2023	A Groves	Added new pot code '1012561' (Defined Benefit Transfer Fee).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_PotCodes_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_PotCodes
	
	/****************************************************************************
	
		Insert rows into temp table 1

	****************************************************************************/

	select	isnull(fipa.ProviderCode,'NullProviderCode') ProviderCode,
			isnull(fipa.ProductSubGroupName,'NullProductSubGroupName') ProductSubGroupName,
			isnull(fipa.ProductBasisCode,'NullProductBasisCode') ProductBasisCode,
			isnull(fipa.ProductBasisDescr,'NullProductBasisDescr') ProductBasisDescr,
			isnull(fipa.ProductCode,'NullProductCode') ProductCode,
			fipa.PayType,
			fipa.RecAmt,
			fipa.PaccId
	into	#Receipts
	from	dbo.owt_Finance_S_PACC fipa 
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
	and		fipa.PayType not in (2,5,15,16)
	
	create index idx_tmp_Receipts
					on #Receipts(	ProviderCode,
									ProductSubGroupName,
									ProductBasisCode,
									ProductBasisDescr,
									ProductCode,
									PayType)
									
	exec msp_ProcessLog @PhaseLog, 'Temp Table 1 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/

	select	ROW_NUMBER() over (order by fipa.ProductCode, fipa.PayType) as ProductBasisKey,
			fipa.ProviderCode,
			fipa.ProductSubGroupName,
			fipa.ProductBasisCode,
			fipa.ProductBasisDescr,
			fipa.ProductCode,
			fipa.PayType,
			sum(fipa.RecAmt) as RecAmt
	into	#Products
	from	#Receipts fipa 
	group	by	fipa.ProviderCode,
				fipa.ProductSubGroupName,
				fipa.ProductBasisCode,
				fipa.ProductBasisDescr,
				fipa.ProductCode,
				fipa.PayType

	create index idx_tmp_Products
					on #Products(	ProviderCode,
									ProductSubGroupName,
									ProductBasisCode,
									ProductBasisDescr,
									ProductCode,
									PayType)

	exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 3

	****************************************************************************/

	select	rec.PayType,
			pr.ProductBasisKey,
			pr.RecAmt,
			agmf.AGENT_CODE as Agmf_AGENT_CODE,
			agmf.AMOUNT as Agmf_AMOUNT,
			agmf.PACC_ID as Agmf_PACC_ID,
			rec.RecAmt as fipa_RecAmt,
			agmp.AMOUNT as Agmp_AMOUNT
	into	#ProductAmounts
	from	#Receipts rec 
			inner join #Products pr 
							on  pr.ProviderCode       = rec.ProviderCode
							and pr.ProductSubGroupName= rec.ProductSubGroupName
							and pr.ProductBasisCode   = rec.ProductBasisCode
							and pr.ProductBasisDescr  = rec.ProductBasisDescr
							and pr.ProductCode        = rec.ProductCode
							and pr.PayType            = rec.PayType
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = rec.PaccId
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID

	exec msp_ProcessLog @PhaseLog, 'Temp Table 3 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 4

	****************************************************************************/

	select	pr.ProductBasisKey,
			case pr.Agmf_AGENT_CODE when '1011543' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011543,
			case pr.Agmf_AGENT_CODE when '10002' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue10002,
			case pr.Agmf_AGENT_CODE when '10004' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue10004,
			case pr.Agmf_AGENT_CODE when '10005' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue10005,
			case pr.Agmf_AGENT_CODE when '1006124' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1006124,
			case pr.Agmf_AGENT_CODE when '1006886' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1006886,
			case pr.Agmf_AGENT_CODE when '1011542' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011542,
			case pr.Agmf_AGENT_CODE when '1011587' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011587,
			case pr.Agmf_AGENT_CODE when '1011623' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011623,
			case pr.Agmf_AGENT_CODE when '1011629' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011629,
			case pr.Agmf_AGENT_CODE when '1011630' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011630,
			case pr.Agmf_AGENT_CODE when '1011631' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011631,
			case pr.Agmf_AGENT_CODE when '1011632' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011632,
			case pr.Agmf_AGENT_CODE when '1011633' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011633,
			case pr.Agmf_AGENT_CODE when '1011634' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011634,
			case pr.Agmf_AGENT_CODE when '1011635' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1011635,
			case pr.Agmf_AGENT_CODE when '1012045' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1012045,	--AG 28/06/2019
			case pr.Agmf_AGENT_CODE when '1012561' then pr.Agmf_AMOUNT else 0 end as OpenWorkAmountDue1012561	--AG 16/01/2023
	into	#ProductAmountSplits
	from	#ProductAmounts pr

	exec msp_ProcessLog @PhaseLog, 'Temp Table 4 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 5

	****************************************************************************/

	select	pr.ProductBasisKey,
			sum(OpenWorkAmountDue1011543) as OpenWorkAmountDue1011543,
			sum(OpenWorkAmountDue10002) as OpenWorkAmountDue10002,
			sum(OpenWorkAmountDue10004) as OpenWorkAmountDue10004,
			sum(OpenWorkAmountDue10005) as OpenWorkAmountDue10005,
			sum(OpenWorkAmountDue1006124) as OpenWorkAmountDue1006124,
			sum(OpenWorkAmountDue1006886) as OpenWorkAmountDue1006886,
			sum(OpenWorkAmountDue1011542) as OpenWorkAmountDue1011542,
			sum(OpenWorkAmountDue1011587) as OpenWorkAmountDue1011587,
			sum(OpenWorkAmountDue1011623) as OpenWorkAmountDue1011623,
			sum(OpenWorkAmountDue1011629) as OpenWorkAmountDue1011629,
			sum(OpenWorkAmountDue1011630) as OpenWorkAmountDue1011630,
			sum(OpenWorkAmountDue1011631) as OpenWorkAmountDue1011631,
			sum(OpenWorkAmountDue1011632) as OpenWorkAmountDue1011632,
			sum(OpenWorkAmountDue1011633) as OpenWorkAmountDue1011633,
			sum(OpenWorkAmountDue1011634) as OpenWorkAmountDue1011634,
			sum(OpenWorkAmountDue1011635) as OpenWorkAmountDue1011635,
			sum(OpenWorkAmountDue1012045) as OpenWorkAmountDue1012045,	--AG 28/06/2019
			sum(OpenWorkAmountDue1012561) as OpenWorkAmountDue1012561	--AG 16/01/2023
	into	#ProductAmountSummary
	from	#ProductAmountSplits pr
	group	by	pr.ProductBasisKey

	exec msp_ProcessLog @PhaseLog, 'Temp Table 5 Created.', null, @Module, @Client
	
	/****************************************************************************
	
		Pull in and index the commission types descriptions

	****************************************************************************/

	select	convert(int,Codes.Code) as CommissionTypeCode,
			codes.Description as CommissionTypeDesc
	into	#CommissionTypes
	from	dbo.msit_MIWarehouseCodesAndDescriptions Codes
	where	Codes.ColumnName = 'CommissionType'

	create clustered index idx_tmp_CommissionTypes on #CommissionTypes(CommissionTypeCode)

	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_PotCodes
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		ProviderCode,
		ProductProviderName,
		ProductSubGroupName,
		ProductBasisCode,
		ProductBasisDescr,
		ProductCode,
		PayType,
		CommDescription,
		RecAmt,
		OpenWorkAmountDue1011543,
		OpenWorkAmountDue10002,
		OpenWorkAmountDue10004,
		OpenWorkAmountDue10005,
		OpenWorkAmountDue1006124,
		OpenWorkAmountDue1006886,
		OpenWorkAmountDue1011542,
		OpenWorkAmountDue1011587,
		OpenWorkAmountDue1011623,
		OpenWorkAmountDue1011629,
		OpenWorkAmountDue1011630,
		OpenWorkAmountDue1011631,
		OpenWorkAmountDue1011632,
		OpenWorkAmountDue1011633,
		OpenWorkAmountDue1011634,
		OpenWorkAmountDue1011635,
		OpenWorkAmountDue1012045,	--AG 28/06/2019
		OpenWorkAmountDue1012561,	--AG 16/01/2023
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate AS FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			p.ProviderCode,
			prpr.ProductProviderName,
			p.ProductSubGroupName,
			p.ProductBasisCode,
			p.ProductBasisDescr,
			p.ProductCode,
			p.PayType,
			ct.CommissionTypeDesc,
			p.RecAmt,
			pr.OpenWorkAmountDue1011543,
			pr.OpenWorkAmountDue10002,
			pr.OpenWorkAmountDue10004,
			pr.OpenWorkAmountDue10005,
			pr.OpenWorkAmountDue1006124,
			pr.OpenWorkAmountDue1006886,
			pr.OpenWorkAmountDue1011542,
			pr.OpenWorkAmountDue1011587,
			pr.OpenWorkAmountDue1011623,
			pr.OpenWorkAmountDue1011629,
			pr.OpenWorkAmountDue1011630,
			pr.OpenWorkAmountDue1011631,
			pr.OpenWorkAmountDue1011632,
			pr.OpenWorkAmountDue1011633,
			pr.OpenWorkAmountDue1011634,
			pr.OpenWorkAmountDue1011635,
			pr.OpenWorkAmountDue1012045,	--AG 28/06/2019
			pr.OpenWorkAmountDue1012561,	--AG 16/01/2023
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	#ProductAmountSummary pr
			inner join #Products p on p.ProductBasisKey = pr.ProductBasisKey
			left join #CommissionTypes ct on ct.CommissionTypeCode = p.PayType
			left join dbo.mstt_ProductProviders prpr on prpr.ProductProviderCode = p.ProviderCode

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_PotCodes_Staging_Backup20190828AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
