/************************************************************************************************
  	 Program:  	owp_Finance_PotCodes_Staging				
	  Author:	A Groves
Date created:	29/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_PotCodes. This is the staging table
				for table dbo.owt_Finance_PotCodes which is populated by another stored proc.
				
				NOTE:
				You will notice the SQL has been split up into a number of tiny steps. This was
				needed to aid performance. When the SQL was combined into fewer statements,
				performance was very poor.
				
				It is called as follows:

				exec owp_Finance_PotCodes_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_PotCodes_Staging_Backup20190828AG] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

