/****** Object:  StoredProcedure [dbo].[owp_Finance_ProductCommMarg_Staging_Backup20230125AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_ProductCommMarg_Staging				
	  Author:	A Groves
Date created:	21/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_ProductCommMarg. This is the staging table
				for table dbo.owt_Finance_ProductCommMarg which is populated by another stored proc.
				
				NOTE:
				You will notice the SQL has been split up into a number of tiny steps. This was
				needed to aid performance. When the SQL was combined into fewer statements,
				performance was very poor.
				
				It is called as follows:

				exec owp_Finance_ProductCommMarg_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_ProductCommMarg_Staging_Backup20230125AG] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_ProductCommMarg
	
	/****************************************************************************
	
		Insert rows into temp table 1

	****************************************************************************/

	select	isnull(fipa.ProviderCode,'NullProviderCode') ProviderCode,
			isnull(fipa.ProductSubGroupName,'NullProductSubGroupName') ProductSubGroupName,
			isnull(fipa.ProductBasisCode,'NullProductBasisCode') ProductBasisCode,
			isnull(fipa.ProductBasisDescr,'NullProductBasisDescr') ProductBasisDescr,
			isnull(fipa.ProductCode,'NullProductCode') ProductCode,
			fipa.PayType,
			fipa.RecAmt,
			fipa.PaccId
	into	#Receipts
	from	dbo.owt_Finance_S_PACC fipa 
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate

	create index idx_tmp_Receipts
					on #Receipts(	ProviderCode,
									ProductSubGroupName,
									ProductBasisCode,
									ProductBasisDescr,
									ProductCode,
									PayType)
									
	exec msp_ProcessLog @PhaseLog, 'Temp Table 1 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/

	select	ROW_NUMBER() over (order by fipa.ProductCode, fipa.PayType) as ProductBasisKey,
			fipa.ProviderCode,
			fipa.ProductSubGroupName,
			fipa.ProductBasisCode,
			fipa.ProductBasisDescr,
			fipa.ProductCode,
			fipa.PayType,
			sum(fipa.RecAmt) as RecAmt
	into	#Products
	from	#Receipts fipa 
	group	by	fipa.ProviderCode,
				fipa.ProductSubGroupName,
				fipa.ProductBasisCode,
				fipa.ProductBasisDescr,
				fipa.ProductCode,
				fipa.PayType

	create index idx_tmp_Products 
					on #Products(	ProviderCode,
									ProductSubGroupName,
									ProductBasisCode,
									ProductBasisDescr,
									ProductCode,
									PayType)

	exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 3

	****************************************************************************/

	select	rec.PayType,
			pr.ProductBasisKey,
			pr.RecAmt,
			agmf.AGENT_CODE as Agmf_AGENT_CODE,
			agmf.AMOUNT as Agmf_AMOUNT,
			agmf.PACC_ID as Agmf_PACC_ID,
			rec.RecAmt as fipa_RecAmt,
			agmp.AMOUNT as Agmp_AMOUNT
	into	#ProductAmounts
	from	#Receipts rec 
			inner join #Products pr 
							on  pr.ProviderCode       = rec.ProviderCode
							and pr.ProductSubGroupName= rec.ProductSubGroupName
							and pr.ProductBasisCode   = rec.ProductBasisCode
							and pr.ProductBasisDescr  = rec.ProductBasisDescr
							and pr.ProductCode        = rec.ProductCode
							and pr.PayType            = rec.PayType
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = rec.PaccId
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID

	exec msp_ProcessLog @PhaseLog, 'Temp Table 3 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 4

	****************************************************************************/

	select	pr.ProductBasisKey,
			pr.RecAmt,
			case pr.Agmf_AGENT_CODE 
						when '1011543' then 0
                        when '10002' then 0
                        when '10004' then 0
                        when '10005' then 0
                        when '1006124' then 0
                        when '1006886' then 0
                        when '1011542' then 0
                        when '1011587' then 0
                        when '1011623' then 0
                        when '1011629' then 0
                        when '1011630' then 0
                        when '1011631' then 0
                        when '1011632' then 0
                        when '1011633' then 0
                        when '1011634' then 0
                        when '1011635' then 0
                        when '1012045' then 0	--AG 28/06/2019
                        else pr.Agmf_AMOUNT 
			end as AgentAmountDue,
			case pr.Agmf_AGENT_CODE 
						when '1011543' then pr.Agmf_AMOUNT
                        when '10002' then pr.Agmf_AMOUNT
                        when '10004' then pr.Agmf_AMOUNT
                        when '10005' then pr.Agmf_AMOUNT
                        when '1006124' then pr.Agmf_AMOUNT
                        when '1006886' then pr.Agmf_AMOUNT
                        when '1011542' then pr.Agmf_AMOUNT
                        when '1011587' then pr.Agmf_AMOUNT
                        when '1011623' then pr.Agmf_AMOUNT
                        when '1011629' then pr.Agmf_AMOUNT
                        when '1011630' then pr.Agmf_AMOUNT
                        when '1011631' then pr.Agmf_AMOUNT
                        when '1011632' then pr.Agmf_AMOUNT
                        when '1011633' then pr.Agmf_AMOUNT
                        when '1011634' then pr.Agmf_AMOUNT
                        when '1011635' then pr.Agmf_AMOUNT
                        when '1012045' then pr.Agmf_AMOUNT	--AG 28/06/2019
                        else 0 
			end as OpenWorkAmountDue,
			case ISNULL(pr.Agmf_PACC_ID,0) 
						when 0 then case pr.PayType 
										when 5 then 0
										when 6 then pr.fipa_RecAmt 
										else pr.fipa_RecAmt 
									end 
								else 0 
			end as NoAgmAmt,       
			case pr.Agmf_AGENT_CODE 
						when '1011543' then 0
                        when '10002' then 0
                        when '10004' then 0
                        when '10005' then 0
                        when '1006124' then 0
                        when '1006886' then 0
                        when '1011542' then 0
                        when '1011587' then 0
                        when '1011623' then 0
                        when '1011629' then 0
                        when '1011630' then 0
                        when '1011631' then 0
                        when '1011632' then 0
                        when '1011633' then 0
                        when '1011634' then 0
                        when '1011635' then 0
                        when '1012045' then 0	--AG 28/06/2019
                        else pr.Agmp_AMOUNT 
			end as AgentAmountPaid,
			case agmf_AGENT_CODE 
						when '1011543' then pr.Agmp_AMOUNT
                        when '10002' then pr.Agmp_AMOUNT
                        when '10004' then pr.Agmp_AMOUNT
                        when '10005' then pr.Agmp_AMOUNT
                        when '1006124' then pr.Agmp_AMOUNT
                        when '1006886' then pr.Agmp_AMOUNT
                        when '1011542' then pr.Agmp_AMOUNT
                        when '1011587' then pr.Agmp_AMOUNT
                        when '1011623' then pr.Agmp_AMOUNT
                        when '1011629' then pr.Agmp_AMOUNT
                        when '1011630' then pr.Agmp_AMOUNT
                        when '1011631' then pr.Agmp_AMOUNT
                        when '1011632' then pr.Agmp_AMOUNT
                        when '1011633' then pr.Agmp_AMOUNT
                        when '1011634' then pr.Agmp_AMOUNT
                        when '1011635' then pr.Agmp_AMOUNT
                        when '1012045' then pr.Agmp_AMOUNT	--AG 28/06/2019
                        else 0 
			end as OpenWorkAmountPaid
	into	#ProductAmountSplits
	from	#ProductAmounts pr

	exec msp_ProcessLog @PhaseLog, 'Temp Table 4 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 5

	****************************************************************************/

	select	pr.ProductBasisKey,
			max(pr.RecAmt) as RecAmt,
			sum(AgentAmountDue) as AgentAmountDue,
			sum(OpenWorkAmountDue) as OpenWorkAmountDue,
			sum(NoAgmAmt) as NoAgmAmt,       
			sum(AgentAmountPaid) as AgentAmountPaid,
			sum(OpenWorkAmountPaid) as OpenWorkAmountPaid
	into	#ProductAmountSummary
	from	#ProductAmountSplits pr
	group	by	pr.ProductBasisKey

	exec msp_ProcessLog @PhaseLog, 'Temp Table 5 Created.', null, @Module, @Client

	/****************************************************************************
	
		Pull in and index the commission types

	****************************************************************************/
	
	select	convert(int,Codes.Code) as CommissionTypeCode,
			codes.Description as CommissionTypeDesc
	into	#CommissionTypes
	from	dbo.msit_MIWarehouseCodesAndDescriptions Codes
	where	Codes.ColumnName = 'CommissionType'

	create clustered index idx_tmp on #CommissionTypes(CommissionTypeCode)
	
	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_ProductCommMarg
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		ProviderCode,
		ProductProviderName,
		ProductSubGroupName,
		ProductBasisCode,
		ProductBasisDescr,
		ProductCode,
		PayType,
		CommDescription,
		RecAmt,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		AgentAmountPaid,
		OpenWorkAmountPaid,
		DateInserted,
		DateLastUpdated		
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			p.ProviderCode,
			prpr.ProductProviderName,
			p.ProductSubGroupName,
			p.ProductBasisCode,
			p.ProductBasisDescr,
			p.ProductCode,
			p.PayType,
			ct.CommissionTypeDesc,
			pr.RecAmt,
			pr.AgentAmountDue,
			pr.OpenWorkAmountDue,
			pr.NoAgmAmt,       
			pr.AgentAmountPaid,
			pr.OpenWorkAmountPaid,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	#ProductAmountSummary pr
			inner join #Products p on p.ProductBasisKey = pr.ProductBasisKey
			left join #CommissionTypes ct on ct.CommissionTypeCode = p.PayType
			left join dbo.mstt_ProductProviders prpr on prpr.ProductProviderCode = p.ProviderCode

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_ProductCommMargClaw_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_ProductCommMargClaw_1Off						
	  Author:	A Groves
Date created:	23/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_ProductCommMargClaw from table
				logi.FinstatReporting9ProductCommMargClaw the original proof-of-concept table.
				
				It is called as follows:

				exec owp_Finance_ProductCommMargClaw_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_ProductCommMargClaw_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @FromDate		= '01-JAN-2006'
set @ToDate			= dateadd(dd,0,datediff(dd,0,getdate()));

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,1,'20168','2016-08-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_ProductCommMargClaw
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				ProviderCode,
				ProductProviderName,
				ProductSubGroupName,
				ProductBasisCode,
				ProductBasisDescr,
				ProductCode,
				PayType,
				CommDescription,
				RecAmt,
				AgentAmountDue,
				OpenWorkAmountDue,
				NoAgmAmt,
				DateInserted,
				DateLastUpdated				
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					ProviderCode,
					ProductProviderName,
					ProductSubGroupName,
					ProductBasisCode,
					ProductBasisDescr,
					ProductCode,
					PayType,
					CommDescription,
					RecAmt,
					AgentAmountDue,
					OpenWorkAmountDue,
					NoAgmAmt,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting9ProductCommMargClaw old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_ProductCommMargClaw
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				ProviderCode,
				ProductProviderName,
				ProductSubGroupName,
				ProductBasisCode,
				ProductBasisDescr,
				ProductCode,
				PayType,
				CommDescription,
				RecAmt,
				AgentAmountDue,
				OpenWorkAmountDue,
				NoAgmAmt,
				DateInserted,
				DateLastUpdated				
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.ProviderCode,
					old.ProductProviderName,
					old.ProductSubGroupName,
					old.ProductBasisCode,
					old.ProductBasisDescr,
					old.ProductCode,
					old.PayType,
					old.CommDescription,
					old.RecAmt,
					old.AgentAmountDue,
					old.OpenWorkAmountDue,
					old.NoAgmAmt,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting8ProductCommMarg old
					left join dbo.owt_Finance_ProductCommMargClaw new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
									and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
									and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
									and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
									and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.PayType is null						--There's no existing row for this item so add it
			or		isnull(old.RecAmt,-999999999) <> isnull(new.RecAmt,-999999999)
			or		isnull(old.AgentAmountDue,-999999999) <> isnull(new.AgentAmountDue,-999999999)
			or		isnull(old.OpenWorkAmountDue,-999999999) <> isnull(new.OpenWorkAmountDue,-999999999)
			or		isnull(old.NoAgmAmt,-999999999) <> isnull(new.NoAgmAmt,-999999999)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_ProductCommMargClaw old
					inner join dbo.owt_Finance_ProductCommMargClaw new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
									and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
									and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
									and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
									and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_ProductCommMargClaw new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_ProductCommMargClaw new
					left join logi.FinstatReporting9ProductCommMargClaw old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
									and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
									and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
									and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
									and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
									and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
									and isnull(old.PayType,-1) = isnull(new.PayType,-1)
									and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			and		old.PayType is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_ProductCommMargClaw_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_ProductCommMargClaw_History					
	  Author:	A Groves
Date created:	23/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_ProductCommMargClaw from staging table 
				dbo.sa_Finance_ProductCommMargClaw which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_ProductCommMargClaw_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_ProductCommMargClaw_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_ProductCommMargClaw
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		ProviderCode,
		ProductProviderName,
		ProductSubGroupName,
		ProductBasisCode,
		ProductBasisDescr,
		ProductCode,
		PayType,
		CommDescription,
		RecAmt,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		DateInserted,
		DateLastUpdated				
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.ProviderCode,
			stag.ProductProviderName,
			stag.ProductSubGroupName,
			stag.ProductBasisCode,
			stag.ProductBasisDescr,
			stag.ProductCode,
			stag.PayType,
			stag.CommDescription,
			stag.RecAmt,
			stag.AgentAmountDue,
			stag.OpenWorkAmountDue,
			stag.NoAgmAmt,
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_ProductCommMargClaw stag
			left join dbo.owt_Finance_ProductCommMargClaw hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.ProviderCode,'') = isnull(hist.ProviderCode,'')
							and isnull(stag.ProductProviderName,'') = isnull(hist.ProductProviderName,'')
							and isnull(stag.ProductSubGroupName,'') = isnull(hist.ProductSubGroupName,'')
							and isnull(stag.ProductBasisCode,'') = isnull(hist.ProductBasisCode,'')
							and isnull(stag.ProductBasisDescr,'') = isnull(hist.ProductBasisDescr,'')									
							and isnull(stag.ProductCode,'') = isnull(hist.ProductCode,'')
							and isnull(stag.PayType,-1) = isnull(hist.PayType,-1)
							and isnull(stag.CommDescription,'') = isnull(hist.CommDescription,'')
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.PayType is null						--There's no existing row for this item so add it
	or		isnull(stag.RecAmt,-999999999) <> isnull(hist.RecAmt,-999999999)
	or		isnull(stag.AgentAmountDue,-999999999) <> isnull(hist.AgentAmountDue,-999999999)
	or		isnull(stag.OpenWorkAmountDue,-999999999) <> isnull(hist.OpenWorkAmountDue,-999999999)
	or		isnull(stag.NoAgmAmt,-999999999) <> isnull(hist.NoAgmAmt,-999999999)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of last month
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_ProductCommMargClaw old
			inner join dbo.owt_Finance_ProductCommMargClaw new		-- Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(old.ProviderCode,'') = isnull(new.ProviderCode,'')
							and isnull(old.ProductProviderName,'') = isnull(new.ProductProviderName,'')
							and isnull(old.ProductSubGroupName,'') = isnull(new.ProductSubGroupName,'')
							and isnull(old.ProductBasisCode,'') = isnull(new.ProductBasisCode,'')
							and isnull(old.ProductBasisDescr,'') = isnull(new.ProductBasisDescr,'')									
							and isnull(old.ProductCode,'') = isnull(new.ProductCode,'')
							and isnull(old.PayType,-1) = isnull(new.PayType,-1)
							and isnull(old.CommDescription,'') = isnull(new.CommDescription,'')
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update new
		set LatestRowInd = 1
	from	dbo.owt_Finance_ProductCommMargClaw new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of last month
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_ProductCommMargClaw hist
			left join dbo.sa_Finance_ProductCommMargClaw stag	-- Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.ProviderCode,'') = isnull(hist.ProviderCode,'')
							and isnull(stag.ProductProviderName,'') = isnull(hist.ProductProviderName,'')
							and isnull(stag.ProductSubGroupName,'') = isnull(hist.ProductSubGroupName,'')
							and isnull(stag.ProductBasisCode,'') = isnull(hist.ProductBasisCode,'')
							and isnull(stag.ProductBasisDescr,'') = isnull(hist.ProductBasisDescr,'')									
							and isnull(stag.ProductCode,'') = isnull(hist.ProductCode,'')
							and isnull(stag.PayType,-1) = isnull(hist.PayType,-1)
							and isnull(stag.CommDescription,'') = isnull(hist.CommDescription,'')
	where	hist.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
	and		stag.PayType is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_ProductCommMargClaw_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_ProductCommMargClaw_Staging				
	  Author:	A Groves
Date created:	21/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_ProductCommMargClaw. This is the staging table
				for table dbo.owt_Finance_ProductCommMargClaw which is populated by another stored proc.
				
				NOTE:
				You will notice the SQL has been split up into a number of tiny steps. This was
				needed to aid performance. When the SQL was combined into fewer statements,
				performance was very poor.
				
				It is called as follows:

				exec owp_Finance_ProductCommMargClaw_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
16/01/2023	A Groves	Added new pot code '1012561' (Defined Benefit Transfer Fee).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_ProductCommMargClaw_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_ProductCommMargClaw
	
	/****************************************************************************
	
		Insert rows into temp table 1

	****************************************************************************/

	select	isnull(fipa.ProviderCode,'NullProviderCode') ProviderCode,
			isnull(fipa.ProductSubGroupName,'NullProductSubGroupName') ProductSubGroupName,
			isnull(fipa.ProductBasisCode,'NullProductBasisCode') ProductBasisCode,
			isnull(fipa.ProductBasisDescr,'NullProductBasisDescr') ProductBasisDescr,
			isnull(fipa.ProductCode,'NullProductCode') ProductCode,
			fipa.PayType,
			fipa.RecAmt,
			fipa.PaccId
	into	#Receipts
	from	dbo.owt_Finance_S_PACC fipa 
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
	and		fipa.PayType in (2,15,16)
	
	exec msp_ProcessLog @PhaseLog, 'Temp Table 1 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/

	select	ROW_NUMBER() over (order by fipa.ProductCode, fipa.PayType) as ProductBasisKey,
			fipa.ProviderCode,
			fipa.ProductSubGroupName,
			fipa.ProductBasisCode,
			fipa.ProductBasisDescr,
			fipa.ProductCode,
			fipa.PayType,
			sum(fipa.RecAmt) as RecAmt
	into	#Products
	from	#Receipts fipa 
	group	by	fipa.ProviderCode,
				fipa.ProductSubGroupName,
				fipa.ProductBasisCode,
				fipa.ProductBasisDescr,
				fipa.ProductCode,
				fipa.PayType

	create index idx_tmp_Finance_ProductCommMargClaw 
					on #Products(	ProviderCode,
									ProductSubGroupName,
									ProductBasisCode,
									ProductBasisDescr,
									ProductCode,
									PayType)

	exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 3

	****************************************************************************/

	select	rec.PayType,
			pr.ProductBasisKey,
			pr.RecAmt,
			agmf.AGENT_CODE as Agmf_AGENT_CODE,
			agmf.AMOUNT as Agmf_AMOUNT,
			agmf.PACC_ID as Agmf_PACC_ID,
			rec.RecAmt as fipa_RecAmt,
			agmp.AMOUNT as Agmp_AMOUNT
	into	#ProductAmounts
	from	#Receipts rec 
			inner join #Products pr 
							on  pr.ProviderCode       = rec.ProviderCode
							and pr.ProductSubGroupName= rec.ProductSubGroupName
							and pr.ProductBasisCode   = rec.ProductBasisCode
							and pr.ProductBasisDescr  = rec.ProductBasisDescr
							and pr.ProductCode        = rec.ProductCode
							and pr.PayType            = rec.PayType
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = rec.PaccId
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID

	exec msp_ProcessLog @PhaseLog, 'Temp Table 3 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 4

	****************************************************************************/

	select	pr.ProductBasisKey,
			pr.RecAmt,
			case pr.Agmf_AGENT_CODE 
						when '1011543' then 0
                        when '10002' then 0
                        when '10004' then 0
                        when '10005' then 0
                        when '1006124' then 0
                        when '1006886' then 0
                        when '1011542' then 0
                        when '1011587' then 0
                        when '1011623' then 0
                        when '1011629' then 0
                        when '1011630' then 0
                        when '1011631' then 0
                        when '1011632' then 0
                        when '1011633' then 0
                        when '1011634' then 0
                        when '1011635' then 0
                        when '1012045' then 0	--AG 28/06/2019
                        when '1012561' then 0	--AG 16/01/2023
                        else pr.Agmf_AMOUNT 
			end as AgentAmountDue,
			case pr.Agmf_AGENT_CODE 
						when '1011543' then pr.Agmf_AMOUNT
                        when '10002' then pr.Agmf_AMOUNT
                        when '10004' then pr.Agmf_AMOUNT
                        when '10005' then pr.Agmf_AMOUNT
                        when '1006124' then pr.Agmf_AMOUNT
                        when '1006886' then pr.Agmf_AMOUNT
                        when '1011542' then pr.Agmf_AMOUNT
                        when '1011587' then pr.Agmf_AMOUNT
                        when '1011623' then pr.Agmf_AMOUNT
                        when '1011629' then pr.Agmf_AMOUNT
                        when '1011630' then pr.Agmf_AMOUNT
                        when '1011631' then pr.Agmf_AMOUNT
                        when '1011632' then pr.Agmf_AMOUNT
                        when '1011633' then pr.Agmf_AMOUNT
                        when '1011634' then pr.Agmf_AMOUNT
                        when '1011635' then pr.Agmf_AMOUNT
                        when '1012045' then pr.Agmf_AMOUNT	--AG 28/06/2019
                        when '1012561' then pr.Agmf_AMOUNT	--AG 16/01/2023
                        else 0 
			end as OpenWorkAmountDue,
			case ISNULL(pr.Agmf_PACC_ID,0) 
						when 0 then case pr.PayType 
										when 5 then 0
										when 6 then pr.fipa_RecAmt 
										else pr.fipa_RecAmt 
									end 
								else 0 
			end as NoAgmAmt
	into	#ProductAmountSplits
	from	#ProductAmounts pr

	exec msp_ProcessLog @PhaseLog, 'Temp Table 4 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 5

	****************************************************************************/

	select	pr.ProductBasisKey,
			max(pr.RecAmt) as RecAmt,
			sum(AgentAmountDue) as AgentAmountDue,
			sum(OpenWorkAmountDue) as OpenWorkAmountDue,
			sum(NoAgmAmt) as NoAgmAmt
	into	#ProductAmountSummary
	from	#ProductAmountSplits pr
	group	by	pr.ProductBasisKey

	exec msp_ProcessLog @PhaseLog, 'Temp Table 5 Created.', null, @Module, @Client

	/****************************************************************************
	
		Pull in and index the commission types

	****************************************************************************/

	select	convert(int,Codes.Code) as CommissionTypeCode,
			codes.Description as CommissionTypeDesc
	into	#CommissionTypes
	from	dbo.msit_MIWarehouseCodesAndDescriptions Codes
	where	Codes.ColumnName = 'CommissionType'

	create clustered index idx_tmp_CommissionTypes on #CommissionTypes(CommissionTypeCode)

	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_ProductCommMargClaw
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		ProviderCode,
		ProductProviderName,
		ProductSubGroupName,
		ProductBasisCode,
		ProductBasisDescr,
		ProductCode,
		PayType,
		CommDescription,
		RecAmt,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		DateInserted,
		DateLastUpdated		
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			p.ProviderCode,
			prpr.ProductProviderName,
			p.ProductSubGroupName,
			p.ProductBasisCode,
			p.ProductBasisDescr,
			p.ProductCode,
			p.PayType,
			ct.CommissionTypeDesc,
			pr.RecAmt,
			pr.AgentAmountDue,
			pr.OpenWorkAmountDue,
			pr.NoAgmAmt,       
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	#ProductAmountSummary pr
			inner join #Products p on p.ProductBasisKey = pr.ProductBasisKey
			left join #CommissionTypes ct on ct.CommissionTypeCode = p.PayType
			left join dbo.mstt_ProductProviders prpr on prpr.ProductProviderCode = p.ProviderCode

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
