/****** Object:  StoredProcedure [dbo].[owp_Finance_S_PACC_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_S_PACC_History						
	  Author:	A Groves
Date created:	15/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_S_PACC from the staging table 
				
				It is called as follows:

				exec dbo.owp_Finance_S_PACC_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
20/09/2016	A Groves	1) Amended initial INSERT to join on dates rather than hist.LatestRowInd = 1
							to ensure no join occurs if the row has previously ended. This will force
							a new row to be created as required for a re-introduction following a 
							period of absence.
						2) Removed fpacc.LatestRowInd = 1 from last UPDATE because this will always
							be true where fpacc.FinancialPeriodToDate = '9999-12-31'.
21/09/2016	A Groves	Correct coding used for last day of previous period.
17/10/2016	A Groves	Used variables rather than date functions to improve performance.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_S_PACC_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2),	--AG 17/10/2016
		@FinancialPeriodEndDate		date,			--AG 17/10/2016
		@FinancialPeriodToDate		date,			--AG 17/10/2016
		@DateLastUpdated			datetime		--AG 17/10/2016

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -999999999.00
set @FinancialPeriodEndDate		= dateadd(month, datediff(month, 0, getdate())-1, 0) - 1
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert expectation changes to the Finance Expectation table.

	****************************************************************************/

	insert into dbo.owt_Finance_S_PACC
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		PaccId,
		AgentCode,
		PayType,
		PolicyID,
		PolicyNum,
		DueAmt,
		RecAmt,
		BacsAmt,
		MinDateRecv,
		MaxDateRecv,
		MatchInd,
		ProductBasisCode,
		ProductBasisDescr,
		CommissionShapeID,
		ProviderCode,
		ProductCode,
		ProductSubGroupCode,
		ProductSubGroupName,
		MatchedToType,
		MatchedToStatement,
		MatchedRecAmt,
		Init_Id,
		DateInserted,
		DateLastUpdated
	)
	select 	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,
			stag.Statement,
			stag.PaccId,
			stag.AgentCode,
			stag.PayType,
			stag.PolicyID,
			stag.PolicyNum,
			stag.DueAmt,
			stag.RecAmt,
			stag.BacsAmt,
			stag.MinDateRecv,
			stag.MaxDateRecv,
			stag.MatchInd,
			stag.ProductBasisCode,
			stag.ProductBasisDescr,
			stag.CommissionShapeID,
			stag.ProviderCode,
			stag.ProductCode,
			stag.ProductSubGroupCode,
			stag.ProductSubGroupName,
			stag.MatchedToType,
			stag.MatchedToStatement,
			stag.MatchedRecAmt,
			stag.Init_Id,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	dbo.sa_Finance_S_PACC stag				--Select from the staging table
			left join dbo.owt_Finance_S_PACC hist	--Check if the row is already known
					on hist.PaccID = stag.PaccID
					--and hist.LatestRowInd = 1		--This ensures only one row will be joined 
					and stag.FinancialPeriodFromDate
							between hist.FinancialPeriodFromDate	--This will ensure just one row is joined			AG 20/09/2016
							and hist.FinancialPeriodToDate			--...but not joined if it has previously ended		AG 20/09/2016
	where	hist.PaccId is null						--There's no existing row for this item so add it
	or		isnull(stag.Statement,-1) <> isnull(hist.Statement,-1)
	or		isnull(stag.AgentCode,'') <> isnull(hist.AgentCode,'')
	or		isnull(stag.PayType,-1) <> isnull(hist.PayType,-1)
	or		isnull(stag.PolicyID,-1) <> isnull(hist.PolicyID,-1)
	or		isnull(stag.PolicyNum,'') <> isnull(hist.PolicyNum,'')
	or		isnull(stag.DueAmt,@LargeNegativeNumber) <> isnull(hist.DueAmt,@LargeNegativeNumber)
	or		isnull(stag.RecAmt,@LargeNegativeNumber) <> isnull(hist.RecAmt,@LargeNegativeNumber)
	or		isnull(stag.BacsAmt,@LargeNegativeNumber) <> isnull(hist.BacsAmt,@LargeNegativeNumber)
	or		isnull(stag.MinDateRecv,0) <> isnull(hist.MinDateRecv,0)
	or		isnull(stag.MaxDateRecv,0) <> isnull(hist.MaxDateRecv,0)
	or		isnull(stag.MatchInd,'') <> isnull(hist.MatchInd,'')
	or		isnull(stag.ProductBasisCode,'') <> isnull(hist.ProductBasisCode,'')
	or		isnull(stag.ProductBasisDescr,'') <> isnull(hist.ProductBasisDescr,'')
	or		isnull(stag.CommissionShapeID,@LargeNegativeNumber) <> isnull(hist.CommissionShapeID,@LargeNegativeNumber)
	or		isnull(stag.ProviderCode,'') <> isnull(hist.ProviderCode,'')
	or		isnull(stag.ProductCode,'') <> isnull(hist.ProductCode,'')
	or		isnull(stag.ProductSubGroupCode,'') <> isnull(hist.ProductSubGroupCode,'')
	or		isnull(stag.ProductSubGroupName,'') <> isnull(hist.ProductSubGroupName,'')
	or		isnull(stag.MatchedToType,@LargeNegativeNumber) <> isnull(hist.MatchedToType,@LargeNegativeNumber)
	or		isnull(stag.MatchedToStatement,@LargeNegativeNumber) <> isnull(hist.MatchedToStatement,@LargeNegativeNumber)
	or		isnull(stag.MatchedRecAmt,@LargeNegativeNumber) <> isnull(hist.MatchedRecAmt,@LargeNegativeNumber)
	or		isnull(stag.Init_Id,@LargeNegativeNumber) <> isnull(hist.Init_Id,@LargeNegativeNumber)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
										then @FinancialPeriodEndDate								-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,					-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated	-- Update the audit info
	from	dbo.owt_Finance_S_PACC old
			inner join dbo.owt_Finance_S_PACC new 
							on new.PaccId = old.PaccId
							and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
							and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_S_PACC new
	where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = @FinancialPeriodEndDate,	-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = @DateLastUpdated					-- Update the audit info
	from	dbo.owt_Finance_S_PACC hist
			left join dbo.sa_Finance_S_PACC stag on stag.PaccID = hist.PaccId
	where	hist.FinancialPeriodToDate = @FinancialPeriodToDate	-- Active row - this excludes any rows already de-activated
	--and		fpacc.LatestRowInd = 1	AG 20/09/2016
	and		stag.PaccId is null
		
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_S_PACC_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_S_PACC_Staging						
	  Author:	A Groves
Date created:	15/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_S_PACC. This is the staging table
				for table dbo.owt_Finance_S_PACC which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_S_PACC_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_S_PACC_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FromDate					= '01-JAN-2006'
set @ToDate						= dateadd(dd,0,datediff(dd,0,getdate()));
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_S_PACC
	
	/****************************************************************************
	
		Insert S_PACC (expectation) rows to the staging table.

	****************************************************************************/

	insert into dbo.sa_Finance_S_PACC
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		PaccId,
		AgentCode,
		PayType,
		PolicyID,
		PolicyNum,
		DueAmt,
		RecAmt,
		BacsAmt,
		MinDateRecv,
		MaxDateRecv,
		MatchInd,
		ProductBasisCode,
		ProductBasisDescr,
		CommissionShapeID,
		ProviderCode,
		ProductCode,
		ProductSubGroupCode,
		ProductSubGroupName,
		MatchedToType,
		MatchedToStatement,
		MatchedRecAmt,
		Init_Id,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			PACC.STATEMENT,
			PACC.ID as PaccId,
			potr.AgentCode,
			pacc.TYPE as PayType,
			potr.PolicyID, 
			polm.CONT_NUM as PolicyNum,
			sum(pacc.amount_due *	case pacc.type 
										when 2  then -1
										when 15 then -1
										when 16 then -1  
										when 17 then -1
										when 19 then -1
										else 1 
									end) as DueAmt, 
			sum(pacc.amount_rec *	case pacc.type 
										when 2  then -1 
										when 15 then -1
										when 16 then -1  
										when 17 then -1
										when 19 then -1
										else 1 
									end) as RecAmt,
			null as BacsAmt,
			min(pacc.DATE_RECV) as MinDateRecv,
			max(pacc.DATE_RECV) as MaxDateRecv,
			case pacc.TYPE 
				when 5 then case ISNULL(paccsu.ID,-1) 
								when -1 then 'N' 
								else 'Y' 
							end 
				else 'Y' 
			end as MatchedInd,
			potr.CommType as ProductBasisCode,
			case potr.CommType 
					when 'L' then 'Level' 
					when 'F' then 'Accrual' 
					when 'T' then 'Indemnity' 
					else 'Unknown' 
			end as ProductBasisDescr,
			potr.CodeCommissionShapeID as CommissionShapeID,
			polm.COMP_CODE as ProviderCode,
			polm.ProductCode,
			prhi.ProductSubGroupCode,
			prhi.ProductSubGroupName,
			pacc_to.TYPE as MatchedToType,
			pacc_to.STATEMENT MatchedToStatement,
			sum(pacc_to.AMOUNT_REC *	case pacc_to.type 
											when 2 then -1 
											when 15 then -1
											when 16 then -1  
											when 17 then -1
											when 19 then -1
											else 1 
										end) as MatchedRecAmt,
			MIN(paccsu.INIT_ID) as Init_Id,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	dbo.sa_swift_S_PACC pacc
			left join dbo.sa_swift_PolicyTransactions potr on pacc.transactionId = potr.Id
			left join dbo.sa_swift_S_POLMAI polm on polm.POL_NUM = potr.PolicyID
			left join dbo.mstt_ProductHierarchy prhi on polm.ProductCode = prhi.ProductCode
			left join dbo.sa_swift_S_PACCSU paccsu on pacc.ID = paccsu.SUSP_ID
			left join dbo.sa_swift_S_PACC pacc_to on pacc_to.ID = paccsu.INIT_ID
	where	pacc.DATE_RECV between @FromDate and @ToDate
	and		pacc.type not in (6)--type !=5
	group	by	potr.PolicyID, 
				potr.AgentCode,
				pacc.Type,
				potr.CodeCommissionShapeID,
				polm.CONT_NUM,
				potr.CommType,
				polm.ProductCode,
				polm.COMP_CODE,
				prhi.ProductSubGroupCode,
				prhi.ProductSubGroupName,
				PACC.STATEMENT,
				paccsu.ID,
				pacc_to.TYPE,
				pacc_to.STATEMENT,
				pacc.ID
		
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_SOBacsDate_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_SOBacsDate_1Off
	  Author:	A Groves
Date created:	04/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_SOBacsDate from table
				logi.FinstatReporting19SOBacsDate the original proof-of-concept table.
				
				It is called as follows:

				exec dbo.owp_Finance_SOBacsDate_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SOBacsDate_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit,
		@LargeNegativeNumber		decimal(16,2),
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,0,'20168','2016-08-01'
	union all
	select 10,0,1,'20169','2016-09-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_SOBacsDate
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				StandingOrderCode,
				BeforeOrAfterBACSTable,
				AgmfAmt,
				AgmpAmtPaid,
				AgmAmount,
				AgmpVatAmt,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					@FinancialPeriodToDate as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					StandingOrderCode,
					BeforeOrAfterBACSTable,
					AgmfAmt,
					AgmpAmtPaid,
					AgmAmount,
					AgmpVatAmt,
					GrossAmtPayable,
					@DateLastUpdated as DateInserted,
					@DateLastUpdated as DateLastUpdated
			from	logi.FinstatReporting19SOBacsDate old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_SOBacsDate
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				StandingOrderCode,
				BeforeOrAfterBACSTable,
				AgmfAmt,
				AgmpAmtPaid,
				AgmAmount,
				AgmpVatAmt,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					@FinancialPeriodToDate as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.StandingOrderCode,
					old.BeforeOrAfterBACSTable,
					old.AgmfAmt,
					old.AgmpAmtPaid,
					old.AgmAmount,
					old.AgmpVatAmt,
					old.GrossAmtPayable,
					@DateLastUpdated as DateInserted,
					@DateLastUpdated as DateLastUpdated
			from	logi.FinstatReporting19SOBacsDate old
					left join dbo.owt_Finance_SOBacsDate new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(new.StandingOrderCode,'') = isnull(old.StandingOrderCode,'')
									and	isnull(new.BeforeOrAfterBACSTable,'') = isnull(old.BeforeOrAfterBACSTable,'')
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.ID is null						--There's no existing row for this item so add it
			or		isnull(new.AgmfAmt,@LargeNegativeNumber) <> isnull(old.AgmfAmt,@LargeNegativeNumber)
			or		isnull(new.AgmpAmtPaid,@LargeNegativeNumber) <> isnull(old.AgmpAmtPaid,@LargeNegativeNumber)
			or		isnull(new.AgmAmount,@LargeNegativeNumber) <> isnull(old.AgmAmount,@LargeNegativeNumber)
			or		isnull(new.AgmpVatAmt,@LargeNegativeNumber) <> isnull(old.AgmpVatAmt,@LargeNegativeNumber)
			or		isnull(new.GrossAmtPayable,@LargeNegativeNumber) <> isnull(old.GrossAmtPayable,@LargeNegativeNumber)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
												then @FinancialPeriodDestination-1							-- Then close it with the last day of last month
												else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,														-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = @DateLastUpdated										-- Update the audit info
			from	dbo.owt_Finance_SOBacsDate old
					inner join dbo.owt_Finance_SOBacsDate new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(new.StandingOrderCode,'') = isnull(old.StandingOrderCode,'')
									and	isnull(new.BeforeOrAfterBACSTable,'') = isnull(old.BeforeOrAfterBACSTable,'')
									and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
									and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_SOBacsDate new
			where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = @DateLastUpdated						-- Update the audit info
			from	dbo.owt_Finance_SOBacsDate new
					left join logi.FinstatReporting19SOBacsDate old			-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(new.StandingOrderCode,'') = isnull(old.StandingOrderCode,'')
									and	isnull(new.BeforeOrAfterBACSTable,'') = isnull(old.BeforeOrAfterBACSTable,'')
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = @FinancialPeriodToDate		-- Active row - this excludes any rows already de-activated
			and		old.FinancialPeriod is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
