/************************************************************************************************
  	 Program:  	owp_Finance_SOBacsDate_History
	  Author:	A Groves
Date created:	04/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_SOBacsDate from staging table 
				dbo.sa_Finance_SOBacsDate which is populated by another stored proc.

				It is called as follows:

				exec dbo.owp_Finance_SOBacsDate_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SOBacsDate_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2),
		@FinancialPeriodFromDate	date,
		@FinancialPeriodEndDate		date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodEndDate		= dateadd(month, datediff(month, 0, getdate())-1, 0) - 1
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_SOBacsDate
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		StandingOrderCode,
		BeforeOrAfterBACSTable,
		AgmfAmt,
		AgmpAmtPaid,
		AgmAmount,
		AgmpVatAmt,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.StandingOrderCode,
			stag.BeforeOrAfterBACSTable,
			stag.AgmfAmt,
			stag.AgmpAmtPaid,
			stag.AgmAmount,
			stag.AgmpVatAmt,
			stag.GrossAmtPayable,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	dbo.sa_Finance_SOBacsDate stag
			left join dbo.owt_Finance_SOBacsDate hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.StandingOrderCode,'') = isnull(hist.StandingOrderCode,'')
							and	isnull(stag.BeforeOrAfterBACSTable,'') = isnull(hist.BeforeOrAfterBACSTable,'')
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.ID is null						--There's no existing row for this item so add it
	or		isnull(stag.AgmfAmt,@LargeNegativeNumber) <> isnull(hist.AgmfAmt,@LargeNegativeNumber)
	or		isnull(stag.AgmpAmtPaid,@LargeNegativeNumber) <> isnull(hist.AgmpAmtPaid,@LargeNegativeNumber)
	or		isnull(stag.AgmAmount,@LargeNegativeNumber) <> isnull(hist.AgmAmount,@LargeNegativeNumber)
	or		isnull(stag.AgmpVatAmt,@LargeNegativeNumber) <> isnull(hist.AgmpVatAmt,@LargeNegativeNumber)
	or		isnull(stag.GrossAmtPayable,@LargeNegativeNumber) <> isnull(hist.GrossAmtPayable,@LargeNegativeNumber)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
										then @FinancialPeriodEndDate								-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																		-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated														-- Update the audit info
	from	dbo.owt_Finance_SOBacsDate old
			inner join dbo.owt_Finance_SOBacsDate new 
							on  isnull(new.StandingOrderCode,'') = isnull(old.StandingOrderCode,'')
							and	isnull(new.BeforeOrAfterBACSTable,'') = isnull(old.BeforeOrAfterBACSTable,'')
							and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
							and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_SOBacsDate new
	where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = @FinancialPeriodEndDate,		-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = @DateLastUpdated						-- Update the audit info
	from	dbo.owt_Finance_SOBacsDate hist
			left join dbo.sa_Finance_SOBacsDate stag				-- Don't join on a column that can change such as some sort of financial amount!!!	
							on  isnull(stag.StandingOrderCode,'') = isnull(hist.StandingOrderCode,'')
							and	isnull(stag.BeforeOrAfterBACSTable,'') = isnull(hist.BeforeOrAfterBACSTable,'')
	where	hist.FinancialPeriodToDate = @FinancialPeriodToDate		-- Active row - this excludes any rows already de-activated
	and		stag.ID is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_SOBacsDate_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_SOBacsDate_Staging						
	  Author:	A Groves
Date created:	04/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_SOBacsDate. This is the staging table
				for table dbo.owt_Finance_SOBacsDate which is populated by another stored proc.
				
				It is called as follows:

				exec dbo.owp_Finance_SOBacsDate_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
28/11/2022	A Groves	Due to an operational error, the Finance Month End ran on 02/03/2022
						instead of on 01/03/2022. This caused the fortnightly pay run for 
						01/03/2022 to be incorrectly included. To further confound the problem,
						none of the payments to bank were lodged on table 
						"dbo.sa_swift_TempBACSExportHistory" by Swift. This table was identified 
						as a transient table by Sam Campbell and Richard Abbott and therefore 
						should never have been used in the Finstat processing.					
						The Finance Team did not want the transient table removed, they just
						wanted the £51K of missing standing order amounts to be included on the 
						Finance locked down table (dbo.owt_Finance_SOBacsDate). Given the above
						background, this code was changed to pull in the missing £51K from 
						S_AGMPAY, but continues to use the transient table for all other
						standing orders.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SOBacsDate_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriod			date,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateInserted				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateInserted				= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_SOBacsDate
	
	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_SOBacsDate
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		StandingOrderCode,
		BeforeOrAfterBACSTable,
		AgmfAmt,
		AgmpAmtPaid,
		AgmAmount,
		AgmpVatAmt,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			agmf.StandingOrderCode,
			case isnull(tbeh.ID,-1) when -1 then 'Before Bacs Table' else 'After Bacs Table' end,
			sum(agmf.AMOUNT) AgmfAmt,
			sum(agmf.AMOUNT_PAID) AgmpAmtPaid,
			sum(agmp.AMOUNT) AgmAmount,
			sum(agmp.VATAmount) AgmpVatAmt,
			--sum(tbeh.Amount) GrossAmtPayable,														  AG 28/11/2022
			sum(case when agmp.EXPORTED = 'T' and convert(date,agmp.EXPORT_DATE) = '2022-03-01'		--AG 28/11/2022
				then agmp.AMOUNT 
				else tbeh.Amount
			end) as GrossAmtPayable,
			@DateInserted as DateInserted,
			@DateInserted as DateLastUpdated
	FROM	dbo.sa_swift_S_AGMFIL agmf
			left join dbo.sa_swift_S_AGMPAY agmp on agmf.ID = agmp.AGMID
			left join dbo.sa_swift_TempBACSExportHistory tbeh on tbeh.S_AGMPAY_ID = agmp.ID   
	where	agmf.TYPE = 8
	group	by	agmf.StandingOrderCode,
				case isnull(tbeh.ID,-1) when -1 then 'Before Bacs Table' else 'After Bacs Table' end
	order	by	agmf.StandingOrderCode
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
