		@LoopCounter				int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	The code below is a 1off and has already run hence it's commeneted out
																		
****************************************************************************/

/* This is here for background info

CREATE TABLE [dbo].[owt_Finance_SOBacsDateNull_1Off](
	[ID] [int] identity(1,1), 
	[FinancialPeriod] [varchar](6) NOT NULL,
	[AgmfID] [int] NULL,
	[StandingOrderCode] [varchar](8) NULL,
	[AgentCode] [varchar](7) NULL,
	[AgentName] [varchar](100) NULL,
	[AgmfAmt] [decimal](16, 2) NULL,
	[AgmpVatAmt] [decimal](16, 2) NULL,
	[DueDate] [datetime] NULL,
