 CONSTRAINT [PK_owt_Finance_SOBacsDateNull_1Off] PRIMARY KEY CLUSTERED 
(
	[ID] ASC
)WITH (PAD_INDEX  = OFF, STATISTICS_NORECOMPUTE  = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS  = ON, ALLOW_PAGE_LOCKS  = ON) ON [FG_DEFAULT]
) ON [FG_DEFAULT]
GO
CREATE NONCLUSTERED INDEX [idx1_Fin_SOBacsDateNull_1Off_FinPer] ON [dbo].[owt_Finance_SOBacsDateNull_1Off] 
(
	[FinancialPeriod] ASC
)WITH (PAD_INDEX  = OFF, STATISTICS_NORECOMPUTE  = OFF, SORT_IN_TEMPDB = OFF, IGNORE_DUP_KEY = OFF, DROP_EXISTING = OFF, ONLINE = OFF, ALLOW_ROW_LOCKS  = ON, ALLOW_PAGE_LOCKS  = ON) ON [FG_DEFAULT]
GO

insert into owt_Finance_SOBacsDateNull_1Off
(
	FinancialPeriod,
	AgmfID,
	StandingOrderCode,
	AgentCode,
	AgentName,
	AgmfAmt,
	AgmpVatAmt,
	DueDate,
	PaymentDueDate,
	GrossAmtPayable
)
select	FinancialPeriod,
		NULL as AgmfID,
		StandingOrderCode,
		AgentCode,
		AgentName,
		AgmfAmt,
		AgmpVatAmt,
		DueDate,
		PaymentDueDate,
		GrossAmtPayable
from	logi.FinstatReporting22SONullBacsDate

*/

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,0,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,0,'20168','2016-08-01'
	union all
	select 10,1,1,'20169','2016-09-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

--		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		Set @RowCount = 1
		set @LoopCounter = 0

		While @RowCount > 0
		Begin

			Update	main
				Set AgmfID = Agmf.MinAgmID
			From	dbo.owt_Finance_SOBacsDateNull_1Off main
					inner join
						(
							Select	AgentCode, StandingOrderCode, PaymentDueDate, AgmfAmt, min(ID) as MinID
							From	dbo.owt_Finance_SOBacsDateNull_1Off
							Where	FinancialPeriod = @FinancialPeriodSource
							and		AgmfID is null
							Group	by AgentCode, StandingOrderCode, PaymentDueDate, AgmfAmt
						) UpdRow
						On UpdRow.AgentCode = main.AgentCode
						And UpdRow.StandingOrderCode = main.StandingOrderCode
						And UpdRow.PaymentDueDate = main.PaymentDueDate
						And UpdRow.AgmfAmt = main.AgmfAmt
						And UpdRow.MinID = main.ID
					inner join
						(
							select	AgentCode, StandingOrderCode, PaymentDueDate, AgmfAmt, min(ID) as MinAgmID
							from
								(
									Select	ag.Agent_Code as AgentCode, ag.StandingOrderCode, ag.PaymentDueDate, convert(decimal(16,2),ag.Amount) as AgmfAmt, ag.ID
									From	sa_swift_S_Agmfil ag
											inner join dbo.sa_swift_S_AGENTS agen on agen.CODE = ag.AGENT_CODE
											left join dbo.sa_swift_S_AGMPAY agmp on ag.ID = agmp.AGMID
											left join dbo.sa_swift_TempBACSExportHistory tbeh 
														on tbeh.S_AGMPAY_ID = agmp.ID 
														and tbeh.CreatedOn < dateadd(mm,1,@FinancialPeriodDestination)
											left join dbo.owt_Finance_SOBacsDateNull_1Off new 
														on  new.AgmfID = ag.ID
														and new.FinancialPeriod = @FinancialPeriodSource
									where	ag.TYPE = 8
									and		ag.CreatedDate < dateadd(mm,1,@FinancialPeriodDestination)
									and		tbeh.ID is null
									and		new.AgmfID is null
								) a
							group by AgentCode, StandingOrderCode, PaymentDueDate, AgmfAmt
						) Agmf
						On Agmf.AgentCode = main.AgentCode
						And Agmf.StandingOrderCode = main.StandingOrderCode
						And Agmf.PaymentDueDate = main.PaymentDueDate
						And Agmf.AgmfAmt = main.AgmfAmt
			Where	main.AgmfID is null
			and		main.FinancialPeriod = @FinancialPeriodSource

			Set @RowCount = @@rowcount

			if @RowCount > 0
			begin
				set @LoopCounter = @LoopCounter + 1
				set @ProcessMessage =  'Loop Counter = ' + convert(varchar(10),@LoopCounter)
				print @ProcessMessage
			end

		End
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

--		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed. Iterations = ' + convert(varchar(20),@LoopCounter)
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
