/************************************************************************************************
  	 Program:  	owp_Finance_SOBacsDateNull_History
	  Author:	A Groves
Date created:	05/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_SOBacsDateNull from staging table 
				dbo.sa_Finance_SOBacsDateNull which is populated by another stored proc.

				It is called as follows:

				exec dbo.owp_Finance_SOBacsDateNull_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SOBacsDateNull_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2),
		@FinancialPeriodFromDate	date,
		@FinancialPeriodEndDate		date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodEndDate		= dateadd(month, datediff(month, 0, getdate())-1, 0) - 1
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_SOBacsDateNull
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		AgmfID,
		StandingOrderCode,
		AgentCode,
		AgentName,
		AgmfAmt,
		AgmpVatAmt,
		DueDate,
		PaymentDueDate,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.AgmfID,
			stag.StandingOrderCode,
			stag.AgentCode,
			stag.AgentName,
			stag.AgmfAmt,
			stag.AgmpVatAmt,
			stag.DueDate,
			stag.PaymentDueDate,
			stag.GrossAmtPayable,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	dbo.sa_Finance_SOBacsDateNull stag
			left join dbo.owt_Finance_SOBacsDateNull hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.AgmfID,-1) = isnull(hist.AgmfID,-1)
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.ID is null						--There's no existing row for this item so add it
	or		isnull(stag.StandingOrderCode,'') <> isnull(hist.StandingOrderCode,'')
	or		isnull(stag.AgentCode,'') <> isnull(hist.AgentCode,'')
	or		isnull(stag.AgentName,'') <> isnull(hist.AgentName,'')
	or		isnull(stag.AgmfAmt,@LargeNegativeNumber) <> isnull(hist.AgmfAmt,@LargeNegativeNumber)
	or		isnull(stag.AgmpVatAmt,@LargeNegativeNumber) <> isnull(hist.AgmpVatAmt,@LargeNegativeNumber)
	or		isnull(stag.DueDate,'') <> isnull(hist.DueDate,'')
	or		isnull(stag.PaymentDueDate,'') <> isnull(hist.PaymentDueDate,'')	
	or		isnull(stag.GrossAmtPayable,@LargeNegativeNumber) <> isnull(hist.GrossAmtPayable,@LargeNegativeNumber)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
										then @FinancialPeriodEndDate								-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																		-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated														-- Update the audit info
	from	dbo.owt_Finance_SOBacsDateNull old
			inner join dbo.owt_Finance_SOBacsDateNull new 
							on  isnull(new.AgmfID,-1) = isnull(old.AgmfID,-1)			
							and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
							and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_SOBacsDateNull new
	where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = @FinancialPeriodEndDate,		-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = @DateLastUpdated						-- Update the audit info
	from	dbo.owt_Finance_SOBacsDateNull hist
			left join dbo.sa_Finance_SOBacsDateNull stag			-- Don't join on a column that can change such as some sort of financial amount!!!	
							on  isnull(stag.AgmfID,-1) = isnull(hist.AgmfID,-1)			
	where	hist.FinancialPeriodToDate = @FinancialPeriodToDate		-- Active row - this excludes any rows already de-activated
	and		stag.ID is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

