  	 Program:  	owp_Finance_SODetail_Staging						
	  Author:	A Groves
Date created:	07/03/2018

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_SODetail. This is the staging table
				for table dbo.owt_Finance_SODetail which is populated by another stored proc.
				
				This proc is part of the 2018/Q1 sweep up to put the straggler scans into Logi
				with the end game being to decomm all the old-style scans in favour of the 
				Finance Logi app. This table replaces Finstat0044b.
				
				It is called as follows:

				exec owp_Finance_SODetail_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SODetail_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()
      
/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_SODetail
	
	/****************************************************************************
	
		Insert standing order rows to the staging table.

	****************************************************************************/

	insert into dbo.sa_Finance_SODetail
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		StandingOrderID,
		AgmID,
		AgentCode,
		SOCode,
		SODescription,
		SOType,
		SOFreq,
		SOAmount,
		VATable,
		UnpaidCreatedDate,
		AuthStatus,
		VatAmount,
		NetAmount,
		PaidAmount,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,										-- Must be zero - will be toggled later
			so.id as StandingOrderID,
			isnull(un.ID,-1) as AgmID,
			so.AgentCode, 
			so.StandingOrderCode as SOCode,
			so.Description as SODescription,
			co.Description as SOType,
			case so.Frequency
			  when 2 then 'Mth'
			  when 5 then 'Ann'
			  when 6 then 'Sin'
			  else 'Oth'
			end as SOFreq,
			so.PaymentAmount as SOAmount,
			case so.SubjectToVAT
			  when 0 then 'N'
			  when 1 then 'Y'
			end as VATable,
			un.CreateDateTime as UnpaidCreatedDate,
			case so.authorised 
			  when 0 then 'Auth' 
			  when 1 then 'Decl' 
			  when 2 then 'O/S'
			end as AuthStatus,
			pa.VATAmount as VatAmount,
			pa.NetAmount as NetAmount,
			pa.Amount as PaidAmount,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated			
	from	sa_swift_CommAgentStandingOrders so
			inner join mstt_Agents ag on ag.Code = so.AgentCode
			inner join sa_swift_CodeStandingOrders co on co.Code = so.StandingOrderCode
			left outer join sa_swift_S_Agmfil un on un.Agent_Code = so.AgentCode and un.StandingOrderID = so.ID
			left outer join sa_swift_S_Agmpay pa on pa.AgmID = un.ID
				
	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
