/************************************************************************************************
  	 Program:  	owp_Finance_SOSummary_Staging						
	  Author:	A Groves
Date created:	05/03/2018

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_SOSummary. This is the staging table
				for table dbo.owt_Finance_SOSummary which is populated by another stored proc.
				
				This proc is part of the 2018/Q1 sweep up to put the straggler scans into Logi
				with the end game being to decomm all the old-style scans in favour of the 
				Finance Logi app. This table replaces Finstat60ExpensesReimbursed.
				
				It is called as follows:

				exec owp_Finance_SOSummary_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SOSummary_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FromDate					= '01-JAN-2006'
set @ToDate						= dateadd(dd,0,datediff(dd,0,getdate()));
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

declare @VAT table (VATRate        decimal(8,2)  not null,
                    VATStartDate   datetime      not null,
                    VATEndDate     datetime      not null)

insert	into @VAT
Select	VATRate    = convert(decimal(8,2),ShortDescription),
		StartDate  = convert(datetime,Code,111),
		EndDate    = convert(datetime,Description,111)
from	msit_MIWarehouseCodesandDescriptions
where	ColumnName = 'VATRate'
  and	ShortDescription is not null 
  and	Description is not null
      
/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_SOSummary
	
	/****************************************************************************
	
		Insert standing order rows to the staging table.

	****************************************************************************/

	insert into dbo.sa_Finance_SOSummary
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		PendingPaymentID,
		StandingOrderCode,
		StandingOrderCodeDesc,
		AgentCode,
		GrossAmount,
		VATRate,
		VATAmount,
		NetAmount,
		PaymentDueDate,
		CreateDateTime,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			pp.ID as PendingPaymentID,
			pp.StandingOrderCode,
			pp.StandingOrderCodeDesc,
			pp.Firm,
			pp.Amount as GrossAmount,
			case
				when pp.SubjectToVAT = 1 AND isnull(PA.NetAmount,0) <> 0 THEN round(((PA.VATAmount / PA.NetAmount) * 100.0) * 2.0, 0) / 2.0		--Roound to the nearest 0.50
				--when pp.SubjectToVAT = 1 AND isnull(PA.NetAmount,0) <> 0 THEN round(100*(isnull(PA.VATAmount,0)/PA.NetAmount) ,2) 
				when pp.SubjectToVAT = 1 THEN V.VATRate
				else 0.0
			end as VATRate,
			null as VATAmount,
			case
				 when pp.SubjectToVAT = 1 AND isnull(PA.NetAmount,0) <> 0 THEN PA.NetAmount  
				 when pp.SubjectToVAT = 1 THEN CAST(pp.Amount / (1.00 + (V.VATRate / 100.00)) AS DECIMAL(16,2))  
				 else CAST(pp.Amount AS DECIMAL(16,2))
			end as NetAmount, 
			PaymentDueDate,
			CreateDateTime,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated			
	FROM	mstt_PaymentsPending pp
			LEFT JOIN @VAT V on DATEADD(dd,0,DATEDIFF(dd,0,CASE WHEN pp.PaymentDueDate >= @FromDate THEN pp.PaymentDueDate ELSE pp.CreateDateTime END)) between V.VATStartDate and V.VATEndDate   
			LEFT JOIN sa_swift_S_AGMPAY PA ON PA.AGMID = pp.ID    
	WHERE	pp.CommissionType = 8
	AND		pp.PaymentDueDate between @FromDate and @ToDate
	
	/****************************************************************************

		We now have the gross and net so find the VAT amount
																			
	****************************************************************************/	

	update stag
		set VATAmount = GrossAmount - NetAmount
	from dbo.sa_Finance_SOSummary stag
	
	/****************************************************************************

		The VAT Rate is derived and sometimes the calculation gets it wrong
		for very small amounts. The code below will correct these.
																			
	****************************************************************************/
	
	--Get any derived VAT Rates different to the possible configured VAT rates 
	select	summ.PendingPaymentID, summ.VATRate, 0 as Diff
	into	#RateDiffs
	from	sa_finance_soSummary summ
			left join @VAT v on v.VATRate = summ.VATRate 
	where	v.VATRate is null
	and		summ.VATRate <> 0

	--For these records with rates different to the possible, find the difference against every configured rate
	select	PendingPaymentID, v.VATRate as ConfiguredVATRate, abs(Diffs.VATRate - v.VATRate) as Diff
	into	#Variances
	from	#RateDiffs diffs
			cross join @VAT v

	--Now update the summary table with the closest configured rate.
	update summ
		set VATRate = v.ConfiguredVATRate
	from sa_finance_soSummary summ
			inner join #Variances v on v.PendingPaymentId = summ.PendingPaymentId  
			inner join (select	PendingPaymentId, 
								MIN(Diff) as MinDiff
						from	#Variances
						group	by PendingPaymentID) SmallestDiff 
								on SmallestDiff.PendingPaymentId = v.PendingPaymentId
								and SmallestDiff.MinDiff = v.Diff
			
	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
