Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_StatementCommMarg_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @FromDate		= '01-JAN-2006'
set @ToDate			= dateadd(dd,0,datediff(dd,0,getdate()));

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,1,'20167','2016-07-01'
	union all
	select 9,0,0,'20168','2016-08-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_StatementCommMarg
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				Statement,
				RecAmt,
				Unallocated,
				MatchedRecAmt,
				StatementTotal,
				AgentAmountDue,
				OpenWorkAmountDue,
				NoAgmAmt,
				AgentAmountPaid,
				OpenWorkAmountPaid,
				StatementDate,
				StatementCreatedDateTime,
				DateInserted,
				DateLastUpdated				
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					Statement,
					RecAmt,
					Unallocated,
					MatchedRecAmt,
					StatmentTotal,
					AgentAmountDue,
					OpenWorkAmountDue,
					NoAgmAmt,
					AgentAmountPaid,
					OpenWorkAmountPaid,
					StatementDate,
					StatementCreatedDateTime,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting7StatementCommMarg logi
			where	logi.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_StatementCommMarg
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				Statement,
				RecAmt,
				Unallocated,
				MatchedRecAmt,
				StatementTotal,
				AgentAmountDue,
				OpenWorkAmountDue,
				NoAgmAmt,
				AgentAmountPaid,
				OpenWorkAmountPaid,
				StatementDate,
				StatementCreatedDateTime,
				DateInserted,
				DateLastUpdated				
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.Statement,
					old.RecAmt,
					old.Unallocated,
					old.MatchedRecAmt,
					old.StatmentTotal,
					old.AgentAmountDue,
					old.OpenWorkAmountDue,
					old.NoAgmAmt,
					old.AgentAmountPaid,
					old.OpenWorkAmountPaid,
					old.StatementDate,
					old.StatementCreatedDateTime,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting7StatementCommMarg old
					left join dbo.owt_Finance_StatementCommMarg new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Statement,-1) = isnull(new.Statement,-1)	-- One statement is null
									and @FinancialPeriodDestination 
											between new.FinancialPeriodFromDate --This will ensure just one row is joined
											and new.FinancialPeriodToDate		--...but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					(new.Statement is null and new.FinancialPeriodFromDate is null)	--There's no existing row for this item so add it
			or		isnull(old.Statement,-1) <> isnull(new.Statement,-1)
			or		isnull(old.RecAmt,-999999999) <> isnull(new.RecAmt,-999999999)			
			or		isnull(old.Unallocated,-999999999) <> isnull(new.Unallocated,-999999999)
			or		isnull(old.MatchedRecAmt,-999999999) <> isnull(new.MatchedRecAmt,-999999999)
			or		isnull(old.StatmentTotal,-999999999) <> isnull(new.StatementTotal,-999999999)
			or		isnull(old.AgentAmountDue,-999999999) <> isnull(new.AgentAmountDue,-999999999)
			or		isnull(old.OpenWorkAmountDue,-999999999) <> isnull(new.OpenWorkAmountDue,-999999999)
			or		isnull(old.NoAgmAmt,-999999999) <> isnull(new.NoAgmAmt,-999999999)
			or		isnull(old.AgentAmountPaid,-999999999) <> isnull(new.AgentAmountPaid,-999999999)
			or		isnull(old.OpenWorkAmountPaid,-999999999) <> isnull(new.OpenWorkAmountPaid,-999999999)			
			or		isnull(old.StatementDate,0) <> isnull(new.StatementDate,0)
			or		isnull(old.StatementCreatedDateTime,0) <> isnull(new.StatementCreatedDateTime,0)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

--if @FinancialPeriodDestination <> '2016-08-01'
--begin

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_StatementCommMarg old
					inner join dbo.owt_Finance_StatementCommMarg new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_StatementCommMarg new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_StatementCommMarg new
					left join logi.FinstatReporting7StatementCommMarg old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			and		old.Statement is null

--end

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_StatementCommMarg_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_StatementCommMarg_History					
	  Author:	A Groves
Date created:	20/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_StatementCommMarg from staging table 
				dbo.sa_Finance_StatementCommMarg which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_StatementCommMarg_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_StatementCommMarg_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_StatementCommMarg
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		RecAmt,
		Unallocated,
		MatchedRecAmt,
		StatementTotal,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		AgentAmountPaid,
		OpenWorkAmountPaid,
		StatementDate,
		StatementCreatedDateTime,
		DateInserted,
		DateLastUpdated		
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.Statement,
			stag.RecAmt,
			stag.Unallocated,
			stag.MatchedRecAmt,
			stag.StatementTotal,
			stag.AgentAmountDue,
			stag.OpenWorkAmountDue,
			stag.NoAgmAmt,
			stag.AgentAmountPaid,
			stag.OpenWorkAmountPaid,
			stag.StatementDate,
			stag.StatementCreatedDateTime,
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_StatementCommMarg stag
			left join dbo.owt_Finance_StatementCommMarg hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(hist.Statement,-1) = isnull(stag.Statement,-1)	-- One statement is null
							and stag.FinancialPeriodFromDate  
									between hist.FinancialPeriodFromDate		--This will ensure just one row is joined
									and hist.FinancialPeriodToDate				--...but not joined if it has previously ended
	where	(hist.Statement is null and hist.FinancialPeriodFromDate is null)	--There's no existing row for this item so add it
	or		isnull(stag.Statement,-1) <> isnull(hist.Statement,-1)
	or		isnull(stag.RecAmt,-999999999) <> isnull(hist.RecAmt,-999999999)			
	or		isnull(stag.Unallocated,-999999999) <> isnull(hist.Unallocated,-999999999)
	or		isnull(stag.MatchedRecAmt,-999999999) <> isnull(hist.MatchedRecAmt,-999999999)
	or		isnull(stag.StatementTotal,-999999999) <> isnull(hist.StatementTotal,-999999999)
	or		isnull(stag.AgentAmountDue,-999999999) <> isnull(hist.AgentAmountDue,-999999999)
	or		isnull(stag.OpenWorkAmountDue,-999999999) <> isnull(hist.OpenWorkAmountDue,-999999999)
	or		isnull(stag.NoAgmAmt,-999999999) <> isnull(hist.NoAgmAmt,-999999999)
	or		isnull(stag.AgentAmountPaid,-999999999) <> isnull(hist.AgentAmountPaid,-999999999)
	or		isnull(stag.OpenWorkAmountPaid,-999999999) <> isnull(hist.OpenWorkAmountPaid,-999999999)			
	or		isnull(stag.StatementDate,0) <> isnull(hist.StatementDate,0)
	or		isnull(stag.StatementCreatedDateTime,0) <> isnull(hist.StatementCreatedDateTime,0)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of the previous month
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_StatementCommMarg old
			inner join dbo.owt_Finance_StatementCommMarg new 
							on  isnull(new.Statement,-1) = isnull(old.Statement,-1)
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_StatementCommMarg new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of the previous month
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_StatementCommMarg hist
			left join dbo.sa_Finance_StatementCommMarg stag	-- Don't join on a column that can change such as some sort of financial amount!!!	
						on isnull(hist.Statement,-1) = isnull(stag.Statement,-1)
	where	hist.FinancialPeriodToDate = '9999-12-31'	-- Active row - this excludes any rows already de-activated
	and		stag.Statement is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_StatementCommMarg_Staging]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_StatementCommMarg_Staging				
	  Author:	A Groves
Date created:	20/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_StatementCommMarg. This is the staging table
				for table dbo.owt_Finance_StatementCommMarg which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_StatementCommMarg_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
16/01/2023	A Groves	Added new pot code '1012561' (Defined Benefit Transfer Fee).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_StatementCommMarg_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_StatementCommMarg
	
	/****************************************************************************
	
		Insert rows into temp table 1

	****************************************************************************/

	select	stmt.statement,
			sum(case fipa.PayType when 5 then 0 else fipa.RecAmt end) RecAmt,
			SUM(case fipa.PayType 
					When 5 
						then case fipa.MatchInd when 'N' 
								then fipa.RecAmt 
								else case fipa.MatchedToType 
										when 5 then fipa.RecAmt 
										else 0 
									  end 
							 end 
						else 0 
					end) as Unallocated,
			SUM(case fipa.Statement 
					when fipa.MatchedToStatement 
						then 0 
						else case fipa.MatchedToType 
								when 5 then 0 
								else fipa.MatchedRecAmt 
							 end 
				end) as MatchedRecAmt,
			stmt.TOTAL as StatementTotal,
			@FinancialPeriodFromDate as FinancialPeriod
	into	#Statement
	from	dbo.owt_Finance_S_PACC fipa 
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement
	WHERE	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
	and		stmt.Statement is not null	--Trevor's proc excluded this (accidently?) by his WHERE 
										--clause (WHERE fipa.FinancialPeriod = @lc_FinacialPeriod).
										--The same is done here to ensure they reconcile.
	group	by stmt.statement,stmt.TOTAL

	create index idx_tmp_Statement on #Statement(Statement,FinancialPeriod)

	exec msp_ProcessLog @PhaseLog, 'Temp Table 1 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/

	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			stat.STATEMENT,
			stat.RecAmt,
			stat.Unallocated,
			stat.MatchedRecAmt,
			stat.StatementTotal,
			agmf.AGENT_CODE as Agmf_AGENT_CODE,
			agmf.AMOUNT as Agmf_Amount,
			agmf.PACC_ID as Agmf_PACC_ID,
			fipa.PayType as fipa_PayType,
			fipa.RecAmt as fipa_RecAmt, 
			agmp.AMOUNT as Agmp_Amount, 
			stmt.STMNT_DATE as stmt_STMNT_DATE,
			stmt.CreatedDateTime as stmt_CreatedDateTime,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	into	#Statement2
	from	#Statement stat
			left join dbo.owt_Finance_S_PACC fipa --00:01:06
						on fipa.Statement = stat.statement
						and stat.FinancialPeriod 
								between fipa.FinancialPeriodFromDate 
								and fipa.FinancialPeriodToDate
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = fipa.PaccId
			--left join dbo.mstt_PaymentsPending agmf on agmf.PACC_ID = fipa.PaccId	--00:02:43	34695509
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID
			--left join dbo.mstt_AgentPayments agmp on agmp.AGMID   = agmf.ID			--00:03:37	34695509
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement	--00:03:31

