								and fipa.FinancialPeriodToDate
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = fipa.PaccId
			--left join dbo.mstt_PaymentsPending agmf on agmf.PACC_ID = fipa.PaccId	--00:02:43	34695509
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID
			--left join dbo.mstt_AgentPayments agmp on agmp.AGMID   = agmf.ID			--00:03:37	34695509
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement	--00:03:31

	exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_StatementCommMarg
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		RecAmt,
		Unallocated,
		MatchedRecAmt,
		StatementTotal,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		AgentAmountPaid,
		OpenWorkAmountPaid,
		StatementDate,
		StatementCreatedDateTime,
		DateInserted,
		DateLastUpdated		
	)
	select	stat.FinancialPeriodFromDate,	
			stat.FinancialPeriodToDate,
			stat.LatestRowInd,	
			stat.STATEMENT,
			stat.RecAmt,
			stat.Unallocated,
			stat.MatchedRecAmt,
			stat.StatementTotal,
			sum(case stat.Agmf_AGENT_CODE 
								when '1011543' then 0
								when '10002' then 0
								when '10004' then 0
								when '10005' then 0
								when '1006124' then 0
								when '1006886' then 0
								when '1011542' then 0
								when '1011587' then 0
								when '1011623' then 0
								when '1011629' then 0
								when '1011630' then 0
								when '1011631' then 0
								when '1011632' then 0
								when '1011633' then 0
								when '1011634' then 0
								when '1011635' then 0
								when '1012045' then 0	--AG 28/06/2019
							    else stat.Agmf_AMOUNT 
				 end ) as AgentAmountDue,
			sum(case stat.Agmf_AGENT_CODE 
								when '1011543' then stat.Agmf_AMOUNT
								when '10002' then stat.Agmf_AMOUNT
								when '10004' then stat.Agmf_AMOUNT
								when '10005' then stat.Agmf_AMOUNT
								when '1006124' then stat.Agmf_AMOUNT
								when '1006886' then stat.Agmf_AMOUNT
								when '1011542' then stat.Agmf_AMOUNT
								when '1011587' then stat.Agmf_AMOUNT
								when '1011623' then stat.Agmf_AMOUNT
								when '1011629' then stat.Agmf_AMOUNT
								when '1011630' then stat.Agmf_AMOUNT
								when '1011631' then stat.Agmf_AMOUNT
								when '1011632' then stat.Agmf_AMOUNT
								when '1011633' then stat.Agmf_AMOUNT
								when '1011634' then stat.Agmf_AMOUNT
								when '1011635' then stat.Agmf_AMOUNT
								when '1012045' then stat.Agmf_AMOUNT	--AG 28/06/2019
								else 0 
				 end ) as OpenWorkAmountDue,
			SUM(case ISNULL(stat.Agmf_PACC_ID,0) 
					when 0 then 
							case stat.fipa_PayType 
								when 5 then 0
								when 6 then stat.fipa_RecAmt 
								else stat.fipa_RecAmt 
							end 
						else 0 
				end) NoAgmAmt,       
			sum(case stat.Agmf_AGENT_CODE 
								when '1011543' then 0
								when '10002' then 0
								when '10004' then 0
								when '10005' then 0
								when '1006124' then 0
								when '1006886' then 0
								when '1011542' then 0
								when '1011587' then 0
								when '1011623' then 0
								when '1011629' then 0
								when '1011630' then 0
								when '1011631' then 0
								when '1011632' then 0
								when '1011633' then 0
								when '1011634' then 0
								when '1011635' then 0
								when '1012045' then 0	--AG 28/06/2019
								else stat.Agmp_AMOUNT 
				end) as AgentAmountPaid,
			sum(case stat.Agmf_AGENT_CODE 
								when '1011543' then stat.Agmp_AMOUNT
								when '10002' then stat.Agmp_AMOUNT
								when '10004' then stat.Agmp_AMOUNT
								when '10005' then stat.Agmp_AMOUNT
								when '1006124' then stat.Agmp_AMOUNT
								when '1006886' then stat.Agmp_AMOUNT
								when '1011542' then stat.Agmp_AMOUNT
								when '1011587' then stat.Agmp_AMOUNT
								when '1011623' then stat.Agmp_AMOUNT
								when '1011629' then stat.Agmp_AMOUNT
								when '1011630' then stat.Agmp_AMOUNT
								when '1011631' then stat.Agmp_AMOUNT
								when '1011632' then stat.Agmp_AMOUNT
								when '1011633' then stat.Agmp_AMOUNT
								when '1011634' then stat.Agmp_AMOUNT
								when '1011635' then stat.Agmp_AMOUNT
								when '1012045' then stat.Agmp_AMOUNT	--AG 28/06/2019
								else 0 
				end) as OpenWorkAmountPaid,
			stat.stmt_STMNT_DATE,
			stat.stmt_CreatedDateTime,
			stat.DateInserted,
			stat.DateLastUpdated
	from	#Statement2 stat
	group	by	stat.FinancialPeriodFromDate,	
				stat.FinancialPeriodToDate,
				stat.LatestRowInd,	
				stat.STATEMENT,
				stat.RecAmt,
				stat.Unallocated,
				stat.MatchedRecAmt,
				stat.StatementTotal,
				stat.stmt_STMNT_DATE,
				stat.stmt_CreatedDateTime,
				stat.DateInserted,
				stat.DateLastUpdated

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_SumDaCommMarg_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_SumDaCommMarg_1Off
	  Author:	A Groves
Date created:	30/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_SumDaCommMarg from table
				logi.FinstatReporting14SumDaCommMarg the original proof-of-concept table.
				
				It is called as follows:

				exec dbo.owp_Finance_SumDaCommMarg_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SumDaCommMarg_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FromDate					datetime,
		@ToDate						datetime,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit,
		@LargeNegativeNumber		decimal(16,2)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @FromDate				= '01-JAN-2006'
set @ToDate					= dateadd(dd,0,datediff(dd,0,getdate()));
set @LargeNegativeNumber	= -999999999.00

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161a','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,1,'20168','2016-08-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_SumDaCommMarg
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				Statement,
				RecAmt,
				Unallocated,
				MatchedRecAmt,
				StatementTotal,
				AgentAmountDue,
				OpenWorkAmountDue,
				NoAgmAmt,
				AgentAmountPaid,
				OpenWorkAmountPaid,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					Statement,
					RecAmt,
					Unallocated,
					MatchedRecAmt,
					StatementTotal,
					AgentAmountDue,
					OpenWorkAmountDue,
					NoAgmAmt,
					AgentAmountPaid,
					OpenWorkAmountPaid,
					GrossAmtPayable,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting14SumDaCommMarg old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_SumDaCommMarg
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				Statement,
				RecAmt,
				Unallocated,
				MatchedRecAmt,
				StatementTotal,
				AgentAmountDue,
				OpenWorkAmountDue,
				NoAgmAmt,
				AgentAmountPaid,
				OpenWorkAmountPaid,
				GrossAmtPayable,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					CONVERT(date,'31/12/9999',103) as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.Statement,
					old.RecAmt,
					old.Unallocated,
					old.MatchedRecAmt,
					old.StatementTotal,
					old.AgentAmountDue,
					old.OpenWorkAmountDue,
					old.NoAgmAmt,
					old.AgentAmountPaid,
					old.OpenWorkAmountPaid,
					old.GrossAmtPayable,
					getdate() as DateInserted,
					getdate() as DateLastUpdated
			from	logi.FinstatReporting14SumDaCommMarg old
					left join dbo.owt_Finance_SumDaCommMarg new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.Statement is null						--There's no existing row for this item so add it
			or		isnull(old.RecAmt,@LargeNegativeNumber) <> isnull(new.RecAmt,@LargeNegativeNumber)
			or		isnull(old.Unallocated,@LargeNegativeNumber) <> isnull(new.Unallocated,@LargeNegativeNumber)
			or		isnull(old.MatchedRecAmt,@LargeNegativeNumber) <> isnull(new.MatchedRecAmt,@LargeNegativeNumber)
			or		isnull(old.StatementTotal,@LargeNegativeNumber) <> isnull(new.StatementTotal,@LargeNegativeNumber)
			or		isnull(old.AgentAmountDue,@LargeNegativeNumber) <> isnull(new.AgentAmountDue,@LargeNegativeNumber)
			or		isnull(old.OpenWorkAmountDue,@LargeNegativeNumber) <> isnull(new.OpenWorkAmountDue,@LargeNegativeNumber)
			or		isnull(old.NoAgmAmt,@LargeNegativeNumber) <> isnull(new.NoAgmAmt,@LargeNegativeNumber)
			or		isnull(old.AgentAmountPaid,@LargeNegativeNumber) <> isnull(new.AgentAmountPaid,@LargeNegativeNumber)
			or		isnull(old.OpenWorkAmountPaid,@LargeNegativeNumber) <> isnull(new.OpenWorkAmountPaid,@LargeNegativeNumber)
			or		isnull(old.GrossAmtPayable,@LargeNegativeNumber) <> isnull(new.GrossAmtPayable,@LargeNegativeNumber)
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'	-- If row still open...
												then @FinancialPeriodDestination-1				-- Then close it with the last day of last month
												else old.FinancialPeriodToDate					-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,															-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = getdate()													-- Update the audit info
			from	dbo.owt_Finance_SumDaCommMarg old
					inner join dbo.owt_Finance_SumDaCommMarg new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and new.FinancialPeriodToDate = '9999-12-31'		-- This....
									and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_SumDaCommMarg new
			where	new.FinancialPeriodToDate = '9999-12-31'		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = getdate()								-- Update the audit info
			from	dbo.owt_Finance_SumDaCommMarg new
					left join logi.FinstatReporting14SumDaCommMarg old	-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(old.Statement,-1) = isnull(new.Statement,-1)
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = '9999-12-31'				-- Active row - this excludes any rows already de-activated
			--and		new.LatestRowInd = 1	-- Should always be 1 if FinancialPeriodToDate = '9999-12-31'
			and		old.Statement is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_SumDaCommMarg_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_SumDaCommMarg_History
	  Author:	A Groves
Date created:	30/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_SumDaCommMarg from staging table 
				dbo.sa_Finance_SumDaCommMarg which is populated by another stored proc.

				It is called as follows:

				exec dbo.owp_Finance_SumDaCommMarg_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SumDaCommMarg_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @LargeNegativeNumber	= -999999999.00

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table from the staging table.

	****************************************************************************/

	insert into dbo.owt_Finance_SumDaCommMarg
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		RecAmt,
		Unallocated,
		MatchedRecAmt,
		StatementTotal,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		AgentAmountPaid,
		OpenWorkAmountPaid,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	stag.FinancialPeriodFromDate,
			stag.FinancialPeriodToDate,
			stag.LatestRowInd,	
			stag.Statement,
			stag.RecAmt,
			stag.Unallocated,
			stag.MatchedRecAmt,
			stag.StatementTotal,
			stag.AgentAmountDue,
			stag.OpenWorkAmountDue,
			stag.NoAgmAmt,
			stag.AgentAmountPaid,
			stag.OpenWorkAmountPaid,
			stag.GrossAmtPayable,
			getdate() as DateInserted,
			getdate() as DateLastUpdated
	from	dbo.sa_Finance_SumDaCommMarg stag
			left join dbo.owt_Finance_SumDaCommMarg hist	--Don't join on a column that can change such as some sort of financial amount!!!
							on  isnull(stag.Statement,-1) = isnull(hist.Statement,-1)
							and stag.FinancialPeriodFromDate 
									between hist.FinancialPeriodFromDate	--This will ensure just one row is joined
									and hist.FinancialPeriodToDate			--...but not joined if it has previously ended
	where	hist.Statement is null						--There's no existing row for this item so add it
	or		isnull(stag.RecAmt,@LargeNegativeNumber) <> isnull(hist.RecAmt,@LargeNegativeNumber)
	or		isnull(stag.Unallocated,@LargeNegativeNumber) <> isnull(hist.Unallocated,@LargeNegativeNumber)
	or		isnull(stag.MatchedRecAmt,@LargeNegativeNumber) <> isnull(hist.MatchedRecAmt,@LargeNegativeNumber)
	or		isnull(stag.StatementTotal,@LargeNegativeNumber) <> isnull(hist.StatementTotal,@LargeNegativeNumber)
	or		isnull(stag.AgentAmountDue,@LargeNegativeNumber) <> isnull(hist.AgentAmountDue,@LargeNegativeNumber)
	or		isnull(stag.OpenWorkAmountDue,@LargeNegativeNumber) <> isnull(hist.OpenWorkAmountDue,@LargeNegativeNumber)
	or		isnull(stag.NoAgmAmt,@LargeNegativeNumber) <> isnull(hist.NoAgmAmt,@LargeNegativeNumber)
	or		isnull(stag.AgentAmountPaid,@LargeNegativeNumber) <> isnull(hist.AgentAmountPaid,@LargeNegativeNumber)
	or		isnull(stag.OpenWorkAmountPaid,@LargeNegativeNumber) <> isnull(hist.OpenWorkAmountPaid,@LargeNegativeNumber)
	or		isnull(stag.GrossAmtPayable,@LargeNegativeNumber) <> isnull(hist.GrossAmtPayable,@LargeNegativeNumber)

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = '9999-12-31'			-- If row still open...
										then dateadd(month,datediff(month,0,getdate())-1,0)-1	-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate							-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																	-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = getdate()															-- Update the audit info
	from	dbo.owt_Finance_SumDaCommMarg old
			inner join dbo.owt_Finance_SumDaCommMarg new 
							on  isnull(new.Statement,-1) = isnull(old.Statement,-1)
							and new.FinancialPeriodToDate = '9999-12-31'		-- This....
							and	new.LatestRowInd = 0							-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1												-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_SumDaCommMarg new
	where	new.FinancialPeriodToDate = '9999-12-31'		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	update	hist
		set FinancialPeriodToDate = dateadd(month,datediff(month,0,getdate())-1,0)-1,	-- Not present this month so close off as at the end of last month	AG 21/09/2016
			DateLastUpdated = getdate()													-- Update the audit info
	from	dbo.owt_Finance_SumDaCommMarg hist
			left join dbo.sa_Finance_SumDaCommMarg stag	-- Don't join on a column that can change such as some sort of financial amount!!!	
							on  isnull(stag.Statement,-1) = isnull(hist.Statement,-1)
	where	hist.FinancialPeriodToDate = '9999-12-31'	-- Active row - this excludes any rows already de-activated
	and		stag.Statement is null

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
