/************************************************************************************************
  	 Program:  	owp_Finance_SumDaCommMarg_Staging						
	  Author:	A Groves
Date created:	30/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_SumDaCommMarg. This is the staging table
				for table dbo.owt_Finance_SumDaCommMarg which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_SumDaCommMarg_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
01/10/2016	A Groves	Split into 3 temporary tables to improve performance.
31/08/2017	A Groves	SR486473. This proc took approximately 50 mins to run on 01/08/2017 
						which is far too long. Performance improvement has been achieved by 
						replacing date and convert functions with variables. Run time reduced
						to approximately 10 mins = 40 mins improvement.
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
16/01/2023	A Groves	Added new pot code '1012561' (Defined Benefit Transfer Fee).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SumDaCommMarg_Staging] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,			--AG 31/08/2017
		@FinancialPeriodToDate		date,			--AG 31/08/2017
		@DateLastUpdated			datetime		--AG 31/08/2017

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd					= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)	--AG 31/08/2017
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)						--AG 31/08/2017
set @DateLastUpdated			= getdate()												--AG 31/08/2017

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_SumDaCommMarg
	
	/****************************************************************************
	
		Insert rows into temp table 1

	****************************************************************************/

	select	stmt.statement,
			sum(case fipa.PayType when 5 then 0 else fipa.RecAmt end) RecAmt,
			sum(case fipa.PayType 
						when 5 then 
								case fipa.MatchInd 
									when 'N' then fipa.RecAmt 
									else 
										case fipa.MatchedToType 
											when 5 then fipa.RecAmt 
											else 0 
										end 
								end 
						else 0 
				end) as Unallocated,
			sum(case fipa.Statement 
						when fipa.MatchedToStatement 
							then 0 
							else 
								case fipa.MatchedToType 
									when 5 then 0 
									else fipa.MatchedRecAmt 
								end 
				end ) as MatchedRecAmt,
			stmt.TOTAL as StatementTotal
	into	#Statements
	from	dbo.owt_Finance_S_PACC fipa
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate	--AG 31/08/2017
	group	by stmt.statement, stmt.TOTAL

	exec msp_ProcessLog @PhaseLog, 'Temp Table 1 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/
	
	select 	fipa.Statement,
			case agmf.AGENT_CODE 
					when '1011543' then 0
					when '10002' then 0
					when '10004' then 0
					when '10005' then 0
					when '1006124' then 0
					when '1006886' then 0
					when '1011542' then 0
					when '1011587' then 0
					when '1011623' then 0
					when '1011629' then 0
					when '1011630' then 0
					when '1011631' then 0
					when '1011632' then 0
					when '1011633' then 0
					when '1011634' then 0
					when '1011635' then 0
					when '1012045' then 0	--AG 28/06/2019
					when '1012561' then 0	--AG 16/01/2023
					else agmf.AMOUNT 
			end as AgentAmountDue,
			case agmf.AGENT_CODE 
					when '1011543' then agmf.AMOUNT
					when '10002' then agmf.AMOUNT
					when '10004' then agmf.AMOUNT
					when '10005' then agmf.AMOUNT
					when '1006124' then agmf.AMOUNT
					when '1006886' then agmf.AMOUNT
					when '1011542' then agmf.AMOUNT
					when '1011587' then agmf.AMOUNT
					when '1011623' then agmf.AMOUNT
					when '1011629' then agmf.AMOUNT
					when '1011630' then agmf.AMOUNT
					when '1011631' then agmf.AMOUNT
					when '1011632' then agmf.AMOUNT
					when '1011633' then agmf.AMOUNT
					when '1011634' then agmf.AMOUNT
					when '1011635' then agmf.AMOUNT
					when '1012045' then agmf.AMOUNT	--AG 28/06/2019
					when '1012561' then agmf.AMOUNT	--AG 16/01/2023
					else 0 
			end as OpenWorkAmountDue,
			case ISNULL(agmf.PACC_ID,0) 
					when 0 then 
						case fipa.PayType 
							when 5 then 0
							when 6 then fipa.RecAmt 
							else fipa.RecAmt 
						end 
					else 0 
			end as NoAgmAmt,       
			case agmf.AGENT_CODE 
					when '1011543' then 0
                    when '10002' then 0
                    when '10004' then 0
                    when '10005' then 0
                    when '1006124' then 0
                    when '1006886' then 0
                    when '1011542' then 0
                    when '1011587' then 0
                    when '1011623' then 0
                    when '1011629' then 0
                    when '1011630' then 0
                    when '1011631' then 0
                    when '1011632' then 0
                    when '1011633' then 0
                    when '1011634' then 0
                    when '1011635' then 0
                    when '1012045' then 0	--AG 28/06/2019
                    when '1012561' then 0	--AG 16/01/2023
                    else agmp.AMOUNT 
            end as AgentAmountPaid,
			case agmf.AGENT_CODE 
					when '1011543' then agmp.AMOUNT
                    when '10002' then agmp.AMOUNT
                    when '10004' then agmp.AMOUNT
                    when '10005' then agmp.AMOUNT
                    when '1006124' then agmp.AMOUNT
                    when '1006886' then agmp.AMOUNT
                    when '1011542' then agmp.AMOUNT
                    when '1011587' then agmp.AMOUNT
                    when '1011623' then agmp.AMOUNT
                    when '1011629' then agmp.AMOUNT
                    when '1011630' then agmp.AMOUNT
                    when '1011631' then agmp.AMOUNT
                    when '1011632' then agmp.AMOUNT
                    when '1011633' then agmp.AMOUNT
                    when '1011634' then agmp.AMOUNT
                    when '1011635' then agmp.AMOUNT
                    when '1012045' then agmp.AMOUNT	--AG 28/06/2019
                    when '1012561' then agmp.AMOUNT	--AG 16/01/2023
                    else 0 
            end as OpenWorkAmountPaid,
			tbeh.Amount as GrossAmtPayable             
	into	#StatementAmounts
	from	dbo.owt_Finance_S_PACC fipa 
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = fipa.PaccId
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID = agmf.ID
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement
			left join dbo.sa_swift_TempBACSExportHistory tbeh on tbeh.S_AGMPAY_ID = agmp.ID
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate	--AG 31/08/2017

	exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 3

	****************************************************************************/

	select 	sa.Statement,
			sum(sa.AgentAmountDue) as AgentAmountDue,
			sum(sa.OpenWorkAmountDue) as OpenWorkAmountDue,
			sum(sa.NoAgmAmt) as NoAgmAmt,
			sum(sa.AgentAmountPaid) as AgentAmountPaid,
			sum(sa.OpenWorkAmountPaid) as OpenWorkAmountPaid,
			sum(sa.GrossAmtPayable) as GrossAmtPayable 
	into	#StatementSummary
	from	#StatementAmounts sa
	group	by sa.Statement	

	exec msp_ProcessLog @PhaseLog, 'Temp Table 3 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_SumDaCommMarg
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		RecAmt,
		Unallocated,
		MatchedRecAmt,
		StatementTotal,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		AgentAmountPaid,
		OpenWorkAmountPaid,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month	--AG 31/08/2017
			@FinancialPeriodToDate as FinancialPeriodToDate,		--AG 31/08/2017
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			stat.STATEMENT,
			stat.RecAmt,
			stat.Unallocated,
			stat.MatchedRecAmt,
			stat.StatementTotal,
			ss.AgentAmountDue,
			ss.OpenWorkAmountDue,
			ss.NoAgmAmt,
			ss.AgentAmountPaid,
			ss.OpenWorkAmountPaid,
			ss.GrossAmtPayable,
			@DateLastUpdated as DateInserted,		--AG 31/08/2017
			@DateLastUpdated as DateLastUpdated		--AG 31/08/2017
	from	#StatementSummary ss
			inner join #Statements stat on stat.Statement = ss.Statement
			
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

