/****** Object:  StoredProcedure [dbo].[owp_Finance_SumDaCommMarg_Staging_Backup20230125AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_SumDaCommMarg_Staging						
	  Author:	A Groves
Date created:	30/09/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.sa_Finance_SumDaCommMarg. This is the staging table
				for table dbo.owt_Finance_SumDaCommMarg which is populated by another stored proc.
				
				It is called as follows:

				exec owp_Finance_SumDaCommMarg_Staging 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
01/10/2016	A Groves	Split into 3 temporary tables to improve performance.
31/08/2017	A Groves	SR486473. This proc took approximately 50 mins to run on 01/08/2017 
						which is far too long. Performance improvement has been achieved by 
						replacing date and convert functions with variables. Run time reduced
						to approximately 10 mins = 40 mins improvement.
28/06/2019	A Groves	Added new pot code '1012045' (OPENWORK RENEWAL POT CODE).
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_SumDaCommMarg_Staging_Backup20230125AG] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodFromDate	date,			--AG 31/08/2017
		@FinancialPeriodToDate		date,			--AG 31/08/2017
		@DateLastUpdated			datetime		--AG 31/08/2017

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd					= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)	--AG 31/08/2017
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)						--AG 31/08/2017
set @DateLastUpdated			= getdate()												--AG 31/08/2017

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Empty out the staging table

	****************************************************************************/
	
	truncate table dbo.sa_Finance_SumDaCommMarg
	
	/****************************************************************************
	
		Insert rows into temp table 1

	****************************************************************************/

	select	stmt.statement,
			sum(case fipa.PayType when 5 then 0 else fipa.RecAmt end) RecAmt,
			sum(case fipa.PayType 
						when 5 then 
								case fipa.MatchInd 
									when 'N' then fipa.RecAmt 
									else 
										case fipa.MatchedToType 
											when 5 then fipa.RecAmt 
											else 0 
										end 
								end 
						else 0 
				end) as Unallocated,
			sum(case fipa.Statement 
						when fipa.MatchedToStatement 
							then 0 
							else 
								case fipa.MatchedToType 
									when 5 then 0 
									else fipa.MatchedRecAmt 
								end 
				end ) as MatchedRecAmt,
			stmt.TOTAL as StatementTotal
	into	#Statements
	from	dbo.owt_Finance_S_PACC fipa
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate	--AG 31/08/2017
	group	by stmt.statement, stmt.TOTAL

	exec msp_ProcessLog @PhaseLog, 'Temp Table 1 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/
	
	select 	fipa.Statement,
			case agmf.AGENT_CODE 
					when '1011543' then 0
					when '10002' then 0
					when '10004' then 0
					when '10005' then 0
					when '1006124' then 0
					when '1006886' then 0
					when '1011542' then 0
					when '1011587' then 0
					when '1011623' then 0
					when '1011629' then 0
					when '1011630' then 0
					when '1011631' then 0
					when '1011632' then 0
					when '1011633' then 0
					when '1011634' then 0
					when '1011635' then 0
					when '1012045' then 0	--AG 28/06/2019
					else agmf.AMOUNT 
			end as AgentAmountDue,
			case agmf.AGENT_CODE 
					when '1011543' then agmf.AMOUNT
					when '10002' then agmf.AMOUNT
					when '10004' then agmf.AMOUNT
					when '10005' then agmf.AMOUNT
					when '1006124' then agmf.AMOUNT
					when '1006886' then agmf.AMOUNT
					when '1011542' then agmf.AMOUNT
					when '1011587' then agmf.AMOUNT
					when '1011623' then agmf.AMOUNT
					when '1011629' then agmf.AMOUNT
					when '1011630' then agmf.AMOUNT
					when '1011631' then agmf.AMOUNT
					when '1011632' then agmf.AMOUNT
					when '1011633' then agmf.AMOUNT
					when '1011634' then agmf.AMOUNT
					when '1011635' then agmf.AMOUNT
					when '1012045' then agmf.AMOUNT	--AG 28/06/2019
					else 0 
			end as OpenWorkAmountDue,
			case ISNULL(agmf.PACC_ID,0) 
					when 0 then 
						case fipa.PayType 
							when 5 then 0
							when 6 then fipa.RecAmt 
							else fipa.RecAmt 
						end 
					else 0 
			end as NoAgmAmt,       
			case agmf.AGENT_CODE 
					when '1011543' then 0
                    when '10002' then 0
                    when '10004' then 0
                    when '10005' then 0
                    when '1006124' then 0
                    when '1006886' then 0
                    when '1011542' then 0
                    when '1011587' then 0
                    when '1011623' then 0
                    when '1011629' then 0
                    when '1011630' then 0
                    when '1011631' then 0
                    when '1011632' then 0
                    when '1011633' then 0
                    when '1011634' then 0
                    when '1011635' then 0
                    when '1012045' then 0	--AG 28/06/2019
                    else agmp.AMOUNT 
            end as AgentAmountPaid,
			case agmf.AGENT_CODE 
					when '1011543' then agmp.AMOUNT
                    when '10002' then agmp.AMOUNT
                    when '10004' then agmp.AMOUNT
                    when '10005' then agmp.AMOUNT
                    when '1006124' then agmp.AMOUNT
                    when '1006886' then agmp.AMOUNT
                    when '1011542' then agmp.AMOUNT
                    when '1011587' then agmp.AMOUNT
                    when '1011623' then agmp.AMOUNT
                    when '1011629' then agmp.AMOUNT
                    when '1011630' then agmp.AMOUNT
                    when '1011631' then agmp.AMOUNT
                    when '1011632' then agmp.AMOUNT
                    when '1011633' then agmp.AMOUNT
                    when '1011634' then agmp.AMOUNT
                    when '1011635' then agmp.AMOUNT
                    when '1012045' then agmp.AMOUNT	--AG 28/06/2019
                    else 0 
            end as OpenWorkAmountPaid,
			tbeh.Amount as GrossAmtPayable             
	into	#StatementAmounts
	from	dbo.owt_Finance_S_PACC fipa 
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = fipa.PaccId
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID = agmf.ID
			left join dbo.sa_swift_S_STMTCT stmt on stmt.STATEMENT = fipa.Statement
			left join dbo.sa_swift_TempBACSExportHistory tbeh on tbeh.S_AGMPAY_ID = agmp.ID
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate	--AG 31/08/2017

	exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 3

	****************************************************************************/

	select 	sa.Statement,
			sum(sa.AgentAmountDue) as AgentAmountDue,
			sum(sa.OpenWorkAmountDue) as OpenWorkAmountDue,
			sum(sa.NoAgmAmt) as NoAgmAmt,
			sum(sa.AgentAmountPaid) as AgentAmountPaid,
			sum(sa.OpenWorkAmountPaid) as OpenWorkAmountPaid,
			sum(sa.GrossAmtPayable) as GrossAmtPayable 
	into	#StatementSummary
	from	#StatementAmounts sa
	group	by sa.Statement	

	exec msp_ProcessLog @PhaseLog, 'Temp Table 3 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/

	insert into dbo.sa_Finance_SumDaCommMarg
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		Statement,
		RecAmt,
		Unallocated,
		MatchedRecAmt,
		StatementTotal,
		AgentAmountDue,
		OpenWorkAmountDue,
		NoAgmAmt,
		AgentAmountPaid,
		OpenWorkAmountPaid,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select 	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month	--AG 31/08/2017
			@FinancialPeriodToDate as FinancialPeriodToDate,		--AG 31/08/2017
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			stat.STATEMENT,
			stat.RecAmt,
			stat.Unallocated,
			stat.MatchedRecAmt,
			stat.StatementTotal,
			ss.AgentAmountDue,
			ss.OpenWorkAmountDue,
			ss.NoAgmAmt,
			ss.AgentAmountPaid,
			ss.OpenWorkAmountPaid,
			ss.GrossAmtPayable,
			@DateLastUpdated as DateInserted,		--AG 31/08/2017
			@DateLastUpdated as DateLastUpdated		--AG 31/08/2017
	from	#StatementSummary ss
			inner join #Statements stat on stat.Statement = ss.Statement
			
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_TTBacsDate_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_TTBacsDate_1Off
	  Author:	A Groves
Date created:	07/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_TTBacsDate from table
				logi.FinstatReporting23TTBacsDate the original proof-of-concept table.
				
				It is called as follows:

				exec dbo.owp_Finance_TTBacsDate_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_TTBacsDate_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit,
		@LargeNegativeNumber		decimal(16,2),
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,0,'20168','2016-08-01'
	union all
	select 10,0,1,'20169','2016-09-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/	
		
		insert into dbo.owt_Finance_TTBacsDate
		(
			FinancialPeriodFromDate,
			FinancialPeriodToDate,
			LatestRowInd,
			BeforeOrAfterBACSTable,
			AgmfAmt,
			AgmpAmtPaid,
			AgmAmount,
			AgmpVatAmt,
			GrossAmtPayable,
			DateInserted,
			DateLastUpdated
		)
		select	@FinancialPeriodDestination as FinancialPeriodFromDate,
				@FinancialPeriodToDate as FinancialPeriodToDate,
				0 as LatestRowInd,			-- Toggled later
				BeforeOrAfterBACSTable,
				AgmfAmt,
				AgmpAmtPaid,
				AgmAmount,
				AgmpVatAmt,
				GrossAmtPayable,
				@DateLastUpdated as DateInserted,
				@DateLastUpdated as DateLastUpdated
		from	logi.FinstatReporting23TTBacsDate old
		where	old.FinancialPeriod = @FinancialPeriodSource
		
		-- Close the penultimate row (if there is one) and it is still active (the new row may
		-- be a re-introduction following a period of absence).

		update	old
			set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
											then @FinancialPeriodDestination-1							-- Then close it with the last day of last month
											else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
										 end,
				LatestRowInd = 0,														-- This is no longer the latest row, so reset the indicator
				DateLastUpdated = @DateLastUpdated										-- Update the audit info
		from	dbo.owt_Finance_TTBacsDate old
				inner join dbo.owt_Finance_TTBacsDate new		-- Don't join on a column that can change such as some sort of financial amount!!!
								on isnull(new.BeforeOrAfterBACSTable,'') = isnull(old.BeforeOrAfterBACSTable,'')
								and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
								and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
		where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

		-- Set the latest row indicator on the latest row.
		-- Note: DateLastUpdated is not updated here as this update is considered 
		--			part of the original insert
		
		update new
			set LatestRowInd = 1
		from	dbo.owt_Finance_TTBacsDate new
		where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
		and		new.LatestRowInd = 0
			
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_TTBacsDate_History]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_TTBacsDate_History
	  Author:	A Groves
Date created:	06/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_TTBacsDate directly (i.e. there
				is no staging table). This is because every month there are only two rows.
				
				I have noted that the SQL looks a bit weird because StandingOrderCode
				is in the Group By but serves no purpose. I have left the code identical
				to Trevor's proof-of-concept code to guarantee reconcilaition to it.

				It is called as follows:

				exec dbo.owp_Finance_TTBacsDate_History 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_TTBacsDate_History] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@LargeNegativeNumber		decimal(16,2),
		@FinancialPeriodFromDate	date,
		@FinancialPeriodEndDate		date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)		
set @FinancialPeriodEndDate		= dateadd(month, datediff(month, 0, getdate())-1, 0) - 1	
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		Insert rows into the history table directly

	****************************************************************************/

	insert into dbo.owt_Finance_TTBacsDate
	(
		FinancialPeriodFromDate,
		FinancialPeriodToDate,
		LatestRowInd,
		BeforeOrAfterBACSTable,
		AgmfAmt,
		AgmpAmtPaid,
		AgmAmount,
		AgmpVatAmt,
		GrossAmtPayable,
		DateInserted,
		DateLastUpdated
	)
	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
			@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			case isnull(tbeh.ID,-1) when -1 then 'Before Bacs Table' else 'After Bacs Table' end,
			sum(agmf.AMOUNT) as AgmfAmt,
			sum(agmf.AMOUNT_PAID) as AgmpAmtPaid,
			sum(agmp.AMOUNT) as AgmAmount,
			sum(agmp.VATAmount) as AgmpVatAmt,
			sum(tbeh.Amount) as GrossAmtPayable,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	FROM	dbo.sa_swift_S_AGMFIL agmf
			left join dbo.sa_swift_S_AGMPAY agmp on agmf.ID = agmp.AGMID
			left join dbo.sa_swift_TempBACSExportHistory tbeh on tbeh.S_AGMPAY_ID = agmp.ID   
	where	agmf.TYPE = 14
	group	by agmf.StandingOrderCode,case isnull(tbeh.ID,-1) when -1 then 'Before Bacs Table' else 'After Bacs Table' end
	order	by agmf.StandingOrderCode

	/****************************************************************************

		Close off the old row and make the new row active.
																		
	****************************************************************************/

	-- Close the penultimate row (if there is one) and it is still active (the new row may
	-- be a re-introduction following a period of absence).
	
	update	old
		set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
										then @FinancialPeriodEndDate								-- Then close it with the last day of last month	AG 21/09/2016
										else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
									 end,
			LatestRowInd = 0,																		-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated														-- Update the audit info
	from	dbo.owt_Finance_TTBacsDate old
			inner join dbo.owt_Finance_TTBacsDate new 
							on  isnull(new.BeforeOrAfterBACSTable,'') = isnull(old.BeforeOrAfterBACSTable,'')
							and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
							and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

	/****************************************************************************

		Set the latest row indicator on the latest row.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_Finance_TTBacsDate new
	where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
	and		new.LatestRowInd = 0
		
	/****************************************************************************

		Close any active rows for items that have dropped out. Note that that the LatestRowInd
		will be 1 and it must remain 1 as it is still the latest row - even though the item 
		has dropped out.
																			
	****************************************************************************/

	-- Can't happen so this code removed.
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_Finance_TTBacsDetails_1Off]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_Finance_TTBacsDetails_1Off
	  Author:	A Groves
Date created:	10/10/2016

		Type:	Financial Reporting 2016
		
 Description:   This proc populates table dbo.owt_Finance_TTBacsDetails from table
				logi.FinstatReporting25TTDetails the original proof-of-concept table.
				
				It is called as follows:

				exec dbo.owp_Finance_TTBacsDetails_1Off 'Openwork', 'Finance 2016'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_Finance_TTBacsDetails_1Off] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@FinancialPeriodSource		varchar(6),
		@FinancialPeriodDestination	datetime,
		@ProcessingPoint			int,
		@PeriodToProcess			int,
		@StopPoint					bit,
		@LargeNegativeNumber		decimal(16,2),
		@FinancialPeriodFromDate	date,
		@FinancialPeriodToDate		date,
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)
set @LargeNegativeNumber		= -9999999999.00
set @FinancialPeriodFromDate	= dateadd(month, datediff(month, 0, getdate())-1, 0)
set @FinancialPeriodToDate		= convert(date,'31/12/9999',103)
set @DateLastUpdated			= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		Define driver table

	****************************************************************************/

	create table #Driver
	(
		ProcessingPoint int,
		StartPoint bit,
		StopPoint bit,
		FinancialPeriodSource	varchar(6),
		FinancialPeriodDestination	datetime
	)

	--StartPoint will always be 1 on one and only one row. It should be zero on all other rows.
	--This data loader will start on the row where StartPoint = 1 and work forward from there
	--until the last period has been processed.

	--This proc relies on ProcessingPoint=1 always being the very first historic period. This
	--is because it is always loaded in full with only subsequent periods loading new or changed
	--rows.

	--StopPoint is the last period to be processed (the period is included).
	
	--StartPoint and StopPoint can both be set on the same row.
			
	insert into #Driver
	(
		ProcessingPoint,
		StartPoint,
		StopPoint,
		FinancialPeriodSource,
		FinancialPeriodDestination
	)
	select 1,1,0,'201512','2015-12-01'
	union all
	select 2,0,0,'20161','2016-01-01'
	union all
	select 3,0,0,'20162','2016-02-01'
	union all
	select 4,0,0,'20163','2016-03-01'
	union all
	select 5,0,0,'20164','2016-04-01'
	union all
	select 6,0,0,'20165','2016-05-01'
	union all
	select 7,0,0,'20166','2016-06-01'
	union all
	select 8,0,0,'20167','2016-07-01'
	union all
	select 9,0,0,'20168','2016-08-01'
	union all
	select 10,0,1,'20169','2016-09-01'
	
	select	@FinancialPeriodSource = d.FinancialPeriodSource,
			@FinancialPeriodDestination = d.FinancialPeriodDestination,
			@ProcessingPoint = d.ProcessingPoint,
			@StopPoint = d.StopPoint
	from	#Driver d
	where	d.StartPoint = 1
	
	set @PeriodToProcess = @@rowcount
	
	while @PeriodToProcess > 0
	begin
	
		/****************************************************************************

			Start transaction
																				
		****************************************************************************/

		BEGIN TRANSACTION
		
		/****************************************************************************
		
			Empty out the staging table

		****************************************************************************/
		
		if @ProcessingPoint = 1 
		begin
			insert into dbo.owt_Finance_TTBacsDetails
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				AgentCode,
				AgentName,
				AgmfAmt,
				AgmpVatAmt,
				CreateDateTime,
				DUE_DATE,
				AMOUNT,
				EXPORTED,
				EXPORT_DATE,
				PaymentDueDate,
				GrossAmtPayable,
				Notes,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					@FinancialPeriodToDate as FinancialPeriodToDate,
					1 as LatestRowInd,	-- Must be 1 first time through
					AgentCode,
					AgentName,
					AgmfAmt,
					AgmpVatAmt,
					CreateDateTime,
					DUE_DATE,
					AMOUNT,
					EXPORTED,
					EXPORT_DATE,
					PaymentDueDate,
					GrossAmtPayable,
					Notes,
					@DateLastUpdated as DateInserted,
					@DateLastUpdated as DateLastUpdated
			from	logi.FinstatReporting25TTDetails old
			where	old.FinancialPeriod = @FinancialPeriodSource
		end
		else
		begin
			insert into dbo.owt_Finance_TTBacsDetails
			(
				FinancialPeriodFromDate,
				FinancialPeriodToDate,
				LatestRowInd,
				AgentCode,
				AgentName,
				AgmfAmt,
				AgmpVatAmt,
				CreateDateTime,
				DUE_DATE,
				AMOUNT,
				EXPORTED,
				EXPORT_DATE,
				PaymentDueDate,
				GrossAmtPayable,
				Notes,
				DateInserted,
				DateLastUpdated
			)
			select	@FinancialPeriodDestination as FinancialPeriodFromDate,
					@FinancialPeriodToDate as FinancialPeriodToDate,
					0 as LatestRowInd,	-- Must be zero - will be toggled later
					old.AgentCode,
					old.AgentName,
					old.AgmfAmt,
					old.AgmpVatAmt,
					old.CreateDateTime,
					old.DUE_DATE,
					old.AMOUNT,
					old.EXPORTED,
					old.EXPORT_DATE,
					old.PaymentDueDate,
					old.GrossAmtPayable,
					old.Notes,
					@DateLastUpdated as DateInserted,
					@DateLastUpdated as DateLastUpdated
			from	logi.FinstatReporting25TTDetails old
					left join dbo.owt_Finance_TTBacsDetails new	--Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(new.AgentCode,'') = isnull(old.AgentCode,'')
									and	isnull(new.CreateDateTime,'') = isnull(old.CreateDateTime,'')
									and @FinancialPeriodDestination between new.FinancialPeriodFromDate and new.FinancialPeriodToDate	--This will ensure just one row is joined - but not joined if it has previously ended
			where	old.FinancialPeriod = @FinancialPeriodSource
			and		
			(
					new.ID is null						--There's no existing row for this item so add it
			or		isnull(new.AgentName,'') <> isnull(old.AgentName,'')
			or		isnull(new.AgmfAmt,@LargeNegativeNumber) <> isnull(old.AgmfAmt,@LargeNegativeNumber)
			or		isnull(new.AgmpVatAmt,@LargeNegativeNumber) <> isnull(old.AgmpVatAmt,@LargeNegativeNumber)
			or		isnull(new.Due_Date,'') <> isnull(old.Due_Date,'')
			or		isnull(new.Amount,@LargeNegativeNumber) <> isnull(old.Amount,@LargeNegativeNumber)
			or		isnull(new.Exported,'') <> isnull(old.Exported,'')
			or		isnull(new.Export_Date,'') <> isnull(old.Export_Date,'')
			or		isnull(new.PaymentDueDate,'') <> isnull(old.PaymentDueDate,'')
			or		isnull(new.GrossAmtPayable,@LargeNegativeNumber) <> isnull(old.GrossAmtPayable,@LargeNegativeNumber)
			or		isnull(new.Notes,'') <> isnull(old.Notes,'')
			)
		
			-- Close the penultimate row (if there is one) and it is still active (the new row may
			-- be a re-introduction following a period of absence).

			update	old
				set FinancialPeriodToDate =	case when old.FinancialPeriodToDate = @FinancialPeriodToDate	-- If row still open...
												then @FinancialPeriodDestination-1							-- Then close it with the last day of last month
												else old.FinancialPeriodToDate								-- ...Otherwise leave it with the existing closed date
											 end,
					LatestRowInd = 0,														-- This is no longer the latest row, so reset the indicator
					DateLastUpdated = @DateLastUpdated										-- Update the audit info
			from	dbo.owt_Finance_TTBacsDetails old
					inner join dbo.owt_Finance_TTBacsDetails new		-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(new.AgentCode,'') = isnull(old.AgentCode,'')
									and	isnull(new.CreateDateTime,'') = isnull(old.CreateDateTime,'')
									and new.FinancialPeriodToDate = @FinancialPeriodToDate	-- This....
									and	new.LatestRowInd = 0								-- ...and this, gives the newly added row
			where	old.LatestRowInd = 1													-- This is the penultimate row (if it exists)

			-- Set the latest row indicator on the latest row.
			-- Note: DateLastUpdated is not updated here as this update is considered 
			--			part of the original insert
			
			update new
				set LatestRowInd = 1
			from	dbo.owt_Finance_TTBacsDetails new
			where	new.FinancialPeriodToDate = @FinancialPeriodToDate		
			and		new.LatestRowInd = 0
			
			-- Close any active rows for events that have dropped out. Note that that the LatestRowInd
			-- will be 1 and it must remain 1 as it is still the latest row - even though the event 
			-- has dropped out.
			
			update new
				set FinancialPeriodToDate = @FinancialPeriodDestination-1,	-- Not present this month so close off as at the end of last month
					DateLastUpdated = @DateLastUpdated						-- Update the audit info
			from	dbo.owt_Finance_TTBacsDetails new
					left join logi.FinstatReporting25TTDetails old			-- Don't join on a column that can change such as some sort of financial amount!!!
									on  isnull(new.AgentCode,'') = isnull(old.AgentCode,'')
									and	isnull(new.CreateDateTime,'') = isnull(old.CreateDateTime,'')
									and old.FinancialPeriod = @FinancialPeriodSource
			where	new.FinancialPeriodToDate = @FinancialPeriodToDate		-- Active row - this excludes any rows already de-activated
			and		old.FinancialPeriod is null

		end
		
		/****************************************************************************

			End transaction
																				
		****************************************************************************/

		COMMIT TRANSACTION   			

		/****************************************************************************

			Log Progress
																				
		****************************************************************************/

		set @ProcessMessage	= @FinancialPeriodSource + ' Completed.'
		exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

		/****************************************************************************

			Check for another iteration
																				
		****************************************************************************/
		
		if @StopPoint = 1
		begin
			set @PeriodToProcess = 0
		end
		else
		begin
			set @ProcessingPoint = @ProcessingPoint + 1
			
			select	@FinancialPeriodSource = d.FinancialPeriodSource,
					@FinancialPeriodDestination = d.FinancialPeriodDestination,
					@StopPoint = d.StopPoint
			from	#Driver d
			where	d.ProcessingPoint = @ProcessingPoint
			
			set @PeriodToProcess = @@rowcount
		end
		
	end	--of while
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
