	case when substring(cast(convert(nvarchar, dateadd(mm,-4,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM03,
	case when substring(cast(convert(nvarchar, dateadd(mm,-5,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM04,
	case when substring(cast(convert(nvarchar, dateadd(mm,-6,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM05,
	case when substring(cast(convert(nvarchar, dateadd(mm,-7,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM06,
	case when substring(cast(convert(nvarchar, dateadd(mm,-8,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM07,
	case when substring(cast(convert(nvarchar, dateadd(mm,-9,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM08,
	case when substring(cast(convert(nvarchar, dateadd(mm,-10,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM09,
	case when substring(cast(convert(nvarchar, dateadd(mm,-11,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM10,
	case when substring(cast(convert(nvarchar, dateadd(mm,-12,@EndDate), 120) as varchar), 1, 7) = DueYrMth then dueamount else 0 end as RHAmtMinusM11,


	case when substring(cast(convert(nvarchar, dateadd(mm,-12,@EndDate), 120) as varchar), 1, 7) > DueYrMth then dueamount else 0 end as RHAmtBeforeMinusMonth11,
	case when substring(cast(convert(nvarchar, dateadd(mm,59,@EndDate), 120) as varchar), 1, 7) < DueYrMth then dueamount else 0 end as AmtOver5
into 	#FutureMonth
