	sum(Amtm17) as Month17,sum(Amtm18) as Month18,sum(Amtm19) as Month19,sum(Amtm20) as Month20,
	sum(Amtm21) as Month21,sum(Amtm22) as Month22,sum(Amtm23) as Month23,sum(Amtm24) as Month24,
	sum(Amtm25) as Month25,sum(Amtm26) as Month26,sum(Amtm27) as Month27,sum(Amtm28) as Month28,
	sum(Amtm29) as Month29,sum(Amtm30) as Month30,sum(Amtm31) as Month31,sum(Amtm32) as Month32,
	sum(Amtm33) as Month33,sum(Amtm34) as Month34,sum(Amtm35) as Month35,sum(Amtm36) as Month36,
	sum(Amtm37) as Month37,sum(Amtm38) as Month38,sum(Amtm39) as Month39,sum(Amtm40) as Month40,
	sum(Amtm41) as Month41,sum(Amtm42) as Month42,sum(Amtm43) as Month43,sum(Amtm44) as Month44,
	sum(Amtm45) as Month45,sum(Amtm46) as Month46,sum(Amtm47) as Month47,sum(Amtm48) as Month48,
	sum(Amtm49) as Month49,sum(Amtm50) as Month50,sum(Amtm51) as Month51,sum(Amtm52) as Month52,
	sum(Amtm53) as Month53,sum(Amtm54) as Month54,sum(Amtm55) as Month55,sum(Amtm56) as Month56,
	sum(Amtm57) as Month57,sum(Amtm58) as Month58,sum(Amtm59) as Month59,sum(Amtm60) as Month60,


	sum(AmtOver5) as Month61plus
into #TranMonth
from #futuremonth
group by tranid
order by tranid

create index TranID on #TranMonth(TranID2)

--select 'Done #Tranmonth',getdate()


Select 	ex.transactionid as TranID,
	
	sum(case
		-- Amended by AG 19/12/07 to add status 3		when ex.status in (2,3) and ex.amount_rec = 0 and ex.type in (2,17) then -1*ex.amount_due
		when ex.status in (2,3) and ex.amount_rec > 0 and ex.type in (2,17) then -1*ex.amount_rec
		when ex.status in (2,3) and ex.amount_rec < 0 and ex.type in (2,17) then ex.amount_rec
		when ex.status in (2,3) and ex.amount_rec <> 0 and ex.type in (1) then amount_rec else 0 end) as TotPaid,

	sum(case 
		-- Amended by AG 19/12/07
		when ex.status = 1 and ex.type = 17 then abs(ex.amount_due) 
		when ex.status in (2,3) and ex.type in (1) and ex.adjust in (1,2) then ex.amount_rec 
		when ex.status <> 1 and ex.type = 17 then abs(ex.amount_due) * -1
		when ex.type = 2 then abs(ex.amount_due) * -1  
		else ex.amount_due end) as TotDue,

	sum(case 
		-- Amended by AG 19/12/07 to add status 3
		when ex.status in (2,3) and ex.type = 1 and ex.adjust in (0) then ex.amount_due
		when ex.status in (2,3) and ex.type = 1 and ex.adjust in (1,2) then ex.amount_rec 
		when ex.status in (2,3) and ex.type in (2,17) and ex.amount_rec <> 0 then abs(ex.amount_rec) * -1 
		when ex.status in (2,3) and ex.type in (2,17) and ex.amount_rec = 0 then abs(ex.amount_due) * -1 
		else 0 end) as TotDuePaid,

	sum(case 
		-- Amended by AG 19/12/07
		when ex.status = 1 and ex.type = 17 then abs(ex.amount_due)
		when ex.status = 1 and ex.type = 1 then ex.amount_due
		when ex.status = 1 and ex.type = 2 then abs(ex.amount_due) * -1 
		else 0 end) as StilltoAccrue,

	min(case 
		when ex.date_due is not null then ex.date_due 
		else '1901/01/01' end) as FirstDueDate,

	min(case 
		when ex.date_due is not null and ex.status = 1 then ex.date_due end) as NextDueDate,

	sum(case 
		-- Amended by AG 19/12/07
		when ex.date_due between @startdate and @EndDate and ex.type = 1 and ex.adjust in (1,2) then ex.amount_rec 
		when ex.date_due between @startdate and @EndDate and ex.type = 17 and ex.status = 1 then abs(ex.amount_due) 
		when ex.date_due between @startdate and @EndDate and ex.status <> 1 and ex.type = 17 then abs(ex.amount_due) * -1 
		when ex.date_due between @startdate and @EndDate and ex.type = 2 then abs(ex.amount_due) * -1 
		else ex.amount_due end) as TotDueinPeriod,

	sum(case 
		when ex.date_due between @startdate and @EndDate and ex.status in (2,3) and ex.amount_rec = 0 and ex.type in (2,17) then -1*abs(ex.amount_due)
		when ex.date_due between @startdate and @EndDate and ex.status in (2,3) and ex.amount_rec <> 0 and ex.type in (2,17) then -1*abs(ex.amount_rec)
		when ex.date_due between @startdate and @EndDate and ex.status in (2,3) and ex.amount_rec <> 0 and ex.type in (1) then amount_rec else 0 end) as TotPaidinPeriod,

	sum(ex.[Distribution Allowance]) as FinStatTot1inPeriod,
	sum(ex.[Franchise Commission]) as FinStatTot7FC,
	sum(ex.[Openwork Margin]) as FinStatTot7OM
into 	#ExpTots
from 	#FinstatExp ex
where 	ex.type in (1,2,17) 
group by ex.transactionid
order by ex.transactionid

create index TranID on #ExpTots(TranID)
--select 'Done #ExpTots',getdate()

select 	un.transactionid as TranID,
	sum(case when ap.id is null then un.amount else 0 end) as AllUnpaid,
	sum(case when ap.exported <> 'T' then ap.amount else 0 end) as AllPaid,
	sum(case when ap.exported = 'T' then ap.amount else 0 end) as AllBACS,
	sum(case when un.agent_code <> 10002 and ap.id is null then un.amount else 0 end) as BusUnpaid,
	sum(case when un.agent_code <> 10002 and ap.exported <> 'T' then ap.amount else 0 end) as BusPaid,
	sum(case when un.agent_code <> 10002 and ap.exported = 'T' then ap.amount else 0 end) as BusBACS,
	sum(case when un.agent_code = 10002 and ap.id is null then un.amount else 0 end) as OWUnpaid,
	sum(case when un.agent_code = 10002 and ap.exported <> 'T' then ap.amount else 0 end) as OWPaid,
	sum(case when un.agent_code = 10002 and ap.exported = 'T' then ap.amount else 0 end) as OWBACS
into 	#Paid
from 	mstt_paymentspending un
	inner join #Trans t1 on un.transactionid = TranID
	--left outer join sa_swift_S_AGMPAY ap on ap.agmid = un.id          --MPC 08/07/2010	--MPC: 17/05/2012
	left outer join msit_S_AGMPAY ap on ap.agmid = un.id          --MPC 08/07/2010	--MPC: 17/05/2012
where 	un.transactionid is not null and un.transactionid <> 0
group by un.transactionid
order by un.transactionid

create index TranID on #Paid(TranID)
--select 'Done #Paid',getdate()


select 	t1.*,
	t3.TotPaid,
	t3.TotDue,
	t3.TotDuePaid,
	t3.StilltoAccrue,
	t3.FirstDueDate,
	t3.TotDueinPeriod,
	t3.TotPaidinPeriod,
	t3.FinStatTot1inPeriod,
	t3.FinStatTot7FC,
	t3.FinStatTot7OM,

	case 
		when t3.NextDueDate is null then t3.FirstDueDate 
		else t3.NextDueDate end as NextDueDate,

	case 
		when t3.NextDueDate is null then 0 
		when t3.NextDueDate <= t3.FirstDueDate and t3.TotPaid = 0 then 0 
		else datediff(mm,t3.FirstDueDate,t3.NextDueDate) end as MonthsPaid,

	t6.AllUnpaid as GrossUnpaidList,
	t6.AllPaid as GrossPaidList,
	t6.AllBACS as GrossBACS,
	t6.BusUnpaid as BusUnpaidList,
	t6.BusPaid as BusPaidList,
	t6.AllBACS as BusBACS,
	t6.OWUnpaid as OWUnpaidList,
	t6.OWPaid as OWPaidList,
	t6.AllBACS as OWBACS
	,t7.*
into #RHAccrual_MCNew
from 	#Trans t1 
	left outer join #ExpTots t3 on t3.tranid = t1.tranid
	left outer join #Paid t6 on t6.tranid = t1.tranid
	left outer join #TranMonth t7 on t7.tranid2 = t1.tranid
order by t1.caseid,t1.tranid

select * 
into #fe2
from #finstatexp fe1
where expectationid = (select max(expectationid) from #finstatExp
                       where transactionid = fe1.transactionid)

select 	rh1.*, fe2.ird
--, fe2.[product sub group] as SubGroup
into #finalht
from #RHAccrual_MCNew rh1
left outer join #fe2 fe2 on fe2.transactionid = rh1.tranid 
--where   (FinStatTot1inPeriod is not null and not finstattot1inperiod = 0) or		--MPC: 17/04/2008
--        (FinStatTot7FC is not null and not finstattot7fc =0) or 			--MPC: 17/04/2008
--	(FinStatTot7OM is not null and not finstattot7om = 0) 				--MPC: 17/04/2008 


insert owhot_FinanceFutureExpectations
(CaseID,ProviderRef,Product,Provider,InitPeriod,TranDA,TranID,TransType,Freq,Basis,Premium,SalesIssueDate,ShapeId,
--Shapedescription,
TFRate,TranTF,CreateDate,TotPaid,TotDue,TotDuePaid,StilltoAccrue,FirstDueDate,TotDueinPeriod,
TotPaidinPeriod,FinStatTot1inPeriod,FinStatTot7FC,FinStatTot7OM,NextDueDate,MonthsPaid,GrossUnpaidList,
GrossPaidList,GrossBACS,BusUnpaidList,BusPaidList,BusBACS,OWUnpaidList,OWPaidList,OWBACS,TranID2,
--DA


	[BeforeMinusMonth11] ,
	[MinusMonth11] ,
	[MinusMonth10] ,
	[MinusMonth09] ,
	[MinusMonth08] ,
	[MinusMonth07] ,
	[MinusMonth06] ,
	[MinusMonth05] ,
	[MinusMonth04] ,
	[MinusMonth03] ,
	[MinusMonth02] ,
	[MinusMonth01] ,
	[MinusMonth00] ,

--BeforeMonth01,
Month01,Month02,Month03,Month04,Month05,Month06,Month07,Month08,Month09,Month10,Month11,
Month12,Month13,Month14,Month15,Month16,Month17,Month18,Month19,Month20,Month21,Month22,Month23,Month24,
Month25,Month26,Month27,Month28,Month29,Month30,Month31,Month32,Month33,Month34,Month35,Month36,Month37,
Month38,Month39,Month40,Month41,Month42,Month43,Month44,Month45,Month46,Month47,Month48,Month49,Month50,
Month51,Month52,Month53,Month54,Month55,Month56,Month57,Month58,Month59,Month60,Month61plus,
ird,
--subgroup,
ComRate,
--Commission
	[BeforeMinusMonth11Com] ,
	[MinusMonth11Com] ,
	[MinusMonth10Com] ,
	[MinusMonth09Com] ,
	[MinusMonth08Com] ,
	[MinusMonth07Com] ,
	[MinusMonth06Com] ,
	[MinusMonth05Com] ,
	[MinusMonth04Com] ,
	[MinusMonth03Com] ,
	[MinusMonth02Com] ,
	[MinusMonth01Com] ,
	[MinusMonth00Com] ,


--	BeforeMonth01Com,
Month01Com,Month02Com,Month03Com,Month04Com,Month05Com,Month06Com,Month07Com,Month08Com,
Month09Com,Month10Com,Month11Com,Month12Com,Month13Com,Month14Com,Month15Com,Month16Com,Month17Com,Month18Com,
Month19Com,Month20Com,Month21Com,Month22Com,Month23Com,Month24Com,Month25Com,Month26Com,Month27Com,Month28Com,
Month29Com,Month30Com,Month31Com,Month32Com,Month33Com,Month34Com,Month35Com,Month36Com,Month37Com,Month38Com,
Month39Com,Month40Com,Month41Com,Month42Com,Month43Com,Month44Com,Month45Com,Month46Com,Month47Com,Month48Com,
Month49Com,Month50Com,Month51Com,Month52Com,Month53Com,Month54Com,Month55Com,Month56Com,Month57Com,Month58Com,
Month59Com,Month60Com,Month61PlusCom,StartDate,EndDate,LoadDate)

select *,

	BeforeMinusMonth11 * ComRate as BeforeMinusMonth11Com ,
	MinusMonth11 * ComRate as MinusMonth11Com ,
	MinusMonth10 * ComRate as MinusMonth10Com ,
	MinusMonth09 * ComRate as MinusMonth09Com ,
	MinusMonth08 * ComRate as MinusMonth08Com ,
	MinusMonth07 * ComRate as MinusMonth07Com ,
	MinusMonth06 * ComRate as MinusMonth06Com ,
	MinusMonth05 * ComRate as MinusMonth05Com ,
	MinusMonth04 * ComRate as MinusMonth04Com ,
	MinusMonth03 * ComRate as MinusMonth03Com ,
	MinusMonth02 * ComRate as MinusMonth02Com ,
	MinusMonth01 * ComRate as MinusMonth01Com ,
	MinusMonth00 * ComRate as MinusMonth00Com ,

		Month01 * ComRate as Month01Com,
		Month02 * ComRate as Month02Com,
		Month03 * ComRate as Month03Com,
		Month04 * ComRate as Month04Com,
		Month05 * ComRate as Month05Com,
		Month06 * ComRate as Month06Com,
		Month07 * ComRate as Month07Com,
		Month08 * ComRate as Month08Com,
		Month09 * ComRate as Month09Com,
		Month10 * ComRate as Month10Com,
 		Month11 * ComRate as Month11Com,
		Month12 * ComRate as Month12Com,
		Month13 * ComRate as Month13Com,
		Month14 * ComRate as Month14Com,
		Month15 * ComRate as Month15Com,
		Month16 * ComRate as Month16Com,
		Month17 * ComRate as Month17Com,
		Month18 * ComRate as Month18Com,
		Month19 * ComRate as Month19Com,
		Month20 * ComRate as Month20Com,
                Month21 * ComRate as Month21Com,
		Month22 * ComRate as Month22Com,
		Month23 * ComRate as Month23Com,
		Month24 * ComRate as Month24Com,
		Month25 * ComRate as Month25Com,
		Month26 * ComRate as Month26Com,
		Month27 * ComRate as Month27Com,
		Month28 * ComRate as Month28Com,
		Month29 * ComRate as Month29Com,
		Month30 * ComRate as Month30Com,
                Month31 * ComRate as Month31Com,
		Month32 * ComRate as Month32Com,
		Month33 * ComRate as Month33Com,
		Month34 * ComRate as Month34Com,
		Month35 * ComRate as Month35Com,
		Month36 * ComRate as Month36Com,
		Month37 * ComRate as Month37Com,
		Month38 * ComRate as Month38Com,
		Month39 * ComRate as Month39Com,
		Month40 * ComRate as Month40Com,
                Month41 * ComRate as Month41Com,
		Month42 * ComRate as Month42Com,
		Month43 * ComRate as Month43Com,
		Month44 * ComRate as Month44Com,
		Month45 * ComRate as Month45Com,
		Month46 * ComRate as Month46Com,
		Month47 * ComRate as Month47Com,
		Month48 * ComRate as Month48Com,
		Month49 * ComRate as Month49Com,
		Month50 * ComRate as Month50Com,
                Month51 * ComRate as Month51Com,
		Month52 * ComRate as Month52Com,
		Month53 * ComRate as Month53Com,
		Month54 * ComRate as Month54Com,
		Month55 * ComRate as Month55Com,
		Month56 * ComRate as Month56Com,
		Month57 * ComRate as Month57Com,
		Month58 * ComRate as Month58Com,
		Month59 * ComRate as Month59Com,
		Month60 * ComRate as Month60Com,
                Month61plus * ComRate as Month61PlusCom
		,@Startdate,@EndDate,getdate()
	from
	(
		Select *,
		case when coalesce(finstattot1inperiod ,0)<>0 and coalesce(finstattot7fc,0)<>0 
			then -1* finstattot7fc / finstattot1inperiod 
		     when coalesce(finstattot7fc,0)=0 and coalesce(finstattot1inperiod,0) <> 0 
	        	then -1
		     else 0 
		end as ComRate
--              from #RHAccrual_MCNew
	        from #finalht
	) Rate

END;
