/****** Object:  StoredProcedure [dbo].[owp_FinanceFutureExpectations_CH3917]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/****************************************************************************************************************

Future Expectations Report

Author:	M Cawood

Amendment History
				
Date		    Author		Description
----		    ------		-----------	
?			      R Hughes	Figures added for previous 12 months.
19/12/2007	A Groves	Wherever Status 2 is checked also check for Status 3.
						          Where Commission Type is 17 (Adjustment - Initial Commission) and Status
						          is 1 (Due) then make amount_due +ve rather than -ve.

17/04/2008	M Cawood	Remove processing that is causing Active Transactions to be dropped 

08/07/2010  M Cawood	Replace mstt_AgentPayments by sa_swift_S_AGMPAY

27/04/2011  M Cawood  Make @StartDate and @EndDate parameters.
                      If @EndDate is NULL then use value defined currently 
                      (last day of previous month)

*****************************************************************************************************************/


CREATE PROCEDURE [dbo].[owp_FinanceFutureExpectations_CH3917] 
	@StartDate	datetime,       --MPC: 27/04/2011
	@EndDate	datetime        --MPC: 27/04/2011
AS

set nocount on

--declare @StartDate datetime set @StartDate = '1 jan 2006'  --MPC: 27/04/2011    
--declare @EndDate datetime                                  --MPC: 27/04/2011

if @enddate is null     --MPC: 27/04/2011
begin                   --MPC: 27/04/2011
  set @enddate = dateadd(dd,-1,convert(datetime,convert(nvarchar(6), getdate(),112) + '01'))  -- End Date (last day of previous month)
end;                    --MPC: 27/04/2011

declare @Lastrun datetime;
set @lastrun = (select max(EndDate) from owhot_FinancefutureExpectations)

--declare @Basis varchar(1) set @Basis = 'L'			-- Level
--declare @Company varchar(10) set @Company = 'ZURICH NEW'	-- Default

IF @enddate > isnull(@lastrun,'31 dec 2005')
BEGIN

--select 'Starting',getdate()

-- DROP TEMP TABLES

IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
   DROP TABLE #IRD

IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
   DROP TABLE #Exp

IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
   DROP TABLE #Comms

IF OBJECT_ID('tempdb..#finalht') IS NOT NULL
   DROP TABLE #Finalht

IF OBJECT_ID('tempdb..#FinstatExp') IS NOT NULL
   DROP TABLE #FinstatExp

IF OBJECT_ID('tempdb..#Trans') IS NOT NULL
	drop table #Trans

IF OBJECT_ID('tempdb..#FutureExp') IS NOT NULL
	drop table #FutureExp

IF OBJECT_ID('tempdb..#FutureMonth') IS NOT NULL
	drop table #FutureMonth

IF OBJECT_ID('tempdb..#LastShapeRate') IS NOT NULL
	drop table #LastShapeRate

IF OBJECT_ID('tempdb..#ExpTots') IS NOT NULL
	drop table #ExpTots

IF OBJECT_ID('tempdb..#TranMonth') IS NOT NULL
	drop table #TranMonth

IF OBJECT_ID('tempdb..#Paid') IS NOT NULL
	drop table #Paid

IF OBJECT_ID('tempdb..#RHAccrual_MCNew') IS NOT NULL
	drop table #RHAccrual_MCNew

IF OBJECT_ID('tempdb..#fe2') IS NOT NULL
	drop table #fe2

--TRUNCATE WAREHOUSE TABLE

truncate table owhot_FinanceFutureExpectations

DECLARE @OD DATETIME
DECLARE @CD DATETIME

SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
	(TransactionID 	int, 
	Type 		tinyint, 
	IRD 		datetime,
	Primary Key (TransactionID,Type)
	)

insert #IRD
select 	TransactionID,
	Type,
	min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from	mstt_expectation
where	TransactionID is not null
	and Type in (1,2,17) 		--MPC: 17/04/2008
--	and Type is not null		--MPC: 17/04/2008
--	and CommType = @Basis
--	and COMP_CODE = @Company
group by TransactionID,
	Type


-- Calculate Margin percent for each Transaction
create table #Comms 
	(
	TransactionID 	int, 
	NetAmount 	decimal(15,2), 
	TotalAmount 	decimal(15,2), 
	Margin_Pct 	float,
	Primary Key (TransactionID)
	)

insert #Comms
select	TransactionID,
	sum(case GrossOrNet
		when 'N' then FixedAmount
		else 0
	end),
	sum(FixedAmount),
	case 
		when coalesce(sum(FixedAmount),0)<>0 then
			sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
			/
			sum(FixedAmount)
		else null	-- should this be null or 0 ?
		-- from UDF comments
		-- Set Margin % = 0 (i.e. Commission % = 100)
		-- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
	end
from	mstt_Commissions
where	CommissionType = 1
and Transactionid in (select distinct Transactionid from mstt_Expectation where type in (1,2,17))	--MPC: 17/04/2008
--	and CommType = @Basis
--	and ProductProviderCode = @Company
group by TransactionID


-- Table to store calculated data for each expectation
create table #Exp (
	ExpectationID	int,
	TransactionID	int,
	Type		tinyint,
	DisplayType	tinyint,
	ProviderCode	varchar(10) collate LATIN1_GENERAL_CI_AS,
	BasisCode	varchar(1) collate LATIN1_GENERAL_CI_AS,
	Basis		varchar(50) collate LATIN1_GENERAL_CI_AS,
	Amount_Due	decimal(15,2),
	Amount_Rec	decimal(15,2),
	Date_Due	datetime,
	Date_Recv	datetime,
	Margin_Pct	float,
	Margin_Due	decimal(15,2),
	Margin_Recv	decimal(15,2),
	Commission_Due	decimal(15,2),
	Commission_Recv	decimal(15,2),
	IRD		datetime,
	PolicyID	int,
	Status		tinyint,
	Adjust		tinyint
	)

insert #Exp
Select	e.ID,
	e.TransactionID,
	e.Type,
	CASE e.Type
		WHEN 1 THEN 1 -- IC
		WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
		WHEN 4 THEN 4 -- RC
		WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
		WHEN 10 THEN 10 -- Trail
		WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
	END , -- Display Type
	e.COMP_CODE,	-- provider code
	CASE
	        WHEN e.Type = 1 or e.Type=17 THEN pt.CommType
        	ELSE NULL
	END , -- Basis only relevant to initial commission
	CASE
        	WHEN e.Type = 1 or e.Type=17 THEN ISNULL(pt.CommissionTypeDesc, 'Unknown')
        	ELSE NULL
	END ,
	CASE
		-- Amended by AG 19/12/07
		WHEN e.type = 17 and e.Status = 1 then coalesce(abs(e.Amount_Due),0)
		WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
		ELSE COALESCE(abs(e.Amount_Due),0) * (-1)
	END,	-- Amount_Due
	CASE 
		WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
		ELSE COALESCE(e.Amount_Rec,0) * (-1)
	END,	-- Amount_Recv
	CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
	CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),	-- convert to "whole day" 
	c.Margin_Pct,	-- Margin Pct
	
	-- Amended by AG 19/12/07
	CASE	WHEN 	e.type in (1,17) -- Only calc margin if commission type is Initial Comm or IC Adj	
		THEN 	CASE 	WHEN e.Type = 17 and e.status = 1 
				THEN COALESCE(ABS(e.Amount_Due) * c.Margin_Pct,0)
				WHEN e.Type in (1,4,10)
				THEN COALESCE(e.Amount_Due * c.Margin_Pct,0)
				ELSE COALESCE(abs(e.Amount_Due) * -1 * c.Margin_Pct,0) END	
		ELSE 	0 	END
	, -- Margin Due

--	COALESCE(e.Amount_Due
--	* CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
--	* CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
--	, -- Margin Due

	COALESCE(e.Amount_Rec
	* CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
	* CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
	, -- Margin Recv

	-- Amended by AG 19/12/07
	COALESCE(
	CASE 	WHEN e.Type = 17 and e.status = 1 
		THEN 1
		WHEN e.Type in (1,4,10) 
		THEN 1 
		ELSE -1 END 
	* CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),abs(e.Amount_Due)) - convert(decimal(15,2),abs(e.Amount_Due) * c.Margin_Pct)) ELSE abs(e.Amount_Due) END
	,0) , -- Commission Due

--	COALESCE(
--	CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
--	* CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
--	,0) , -- Commission Due

	COALESCE(
	CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
	* CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
	,0) , -- Commission Recv

	i.IRD,	-- IRD
	pt.PolicyID,
	e.status,
	e.adjust
from	mstt_Expectation e
	inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
	left outer join mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork		--MPC: 17/04/2008
	left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
	left outer join #Comms c on e.transactionID = c.TransactionID

where	e.Type IN (1, 17)
--	and a.CompanyCode = 10002 -- Openwork		--MPC: 17/04/2008
--	and e.CommType = @Basis
--	and e.COMP_CODE = @Company        

create index ExpID on #exp(ExpectationID)
create index TranID on #exp(TransactionID)

--select 'Done #exp',getdate()

select	e.*,
	substring(cast(convert(nvarchar, e.IRD, 120) as varchar), 1, 7) as IRDYrMth,
	substring(cast(convert(nvarchar, e.IRD, 120) as varchar), 1, 4) as IRDYear,
	substring(cast(convert(nvarchar, e.IRD, 120) as varchar), 6, 2) as IRDMonth,
	substring(cast(convert(nvarchar, e.date_due, 120) as varchar), 1, 7) as DueYrMth,
	substring(cast(convert(nvarchar, e.date_due, 120) as varchar), 1, 4) as DueYear,
	substring(cast(convert(nvarchar, e.date_due, 120) as varchar), 6, 2) as DueMonth,

	ISNULL(ProductProviders.ReportingProductProviderName, 'Unknown') AS 'Provider',
	ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') AS 'Product',
	ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group',

	convert(decimal(15,2),
		case
			when	(e.Date_Recv <= @CD AND e.Amount_Rec <> 0.00)
				AND (	(e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
					OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
					OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
				)
			then	e.Amount_Rec * (-1)
			else	0
		end --RptCommRec,
		+
		case
			when	((e.Date_Recv > @CD AND e.Amount_Rec <> 0.00) OR e.Date_Recv IS NULL)
				AND (	(e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
					OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
				)
			then	e.Amount_Due * (-1)
			else	0
		end --RptCommDue,
		+
		case
			when
				(e.IRD < @OD 
		                 AND e.Date_Due < @OD
	        	         AND e.Date_Recv >= @OD
	                	 AND e.Date_Recv <= @CD
		                 AND e.Amount_Rec <> 0.00
	        	        )

			then	(e.Amount_Due - e.Amount_Rec)
			else	0
		end
	)
	AS 'Distribution Allowance',

	convert(decimal(15,2),
		case
			when	(e.Date_Recv <= @CD AND e.Amount_Rec <> 0.00)
				AND (	(e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
					OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
					OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
				)
			then	e.Commission_Recv
			else	0
		end --RptCommRec,
		+
		case
			when	((e.Date_Recv > @CD AND e.Amount_Rec <> 0.00) OR e.Date_Recv IS NULL)
				AND (	(e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
					OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
				)
			then	e.Commission_Due
			else	0
		end --RptCommDue,
		+
		case
			when
				(e.IRD < @OD 
		                 AND e.Date_Due < @OD
	        	         AND e.Date_Recv >= @OD
	                	 AND e.Date_Recv <= @CD
		                 AND e.Amount_Rec <> 0.00
	        	        )
			then	(e.Commission_Due - e.Commission_Recv) * (-1)
			else	0
		end
	) --RptCommOverDue
	AS 'Franchise Commission',

	convert(decimal(15,2),
		case
			when	(e.Date_Recv <= @CD AND e.Amount_Rec <> 0.00)
				AND (	(e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
					OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
					OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
				)
			then	e.Margin_Recv
			else	0
		end --RptMarginRec,
		+
		case
			when	((e.Date_Recv > @CD AND e.Amount_Rec <> 0.00) OR e.Date_Recv IS NULL)
				AND (	(e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
					OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
				)
			then	e.Margin_Due
			else	0
		end --RptMarginDue,
		+
		case
			when
				(e.IRD < @OD 
		                 AND e.Date_Due < @OD
	        	         AND e.Date_Recv >= @OD
	                	 AND e.Date_Recv <= @CD
		                 AND e.Amount_Rec <> 0.00
	        	        )
			then	(e.Margin_Due - e.Margin_Recv) * (-1)
			else	0
		end
	) --RptMarginOverDue
	AS 'Openwork Margin'
into 	#FinstatExp
from 	#exp e
	LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = e.ProviderCode
	LEFT JOIN mstt_Policies Policies ON Policies.POL_NUM = e.PolicyID 
	LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON Policies.ProductGroupCode = CodeProductGroup.ProductGroupCode
	LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode

create index TranID on #FinstatExp(TransactionID)
--select 'Done #Finstatexp',getdate()


select codecommissionshapeid as ShapeID,max(id) as LastRateID
into #LastShapeRate
from msit_codecommissionshaperatehistory
group by codecommissionshapeid
order by codecommissionshapeid

select 
	po.policyref as CaseID,
	po.cont_num as ProviderRef,
	coalesce(po.productcode,pt.commproductcode) as Product,
	coalesce(po.comp_code,pt.commcompanycode) as Provider,
	pt.comminitialperiod as InitPeriod,
	pt.comminitialamount as TranDA,
	pt.ID as TranID,
	pt.TransType,
	case pt.frequency when 2 then 'Month' when 5 then 'Annual' when 6 then 'Single' end as Freq,
	case pt.commtype when 'F' then 'Accrual' when 'L' then 'Level' when 'T' then 'IT' end as Basis,
	pt.amount as Premium,
	ctd.transactiondate as SalesIssueDate,
	pt.codecommissionshapeid as ShapeId,
--        sh.Description as Shapedescription,
	sr.trailfeerate as TFRate,
	case when sr.trailfeerate <> 0 then 'With TF' when sr.trailfeerate = 0 then 'No TF' end as TranTF,
	pt.createdatetime as CreateDate
into 	#Trans
from 	mstt_policytransactions pt
	inner join mstt_policies po on po.pol_num = pt.policyid
	left outer join msit_codecommissionshape sh on sh.id = pt.codecommissionshapeid
	left outer join #LastShapeRate t1 on t1.shapeid = sh.id
	left outer join msit_codecommissionshaperatehistory sr on sr.id = t1.LastRateID
	left outer join mstt_commtraninitialdate ctd on ctd.id = pt.id
where pt.id in (select distinct Transactionid from mstt_Expectation where type not in (5,6)) 	--MPC: 17/04/2008 
--where	pt.CommType = @Basis
--	and coalesce(pt.commcompanycode,po.Comp_code) = @Company
order by pt.id

create index TranID on #Trans(TranID)

--select 'Done #trans',getdate()

select 	ex.transactionid as TranID,
	ex.DueYrMth,
	ex.DueYear,
	ex.DueMonth,
	-- Amended by AG 19/12/07
	cast(sum(case 	when ex.status = 1 and ex.type = 17 then abs(ex.amount_due)
			when ex.status = 1 and ex.type = 1 then ex.amount_due 
              		when ex.status = 1 and ex.type = 2 then abs(ex.amount_due) * -1 else 0 end) 
--	cast(sum(case 	when ex.status = 1 and ex.type = 1 then ex.amount_due 
--              		when ex.status = 1 and ex.type in (2,17) then abs(ex.amount_due) * -1 else 0 end) 
              as decimal(15,2)) as DueAmount
into 	#FutureExp
from 	#FinstatExp ex
	inner join #Trans t1 on t1.tranid = ex.transactionid
where 	ex.type in (1,2,17) 
	and ex.status = 1 
--	and ex.IRD <= @EndDate 		--MPC: 17/04/2008
--	and ex.Basis <> 'IT'		--MPC: 17/04/2008
group by ex.transactionid,
	ex.DueYrMth,
	ex.DueYear,
	ex.DueMonth,
	ex.date_due
order by ex.transactionid,
	ex.DueYrMth,
	ex.DueYear,
	ex.DueMonth,
	ex.date_due

create index TranID on #FutureExp(TranID)

--select 'Done #Futureexp',getdate()

