create index TranID on #FutureMonth(TranID)

--select 'Done #Futuremonth',getdate()

select TranID as TranID2,

	sum(RHAmtBeforeMinusMonth11) as BeforeMinusMonth11, 
	sum(RHAmtMinusM11) as MinusMonth11,
	sum(RHAmtMinusM10) as MinusMonth10,
	sum(RHAmtMinusM09) as MinusMonth09,
