/****** Object:  StoredProcedure [dbo].[owp_FinanceSSIS_Finstat38a_TablePopulation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************

Program:	owp_FinanceSSIS_Finstat38a_TablePopulation
			(based owp_BatchFINSTAT0038a by P Robathan 25/09/2008)           

Author:		A Groves

Date:		23/04/2019              
                      
Description: This program effectively replaces report FINSTAT0037a.  It is designed
				only to be called via a batch process to enable the Month End report 
				runs to be automated.

  This proc would be called as follows:

  declare @LastDayOfPrevMth varchar(8)
  select @LastDayOfPrevMth = dbo.owf_LastDayOfPrevMth(getdate())
  exec owp_FinanceSSIS_Finstat38a_TablePopulation 'Openwork', 'Finance 2016', '20060101', @LastDayOfPrevMth
  
  Where 20060101 is always the same but the second date is the month end date
  The report is designed to produce a report of the transactions for Access Agents plus 
  Practice Unwind Sales.  Any Franchise with a MCV Date <= '1 Jun 2005' will be treated as
  company AFML (Access Franchise Mgtmt Ltd) and any after this will be OAL (Openwork Access
  Ltd).       
        
  Note: As Openwork have separated from Zurich as of April 2018, the AFML files are no longer produced.
  
  Amendment History               
  -----------------               
                      
  Date			Who     Description       
  ----			---     ----------- 
  12/02/2009	PR		Add an extra report plus remove some of the filters when producing Agents table   
  24/02/2016	PR		Add changes as requested by Jacinta Magee and Pat Thompson
  
***************************************************************************/ 

CREATE  PROCEDURE [dbo].[owp_FinanceSSIS_Finstat38a_TablePopulation] 
  @Client     varchar(50),
  @Module     varchar(50),
  @StartDate    varchar(10),
  @EndDate    varchar(10)

as

set nocount on

declare	@PhaseStart			varchar(50),
		@PhaseEnd			varchar(50),
		@Process			varchar(100),
		@OWDate				datetime,
		@DateInserted		datetime

/****************************************************************************

  Set initial parameters                                
                                    
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd		= 'END'
set @Process		= object_name(@@procid)
Set @OWDate			= '1 Jun 2005'
set @DateInserted	= GETDATE()

/****************************************************************************

  Log start                               
                                    
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

  Select data
                                    
****************************************************************************/

-- Derive Access Agent List
select	Code as AccessAgentCode, 
		MCVDate,
		isnull(TradingName, Descn) as AccessAgentName,
		OscarAgentPrefix + OscarAgentSerial + OscarAgentSuffix as OscarCode
into	#AccessAgents  
from	mstt_Agents
where	AgentType = 46
and		CompetentStatus in (1,2)

-- Derive Access Sellers List
select	ahh.AgentCode as SellerCode,
		aa.AccessAgentCode,
		min(StartDate) as AccessStartDate,
		max(EndDate) as AccessEndDate 
into	#AccessSellers
from	msit_AgentHierarchyHistory ahh
		inner join #AccessAgents aa on ahh.DetailAgentCode = aa.AccessAgentCode
where	ahh.DefaultValue = 1 
and		ahh.ParticipantType = 9
group	by ahh.AgentCode, aa.AccessAgentCode

-- Derive Seller Previous Business
select	sub.SellerCode,
		ahh.DetailAgentCode as PreviousBusiness
into	#AccessPreviousBusiness
from	msit_AgentHierarchyHistory ahh
		inner join (select	ahh1.AgentCode as SellerCode,
							ahh1.ParticipantType,
							max(ahh1.EndDate) as MaxEndDate
					from	msit_AgentHierarchyHistory ahh1
							inner join #AccessSellers acs on ahh1.AgentCode = acs.SellerCode
					where	ahh1.EndDate is not null
					and		ahh1.EndDate < acs.AccessStartDate    
					and		ahh1.ParticipantType in (6,7,8)
					group	by ahh1.AgentCode, ahh1.ParticipantType) as sub
					on ahh.AgentCode = sub.SellerCode
					and ahh.ParticipantType = sub.ParticipantType
					and ahh.EndDate = sub.MaxEndDate

--Combine all these
select	aa.AccessAgentCode,
		aa.AccessAgentName,
		aa.MCVDate,
		acs.SellerCode,
		acs.AccessStartDate,
		acs.AccessEndDate,
		apb.PreviousBusiness,
		aa.OscarCode
into	#AccessDetails
from	#AccessSellers acs
		left join #AccessAgents aa on acs.AccessAgentCode = aa.AccessAgentCode
		left join #AccessPreviousBusiness apb on acs.SellerCode = apb.SellerCode

update	#AccessDetails
	set PreviousBusiness = m.MCVUID
from	#AccessDetails a
		inner join dbo.owt_Finance_Finstat38a_MCVTakers m on a.AccessAgentCode = m.PAAgentUID

-- get data for business from openworkadviserlisting
select	oal1.BusinessCode,
		oal1.BusinessName,
		ad.OscarCode,
		oal1.ProdType,
		oal1.PayBasis,
		m.Description as 'FeeType',
		oal1.Frequency,
		oal1.TotalPayment,
		oal1.Month,
		oal1.CreateDate,
		ad.MCVDate,
		Case when ad.MCVDate <= @OWDate then 'AFML' else 'OAL' end as Company,
		'Agency Period Sales' as ReportType, 
		oal1.Source
into	#oal1
from	msit_OpenworkAdviserListing oal1
		inner join (select distinct AccessAgentCode, OscarCode, MCVDate from #AccessDetails) ad on ad.AccessAgentCode = oal1.BusinessCode
		inner join msit_commissionstatement cs on cs.id = oal1.SourceID
		inner join msit_MIWarehouseCodesAndDescriptions m on m.Code = cs.commissionType
where	oal1.CreateDate between  @StartDate and @EndDate
and		oal1.Source = 'Openwork 2006'
and		m.Columnname = 'CommissionType'

-- get previous business from openworkadviserlisting
select	oal.BusinessCode,
		oal.BusinessName,
		a.OscarAgentPrefix + a.OscarAgentSerial + a.OscarAgentSuffix as OscarCode,
		oal.ProdType,
		oal.PayBasis,
		m.Description as 'FeeType',
		oal.Frequency,
		oal.TotalPayment,
		oal.Month,
		oal.CreateDate,
		ad.MCVDate,
		Case when ad.MCVDate <= @OWDate then 'AFML' else 'OAL' end as Company,
		'Practice Asset Unwind' as ReportType,
		oal.source
into	#oal2
from	msit_OpenworkAdviserListing oal
		inner join (select distinct PreviousBusiness, MCVDate from #AccessDetails) ad on ad.PreviousBusiness = oal.BusinessCode and ad.MCVDate <= oal.Createdate 
		inner join mstt_Agents a on a.code = ad.PreviousBusiness
		inner join msit_CommissionStatement cs on cs.id = oal.SourceID
		inner join msit_MIWarehouseCodesAndDescriptions m on m.Code = cs.commissionType
where	oal.CreateDate between @StartDate and @EndDate
and		oal.Source = 'Openwork 2006'
and		m.Columnname = 'CommissionType'

-- get data for business from openworkbankdetails
select	opd.BusinessCode,
		opd.BusinessName,
		opd.BusinessEcode as OscarCode,
		opd.TransactionType,
		opd.Amount,
		opd.Month,
		opd.TransactionDate,
		ad.MCVDate,
		Case when ad.MCVDate <= @OWDate then 'AFML' else 'OAL' end as Company,
		'Agency Period Sales' as ReportType,
		replace(replace(replace(Notes,',',' '),char(10),' '),char(13),' ') as Notes
into	#opd
from	msit_OpenworkBankDetails opd
		inner join (select distinct AccessAgentCode, OscarCode, MCVDate from #AccessDetails) ad on ad.AccessAgentCode = opd.BusinessCode
where	opd.Transactiondate between @StartDate and @EndDate
and		opd.Source in ('Openwork 2006')
and		opd.PaymentType not in ('0','90','99')
order	by opd.BusinessCode, opd.TransactionType, opd.TransactionDate

-- get previous business from openworkbankdetails
select	opd.BusinessCode,
		opd.BusinessName,
		opd.BusinessEcode as OscarCode,
		opd.TransactionType,
		opd.Amount,
		opd.Month,
		opd.TransactionDate,
		ad.MCVDate,
		Case when ad.MCVDate <= @OWDate then 'AFML' else 'OAL' end as Company,
		'Practice Asset Unwind' as ReportType,
		replace(replace(replace(Notes,',',' '),char(10),' '),char(13),' ') as Notes
into	#opd1 
from	msit_OpenworkBankDetails opd
		inner join (select distinct PreviousBusiness,OscarCode,MCVDate from #AccessDetails) ad on ad.PreviousBusiness = opd.BusinessCode and ad.MCVDate <= opd.TransactionDate
where	opd.TransactionDate between @StartDate and @EndDate
and		opd.Source in ('Openwork 2006')
and		opd.PaymentType not in ('0','90','99')
order	by opd.BusinessCode, opd.TransactionType, opd.TransactionDate

----------------------------------------------------------------------------------------------------------------------
-- Persist the Commission Listing data for Report 9 - Acrual breakdown
----------------------------------------------------------------------------------------------------------------------

truncate table dbo.owt_Finance_Finstat38a_AccrualBreakdown

insert into dbo.owt_Finance_Finstat38a_AccrualBreakdown
(
	BusinessCode,
	BusinessName,
	OscarCode,
	FeeType,
	ProdType,
	PayBasis,
	Frequency,
	TotalPayment,
	Month,
	CreateDate,
	MCVDate,
	Company,
	ReportType,
	DateInserted
)
select	BusinessCode,
		BusinessName,
		OscarCode,
		FeeType,
		ProdType,
		PayBasis,
		Frequency,
		TotalPayment,
		Month,
		CreateDate,
		MCVDate,
		Company,
		ReportType, 
		@DateInserted
from	#oal1  
    
----------------------------------------------------------------------------------------------------------------------
-- Persist the Bank Details for Reports 7 and 8
----------------------------------------------------------------------------------------------------------------------

truncate table dbo.owt_Finance_Finstat38a_Bank

insert into dbo.owt_Finance_Finstat38a_Bank
(
	BusinessCode,
	BusinessName,
	OscarCode,
	TransactionType,
	Amount,
	Company,
	ReportType,
	Notes,
	DateInserted
)
select	BusinessCode,
		BusinessName,
		OscarCode,
		TransactionType,
		Amount,
		Company,
		ReportType,
		Notes,
		@DateInserted
from	#opd
where	Company = 'OAL' 

union all 

select	BusinessCode,
		BusinessName,
		OscarCode,
		TransactionType,
		Amount,
		Company,
		ReportType,
		Notes,
		@DateInserted
from	#opd1 
where	Company = 'OAL' 

----------------------------------------------------------------------------------------------------------------------
-- Persist the summary details for Reports 3 and 4
----------------------------------------------------------------------------------------------------------------------

truncate table dbo.owt_Finance_Finstat38a_Main

insert into dbo.owt_Finance_Finstat38a_Main 
(
	BusinessCode,
	BusinessName,
	OscarCode,
	Description,
	ProdType,
	ProductGroupName,
	PayBasis,
	FeeType,
	Frequency,
	SubTotal,
	Company,
	ReportType,
	Seq,
	DateInserted
)
select	oal1.businesscode,
		oal1.businessname,
		oal1.Oscarcode,
		'Commission Accrual' as Description,
		oal1.ProdType,
		p.ProductGroupName,
		oal1.PayBasis,
		oal1.feetype,
		oal1.frequency,
		sum(oal1.TotalPayment) as Subtotal,
		oal1.Company,
		oal1.ReportType, 
		case 
			when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
			when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
			when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
			when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
		end as Seq,
		@DateInserted as DateInserted
from	#oal1 oal1
		inner join mstt_ProductHierarchy p 
					on  p.productcode =  case
											  when oal1.source = 'openwork 2006' and oal1.prodtype = 'MORTGAGE' then 'NBI_MTG'
											  when oal1.source = 'openwork 2006' and oal1.prodtype is null then oal1.prodtype
											  when oal1.source = 'openwork 2006' and oal1.prodtype <> 'MORTGAGE' then oal1.prodtype
											  else oal1.prodtype
										 end
group	by oal1.BusinessCode, oal1.BusinessName, oal1.OscarCode, oal1.ProdType, p.ProductGroupName, oal1.PayBasis, oal1.FeeType, oal1.Frequency, oal1.Company, oal1.ReportType

union all

select	oal2.BusinessCode,
		oal2.BusinessName,
		oal2.OscarCode,
		'Commission Accrual' as Description,
		oal2.ProdType,
		p.ProductGroupName,
		oal2.PayBasis,
		oal2.FeeType,
		oal2.Frequency,
		sum(oal2.TotalPayment) as SubTotal,
		oal2.Company,
		oal2.ReportType, 
		case 
			when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
			when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
			when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
			when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
		end as Seq,
		@DateInserted as DateInserted
from	#oal2 oal2
		inner join mstt_ProductHierarchy p 
					on  p.productcode =  case
											  when oal2.source = 'openwork 2006' and oal2.prodtype = 'MORTGAGE' then 'NBI_MTG'
											  when oal2.source = 'openwork 2006' and oal2.prodtype is null then oal2.prodtype
											  when oal2.source = 'openwork 2006' and oal2.prodtype <> 'MORTGAGE' then oal2.prodtype
											  else oal2.prodtype
										 end
group by oal2.BusinessCode, oal2.BusinessName, oal2.OscarCode, oal2.ProdType, p.ProductGroupName, oal2.PayBasis, oal2.FeeType, oal2.Frequency, oal2.Company, oal2.ReportType

union all

select	opd.BusinessCode,
		opd.BusinessName,
		opd.OscarCode,
		opd.TransactionType as Description,
		'' as ProdType,
		'' as ProductGroupName,
		'' as PayBasis,
		'' as FeeType,
		'' as Frequency,
		sum(opd.Amount) as SubTotal,
		opd.Company,
		opd.ReportType,
		case 
			when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
			when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
			when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
			when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
		end as Seq,
		@DateInserted as DateInserted
from	#opd opd
group	by opd.BusinessCode, opd.BusinessName, opd.OscarCode, opd.TransactionType, opd.Company, opd.ReportType

union all

select	opd1.BusinessCode,
		opd1.BusinessName,
		opd1.OscarCode,
		opd1.TransactionType as Description,
		'' as ProdType,
		'' as ProductGroupName,
		'' as PayBasis,
		'' as FeeType,
		'' as Frequency,
		sum(opd1.Amount) as SubTotal,
		opd1.Company,
		opd1.ReportType, 
		case 
			when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
			when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
			when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
			when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
		end as Seq,
		@DateInserted as DateInserted
from	#opd1 opd1
group	by opd1.BusinessCode, opd1.BusinessName, opd1.OscarCode, opd1.TransactionType, opd1.Company, opd1.ReportType

-- create a summary Closing Balance record for each business in each report category 
insert into dbo.owt_Finance_Finstat38a_Main 
(
	BusinessCode,
	BusinessName,
	OscarCode,
	Description,
	ProdType,
	ProductGroupName,
	PayBasis,
	FeeType,
	Frequency,
	SubTotal,
	Company,
	ReportType,
	Seq,
	DateInserted
)
select	BusinessCode,
		BusinessName,
		OscarCode,
		'Closing Balance',
		' ',
		' ',
		' ',
		' ',
		' ',
		Sum(SubTotal)*-1,
		Company,
		ReportType,
		Seq,
		@DateInserted as DateInserted
from	dbo.owt_Finance_Finstat38a_Main 
group	by BusinessCode, BusinessName, OscarCode, Company, ReportType, Seq

