/*********************************************************************************************************

Program:	owp_FinanceSSIS_Finstat43
			(based on owp_BatchFINSTAT0043PlatformSeparation by A Groves on 22/11/2013) 
			(based on owp_BatchFINSTAT0043 by A Harrison on 02/03/09)            

Author:		A Groves
Date:		20/12/2018            

Description:	Finstat 43 converted from using xp--cmdshell to running in SSIS.
				Note: This stored proc is called by SSIS package "Finstat43ExportToExcel32Bit.dtsx".

Amendment History
-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE procedure [dbo].[owp_FinanceSSIS_Finstat43]

as

SELECT  stmt.STATEMENT, 
		stmt.COMP_CODE, 
		convert(varchar, stmt.STMNT_DATE,103) as STMNT_DATE, 
		convert(decimal(15,2), case when (stmt.COMP_CODE in ('IFDL','OPENWORK','ZURICH PLT') or left(isnull(stmt.Notes,''),2) = 'OW') then TOTAL else 0 end) as PLATFORM_TOTAL, 
		convert(decimal(15,2), case when not (stmt.COMP_CODE in ('IFDL','OPENWORK','ZURICH PLT') or left(isnull(stmt.Notes,''),2) = 'OW') then TOTAL else 0 end) as NON_PLATFORM_TOTAL, 
		convert(decimal(15,2), stmt.TOTAL) as TOTAL, 
		convert(decimal(15,2), stmt.TOT_INIT) as TOT_INIT, 
		convert(decimal(15,2), stmt.TOT_CLAWBK) as TOT_CLAWBK, 
		convert(decimal(15,2), stmt.TOT_RENEW) as TOT_RENEW, 
		convert(decimal(15,2), stmt.TOT_UNALL) as TOT_UNALL, 
		isnull(stmt.NOTES,'(NONE)') as NOTES 
FROM    dbo.sa_swift_S_STMTCT stmt
WHERE   (Deleted <> - 1) 
AND		(STMNT_DATE >= '1 January 2006') 
AND		(STMNT_DATE <= getdate())
ORDER	BY Stmnt_Date, Statement








