/*********************************************************************************************************

Program:	owp_FinanceSSIS_Finstat44b
			(based on  owp_BatchFINSTAT0044b by A Harrison on 03/03/09)            

Author:		A Groves
Date:		03/04/2019            

Description:	Finstat 44b converted from using xp--cmdshell to running in SSIS.
				Note: This stored proc is called by SSIS package "Finstat44bExportToExcel32Bit.dtsx".

Amendment History
-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE procedure [dbo].[owp_FinanceSSIS_Finstat44b]

as

SELECT  --top 20
		convert(nvarchar(7),so.agentcode) as AgentUID,
		so.id as SOID,
		convert(nvarchar(255),rtrim(coalesce(ag.tradingname,ag.descn))) as AgentName,
		convert(nvarchar(9),case ag.agt_type
			when 2 then 'Franchise'
			when 46 then 'Access'
			when 49 then 'DA'
			else 'Other'
		end) as AgentType,
		convert(nvarchar(6),case ag.competentstatus
			when 1 then 'Active'
			when 2 then 'Left'
			when 4 then 'Canc'
			when 5 then 'PreApp'
			when 6 then 'NPW'
		end) as AgentStatus,
		convert(nvarchar(7),ag.manager2code) as RSMUID,
		convert(nvarchar(255),rtrim(a2.descn)) as RSMName,
		convert(nvarchar(7),a2.manager4code) as ASDUID,
		convert(nvarchar(255),rtrim(a3.descn)) as ASDName,
		convert(nvarchar(8),so.StandingOrderCode) as SOCode,
		convert(nvarchar(50),so.Description) as Description,
		convert(nvarchar(8),co.Description) as SOType,
		convert(nvarchar(10),so.startdate,103) as StartDate,
		convert(nvarchar(10),so.EndDate,103) as EndDate,
		convert(nvarchar(10),so.nextpaymentDue,103) as NextPaymentOn,
		convert(nvarchar(3),case so.Frequency
			when 2 then 'Mth'
			when 5 then 'Ann'
			when 6 then 'Sin'
			else 'Oth'
		end) as SOFreq,
		so.paymentamount as SOAmount,
		so.Totalpaymentamount as SOTotalAmount,
		so.amountpaidtodate as SOPaidToDate,
		convert(nvarchar(1),case so.subjecttovat
			when 0 then 'N'
			when 1 then 'Y'
		end) as VATable,
		un.amount as UnpaidAmount,
		convert(nvarchar(10),un.paymentduedate,103) as UnpaidPaymentDue,
		convert(nvarchar(3),case when un.paymentduedate is not null and un.paymentduedate > so.EndDate
			then 'Yes'
		end) as PastEndDate,
		convert(nvarchar(10), pa.export_date,103) as BACSDate,
		convert(nvarchar(10), un.createdatetime,103) as UnpaidCreatedDate,
		convert(nvarchar(4),case so.authorised 
			when 0 then 'Auth' 
			when 1 then 'Decl' 
			when 2 then 'O/S'
		end) as AuthStatus,
		convert(decimal(12,2),un.amount) as UnpaidListAmount,
		convert(decimal(12,2),pa.vatamount) as VatAmount,
		convert(decimal(12,2),pa.netamount) as NetAmount,
		convert(decimal(12,2),pa.amount) as PaidAmount
FROM	msit_CommAgentStandingOrders so
		inner join msit_S_Agents ag on ag.code = so.agentcode
		inner join msit_CodeStandingOrders co on co.code = so.standingordercode
		left outer join msit_S_Agmfil un on un.agent_code = so.agentcode and un.standingorderid = so.id
		left outer join msit_S_Agmpay pa on pa.agmid = un.id
		inner join msit_S_Agents a2 on a2.code = ag.manager2code
		inner join msit_S_Agents a3 on a3.code = a2.manager4code
order by pa.export_date	--BACSDate










GO
