		left outer join msit_S_Agmfil un on un.agent_code = so.agentcode and un.standingorderid = so.id
		left outer join msit_S_Agmpay pa on pa.agmid = un.id
		inner join msit_S_Agents a2 on a2.code = ag.manager2code
