/****** Object:  StoredProcedure [dbo].[owp_FinanceSSIS_Finstat60]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/****************************************************************************************
Program:		owp_FinanceSSIS_Finstat60
				(based on cscp_ExpensesReimbursed by M Cawood on 09/02/2011)
											
Description:	Finstat 60
				Cater for variable VAT Rates as per owp_BatchFINSTAT0052: 

                Derive VAT Rates from msit_MIWarehouseCodesandDescriptions 
                and store for use against each Payment.
                        
                Determine VAT Rate according to the PaymentDueDate held on 
                the mstt_PaymentsPending table (defaulting to CreateDatetime
                if not set or dummy date (i.e. prior to 1 Jan 2005). If
                Payment on S_AGMPAY derive VAT Rate by deriving VATAmount
                into NetAmount and rounding to 2 dec places. Default values to
                15%, 17.5% or 20% to cater for rounding differences.
                        
                Default Net Amount to value held on S_AGMPAY table if present
                as this represents the actual value derived on SWIFT.
	
****************************************************************************************/
CREATE   PROCEDURE [dbo].[owp_FinanceSSIS_Finstat60]
AS
BEGIN
	DECLARE 
	@StartDt DATETIME = '20060101',
	@EndDt DATETIME = dbo.owf_LastDayOfPrevMth(GETDATE());

	WITH VAT AS
	(
	SELECT 
		 CONVERT(DECIMAL(8,2),ShortDescription) AS VATRate
		,CONVERT(DATETIME,Code,111) AS StartDate
		,CONVERT(DATETIME,Description,111) AS EndDate
	FROM	dbo.msit_MIWarehouseCodesandDescriptions
	WHERE	ColumnName = 'VATRate'
	AND		ShortDescription IS NOT NULL
	AND		Description IS NOT NULL
	)
	, OTH0001 AS
	(
	SELECT
		 LTRIM(ISNULL(PaymentsPending.StandingOrderCode, 'Unknown')) + ' / ' + ISNULL(PaymentsPending.StandingOrderCodeDesc, 'Unknown') AS [Standing Order]
		,CASE 
			WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.Code
			ELSE Agents.Code 
		 END AS [Enterprise Code]
		,CASE
			WHEN agents.Firm IS NOT NULL AND RTRIM(agents.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown'))
			ELSE RTRIM(ISNULL(Agents.DESCN, 'Unknown'))
		 END AS [Enterprise Name]
		,CAST(PaymentsPending.Amount AS DECIMAL(15,2)) AS [GrossAmount]
		,NULL AS [VAT]
		,CAST(	CASE
					WHEN PaymentsPending.SubjectToVAT = 1 AND ISNULL(PA.NetAmount,0) <> 0 THEN PA.NetAmount
					WHEN PaymentsPending.SubjectToVAT = 1 THEN PaymentsPending.Amount / (1.00 + (V.VATRate / 100.00))
					ELSE PaymentsPending.Amount
				END 
				AS DECIMAL(15,2)
			) AS [NetAmount]
		,CASE
			WHEN PaymentsPending.SubjectToVAT = 1 AND ISNULL(PA.NetAmount,0) <> 0 THEN ROUND(100*(ISNULL(PA.VATAmount,0)/PA.NetAmount) ,2)
			WHEN PaymentsPending.SubjectToVAT = 1 THEN V.VATRate
		 END AS [VATRate]
	FROM		dbo.mstt_PaymentsPending PaymentsPending 
	LEFT JOIN	dbo.mstt_agents AS agents ON PaymentsPending.Agent_Code = agents.code
	LEFT JOIN	dbo.mstt_agents AS agents_fr ON agents.Firm = agents_fr.code
	LEFT JOIN	VAT V ON DATEADD(dd,0,DATEDIFF(dd,0,CASE WHEN PaymentsPending.PaymentDueDate >= '1 Jan 2005' THEN PaymentsPending.PaymentDueDate ELSE PaymentsPending.CreateDatetime END)) BETWEEN V.StartDate AND V.EndDate
	LEFT JOIN	dbo.sa_swift_S_AGMPAY PA ON PA.AGMID = PaymentsPending.ID
	WHERE	PaymentsPending.CommissionType = 8
	AND		CAST(PaymentsPending.PaymentDueDate AS DATE) BETWEEN @StartDt AND @EndDt
	)
	SELECT 
		 [Standing Order] AS [Standing Order]
		,[Enterprise Code] AS [Enterprise Code]
		,[Enterprise Name] AS [Enterprise Name]
		,ISNULL(SUM(ISNULL(CAST([GrossAmount] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Amount]
		,ISNULL(SUM(ISNULL(CAST([GrossAmount] AS DECIMAL(15,2)), 0.00)), 0.00) - ISNULL(SUM(ISNULL(CAST([NetAmount] AS DECIMAL(15,2)), 0.00)), 0.00) AS [VAT]
		,ISNULL(SUM(ISNULL(CAST([NetAmount] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Net Amount]
		,CASE
			WHEN [VATRate] BETWEEN 17.3 AND 17.7 THEN 17.50
			WHEN [VATRate] BETWEEN 14.8 AND 15.2 THEN 15.00
			WHEN [VATRate] BETWEEN 19.8 AND 20.2 THEN 20.00
			ELSE [VATRate] 
		 END AS [Error]
	FROM	OTH0001
	WHERE	[GrossAmount] <> 0.00 /* Display only non-zero values */
	GROUP BY 
		 [Standing Order]
		,[Enterprise Code]
		,[Enterprise Name]
		,CASE
			WHEN [VATRate] BETWEEN 17.3 AND 17.7 THEN 17.50
			WHEN [VATRate] BETWEEN 14.8 AND 15.2 THEN 15.00
			WHEN [VATRate] BETWEEN 19.8 AND 20.2 THEN 20.00
			ELSE [VATRate] 
		 END
	ORDER BY
		 [Standing Order]
		,[Enterprise Code]
		,[Enterprise Name]
		;
END
GO
/****** Object:  StoredProcedure [dbo].[owp_FinstatFixExpSign]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owp_FinstatFixExpSign]

as

/*

RH 27 Nov 2007
Proc called from various Finstat procs to apply sign to figures that should be negative

*/

set nocount on

declare @TableID int

select  @TableID = OBJECT_ID('tempdb..#Exp')

if exists (select * from tempdb..syscolumns where id = @TableID and name='Amount_Due')
begin
exec sp_ExecuteSQL N'
  update #Exp
  set Amount_Due = 
    CASE
      WHEN Type in (17,18,19) and status = 1 THEN COALESCE(Amount_Due,0)
      ELSE COALESCE(Amount_Due,0) * (-1)
    END
  where type not in (1,4,10) -- Minimise amount of actual updates being done
'
end


if exists (select * from tempdb..syscolumns where id = @TableID and name='Margin_Due')
begin
exec sp_ExecuteSQL N'
  update #Exp
  set Margin_Due = 
    CASE
      WHEN Type in (17,18,19) and status = 1 THEN COALESCE(Margin_Due,0)
      ELSE COALESCE(Margin_Due,0) * (-1)
    END
  where type not in (1,4,10) -- Minimise amount of actual updates being done
'
end


if exists (select * from tempdb..syscolumns where id = @TableID and name='Commission_Due')
begin
exec sp_ExecuteSQL N'
  update #Exp
  set Commission_Due = 
    CASE
      WHEN Type in (17,18,19) and status = 1 THEN COALESCE(Commission_Due,0)
      ELSE COALESCE(Commission_Due,0) * (-1)
    END
  where type not in (1,4,10) -- Minimise amount of actual updates being done
'
end

GO
