/****************************************************************************
  	 Program:  	owp_GetDatabaseDetails						
	  Author:	A Groves
Date created:	28/04/2008							
											
 Description:   The purpose of this proc is to read table mst_ImportControl
				to identify what environment the proc is running in (i.e. IT, 
				UAT or PROD) in case there is any environment specific
				processing to do.

			It is called as follows:

			exec owp_GetDatabaseDetails 'Openwork', 'Swift', @database output,
										@server output, @environment output
									
	Amendment History								
	-----------------								
											
	Date		Who			Description				
	----		---			-----------			
	12/05/2008	A Groves	Added in check for Yoda Document Archive.  Database
							name is the same so determine via server name.
	14/01/2011	A Groves	Removed @environment hardcoding.
****************************************************************************/

CREATE PROCEDURE [dbo].[owp_GetDatabaseDetails]	@Type varchar(50), 
												@Module varchar(50),
												@Database varchar(50) output,
												@server varchar(50) output,
												@environment varchar(50) output
AS
BEGIN

set nocount on

select	@database		= [database],
		@server			= [server],
		@environment	= Environment
from	mst_ImportControl
where	Type = @Type
and		Module = @Module

END


