/****** Object:  StoredProcedure [dbo].[owp_GetDependantUsers]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_GetDependantUsers](@UserID uniqueidentifier)
as
begin
  set nocount on;

  --Declare variables
  declare @BaseHNL    uniqueidentifier;
  declare @BaseUPs    uniqueidentifier;
  declare @ReportDate datetime;
  declare @LevelID    smallint;
  declare @RowCount   int;
  declare @UserTypeId int;
  declare @DIST_ID    uniqueidentifier;
  
  --Declare variable tables
  declare @Hierarchy table(NodeID   uniqueidentifier not null, -- primary key nonclustered,
                           ParentID uniqueidentifier null,
                           LevelID  smallint not null,
                           DIST_ID  uniqueidentifier null);
  
  declare @Ret table(PTLCode        varchar(20),
                     Name           varchar(20),
                     Address        varchar(20),
                     Title          varchar(20),
                     Qualifications varchar(20),
                     EnterpriseName varchar(20));

  begin try
    --Initialize variables
    set @LevelID    = 0;
    set @DIST_ID    = null;
    set @ReportDate = dateadd(day, datediff(day, 0, getdate()), 0);
    
    --Get UserTypeId for UserType= 'PA'
    select top 1
           @UserTypeId = convert(int, c.Code_Code)
    from dbo.sa_insight_CodeType t with(nolock)
         inner join dbo.sa_insight_CodeDescription c with(nolock) on c.Code_CodeType    = t.CT_Code and
                                                                     c.Code_Description = 'PA'
    where t.CT_Description = 'User Type'
    order by t.CT_CreatedDate   desc,
             c.Code_CreatedDate desc;
    
    --Get sa_insight_HierarchyNodeLink for @UserID
    select @BaseUPs = p.UPS_ID,
           @BaseHNL = nl.HNL_NodeID
    from dbo.sa_insight_UserPosition p with(nolock)
         inner join dbo.sa_insight_HierarchyNodeLink nl with(nolock) on nl.HNL_ParentID  = p.UPS_ID and
                                                                        nl.HNL_Type      = 5 and --Person --> OU
                                                                        @ReportDate between isnull(nl.HNL_DateFrom, '19000101') and isnull(nl.HNL_DateTo, '99991231')
    where p.UPS_UserID    = @UserID and
          p.UPS_UserType  = @UserTypeId and
          p.UPS_Enabled   = 1 and
          @ReportDate between isnull(p.UPS_DateFrom, '19000101') and isnull(p.UPS_DateTo, '99991231');
  
    --Read details if the person is: found, 'PA', enabled and active in the report day
    if @BaseHNL is not null
    begin
      --Insert current level of OU Hierarchy - level 0
      insert into @Hierarchy(NodeID,
                             ParentID,
                             LevelID,
                             DIST_ID)
      select NodeID   = nl.HNL_NodeID,
             ParentID = nl.HNL_ParentID,
             LevelID  = @LevelID,
             DIST_ID  = null
      from dbo.sa_insight_HierarchyNodeLink nl with(nolock)
      where nl.HNL_NodeID = @BaseHNL and
            nl.HNL_Type   = 0 and   --OU Hierarchy
            @ReportDate between isnull(nl.HNL_DateFrom, '19000101') and isnull(nl.HNL_DateTo, '99991231');
      
      --Check if anything inserted
      set @RowCount = @@rowcount;
      
      --Build OU Hierarchy down
      while @RowCount > 0
      begin
        insert into @Hierarchy(NodeID,
                               ParentID,
                               LevelID,
                               DIST_ID)
        select NodeID   = nl.HNL_NodeID,
               ParentID = nl.HNL_ParentID,
               LevelID  = @LevelID + 1,
               DIST_ID  = null
        from @Hierarchy h
             inner join dbo.sa_insight_HierarchyNodeLink nl  with(nolock) on nl.HNL_ParentID  = h.NodeID and
                                                                             nl.HNL_Type      = 0 and --OU Hierarchy
                                                                             nl.HNL_DateFrom <= @ReportDate and
                                                                             isnull(nl.HNL_DateTo, '99991231') >= @ReportDate
        where h.LevelID = @LevelID;
        
        set @RowCount = @@rowcount;
        set @LevelID = @LevelID + 1;
      end;

      --Find the closest distributor
      set @LevelID  = 0;
      set @RowCount = 1;
      
      while @RowCount > 0 and @DIST_ID is null
      begin 
        insert into @Hierarchy(NodeID,
                               ParentID,
                               LevelID)
        select NodeID   = nl.HNL_NodeID,
               ParentID = nl.HNL_ParentID,
               LevelID  = @LevelID - 1
        from @Hierarchy h
             inner join dbo.sa_insight_HierarchyNodeLink nl  with(nolock) on nl.HNL_NodeID = h.ParentID and
                                                                             nl.HNL_Type   = 0 and --OU Hierarchy
                                                                             @ReportDate between isnull(nl.HNL_DateFrom, '19000101') and isnull(nl.HNL_DateTo, '99991231')
        where h.LevelID = @LevelID;

        --Check outcome and decrease level        
        set @RowCount = @@rowcount;
        set @LevelID = @LevelID - 1;
      end;
    end;

    select hn.HN_Description, d.DIST_CompanyName, *
    from @Hierarchy h
         left outer join dbo.sa_insight_HierarchyNode hn on hn.HN_ID                            = h.NodeID and
                                                            @ReportDate between isnull(hn.HN_DateFrom, '19000101') and isnull(hn.HN_DateTo, '99991231')
         left outer join dbo.sa_insight_HierarchyNodeLink dl on dl.HNL_NodeID = h.NodeID and
                                                                dl.HNL_Type   = 2 and
                                                                @ReportDate between isnull(dl.HNL_DateFrom, '19000101') and isnull(dl.HNL_DateTo, '99991231')
         left outer join dbo.sa_insight_Distributor d on dl.HNL_ParentID = d.DIST_ID and
                                                         @ReportDate between isnull(d.DIST_DateFrom, '19000101') and isnull(d.DIST_DateTo, '99991231')
    order by h.LevelID asc,
             hn.HN_Description
    
  end try
  begin catch
    print (error_message());
  end catch;
       
  select *
  from @Ret;
end;
GO
/****** Object:  StoredProcedure [dbo].[owp_GetFileLocation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
/****************************************************************************
     Program: owp_GetFileLocation           
      Author: A Groves
Date created: 25/04/2008              
                      
 Description:   The purpose of this proc is to read file SCANS.INI to
				identify the filepath to be used for the "key" that is
				passed in as a parameter.

      It is called as follows:

      exec owp_GetFileLocation 'FSDOPSRPTS', @file_path output
                  
Amendment History               
-----------------               
                      
Date		Who			Description       
----		---			-----------     
08/05/2008	A Groves	Remove hardcoding of @key_object extraction by 
						using patindex to find position after "=".
29/10/2010	A Groves	Replace hardcoding for ACS to Rackspace migration.
---------------------------------------------------------------------------
28/04/2014	A Groves	Complete re-write for SQL Server 2008 R2 upgrade
						project. Previously this proc read file:
						\\openwork.local\midb\MIDATA\HeadOfficeSystems\DTS\BAT\SCANS.INI
						However, as there is only one file system, this stopped
						a parallel run from being created for reports. The solution
						below places all the report config onto table 
						mst_DataImportConfiguration instead, allowing parallel run.
****************************************************************************/

CREATE PROCEDURE [dbo].[owp_GetFileLocation]  @key varchar(100), @key_object varchar(400) output

AS
BEGIN

set nocount on

declare @sql        varchar(1000),
    @FilePath     varchar(500),
    @FileName     varchar(500),
    @rowcount     int

select	@key_object = [Path]
from	mst_DataImportConfiguration with (nolock)
where	Client = 'Openwork'
and		Module = @key

END






GO
/****** Object:  StoredProcedure [dbo].[owp_GetFranchiseSize]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
/****************************************************************************
     Program:   owp_GetFranchiseSize            
    Author: A Groves
Date created: 22/10/2008              
                      
 Description:   The purpose of this proc is to calculate the Franchise Size according
        to the rules below:

        If the AgentType is 2 (Franchise) count the number of Agents 
        that have GivesAdvice = 'Y' that has this agent in the OfficeCode. 

        If the AgentType is 49 (Directly Authorised) count the number of 
        Agents that have GivesAdvice = 'Y' that has this agent in the 
        DirectlyAuthorisedCode. 

        If the AgentType is 47 (StrategicAlliance) count the number of Agents 
        that have GivesAdvice = 'Y' that has this agent in the 
        StrategicAllianceCode. 

        If the AgentType is 46 (AccessAgent) count the number of Agents that 
        have GivesAdvice = 'Y' that has this agent in the AccessAgentCode 


      It is called as follows:

      exec owp_GetFranchiseSize @AgentCode, @AgentType, @NewFranchiseSize output
                  
  Amendment History               
  -----------------               
                      
  Date    Who     Description       
  ----    ---     -----------     
  
****************************************************************************/

CREATE PROCEDURE [dbo].[owp_GetFranchiseSize] @AgentCode varchar(7), 
                        @AgentType int,
                        @FranchiseSize int output

AS

--Franchise
if @AgentType = 2 
begin
  select  @FranchiseSize = count(*) 
  from  mstt_AgentsHistory s 
  where s.GivesAdvice   = 'Y'  
  and   s.active      = 1    
  and   s.CompetentStatus = 1 
  and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
  and   s.FranchiseCode   = @AgentCode
end


--Directly Authorised
if @AgentType = 49 
begin
  select  @FranchiseSize = count(*) 
  from  mstt_AgentsHistory s 
  where s.GivesAdvice   = 'Y'  
  and   s.active      = 1    
  and   s.CompetentStatus = 1 
  and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
  and   s.DirectlyAuthorisedCode = @AgentCode
end


--StrategicAlliance
if @AgentType = 47 
begin
  select  @FranchiseSize = count(*) 
  from  mstt_AgentsHistory s 
  where s.GivesAdvice   = 'Y'  
  and   s.active      = 1    
  and   s.CompetentStatus = 1 
  and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
  and   s.StrategicAllianceCode = @AgentCode
end


--AccessAgent
if @AgentType = 46 
begin
  select  @FranchiseSize = count(*) 
  from  mstt_AgentsHistory s 
  where s.GivesAdvice   = 'Y'  
  and   s.active      = 1    
  and   s.CompetentStatus = 1 
  and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
  and   s.AccessAgentCode = @AgentCode
end
  

GO
/****** Object:  StoredProcedure [dbo].[owp_GetFranchiseSize_RV]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
