/****************************************************************************
     Program:   owp_GetFranchiseSize            
    Author: A Groves
Date created: 22/10/2008              
                      
 Description:   The purpose of this proc is to calculate the Franchise Size according
        to the rules below:

        If the AgentType is 2 (Franchise) count the number of Agents 
        that have GivesAdvice = 'Y' that has this agent in the OfficeCode. 

        If the AgentType is 49 (Directly Authorised) count the number of 
        Agents that have GivesAdvice = 'Y' that has this agent in the 
        DirectlyAuthorisedCode. 

        If the AgentType is 47 (StrategicAlliance) count the number of Agents 
        that have GivesAdvice = 'Y' that has this agent in the 
        StrategicAllianceCode. 

        If the AgentType is 46 (AccessAgent) count the number of Agents that 
        have GivesAdvice = 'Y' that has this agent in the AccessAgentCode 


      It is called as follows:

      exec owp_GetFranchiseSize @AgentCode, @AgentType, @NewFranchiseSize output
                  
  Amendment History               
  -----------------               
                      
  Date    Who     Description       
  ----    ---     -----------     
  
****************************************************************************/

CREATE PROCEDURE [dbo].[owp_GetFranchiseSize_RV] @AgentCode varchar(7), 
                        @AgentType int,
                        @FranchiseSize int output

AS

Declare
@DefaultGivesAdvice     nvarchar(1),	---MF 12/03/2024 Added as Tech Debt reverse engineering for ow_TranformationMovements
@Active					int,			---MF 11/03/2024: Added to resolve Tech Debt
--@AgentCode              varchar(7),		---MF 11/03/2024: Added to resolve Tech Debt
--@AgentType              int,			---MF 11/03/2024: Added to resolve Tech Debt
@BusinessAgentType      int,			---MF 11/03/2024: Added to resolve Tech Debt
--@FranchiseSize          int,			---MF 11/03/2024: Added to resolve Tech Debt
@ProcessDate            datetime,		-- AG 25/09/2008
@PortalLogon			varchar(20)		---MF 11/03/2024: Added to resolve Tech Debt

set @DefaultGivesAdvice  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'GivesAdvice')  ---MF 12/03/2024 Tech Debt reverse engineering for ow_TranformationMovements
set @ProcessDate         = (select ProcessDate from mst_ImportControl where Type = 'Openwork' and Module = 'Swift') -- AG 25/09/2008
set @Active		= 0

-- We are going to process one agent record at a time with lots of steps hence the cursor.
-- BusinessAgentTypes need to be processed last because, for them, we need to calculate
-- FranchiseSize and for that, all the non-business records need to be created first so
-- they can be counted.

-- AG 13/03/2009 Start

--declare AgentCheck cursor 
---fast_forward
  Insert into #FranchiseSize
  select  Code as AgentCode, 
      case Agt_type
        when 2 then 2
        when 46 then 2
        when 47 then 2
        when 49 then 2
        else 1
      end as BusinessAgentType, -- Process all agent types i.e. businesses and people. AG 17/06/2010.
      Agt_type as AgentType
  from  sa_swift_S_AGENTS Ag
  where len(Code) > 0     --MPC: 31/05/2008
  and   (LastModifiedDate >= (@ProcessDate - 8) -- Changed in the last eight days or....
  or    Code in (select   AH.Code       -- Their PortalLogin has changed at any time
            from  sa_swift_S_AGENTS AH
                inner join sa_swift_IntUsers IU on IU.AssociatedAgent = AH.Code
            where isnull(@PortalLogon,'') <> isnull(IU.Name,'')
            and   IU.ID < 99000 -- Above 99000 are the mitest logons
            and   @Active = 1))
  union -- Include all businesses for modified sellers to ensure Franchise Size is updated for the leagues AG 18/05/2010.
  select  Ag.Code as AgentCode,
      2 as BusinessAgentType,
      Ag.Agt_type as AgentType
 -- from  msit_S_Agents Ag
  from sa_swift_S_Agents Ag
  where Ag.Agt_Type in (2,46,47,49)
  and   Ag.code in (select  sellers.firm 
             ---from msit_S_Agents sellers
			 from sa_swift_S_Agents sellers
             where  sellers.Agt_Type not in (2,46,47,49) 
             and  sellers.LastModifiedDate >= (@ProcessDate - 8))
  order by 2, 1 
 ---- for   read only--- MF 11/03/2024: Added to resolve Tech Debt

  ---open AgentCheck
  
 ---fetch AgentCheck
 ---into  @AgentCode, @BusinessAgentType, @AgentType

--Franchise
--if AgentType = 2 
begin
  select  @FranchiseSize = count(*) 
  -----from  mstt_AgentsHistory s  
  from sa_swift_S_AGENTS s				---MF 12/03/2024 Tech Debt Replacement
  inner join #FranchiseSize f on s.CODE = f.AgentCode
  ---where s.GivesAdvice   = 'Y'		
  where @DefaultGivesAdvice	= 'Y'		---MF 12/03/2024 Tech Debt Replacement
  ---and   s.active      = 1    
  and @Active = 1							---MF 12/03/2024 Tech Debt Replacement
  and   s.CompetentStatus = 1 
  ---and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
  and s.AGT_TYPE in (4, 43, 51) -- Seller, Principal, PFA Principal      ---MF 12/03/2024 Tech Debt Replacement
 ---- and   s.FranchiseCode   = @AgentCode
  and   s.OfficeCode   = f.AgentCode 		---MF 12/03/2024 Tech Debt Replacement
end


--Directly Authorised
---if AgentType = 49 
begin
  select  @FranchiseSize = count(*) 
 -----from  mstt_AgentsHistory s  
  from sa_swift_S_AGENTS s				---MF 12/03/2024 Tech Debt Replacement
  inner join #FranchiseSize f on s.CODE = f.AgentCode
  ---where s.GivesAdvice   = 'Y'		
  where @DefaultGivesAdvice	= 'Y'		---MF 12/03/2024 Tech Debt Replacement  and   s.active      = 1    
  and   s.CompetentStatus = 1 
  ---and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
  and   s.AGT_TYPE in (4, 43, 51) -- Seller, Principal, PFA Principal			---MF 12/03/2024 Tech Debt Replacement
  and   s.DirectlyAuthorisedCode = f.AgentCode
end


--StrategicAlliance
---if AgentType = 47 
begin
  select  @FranchiseSize = count(*) 
 -----from  mstt_AgentsHistory s  
  from sa_swift_S_AGENTS s				---MF 12/03/2024 Tech Debt 
  inner join #FranchiseSize f on s.CODE = f.AgentCode
  ---where s.GivesAdvice   = 'Y'		
  where @DefaultGivesAdvice	= 'Y'		---MF 12/03/2024 Tech Debt Replacement
  ---and   s.active      = 1    
  and @Active = 1						---MF 12/03/2024 Tech Debt Replacement
  and   s.CompetentStatus = 1 
  ---and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
   and   s.AGT_TYPE in (4, 43, 51) -- Seller, Principal, PFA Principal			---MF 12/03/2024 Tech Debt Replacement
  and   s.StrategicAllianceCode = f.AgentCode
end


--AccessAgent
--if AgentType = 46 
begin
  select  @FranchiseSize = count(*) 
 -----from  mstt_AgentsHistory s  
  from sa_swift_S_AGENTS s				---MF 12/03/2024 Tech Debt Replacement
  inner join #FranchiseSize f on s.CODE = f.AgentCode
  ---where s.GivesAdvice   = 'Y'		
  where @DefaultGivesAdvice	= 'Y'		---MF 12/03/2024 Tech Debt Replacement  and   s.active      = 1    
  and   s.CompetentStatus = 1 
  ----and   s.AgentType in (4, 43, 51) -- Seller, Principal, PFA Principal
   and   s.AGT_TYPE in (4, 43, 51) -- Seller, Principal, PFA Principal			---MF 12/03/2024 Tech Debt Replacement
  and   s.AccessAgentCode = f.AgentCode
end
  
--close AgentCheck
--deallocate AgentCheck


GO
/****** Object:  StoredProcedure [dbo].[owp_HeadOfficePTLsFromActiveDirectoryGroup]    Script Date: 7/3/2026 3:44:25 PM ******/
