/****************************************************************************
     Program:	owp_HeadOfficePTLsFromActiveDirectoryGroup
				(Cloned on owp_HeadOfficeUsersFromActiveDirectory by A Groves 01/11/2013)         
      Author:	A Groves
Date created:	22/10/2013              
                      
Description:	This proc calls proc sp_OWUtil_ActiveDirectoryReader to
				provide a results set of PTL codes of Head Office staff who
				need to be given permission to access the documents from
				Yoda of advisers who have left. This is needed because the
				PTL codes of advisers who have left disappear from the 
				permissions lists.

				This proc would be called as follows:

					exec owp_HeadOfficePTLsFromActiveDirectoryGroup 'Openwork', 'ActiveDirectory',
								'Domain', 'YodaTerminatedAdvisers'
          
        
  Amendment History               
  -----------------               
                      
  Date			Who			Description       
  ----			---			-----------     

****************************************************************************/
CREATE PROCEDURE [dbo].[owp_HeadOfficePTLsFromActiveDirectoryGroup]
	@Client		varchar(50),
	@Module		varchar(50),
	@Domain		varchar(255),
	@ADGroup	varchar(255)

AS

declare	@ProcName				varchar(100),
		@PhaseStart				varchar(50),
		@PhaseEnd				varchar(50),
		@Process				varchar(100),
		@ReturnStatus			int,
		@RowCount				int


/****************************************************************************

  Set initial parameters                                
                                    
****************************************************************************/


set @PhaseStart		= 'START'
set @PhaseEnd		= 'END'
set @ProcName		= object_name(@@procid)

select	@Domain = Path 
from	mst_DataImportConfiguration 
where	Client	= @Client
and		Module	= 'ADDomain'
and		Type	= @Domain
and		Active	= 1

select	@ADGroup= Name
from	mst_DataImportConfiguration 
where	Client	= @Client 
and		Module	= 'ADHeadOfficeUsers'
and		Type	= @ADGroup
and		Active	= 1

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client


/****************************************************************************

  Read Active Directory                                
                                    
****************************************************************************/


create table #AD		   
	(objectguid							uniqueidentifier,
	homemdb								varchar(1000),
	cn									varchar(1000),
	samaccounttype						int, 
	badpasswordtime						bigint,
	distinguishedname					varchar(1000),
	homemta								varchar(1000),
	l									varchar(1000),
	c									varchar(1000),
	accountexpires						bigint,
	lockouttime							bigint, 
	name								varchar(1000),
	msexchmailboxsecuritydescriptor		varbinary(8000),
	logonhours							varbinary(8000),
	userprincipalname					varchar(1000),
	givenname							varchar(1000),
	adspath								varchar(1000),
	displayname							varchar(1000),
	mdbusedefaults						int,
	pwdlastset							bigint,
	instancetype						int,
	homephone							varchar(1000),
	codepage							int,
	whenchanged							datetime,
	co									varchar(1000),
	usncreated							int,
	sn									varchar(1000),
	msexchmailboxguid					uniqueidentifier,
	lastlogoff							int,
	badpwdcount							int,
	telephonenumber						varchar(1000),
	mobile								varchar(1000),
	usnchanged							int,
	useraccountcontrol					int,
	primarygroupid						int,
	st									varchar(1000),
	legacyexchangedn					varchar(1000),
	msexchuseraccountcontrol			int,
	whencreated							datetime,
	objectsid							uniqueidentifier,
	postalcode							varchar(1000),
	logoncount							int,
	textencodedoraddress				varchar(1000),
	mail								varchar(1000),
	samaccountname						varchar(1000),
	countrycode							int,
	admincount							int,
	msexchalobjectversion				varchar(1000),
	mailnickname						varchar(1000),
	objectcategory						varchar(1000),
	lastlogon							bigint,
	msexchhomeservername				varchar(1000),
	ADGroup								varchar(1000),
	DomainLogin							varchar(255)
)


insert into #AD
	exec @ReturnStatus = Utilities..sp_OWUtil_ActiveDirectoryReader @Domain, @ADGroup


if @ReturnStatus <> 0
		return @ReturnStatus


/****************************************************************************

      Output the PTL codes of Support Centre staff

****************************************************************************/


if OBJECT_ID('tempdb..##HeadOfficePTLs') is null
	create table ##HeadOfficePTLs
	(
		LoggedInUserFK	varchar(20)
	)
else
	delete from ##HeadOfficePTLs


insert into ##HeadOfficePTLs
(
	LoggedInUserFK
)
select	SamAccountName
from	#AD


set @RowCount = @@rowcount


/****************************************************************************

      E N D                             

****************************************************************************/

drop table #AD

select @ProcName = @ProcName + ' = ' + convert(varchar(20),@RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client





