/************************************************************************************************
     Program:	owp_HeadOfficeReportDevelopersFromActiveDirectory
				(based on owp_HeadOfficeUsersFromActiveDirectory by A Groves on 01/11/2010)         
      Author:	A Groves
Date created:	19/05/2017
                      
Description:	This proc calls proc "Utilities..sp_OWUtil_ActiveDirectoryReader" to
				populate table "owt_HeadOfficeReportDevelopers".  

				The first requirement for this process and table was the Ringo Security
				proc (pr_Ringo_UserSecurity) to ensure impersonation was restricted to
				just those members of the following security AD Groups:
				1) GLS_Logi_AppManTeam
				2) GLS_Logi_Report_Developers

				This proc would be called as follows:

					exec owp_HeadOfficeReportDevelopersFromActiveDirectory 'Openwork', 'ActiveDirectory'
          
        
  Amendment History               
  -----------------               
                      
  Date			Who			Description       
  ----			---			-----------     
  
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_HeadOfficeReportDevelopersFromActiveDirectory]
	@Client		varchar(50),
	@Module		varchar(50)

AS

declare	@ProcName				varchar(100),
		@PhaseStart				varchar(50),
		@PhaseEnd				varchar(50),
		@Process				varchar(100),
		@ReturnStatus			int,
		@Domain					varchar(255),
