/****** Object:  StoredProcedure [dbo].[owp_JobRun]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_JobRun](@JobId      smallint,
                               @FromStepId smallint = null)
as
begin
  set nocount on;

  --Declare basic variables
  declare @CR                 varchar(2);
  declare @SQL                nvarchar(max);
  declare @TranCount          int;
  declare @ProcedureName      varchar(255);
  declare @Message            varchar(max);  
  
  --Declare additional variables
  declare @SaveHistory        bit;
  declare @RunId              int;
  declare @JobStartAt         datetime;
  declare @JobEndAt           datetime;
  declare @JobIdRead          smallint;
  declare @JobName            varchar(50);
  declare @SuccessReportTo    varchar(2048);
  declare @FailureReportTo    varchar(2048);
  
  declare @StepStartAt        datetime;
  declare @StepEndAt          datetime;
  declare @StepId             smallint;
  declare @StepName           varchar(100);
  declare @StepCommand        nvarchar(max);
  declare @StepNumber         smallint;
  declare @CmpDataSource1     varchar(128);
  declare @CmpDataSource2     varchar(128);
  declare @CmpDifferenceTable varchar(128);
  declare @CmpCommand         nvarchar(max);
  declare @CmpIsActive        bit;
  declare @TotalSteps         smallint;
  declare @DiffCount          int;
  
  begin try
    --Initialize variables
    set @CR            = char(13)+char(10);     --Enter
    set @TranCount     = @@trancount;           --Number of active transactions on entry
    set @ProcedureName = object_name(@@procid); --Current procedure name
    set @SaveHistory   = 0;                     --Save run history into owt_JobRunHistory table

    -----------------------------------------------------------------------------------------------
    --Check entry data
    -----------------------------------------------------------------------------------------------
    select @JobIdRead       = d.JobId,
           @JobName         = d.JobName,
           @SuccessReportTo = d.SuccessReportTo,
           @FailureReportTo = d.FailureReportTo
    from dbo.owt_JobDefinition d
    where d.JobId = @JobId;

    if @JobIdRead is null
    begin
      set @Message = 'JobId = '+isnull(convert(varchar(18), @JobId), 'NULL')+' is not defined.';
      raiserror(@Message, 16, 10);
    end;

    -----------------------------------------------------------------------------------------------
    --Initialize
    -----------------------------------------------------------------------------------------------
    --Get last run status
    select @RunId      = h.RunId,
           @JobStartAt = h.StartAt,
           @JobEndAt   = h.EndAt
    from dbo.owt_JobRunHistory h
    where h.JobId = @JobId;
    
    if @RunId is not null and @JobEndAt is null --Job in progress
    begin
      set @Message = 'Previous run, RunId = '+convert(varchar(18), @RunId)+
                     ' started on '+convert(varchar(19), @JobStartAt, 121)+', is not finished yet.'+@CR+
                     'Job cannot be started until previous run is not finished.';
      raiserror(@Message, 16, 10);
    end;

    --Insert owt_JobRunHistory record
    insert into dbo.owt_JobRunHistory(JobId,
                                  StartAt,
                                  EndAt,
                                  ErrorMessage)
    select JobId        = @JobId,
           StartAt      = getdate(),
           EndAt        = null,
           ErrorMessage = null;

    set @RunId = scope_identity();
    set @SaveHistory = 1;

    -----------------------------------------------------------------------------------------------
    --Run job steps
    -----------------------------------------------------------------------------------------------
    declare StepsCursor cursor local static
    for select d.StepId,
               d.StepName,
               d.StepCommand,
               d.CmpDataSource1,
               d.CmpDataSource2,
               d.CmpDifferenceTable,
               d.CmpCommand,
               d.CmpIsActive
        from dbo.owt_JobDefinitionDetails d
        where d.JobId    = @JobId and
              d.IsActive = 1 and
              d.StepId  >= isnull(@FromStepId, 0)
        order by d.StepId;
        
    open StepsCursor;
    
    if cursor_status('local', 'StepsCursor') = 0
    begin
      if isnull(@FromStepId, 0) = 0
        set @Message = 'There are no active steps defined in the job '''+@JobName+'''.'
      else  
        set @Message = 'There are no active steps with StepID >= '+convert(varchar(18), @FromStepId)+
                       ' in the job '''+@JobName+'''.'
      raiserror(@Message, 16, 10);
    end;

    if cursor_status('local', 'StepsCursor') < 0
    begin
      set @Message = 'Error opening cursor StepsCursor.';
      raiserror(@Message, 16, 10);
    end;
    
    fetch next from StepsCursor
    into @StepId,
         @StepName,
         @StepCommand,
         @CmpDataSource1,
         @CmpDataSource2,
         @CmpDifferenceTable,
         @CmpCommand,
         @CmpIsActive;
    
    set @StepNumber = 0;
    set @TotalSteps = @@cursor_rows;
    
    --Run step by step
    while @@fetch_status = 0
    begin
      set @DiffCount  = null;
      set @StepNumber = @StepNumber + 1;
      
      print(convert(varchar(19), getdate(), 121)+' - Step '+convert(varchar(18), @StepNumber)+' of '+
            convert(varchar(18), @TotalSteps)+' - '''+@StepName+'''...');
      print('-------------------------------------------------------------------------------------------------->');

      set @StepStartAt = getdate();

      --Insert dbo.owt_JobRunHistoryDetails record
      insert into dbo.owt_JobRunHistoryDetails(RunId,
                                               JobId,
                                               StepId,
                                               StartAt,
                                               EndAt,
                                               ErrorMessage,
                                               CmpDifferenceCount)
      select RunId              = @RunId,
             JobId              = @JobId,
             StepId             = @StepId,
             StartAt            = @StepStartAt,
             EndAt              = null,
             ErrorMessage       = null,
             CmpDifferenceCount = null;

       --Check errors
      if rtrim(isnull(@StepCommand, '')) = ''
      begin
        set @Message = 'StepCommand for step '''+isnull(@StepName, 'NULL')+' is null or empty';
        raiserror(@Message, 16, 10);
      end;

      --Run the step SQL command
      exec(@StepCommand);

      set @StepEndAt = getdate();

      if @CmpIsActive = 1
      begin
        print(convert(varchar(19), getdate(), 121)+' - Main task of the step completed.');
        print(convert(varchar(19), getdate(), 121)+' - Compare data between '+isnull(@CmpDataSource1, 'NULL')+
              ' and '+isnull(@CmpDataSource2, 'NULL')+'.'+@CR+
              space(22)+'Store differences in '+isnull(@CmpDifferenceTable, 'NULL')+'...');
              
        --Check data
        set @CmpDataSource1     = object_name(object_id(@CmpDataSource1));
        set @CmpDataSource2     = object_name(object_id(@CmpDataSource2));
        set @CmpDifferenceTable = coalesce(object_name(object_id(@CmpDifferenceTable)), @CmpDifferenceTable);
        set @CmpCommand         = nullif(rtrim(isnull(@CmpCommand, '')), '');

        --Check errors
        set @Message = null;
        if @CmpDataSource1 is null
          set @Message = isnull(@Message+','+@CR, '')+'CmpDataSource1 cannot be null or empty'

        if @CmpDataSource2 is null
          set @Message = isnull(@Message+','+@CR, '')+'CmpDataSource2 cannot be null or empty'

        if @CmpDifferenceTable is null
          set @Message = isnull(@Message+','+@CR, '')+'CmpDifferenceTable cannot be null or empty'

        if @Message is not null
          raiserror(@Message, 16, 10);

        if @CmpCommand is null
        begin
          exec dbo.owp_CheckDataMatches @RunId     = @RunId,
                                        @JobId     = @JobId,
                                        @StepId    = @StepId,
                                        @DebugMode = 1;
        end
        else
        begin
          exec dbo.sp_executesql @stmt   = @CmpCommand,
                                 @params = N'@RunId int',
                                 @RunId  = @RunId;
        end;

        set @SQL = 'select @iDiffCount = count(1)'+@CR+
                   'from dbo.'+quotename(@CmpDifferenceTable)+' d with(nolock)'+@CR+
                   'where d.RunId = @iRunId;';
                   
        exec sp_executesql @stmt       = @SQL,
                           @params     = N'@iRunId int, @iDiffCount int output',
                           @iRunId     = @RunId,
                           @iDiffCount = @DiffCount output;
                          
        print(convert(varchar(19), getdate(), 121)+' - Comparision complete. '+isnull(convert(varchar(18), @DiffCount), 'NULL')+' row(s) are different.');
      end
      else
        print(convert(varchar(19), getdate(), 121)+' - Step completed.');
      
      print('--------------------------------------------------------------------------------------------------<');
      print('');

      --Update EndAt value dbo.owt_JobRunHistoryDetails record adding 
      update dbo.owt_JobRunHistoryDetails
      set EndAt              = @StepEndAt,
          ErrorMessage       = null,
          CmpDifferenceCount = @DiffCount
      where RunId  = @RunId and
            JobId  = @JobId and
            StepId = @StepId;

      fetch next from StepsCursor
      into @StepId,
           @StepName,
           @StepCommand,
           @CmpDataSource1,
           @CmpDataSource2,
           @CmpDifferenceTable,
           @CmpCommand,
           @CmpIsActive;
    end;
    
    if cursor_status('local', 'StepsCursor') >= 0
      close StepsCursor;

    if cursor_status('local', 'StepsCursor') = -1
      deallocate StepsCursor;

    -----------------------------------------------------------------------------------------------
    --Finalize
    -----------------------------------------------------------------------------------------------
    print(convert(varchar(19), getdate(), 121)+' - update dbo.owt_JobRunHistory record.');
    update dbo.owt_JobRunHistory
    set EndAt        = getdate(),
        ErrorMessage = null
    where RunId = @RunId;
    
    --Send e-mail
    exec dbo.owp_JobRunReport @JobId    = @JobId,
                              @SendTo   = @SuccessReportTo,
                              @SendToCC = null;
  end try
  begin catch
  print('Error')
    -----------------------------------------------------------------------------------------------
    --Finalize
    -----------------------------------------------------------------------------------------------
    set @Message = 'Error in line '+convert(varchar(18), error_line())+
                   ' of '+isnull(quotename(error_procedure())+':', 'ad-hoc query in '+
                   quotename(@ProcedureName)+' procedure:')+@CR+isnull(error_message(), '');

    --Print error message
    print(@Message);

    -----------------------------------------------------------------------------------------------
    --Error handling
    -----------------------------------------------------------------------------------------------
    --Rollback all transactions started inside the procedure
    while @@trancount > @TranCount
      rollback transaction;

    if cursor_status('local', 'StepsCursor') >= 0
      close StepsCursor;

    if cursor_status('local', 'StepsCursor') = -1
      deallocate StepsCursor;

    if @SaveHistory = 1
    begin
      --Update EndAt and ErrorMessage values in dbo.owt_JobRunHistory 
      print(convert(varchar(19), getdate(), 121)+' - update dbo.owt_JobRunHistory record.');

      update dbo.owt_JobRunHistory
      set EndAt        = getdate(),
          ErrorMessage = @Message
      where RunId = @RunId;

      --Update EndAt value dbo.owt_JobRunHistoryDetails record adding 
      update dbo.owt_JobRunHistoryDetails
      set EndAt        = @StepEndAt,
          ErrorMessage = error_message()
      where RunId  = @RunId and
            JobId  = @JobId and
            StepId = @StepId;
    end;

    --Send e-mail
    exec dbo.owp_JobRunReport @JobId    = @JobId,
                          @SendTo   = @FailureReportTo,
                          @SendToCC = null;
  end catch;
end;
GO
/****** Object:  StoredProcedure [dbo].[owp_JobRunReport]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create procedure [dbo].[owp_JobRunReport](@JobId    smallint,
                                      @SendTo   varchar(2048),
                                      @SendToCC varchar(2048))
as
begin
  set nocount on;

  --Declare variables
  declare @CR           varchar(2);
  declare @Report       varchar(max);
  declare @ErrorMessage varchar(max);
  declare @Subject      varchar(255);
  declare @JobName      varchar(50);
  declare @IsError      bit;
  
  declare @StepId       smallint;
  declare @StepName     varchar(100);
  declare @Run7         varchar(100);
  declare @Run6         varchar(100);
  declare @Run5         varchar(100);
  declare @Run4         varchar(100);
  declare @Run3         varchar(100);
  declare @Run2         varchar(100);
  declare @Run1         varchar(100);
  declare @Run0         varchar(100);
  declare @Error0       varchar(max);
  declare @RowClass     varchar(50);
  declare @DiffCnt      varchar(50);
  
  --Initialize variables
  set @CR = char(13)+char(10);  --Enter
  
  begin try
    --Read job name
    select @JobName = JobName
    from dbo.owt_JobDefinition
    where JobId = @JobId;
    
    if @JobName is null
      raiserror('Job is not defined in dbo.owt_JobDefinition table.', 16, 10);
    
    --Read last status
    select top 1
           @IsError      = case when ErrorMessage is null then 0 else 1 end,
           @ErrorMessage = ErrorMessage
    from dbo.owt_JobRunHistory
    where JobId = @JobId
    order by RunId desc;

    --Report header
    set @Report = '<html xmlns="http://www.w3.org/1999/xhtml">'+@CR+
                  '<head>'+@CR+
                  '<meta http-equiv="Content-Type" content="text/html; charset=utf-8">'+@CR+
                  '<title>Document</title>'+@CR+
                  '<style type="text/css">'+@CR+
                  '<!--'+@CR+
                  '  body,th {font-family: Arial, Helvetica, sans-serif; font-size: 11px; color: #333333;}'+@CR+
                  '  a:link {color: #333333; text-decoration: none;}'+@CR+
                  '  a:visited {text-decoration: none; color: #333333;}'+@CR+
                  '  a:hover {text-decoration: none; color: #0000FF;}'+@CR+
                  '  a:active {text-decoration: none; color: #FF0000;}'+@CR+
                  '  .TitleStyle {font-family: Arial, Helvetica, sans-serif; font-size: 16px; color: #333333; font-weight: bold;}'+@CR+
                  '  .TableHeader {font-family: Arial, Helvetica, sans-serif; font-size: 12px; color: #FFFFFF; font-weight: bold; background-color: #5375AD; background-position: center center; text-align: center; padding-right: 2px; padding-left: 2px; vertical-align: middle;}'+@CR+
                  '  .TableOdd {font-family: Arial, Helvetica, sans-serif; font-size: 11px; color: #333333; background-color: #FFFFFF; padding-right: 1px;  padding-left: 1px;}'+@CR+
                  '  .TableEven {font-family: Arial, Helvetica, sans-serif; font-size: 11px; color: #333333; background-color: #E9E9FA; padding-right: 1px; padding-left: 1px;}'+@CR+
                  '  .TableNormal {font-family: Arial, Helvetica, sans-serif; font-size: 11px; color: #333333; background-color: #FFFFFF; padding-right: 1px; padding-left: 1px;}'+@CR+
                  '  .TableError {font-family: Arial, Helvetica, sans-serif; font-size: 11px; color: #333333; background-color: #FF9999; padding-right: 1px; padding-left: 1px;}'+@CR+
                  '-->'+@CR+
                  '</style>'+@CR+
                  '</head>'+@CR+
                  ''+@CR+
                  '<body>'+@CR+
                  '<p class="TitleStyle">Job '''+@JobName+''' report on '+convert(varchar(16), getdate(), 121)+'</p>'+@CR+
                  '<table border="0" cellpadding="2" cellspacing="2" bgcolor="#83A5DD">'+@CR+
                  '  <tr class="TableHeader">'+@CR+
                  '    <td colspan="2">Step</td>'+@CR+
                  '    <td colspan="8">Run time</td>'+@CR+
                  '    <td rowspan="2">Diff.<br>count</td>'+@CR+
                  '    <td rowspan="2">Error<br>message</td>'+@CR+
                  '  </tr>'+@CR+
                  '  <tr class="TableHeader">'+@CR+
                  '    <td>Id</td>'+@CR+
                  '    <td>Name</td>'+@CR+
                  '    <td>Day -7</td>'+@CR+
                  '    <td>Day -6</td>'+@CR+
                  '    <td>Day -5</td>'+@CR+
                  '    <td>Day -4</td>'+@CR+
                  '    <td>Day -3</td>'+@CR+
                  '    <td>Day -2</td>'+@CR+
                  '    <td>Day -1</td>'+@CR+
                  '    <td>Today</td>'+@CR+
                  '  </tr>'+@CR;

    declare RowsCursor cursor local fast_forward
    for select StepId   = s.StepId,
               StepName = s.StepName,
               Run7     = nullif(max(case when sd.Id = 8 then isnull(sd.StepDuration, '') else '' end), ''),
               Run6     = nullif(max(case when sd.Id = 7 then isnull(sd.StepDuration, '') else '' end), ''),
               Run5     = nullif(max(case when sd.Id = 6 then isnull(sd.StepDuration, '') else '' end), ''),
               Run4     = nullif(max(case when sd.Id = 5 then isnull(sd.StepDuration, '') else '' end), ''),
               Run3     = nullif(max(case when sd.Id = 4 then isnull(sd.StepDuration, '') else '' end), ''),
               Run2     = nullif(max(case when sd.Id = 3 then isnull(sd.StepDuration, '') else '' end), ''),
               Run1     = nullif(max(case when sd.Id = 2 then isnull(sd.StepDuration, '') else '' end), ''),
               Run0     = nullif(max(case when sd.Id = 1 then isnull(sd.StepDuration, '') else '' end), ''),
               DiffCnt  = nullif(max(case when sd.Id = 1 then isnull(sd.DiffCnt, '')      else '' end), ''),
               Error0   = nullif(max(case when sd.Id = 1 then isnull(sd.ErrorMessage, '') else '' end), '')
        from dbo.owt_JobDefinitionDetails s
             left outer join (select Id           = h.Id,
                                     StepId       = d.StepId,
                                     StepDuration = case when d.ErrorMessage is not null then 'Failed'
                                                         when d.EndAt is null then '...'
                                                         else convert(varchar(8), d.EndAt - d.StartAt, 108)
                                                    end,
                                     DiffCnt      = convert(varchar(18), d.CmpDifferenceCount),
                                     ErrorMessage = d.ErrorMessage
                              from (select top 8 
                                           Id    = row_number() over (order by ih.RunId desc),
                                           RunId = ih.RunId
                                    from dbo.owt_JobRunHistory ih
                                    where ih.JobId = @JobId
                                    order by ih.RunId desc) h
                                   left outer join dbo.owt_JobRunHistoryDetails d on h.RunId = d.RunId) as sd on s.StepId = sd.StepId
        where s.JobId    = @JobId and
              s.IsActive = 1
        group by s.StepId,
                 s.StepName;        
                 
    open RowsCursor;
    
    fetch next from RowsCursor
    into @StepId,
         @StepName,
         @Run7,
         @Run6,
         @Run5,
         @Run4,
         @Run3,
         @Run2,
         @Run1,
         @Run0,
         @DiffCnt,
         @Error0;
         
    set @RowClass = 'TableEven';
         
    while @@fetch_status = 0
    begin
      set @RowClass = case when @RowClass = 'TableEven' then 'TableOdd' else 'TableEven' end;

      set @StepName = replace(replace(isnull(@StepName, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run7     = replace(replace(isnull(@Run7, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run6     = replace(replace(isnull(@Run6, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run5     = replace(replace(isnull(@Run5, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run4     = replace(replace(isnull(@Run4, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run3     = replace(replace(isnull(@Run3, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run2     = replace(replace(isnull(@Run2, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run1     = replace(replace(isnull(@Run1, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Run0     = replace(replace(isnull(@Run0, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @DiffCnt  = replace(replace(isnull(@DiffCnt, '&nbsp;'), '''', ''''''), @CR, '<br>');
      set @Error0   = replace(replace(isnull(@Error0, '&nbsp;'), '''', ''''''), @CR, '<br>');

      
      set @Report = @Report + '  <tr class="'+@RowClass+'">'+@CR;
      set @Report = @Report + '    <td align="center">'+convert(varchar(18), @StepId)+'</td>'+@CR;
      set @Report = @Report + '    <td>'+@StepName+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run7+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run6+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run5+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run4+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run3+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run2+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run1+'</td>'+@CR;
      set @Report = @Report + '    <td align="center">'+@Run0+'</td>'+@CR;
      if @DiffCnt not in ('0', '&nbsp;')
        set @Report = @Report + '    <td class="TableError" align="center">'+@DiffCnt+'</td>'+@CR;
      else  
        set @Report = @Report + '    <td align="center">'+@DiffCnt+'</td>'+@CR;
      if @Error0 <> '&nbsp;'
        set @Report = @Report + '    <td class="TableError">'+@Error0+'</td>'+@CR;
      else  
        set @Report = @Report + '    <td>'+@Error0+'</td>'+@CR;
      set @Report = @Report + '  </tr>'+@CR;

      fetch next from RowsCursor
      into @StepId,
           @StepName,
           @Run7,
           @Run6,
           @Run5,
           @Run4,
           @Run3,
           @Run2,
           @Run1,
           @Run0,
           @DiffCnt,
           @Error0;
    end;
    
    close RowsCursor;
    deallocate RowsCursor;

    set @Report = @Report + '</table>'+@CR;
    
    if @ErrorMessage is not null
      set @Report = @Report + '<p>'+@ErrorMessage+'</p>';
  end try
  begin catch
    set @ErrorMessage = 'Error in line '+convert(varchar(18), error_line())+
                        ' of '+isnull(quotename(error_procedure())+':', 'ad-hoc query:')+
                        '<br>'+@CR+isnull(error_message(), '');
    set @Report = isnull(@Report, '') + '<p>'+@CR+@ErrorMessage+'</p>'+@CR;
  end catch;

  set @Report = @Report + '</body>'+@CR+
                          '</html>';
                          
  set @SendTo   = nullif(rtrim(isnull(@SendTo, '')), '');
  set @SendToCC = nullif(rtrim(isnull(@SendToCC, '')), '');
  set @Subject  = 'Job '''+@JobName+''''+
                  case when @IsError = 1 then ' error.'
                       when @IsError = 0 then ' completed successfully.'
                       else ' report.'
                  end;
    
  --Send e-mail
  exec msdb.dbo.sp_send_dbmail @profile_name    = null,
                               @recipients      = @SendTo,
                               @copy_recipients = @SendToCC,
                               @subject         = @Subject,
                               @body            = @Report,
                               @body_format     = 'HTML';  
  
end;
GO
/****** Object:  StoredProcedure [dbo].[owp_ListMultiplePoliciesForSameClient]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/****************************************************************************
Program:        owp_ListMultiplePoliciesForSameClient
Author:         Mike Cawood
Date Created:   15/09/2010              
                      
Description:  

This procedure lists the Proposal Transactions created in the Period defined by
the input @Days2 parameter for which policies for the same Product and Client have
been loaded in the period defined by the input @Days parameter. The Panel for the
Selling Agent of the case is derived from Insight effective as at the run date.

It is called as follows:
    exec owp_ListMultiplePoliciesForSameClient '5','0' 

      
Amendment History               
-----------------               
                      
Date          Who           Description       
----          ---           -----------     
27/09/2010    M Cawood      1) Match by Product rather than Provider (i.e. match
                               on CommProductCode not CommCompanyCode).
                            2) Avoid duplicates when matching to OBP Opportunity.

****************************************************************************/
CREATE PROCEDURE [dbo].[owp_ListMultiplePoliciesForSameClient]
  @Days int = 5,      --Defines period over which multiple Client instances derived
  @Days2 int = 0      --Defines period for which cases are listed
AS

declare @Yesterday datetime;
set @Yesterday = dateadd(dd,-1,datediff(dd,0,getdate()))

declare @ExtractDate datetime;
set @ExtractDate = (select dbo.owf_CalcDateNWorkingDaysEarlierthanDate(@Yesterday,@Days))

declare @ExtractDate2 datetime;
set @ExtractDate2 = (select dbo.owf_CalcDateNWorkingDaysEarlierthanDate(@Yesterday,@Days2))

Select
CaseID              = Y.PolicyRef,
PolicyNumber        = Y.CONT_NUM,
Source              = OS.Description,
Product             = PT.CommProductCode,
Provider            = PT.CommCompanyCode,
ProductGroup        = substring(isnull(PH.ProductGroupName,'Unknown'),1,20),
CreatedDate         = PT.CreateDateTime,
Client1Name         = ltrim(rtrim(C1.FirstNames)) + ' ' + ltrim(rtrim(C1.[Name])),
Client1DoB          = C1.BirthDate,
Client1PostCode     = C1.Postcode,
Client2Name         = ltrim(rtrim(C2.FirstNames)) + ' ' + ltrim(rtrim(C2.[Name])),
Client2DoB          = C2.BirthDate,
Client2PostCode     = C2.Postcode,
Opportunity         = SPQ.ClientOppId,
OppStatus           = SPQ2.Milestone,                                               --MPC: 27/09/2010
ProposalDate        = PT.ProposalDate,
Premium             = convert(decimal(28,2),isnull(PT.Amount,PT.MortgageAmount)),
DA                  = convert(decimal(28,2),isnull(PT.CommInitialAmount,0)),
CommShapeId         = PT.CodeCommissionShapeID,
CommshapeName       = CS.Description

from dbo.mstt_PolicyTransactions PT
inner join (Select P.POL_NUM,P.CLIENT_NUM,P.JOINT_NUM,P.PolicyRef,P.CONT_NUM,P.OriginatingSource
            From mstt_Policies P
            Inner Join (select PO1.CLIENT_NUM as ClientId,PT1.CommProductCode       --MPC: 27/09/2010
                        from dbo.mstt_policies PO1
                        inner join dbo.mstt_PolicyTransactions PT1 on PT1.PolicyId = PO1.POL_NUM
                        where PT1.CreateDateTime >= @ExtractDate
                          and PT1.TransType = 39
                          and PO1.OriginatingSource in (5,6) --OBP and OBP MANUAL
                          and PO1.CLIENT_NUM is not NULL
                        Group by PO1.CLIENT_NUM,PT1.CommProductCode                 --MPC: 27/09/2010
                        Having Count(Distinct PT1.PolicyID) > 1
                        UNION
                        select PO2.JOINT_NUM as ClientId,PT2.CommProductCode        --MPC: 27/09/2010
                        from dbo.mstt_policies PO2
                        inner join dbo.mstt_PolicyTransactions PT2 on PT2.PolicyId = PO2.POL_NUM
                        where PT2.CreateDateTime >= @ExtractDate
                          and PT2.TransType = 39
                          and PO2.OriginatingSource in (5,6) --OBP and OBP MANUAL
                          and PO2.JOINT_NUM is not NULL
                        Group by PO2.JOINT_NUM,PT2.CommProductCode                  --MPC: 27/09/2010
                        Having Count(Distinct PT2.PolicyID) > 1
                        ) X on (P.CLIENT_NUM = X.ClientId OR P.JOINT_NUM = X.ClientId) 
                                and P.ProductCode = X.CommProductCode               --MPC: 27/09/2010
            Group BY P.POL_NUM,P.CLIENT_NUM,P.JOINT_NUM,P.PolicyRef,P.CONT_NUM,P.OriginatingSource
            ) Y ON Y.POL_NUM = PT.PolicyID    
left join dbo.mstt_Clients C1 on Y.CLIENT_NUM = C1.CLIENT_NUM
left join dbo.mstt_Clients C2 on Y.JOINT_NUM = C2.CLIENT_NUM
left join mstt_ProductHierarchy PH on PH.ProductCode = PT.Commproductcode
left join sa_swift_CodeCommissionShape CS on CS.Id = PT.CodeCommissionShapeId
left join sa_swift_CodeOriginatingSources OS on OS.ID = Y.OriginatingSource
--left join dbo.rds_obpmi_SubmittedPlanQuotes SPQ                                                                               --MPC: 27/09/2010
--      ON CASE WHEN SPQ.QuoteCaseId is NOT NULL THEN cast(SPQ.QuoteCaseId as varchar(20)) ELSE SPQ.PolicyNumber END            --MPC: 27/09/2010
--         = CASE WHEN SPQ.QuoteCaseId is NOT NULL THEN cast(Y.PolicyRef as varchar(20)) ELSE Y.CONT_NUM END                    --MPC: 27/09/2010
left join (Select ClientOppId,QuoteCaseID,PolicyNumber,Max(MilestoneId) as MilestoneId                                          --MPC: 27/09/2010
           from dbo.rds_obpmi_SubmittedPlanQuotes                                                                               --MPC: 27/09/2010
           group by ClientOppId,QuoteCaseID,PolicyNumber) SPQ                                                                   --MPC: 27/09/2010
            on CASE WHEN SPQ.QuoteCaseId is NOT NULL THEN cast(SPQ.QuoteCaseId as varchar(20)) ELSE SPQ.PolicyNumber END        --MPC: 27/09/2010
                = CASE WHEN SPQ.QuoteCaseId is NOT NULL THEN cast(Y.PolicyRef as varchar(20)) ELSE Y.CONT_NUM END               --MPC: 27/09/2010
left join (Select ClientOppId,MilestoneId,Milestone                                                                             --MPC: 27/09/2010
           from dbo.rds_obpmi_SubmittedPlanQuotes                                                                               --MPC: 27/09/2010
           Group by ClientOppId,MilestoneId,Milestone) SPQ2                                                                     --MPC: 27/09/2010
            on SPQ2.ClientOppId = SPQ.ClientOppId and SPQ.MilestoneId = SPQ2.MilestoneId                                        --MPC: 27/09/2010

where PT.CreateDateTime >= @ExtractDate2
  and PT.TransType = 39
  and Y.OriginatingSource in (5,6) --OBP and OBP MANUAL

Order by ltrim(rtrim(C1.FirstNames)) + ' ' + ltrim(rtrim(C1.[Name])),Y.PolicyRef,PT.CreateDateTime
;
GO
/****** Object:  StoredProcedure [dbo].[owp_ListSalesonmixedPanelEnterprises]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
Program:  	    owp_ListSalesonmixedPanelEnterprises
Author:	        Mike Cawood
Date Created:	  10/09/2010							
											
Description:	

This procedure lists the Proposal Transactions created in the Period defined 
by the input @Days parameter. The Panel for the Selling Agent of the case is
derived from Insight effective as at the run date.

It is called as follows:
		exec owp_ListSalesonmixedPanelEnterprises 

			
Amendment History								
-----------------								
											
Date		  Who		    		Description				
----		  --- 			  	-----------			


****************************************************************************/
CREATE PROCEDURE [dbo].[owp_ListSalesonmixedPanelEnterprises]
AS

declare @Yesterday datetime;
set @Yesterday = dateadd(dd,-1,datediff(dd,0,getdate()))

declare @ExtractDate datetime;
set @ExtractDate = dateadd(dd,-6,@Yesterday)

select
Enterprise      = CASE 
                    WHEN LEN(AG.FIRM) = 7 THEN AG.FIRM
                  END,
EnterpriseName  = rtrim(ltrim(isnull(AE.TradingName,AE.DESCN))),
NumberofPanels  = MULT.PanelCount, 
AgentCode       = PT.AgentCode,
SellerPanel     = isnull(PANEL,0),
InsightEffFrom  = PANEL.EffFrom,
InsightEffTo    = PANEL.EffTo,
AgentName       = rtrim(ltrim(AG.DESCN)),                         
CaseID          = PO.PolicyRef,
PolicyNumber    = PO.CONT_NUM,
Source          = OS.Description,
ProductCode     = PT.CommProductCode,
CommShapeId     = PT.CodeCommissionShapeId,
CommShapePanel  = CASE
                    WHEN Isnumeric(Substring(CSH.Description,1,3)) = 1 THEN Substring(CSH.Description,1,3)
                    ELSE 0
                  END,
CommShapeName   = CSH.Description,
ProposalDate    = PT.ProposalDate,
CaseCreateDate  = PT.CreateDateTime,
ClientName      = rtrim(ltrim(CL.FirstNames)) + ' ' + rtrim(ltrim(CL.NAME)),
Premium_MLA     = isnull(PT.Amount,PT.MortgageAmount)
from dbo.mstt_PolicyTransactions PT
inner join dbo.mstt_Policies PO 
  on PO.POL_NUM = PT.PolicyId
left join dbo.mstt_Clients CL
  on CL.CLIENT_NUM = PO.CLIENT_NUM
inner join dbo.mstt_Agents AG
  on AG.CODE = PT.AgentCode
inner join dbo.mstt_Agents AE
  on AE.CODE = CASE WHEN LEN(AG.FIRM) = 7 THEN AG.FIRM END
left join (Select InsightAgentUID, Max(EffFrom) as EffFrom
           from dbo.f_Insight_ListPanelHistoryOfAllSellers()
           Where EffFrom <= @Yesterday
           Group by InsightAgentUID) LAST
  on PT.AgentCode = LAST.InsightAgentUID 
left join dbo.f_Insight_ListPanelHistoryOfAllSellers() PANEL 
  on PT.AgentCode = PANEL.InsightAgentUID and LAST.EffFrom = PANEL.EffFrom
     and @Yesterday between isnull(PANEL.EffFrom,'1 Jan 1899') and Isnull(PANEL.EffTo,'31 Dec 2999')
inner join (Select Firm,count(distinct isnull(Panel,0)) as PanelCount
            from mstt_Agents
            left outer join dbo.f_Insight_ListPanelHistoryOfAllSellers() PANEL 
                 on Code = PANEL.InsightAgentUID 
                    and getdate() between isnull(PANEL.EffFrom,'1 Jan 1899') and Isnull(PANEL.EffTo,'31 Dec 2999')
            where GivesAdvice = 'Y' -- Seller
            and (CompetentStatus = 1 or (CompetentStatus = 2 and CDIStatusDate > getdate()))    --Active or Leaving Date in future
            group by Firm
            having count(distinct isnull(Panel,0)) > 1) MULT on MULT.FIRM = AE.CODE
left join dbo.sa_swift_CodeCommissionShape CSH 
  on CSH.ID = PT.CodeCommissionShapeId
inner join dbo.sa_swift_CodeOriginatingSources OS
  on OS.ID = PO.OriginatingSource
where isnull(PT.CodeCommissionShapeId,0) > 0
and OS.Description like '%OBP%'
and PT.CreateDateTime >= @ExtractDate
and PT.TransType = 39               --Proposal
and isnull(AE.FranchiseSize,0) > 1  --More than 1 Active Seller
Order by AG.FIRM,PT.AgentCode,PO.PolicyRef,PT.CreateDateTime;
GO
/****** Object:  StoredProcedure [dbo].[owp_LoadSalesTurnoverAudit]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROCEDURE [dbo].[owp_LoadSalesTurnoverAudit] -- WITH RECOMPILE,ENCRYPTION
@Year int
AS

/******************************************************************************
This procedure loads the owt_SalesTurnoverAudit table with all movements for the
Year specified as the input parameter. All data for that Year is deleted from the
Audit table and then reloaded.

Data is loaded at the lowest level: transaction split for Swift, transition entry 
for PreSwift or individual production adjustment.

The scan replicates the following elements of the League processing: 
Franchise to RSM Hierarchy,Seller to Franchise Hiearchy, Max Franchise Size,
League overrides of Status, Size or Business (mergers).
*******************************************************************************/
--declare @Year int set @year = 2007

set dateformat dmy

--Get overrides and other info from CodesAndDescriptions spreadsheet.

--Competent Status Overrides
select distinct Code as FranchiseCode,Description as CompetentStatus
into #CompetentStatusOverride
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Status'

--Franchise Size Overrides
select distinct Code as FranchiseCode,
  case  when Description = 'SOLE' then 1 
    when Description = 'SMALL' then 2
    when Description = 'LARGE' then 10
  else Description end as FranchiseSize 
into #FranchiseSizeOverride
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Size'

--Mergers
select distinct Code as FromFranchiseCode,Description as ToFranchiseCode 
into #Merger
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-Merge'

--Business Types
select distinct Code as AgentType
into #BusinessAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType' and Description = 'Business'
UNION -- Include Access Agents and DA values
select Distinct AgentType from mstt_agents where agenttype in (46,49)


--Seller Types
select distinct Code as AgentType
into #SellerAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType' and Description = 'Seller'

--Determine first day-of-year date value from commission statement periods
select Year,min(PeriodStartDate) as FirstDay,max(PeriodEndDate) as LastDay,
min(OscarStartDate) as OscarStart,max(OscarEndDate) as OscarEnd
into #YearDates
from msit_commissionstatementperiods
where Year = @Year
group by Year
order by Year

--Determine maximum franchise size during the year for each franchise
select Code,t1.Year,max(FranchiseSize) as FranchiseSize
into #MaxFranchiseSizeForYear
from mstt_AgentsHistory
inner join #YearDates t1 on (ValidToDate between t1.FirstDay and t1.LastDay or ValidToDate > t1.LastDay)
where agenttype in (select AgentType from #BusinessAgentType) 
group by Code,t1.Year
order by Code,t1.Year

-- Set Minimum Franchise Size to 1
update m
set FranchiseSize = 1
from #MaxFranchiseSizeForYear m
where m.FranchiseSize < 1

-- Declare Period Dates for Year
declare @Yesterday datetime set @yesterday = CAST(CONVERT(NVARCHAR,dateadd(dd,-1,getdate()),112) as datetime) 
declare @SwiftStart datetime set @SwiftStart = (select FirstDay from #YearDates)
declare @SwiftEnd datetime set @SwiftEnd = (select LastDay from #YearDates)
declare @OscarStart datetime set @OscarStart = (select OscarStart from #YearDates)
declare @OscarEnd datetime set @OscarEnd = (select OscarEnd from #YearDates)
-- Set HierarchyDate to earlier of LastDay of Year and Yesterday
declare @HierarchyDate datetime set @HierarchyDate = @SwiftEnd
IF @HierarchyDate > @Yesterday begin set @HierarchyDate = @Yesterday end

--Create temporary table to store agent hierarchy history values
/*
Create Table #AgentHierarchyHistory (
AgentCode varchar(7), 
DefaultValue int, 
StartDate datetime, 
EndDate datetime, 
Status int,
DetailAgentCode varchar(7), 
ParticipantType int)

CREATE INDEX AgentHierarchyHistory_AgentCode ON #AgentHierarchyHistory (AgentCode)
*/

--insert into #AgentHierarchyHistory  
select  ahh4.AgentCode, 
  ahh4.DefaultValue, 
  ahh4.StartDate, 
  ahh4.EndDate, 
  ahh4.Status, 
  ahh4.DetailAgentCode, 
  ahh4.ParticipantType 
into #AgentHierarchyHistory
from msit_AgentHierarchyHistory ahh4
inner join 
  (--Get the max Id if there are multiple entries for a StartDate/EndDate/ParticipantType combo
  select max(ahh2.Id) as Id, 
    ahh2.AgentCode, 
    ahh2.ParticipantType, 
    ahh2.StartDate, 
    ahh2.EndDate 
  from msit_AgentHierarchyHistory ahh2
  inner join (--Get the latest end date for each start date
      select ahh.AgentCode,ahh.ParticipantType,ahh.StartDate, 
        max(isnull(ahh.EndDate, '31 Dec 9999')) as EndDate
      from msit_agenthierarchyhistory ahh
      group by ahh.AgentCode, ahh.ParticipantType, ahh.StartDate ) ahh1
    on ahh2.AgentCode = ahh1.AgentCode and ahh2.ParticipantType = ahh1.ParticipantType
    and ahh2.StartDate = ahh1.StartDate
    and isnull(ahh2.EndDate, '31 Dec 9999') = ahh1.EndDate
  group by ahh2.AgentCode,ahh2.ParticipantType,ahh2.StartDate,ahh2.EndDate ) ahh3 on ahh4.id = ahh3.Id
  inner join mstt_Agents a on ahh4.AgentCode = a.Code
where ahh4.ParticipantType = 4            --Hierarchy relationship type is to a RSM
and a.AgentType in (select distinct AgentType from #BusinessAgentType)  --Franchise Agent types in list of business types
and isnull(ahh4.EndDate, '31 dec 2999') >= '01 Jan 2006'      --Exclude records prior to 1st Jan 2006
and ahh4.StartDate <> isnull(ahh4.EndDate, '31 dec 9999')   --Exclude records where StartDate = EndDate
order by 1

--Using the agent hierarchy history table create a list of franchises and their matching RSM & ASD
select distinct Franchise.AgentCode as FranchiseCode,
  FranchiseAgent.Descn as Franchise,
  RSM.AgentCode as RegionalSalesManagerCode,
  RSMAgent.Descn as RegionalSalesManager,
  ASD.AgentCode as AreaSalesManagerCode,
  ASDAgent.Descn as AreaSalesManager
into #HistoricalHierarchy
from #AgentHierarchyHistory Franchise
  inner join mstt_Agents FranchiseAgent
    on Franchise.AgentCode = FranchiseAgent.Code
  inner join msit_AgentHierarchyHistory RSM
    on Franchise.DetailAgentCode = RSM.AgentCode
  inner join mstt_Agents RSMAgent
    on RSM.AgentCode = RSMAgent.Code
  inner join msit_AgentHierarchyHistory ASD
    on RSM.DetailAgentCode = ASD.AgentCode
  inner join mstt_Agents ASDAgent
    on ASD.AgentCode = ASDAgent.Code
where @HierarchyDate between Franchise.StartDate and isnull(Franchise.EndDate, '31 Dec 9999')
and @HierarchyDate between RSM.StartDate and isnull(RSM.EndDate, '31 Dec 9999')
and @HierarchyDate between ASD.StartDate and isnull(ASD.EndDate, '31 Dec 9999')
and RSM.ParticipantType = 2   --Hierarchy relationship type is to an ASD
and Franchise.DefaultValue = 1
order by 1, 2, 3

/*
Insert summed up Turnover values from msft_Sales into a temporary table
There are 5 select statements: 
 - Select Swift Sales for Advisers
 - Select Swift Sales for Adviser Dummies
 - Select Production Adjustments NOT in msft_Sales
 - Select Transition Sales and Production Adjustments in msft_Sales for Advisers
 - Select Transition Sales and Production Adjustments in msft_Sales for Adviser Dummies
*/

select
 ag.Code as AgentCode,
 hh.FranchiseCode,
 'Sale' as MovementType,
 'Swift' as SourceType,
 'Unknown' as Source,
 p.ProductCode,
 s.PolicyNumber as PolicyID,
 s.Transactionid,
 s.CommissionTransactionID as CommissionID,
 0 as ClientID,
 'Policy Number is not Known' as PolicyNumber,
 0 as CaseID,
 ct.DateTime as TransactionDate,
 (select Month from msit_CommissionStatementPeriods 
  where ct.DateTime between PeriodStartDate and PeriodEndDate) as Month,
 @Year as Year,
 m.FranchiseSize as FranchiseSize,
 ag.CompetentStatus as FranchiseStatus,
 hh.FranchiseCode as LeagueFranchise,
 m.FranchiseSize as LeagueSize,
 ag.CompetentStatus as LeagueStatus,
 s.Turnover, 
 s.APE,
 s.NBI,
 s.Cases,
 hh.AreaSalesManagerCode as ASDCode,
 hh.RegionalSalesManagerCode as RSMCode,
 'Y' as SaleType,
 Null as Notes

into #Sales

from msft_Sales s
inner join msdt_Adviser a on a.AdviserId = s.AdviserId
inner join mstt_Agents ag on a.FranchiseCode = ag.Code
inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
inner join msdt_CalendarTime ct on s.DateIssuedId = ct.DateId and ct.entrytypeid = 2
inner join msdt_Products p on s.ProductId = p.ProductId
inner join mstt_Agents ag_Seller on s.AgentCode = ag_Seller.Code
left outer join #MaxFranchiseSizeForYear m on ag.Code = m.Code
where
 s.BusinessTypeId = 2 and       -- Issued Business
 s.comparisonId = 1 and         -- Actual
 s.TransactionId > 0 and        -- Exclude Transition Data and Production Adjustments
 (ct.[DateTime] between @SwiftStart and @SwiftEnd) and  -- Current League year
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType) and
 --Selling Agent is in list of Seller Types OR Business Types (some transactions refernce the franchise as the selling agent)
 ag_Seller.AgentType in (select distinct AgentType from #SellerAgentType union select distinct AgentType from #BusinessAgentType)
 
--Get the same information, but this time join to AdviserDummies, as there is some
--business that is linked to Franchises who are NOT in msdt_Adviser - eg Inactive Franchises

UNION ALL

select
 ag.Code as AgentCode,
 hh.FranchiseCode,
 'Sale' as MovementType,
 'Swift' as SourceType,
 Null as Source,
 p.ProductCode,
 s.PolicyNumber as PolicyID,
 s.Transactionid,
 s.CommissionTransactionID as CommissionID,
 0 as ClientID,
 Null as PolicyNumber,
 0 as CaseID,
 ct.DateTime as TransactionDate,
 (select Month from msit_CommissionStatementPeriods 
  where ct.DateTime between PeriodStartDate and PeriodEndDate) as Month,
 @Year as Year,
 m.FranchiseSize as FranchiseSize,
 ag.CompetentStatus as FranchiseStatus,
 hh.FranchiseCode as LeagueFranchise,
 m.FranchiseSize as LeagueSize,
 ag.CompetentStatus as LeagueStatus,
 s.Turnover, 
 s.APE,
 s.NBI,
 s.Cases,
 hh.AreaSalesManagerCode as ASDCode,
 hh.RegionalSalesManagerCode as RSMCode,
 'Y' as SaleType,
 Null as Notes
from msft_Sales s
inner join msdt_AdviserDummies a on a.AdviserId = s.AdviserId
inner join mstt_Agents ag on a.FranchiseCode = ag.Code
inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
inner join msdt_CalendarTime ct on s.DateIssuedId = ct.DateId and ct.entrytypeid = 2
inner join msdt_Products p on s.ProductId = p.ProductId
inner join mstt_Agents ag_Seller on s.AgentCode = ag_Seller.Code
left outer join #MaxFranchiseSizeForYear m on ag.Code = m.Code
where
 s.BusinessTypeId = 2 and       -- Issued Business
 s.comparisonId = 1 and         -- Actual
 s.TransactionId > 0 and        -- Exclude Transition Data and Production Adjustments
 (ct.[DateTime] between @SwiftStart and @Swiftend) and  -- Current League year
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType) and
 --Selling Agent is in list of Seller Types OR Business Types (some transactions refernce the franchise as the selling agent)
 ag_Seller.AgentType in (select distinct AgentType from #SellerAgentType union select distinct AgentType from #BusinessAgentType)

-- Add All Production Adjustments 

UNION ALL

select
 ag.Code as AgentCode,
 ag.Code as FranchiseCode,
 'Adjustment' as MovementType,
 'Adjustment' as Source,
 (case  when s.productcode like 'LDG_%' then 'Ledger' when s.productcode like 'O_%' then 'OMS'
  when s.productcode like 'Susp_%' then 'Suspense' else 'Adjustment' end) as SourceType,
 (case when s.productcode like 'Susp_%' then substring(s.productcode,6,8) 
  else substring(s.productcode,1,8) end) as ProductCode,
 s.PolicyNumber as PolicyID,
 s.Transactionid,
 s.CommissionTransactionID as CommissionID,
 0 as ClientID,
 Null as PolicyNumber,
 0 as CaseID,
 ct.DateTime as TransactionDate,
 (select Month from msit_CommissionStatementPeriods 
  where ct.DateTime between PeriodStartDate and PeriodEndDate) as Month,
 s.Year as Year,
 m.FranchiseSize as FranchiseSize,
 ag.CompetentStatus as FranchiseStatus,
 ag.Code as LeagueFranchise,
 m.FranchiseSize as LeagueSize,
 ag.CompetentStatus as LeagueStatus,
 isnull(s.Turnover,0) as Turnover, 
 isnull(s.APE,0) as APE,
 isnull(s.NBI,0) as NBI,
 isnull(s.Cases,0) as Cases,
 hh.AreaSalesManagerCode as ASDCode,
 hh.RegionalSalesManagerCode as RSMCode,
 s.ProductionFlag as SaleType,
 s.Comment as Notes
from mstt_ProductionAdjustments s
inner join mstt_Agents ag on s.AgentCode = ag.Code
inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
inner join msdt_CalendarTime ct on s.DateIssuedId = ct.DateId and ct.entrytypeid = 2 
left outer join #MaxFranchiseSizeForYear m on ag.Code = m.Code
where
-- Select adjustments for current Year with non-zero Turnover
 s.Year = @Year and isnull(s.Turnover,0) <> 0 and 
--Franchise Agent type is in list of Business Types Seller Types OR Business Types (some transactions refernce the franchise as the selling agent)
 ag.AgentType in (select distinct AgentType from #SellerAgentType union select distinct AgentType from #BusinessAgentType)
 
-- Add Transition Data in msft_Sales using Oscar dates

UNION ALL

select
 ag.Code as AgentCode,
 hh.FranchiseCode,
 'Sale' as MovementType,
 'PreSwift' as SourceType,
 'PreSwift' as Source,
 p.ProductCode,
 s.PolicyNumber as PolicyID,
 s.Transactionid,
 s.CommissionTransactionID as CommissionID,
 0 as ClientID,
 Null as PolicyNumber,
 0 as CaseID,
 ct.DateTime as TransactionDate,
 (select Month from msit_CommissionStatementPeriods 
  where ct.DateTime between PeriodStartDate and PeriodEndDate) as Month,
 @Year as Year,
 m.FranchiseSize as FranchiseSize,
 ag.CompetentStatus as FranchiseStatus,
 hh.FranchiseCode as LeagueFranchise,
 m.FranchiseSize as LeagueSize,
 ag.CompetentStatus as LeagueStatus,
 s.Turnover, 
 s.APE,
 s.NBI,
 s.Cases,
 hh.AreaSalesManagerCode as ASDCode,
 hh.RegionalSalesManagerCode as RSMCode,
 'Y' as SaleType,
 Null as Notes
from msft_Sales s
inner join msdt_Adviser a on a.AdviserId = s.AdviserId
inner join mstt_Agents ag on a.FranchiseCode = ag.Code
inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
inner join msdt_CalendarTime ct on s.DateIssuedId = ct.DateId and ct.entrytypeid = 2
inner join msdt_Products p on s.ProductId = p.ProductId
inner join mstt_Agents ag_Seller on s.AgentCode = ag_Seller.Code
left outer join #MaxFranchiseSizeForYear m on ag.Code = m.Code
where
 s.BusinessTypeId = 2 and       -- Issued Business
 s.comparisonId = 1 and         -- Actual
 s.TransactionId = -99 and        -- Transition Data only
 (ct.[DateTime] between @OscarStart and @OscarEnd) and  -- Current League year
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType) and
 --Selling Agent is in list of Seller Types OR Business Types (some transactions refernce the franchise as the selling agent)
 ag_Seller.AgentType in (select distinct AgentType from #SellerAgentType union select distinct AgentType from #BusinessAgentType)
  
-- Add Transition Data in msft_Sales using Oscar dates, but this time join to 
-- AdviserDummies, as there is some business that is linked to Franchises who are NOT in msdt_Adviser - eg Inactive Franchises

UNION ALL

select
 ag.Code as AgentCode,
 hh.FranchiseCode,
 'Sale' as MovementType,
 'PreSwift' as SourceType,
 'PreSwift' as Source,
 p.ProductCode,
 s.PolicyNumber as PolicyID,
 s.Transactionid,
 s.CommissionTransactionID as CommissionID,
 0 as ClientID,
 Null as PolicyNumber,
 0 as CaseID,
 ct.DateTime as TransactionDate,
 (select Month from msit_CommissionStatementPeriods 
  where ct.DateTime between PeriodStartDate and PeriodEndDate) as Month,
 @Year as Year,
 m.FranchiseSize as FranchiseSize,
 ag.CompetentStatus as FranchiseStatus,
 hh.FranchiseCode as LeagueFranchise,
 m.FranchiseSize as LeagueSize,
 ag.CompetentStatus as LeagueStatus,
 s.Turnover, 
 s.APE,
 s.NBI,
 s.Cases,
 hh.AreaSalesManagerCode as ASDCode,
 hh.RegionalSalesManagerCode as RSMCode,
 'Y' as SaleType,
 Null as Notes
from msft_Sales s
inner join msdt_AdviserDummies a on a.AdviserId = s.AdviserId
inner join mstt_Agents ag on a.FranchiseCode = ag.Code
inner join #HistoricalHierarchy hh on ag.Code = hh.FranchiseCode
inner join msdt_CalendarTime ct on s.DateIssuedId = ct.DateId and ct.entrytypeid = 2
inner join msdt_Products p on s.ProductId = p.ProductId
inner join mstt_Agents ag_Seller on s.AgentCode = ag_Seller.Code
left outer join #MaxFranchiseSizeForYear m on ag.Code = m.Code
where
 s.BusinessTypeId = 2 and       -- Issued Business
 s.comparisonId = 1 and         -- Actual
 s.TransactionId = -99 and        -- Transition Data only
 (ct.[DateTime] between @OscarStart and @OscarEnd) and  -- Current League year
 --Franchise Agent type is in list of Business Types
 ag.AgentType in (select distinct AgentType from #BusinessAgentType) and
 --Selling Agent is in list of Seller Types OR Business Types (some transactions refernce the franchise as the selling agent)
 ag_Seller.AgentType in (select distinct AgentType from #SellerAgentType union select distinct AgentType from #BusinessAgentType)

-- Update Swift Policy Details
update s
set Source = p.Comp_code,
    ClientID = isnull(p.Client_Num,0),
    PolicyNumber = p.cont_num,
    CaseID = isnull(p.policyref,0)
from #Sales s
inner join mstt_policies p on p.pol_num = s.policyid
where s.SourceType = 'Swift'

-- Update Status as at Hierarchy Date and Apply overrides
select Code,max(validfromdate) as FromDate
into #LatestHistory
from mstt_AgentsHistory 
where ValidFromDate <= @HierarchyDate
group by Code
order by Code

update s
set FranchiseStatus = h.CompetentStatus,
    Leaguestatus = h.CompetentStatus
from #Sales s
inner join #LatestHistory t1 on t1.code = s.franchisecode
inner join mstt_AgentsHistory h on h.code = t1.code and h.validfromdate = t1.FromDate

update s
set LeagueStatus = cso.CompetentStatus
from #Sales s
inner join #CompetentStatusOverride cso on s.FranchiseCode = cso.franchisecode

--Apply Franchise Size overrides
update s
set LeagueSize = fso.FranchiseSize
from #Sales s
inner join #FranchiseSizeOverride fso on s.FranchiseCode = fso.FranchiseCode

--Apply the Mergers
select distinct m.FromFranchisecode,m.ToFranchiseCode,
s.LeagueSize,s.LeagueStatus,s.ASDCode,s.RSMCode
into #Merger2
from #Sales s
inner join #Merger m on s.FranchiseCode = m.ToFranchiseCode

update s
set LeagueFranchise = m.ToFranchiseCode,
    LeagueSize = m.LeagueSize,
    LeagueStatus = m.LeagueStatus,
    ASDCode = m.ASDCode,
    RSMCode = m.RSMCode
from #Sales s
inner join #Merger2 m on s.FranchiseCode = m.FromFranchiseCode

-- Clear down existing entries on audit table for Year
delete from owt_SalesTurnoverAudit where Year = @Year

-- Insert Sales entries into audit table
insert into owt_SalesTurnoverAudit
(AgentCode,FranchiseCode,MovementType,SourceType,Source,ProductCode,PolicyID,TransactionId,
 CommissionID,ClientID,PolicyNumber,CaseID,TransactionDate,Month,Year,FranchiseSize,FranchiseStatus,
 LeagueFranchise,LeagueSize,LeagueStatus,Turnover,APE,NBI,Cases,ASDCode,RSMCode,SaleType,Notes)
select 
 AgentCode,FranchiseCode,MovementType,SourceType,Source,ProductCode,PolicyID,TransactionId,
 CommissionID,ClientID,PolicyNumber,CaseID,TransactionDate,Month,Year,FranchiseSize,FranchiseStatus,
 LeagueFranchise,LeagueSize,LeagueStatus,Turnover,APE,NBI,Cases,ASDCode,RSMCode,SaleType,Notes
from #Sales

drop table #CompetentStatusOverride
drop table #HistoricalHierarchy
drop table #MaxFranchiseSizeForYear
drop table #AgentHierarchyHistory
drop table #FranchiseSizeOverride
drop table #YearDates
drop table #Merger
drop table #BusinessAgentType
drop table #SellerAgentType
drop table #Merger2
drop table #LatestHistory
drop table #Sales



GO
