/****** Object:  StoredProcedure [dbo].[owp_MIWaitForAvailability]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_MIWaitForAvailability						
	  Author:	A Groves
Date created:	11/06/08							
											
 Description:   This proc will loop for a parameterised period of time until
				OpenAccess is available.  You can parameterise a timeout
				period which when reached causes the proc to exit with an
				error.  The error status can then be interrogated to 
				determine course of action.

				While the routine is waiting for OpenAccess to become available,
				it will write to the process log for each availability check.  
				This can be switched off using the @ProcessLog parameter.


			It is called as follows:

			exec owp_MIWaitForAvailability 'Openwork', 'Data Warehouse', 'BIStream2', '00:01:00', 3, 'Y'
									
	Amendment History								
	-----------------								
											
	Date		Who			Description				
	----		---			-----------			
	16/06/2008	A Groves	Added flag @ProcessLog to switch on/off re-check audit.
							Audit start and end of module execution.
	21/08/2009	A Groves	Fixed bug whereby hours were being rounded down to use
							minutes which have a negligible effect when rounded down.
	06/06/2019	A Groves	Needed to introduce a check that the incremental processing
							had completed without a checking loop. Previously, no checking
							loop caused an error to be raised even if it was in the completed 
							state. This is now corrected so that only an incomplete state will 
							raise an error.  
************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_MIWaitForAvailability]	@Client			varchar(50), 
													@Module			varchar(50),
													@SubModule		varchar(50),
													@DelayPeriod	varchar(8),
													@TimeOutHours	int,
													@ProcessLog		varchar(1)		
AS

declare @IsAvailable				bit,
		@Error						int,
		@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@ProcessDelay				varchar(100),
		@LoopingMinutes				int,
		@TimeOutMinutes				int,
		@StartDateTime				datetime

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @Process			= 'msp_MIAccessControl'
set @ProcessDelay		= 'msp_MIAccessControl Delay'
set @LoopingMinutes		= 0
set @TimeOutMinutes		= @TimeOutHours * 60
set @StartDateTime		= getdate()

exec msp_ProcessLog @PhaseStart, @Process, null, @SubModule, @Client

exec msp_MIAccessControl @Client, @Module, @IsAvailable output, null, null, null, @Error output

while @IsAvailable = 0 and @LoopingMinutes < @TimeOutMinutes
begin
	if @ProcessLog = 'Y'
		exec msp_ProcessLog @PhaseStart, @ProcessDelay, null, @SubModule, @Client

	waitfor delay @DelayPeriod
	
	exec msp_MIAccessControl @Client, @Module, @IsAvailable output, null, null, null, @Error output
	
	select @LoopingMinutes = datediff(mi, @StartDateTime, getdate())
end

exec msp_ProcessLog @PhaseEnd, @Process, null, @SubModule, @Client

if @IsAvailable = 0 and @LoopingMinutes >= @TimeOutMinutes		--AG 06/06/2019
	RAISERROR ('', 16, 1)


GO
