-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_MonthlyReportSSIS_0009aAgents]

AS

SELECT  convert(nvarchar(50),ah.FirmTypeDescription) as FirmTypeDescription,
		convert(nvarchar(7),ah.FirmCode) as FirmCode, 
		convert(nvarchar(255),ah.FirmDescn) as FirmDescn,
		convert(nvarchar(50),ah.FirmCategoryDesc) as FirmCategoryDesc,
		convert(nvarchar(255),left(ah.FirmOscarCode,255)) as FirmOscarCode,
		convert(nvarchar(6),ah.FirmCompStatus) as FirmCompStatus,
		convert(nvarchar(20),ah.FirmCompStatDesc) as FirmCompStatDesc,
		convert(nvarchar(15),mstt_Clients_1.NI_NUMBER) as FirmNINO,
		convert(nvarchar(255),ah.RSMName) as RSMName,
		convert(nvarchar(10),ah.FirmStartDate,103) as FirmStartDate,
		convert(nvarchar(7),ah.AgentCode) as AgentCode,
		convert(nvarchar(255),ah.AgentDesc) as AgentDesc,
		convert(nvarchar(50),ah.AgentTypeDescription) as AgentTypeDescription,
		convert(nvarchar(255),left(ah.AgentOscarCode,255)) as AgentOscarCode,
		convert(nvarchar(6),ah.CompetentStatus) as CompetentStatus,
		convert(nvarchar(20),ah.CompetentStatusDescription) as CompetentStatusDescription,
		convert(nvarchar(15),dbo.mstt_Clients.NI_NUMBER) AS AgentNINO,
		convert(nvarchar(10),ah.AgentStartDate,103) as AgentStartDate
FROM	dbo.cscv_AgentsHierarchy ah 
		LEFT OUTER JOIN dbo.mstt_Clients mstt_Clients_1 ON ah.FirmCode = mstt_Clients_1.AgentCode 
		LEFT OUTER JOIN dbo.mstt_Clients ON ah.AgentCode = dbo.mstt_Clients.AgentCode
WHERE	ah.FirmCode IS NOT NULL 
AND		ah.FirmType IS NOT NULL
and		ISNUMERIC(ah.AgentCode) = 1
order	by ah.FirmTypeDescription, ah.FirmCode

