**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_MonthlyReportSSIS_0009bAllCodesPart1]

AS

truncate table dbo.owt_MonthlyReport0009b

SELECT  distinct isnull(ah.AgentCode,'') as SwiftCode, 
		isnull(ah.AgentDesc,'') as Name, 
		isnull(ah.CompetentStatusDescription,'') as Status, 
		isnull(ah.OscarAgentID,'') as AgentID, 
		isnull(ah.AgentOscarCode,'') as AgentOscarCode, 
		isnull(cl.NI_Number,'') as NI_NUMBER, 
		isnull(ah.GivesAdvice,'') as GivesAdvice, 
		isnull(ag.PortalLogon,'') as PortalLogon
INTO	#tmp0
FROM	dbo.cscv_AgentsHierarchy ah 
		LEFT OUTER JOIN dbo.mstt_Agents ag ON ah.AgentCode = ag.CODE 
		LEFT OUTER JOIN dbo.mstt_Clients cl ON ah.AgentCode = cl.AgentCode 
		LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE	(aan.ProductProviderCode LIKE 'scot eq%') 
OR		(aan.ProductProviderCode LIKE 'zurich%') 
OR		(aan.ProductProviderCode = 'UKPL') 
OR		(aan.ProductProviderCode = 'sterling') 
OR		(aan.ProductProviderCode = 'SIML') 
OR		(aan.ProductProviderCode LIKE 'pym%')

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as Paymentshield
INTO #tmp1
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'PYMTSHLD'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as UKPL
INTO #tmp2
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'UKPL'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as Sterling
INTO #tmp3
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'Sterling'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as SIML
INTO #tmp4
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'SIML'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as 'Scottish Equitable'
INTO #tmp5
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'SCOT EQ'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as 'Scottish Equitable - Legacy'
INTO #tmp6
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'SCOT EQLEG'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as 'Scottish Equitable International'
INTO #tmp7
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'SCOT EQINT'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as 'Zurich New'
INTO #tmp8
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'ZURICH NEW'

SELECT  isnull(ah.AgentCode,'') as SwiftCode, isnull(aan.AgencyNo,'') as 'Zurich Legacy'
INTO #tmp9
FROM dbo.cscv_AgentsHierarchy ah LEFT OUTER JOIN dbo.mstt_AgentAgencyNumbers aan ON ah.AgentCode = aan.AgentCode
WHERE aan.ProductProviderCode = 'ZURICH LEG'

insert into dbo.owt_MonthlyReport0009b
(
  SwiftCode,
  Name,
  Status,
  AgentID,
  AgentOscarCode,
  NINumber,
  GivesAdvice,
  PortalLogon,
  PaymentShield,
  UKPL,
  Sterling,
  SIML,
  ScottishEquitable,
  ScottishEquitableLegacy,
  ScottishEquitableInternational,
  ZurichNew,
  ZurichLegacy
)
SELECT	convert(nvarchar(7),#tmp0.SwiftCode) as SwiftCode, 
		convert(nvarchar(255),#tmp0.Name) as Name, 
		convert(nvarchar(20),#tmp0.Status) as Status, 
		convert(nvarchar(255),#tmp0.AgentID) as AgentID, 
		convert(nvarchar(255),#tmp0.AgentOscarCode) as AgentOscarCode, 
		convert(nvarchar(15),#tmp0.NI_NUMBER) as NINumber, 
		convert(nvarchar(1),#tmp0.GivesAdvice) as GivesAdvice, 
		convert(nvarchar(20),#tmp0.PortalLogon) as PortalLogon,
		isnull(convert(nvarchar(20),#tmp1.Paymentshield),'') as Paymentshield, 
		isnull(convert(nvarchar(20),#tmp2.UKPL),'') as UKPL,
		isnull(convert(nvarchar(20),#tmp3.Sterling),'') as Sterling, 
		isnull(convert(nvarchar(20),#tmp4.SIML),'') as SIML, 
		isnull(convert(nvarchar(20),#tmp5.[Scottish Equitable]),'') as ScottishEquitable, 
		isnull(convert(nvarchar(20),#tmp6.[Scottish Equitable - Legacy]),'') as ScottishEquitableLegacy, 
		isnull(convert(nvarchar(20),#tmp7.[Scottish Equitable International]),'') as ScottishEquitableInternational, 
		isnull(convert(nvarchar(20),#tmp8.[Zurich New]),'') as ZurichNew, 
		isnull(convert(nvarchar(20),#tmp9.[Zurich Legacy]),'') as ZurichLegacy
FROM	#tmp0
		LEFT OUTER JOIN #tmp1 ON #tmp0.SwiftCode = #tmp1.SwiftCode
		LEFT OUTER JOIN #tmp2 ON #tmp0.SwiftCode = #tmp2.SwiftCode
		LEFT OUTER JOIN #tmp3 ON #tmp0.SwiftCode = #tmp3.SwiftCode
		LEFT OUTER JOIN #tmp4 ON #tmp0.SwiftCode = #tmp4.SwiftCode
		LEFT OUTER JOIN #tmp5 ON #tmp0.SwiftCode = #tmp5.SwiftCode
		LEFT OUTER JOIN #tmp6 ON #tmp0.SwiftCode = #tmp6.SwiftCode
		LEFT OUTER JOIN #tmp7 ON #tmp0.SwiftCode = #tmp7.SwiftCode
		LEFT OUTER JOIN #tmp8 ON #tmp0.SwiftCode = #tmp8.SwiftCode
		LEFT OUTER JOIN #tmp9 ON #tmp0.SwiftCode = #tmp9.SwiftCode




 
GO
