CREATE PROCEDURE [dbo].[owp_MonthlyReportSSIS_0013ZurichEnterpriseList]

AS

select	convert(nvarchar(10),getdate(),103) as ScanDate, 
		convert(nvarchar(255),isnull(rtrim(dbo.owf_CleanText(ag.Descn)),'')) as EnterpriseName, 
		convert(nvarchar(25),isnull(rtrim(ag.Code),'')) as EnterpriseCode, 
		convert(nvarchar(100),isnull(rtrim(ah.FranchiseType),'')) as EnterpriseType, 
		convert(nvarchar(10), ag.OscarDateStarted, 103) AS StartDate,	
		case 
			when isnull(client.CorrAddress1,'') <> '' 
			then convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(client.CorrAddress1,''))))
			else convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(ag.Address1,''))))
		end as EnterpriseAddress1,	
		case 
			when isnull(client.CorrAddress1,'') <> '' 
			then convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(client.CorrAddress2,''))))
			else convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(ag.Address2,''))))
		end as EnterpriseAddress2,	
		case 
			when isnull(client.CorrAddress1,'') <> '' 
			then convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(client.CorrAddress3,''))))
			else convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(ag.Address3,''))))
		end as EnterpriseAddress3,	
		case 
			when isnull(client.CorrAddress1,'') <> '' 
			then convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(client.CorrTown,''))))
			else convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(ag.Address4,''))))
		end as EnterpriseAddress4,	
		case 
			when isnull(client.CorrAddress1,'') <> '' 
			then convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(client.CorrCounty,''))))
			else convert(nvarchar(255),rtrim(dbo.owf_CleanText(isnull(ag.Address5,''))))
		end as EnterpriseAddress5,	
		case 
			when isnull(client.CorrAddress1,'') <> '' 
			then convert(nvarchar(25),rtrim(dbo.owf_CleanText(isnull(client.CorrPostCode,''))))
			else convert(nvarchar(25),rtrim(dbo.owf_CleanText(isnull(ag.PostCode,''))))
		end as EnterprisePostcode, 
		convert(nvarchar(100),isnull(rtrim(dbo.owf_CleanText(ag.Telephone)),'')) as EnterpriseTelephone, 
		convert(nvarchar(255),isnull(rtrim(ag.Email),'')) as EnterpriseEmail, 
		convert(nvarchar(255),isnull(rtrim(dbo.owf_CleanText(mstt_Agents_1.Descn)),'')) as BQM, 
		convert(nvarchar(255),isnull(rtrim(dbo.owf_CleanText(mstt_Agents_2.Descn)),'')) as ASD
from	mstt_agents ag
		INNER JOIN mstt_Agents AS mstt_Agents_1 ON ag.Manager2CODE = mstt_Agents_1 .CODE
		INNER JOIN mstt_Agents AS mstt_Agents_2 ON ag.Manager4CODE = mstt_Agents_2 .CODE
		LEFT JOIN cscv_AgentsHierarchy ah ON ag.Code = ah.AgentCode
		LEFT JOIN msit_S_Client client on ag.Code = Client.Refer
where	ag.agenttype in (2,46) --Franchise, AccessAgent
and		ag.CompetentStatus = '1' --Active
order	by ag.Code







GO
/****** Object:  StoredProcedure [dbo].[owp_MonthlyReportSSIS_0014ZurichProInvSellerListPart1]    Script Date: 7/3/2026 3:44:25 PM ******/
