/*********************************************************************************************************

Program:	owp_MonthlyReportSSIS_0029ZurichBizProtIHTSellerListPart1
			(based on owp_MonthlyReport0014 by A Harrison on 03/03/09)            

Author:		A Groves
Date:		12/04/2019            

Description:	This file is generated by the Month End process for Zurich.
				This report is split into two procs (Part 1 and 2) because SSIS can't map columns 
				where there are temporary tables. So Part 2 has to be a simple SELECT statement
				from a permanent table.


Execution:		exec owp_MonthlyReportSSIS_0029ZurichBizProtIHTSellerListPart1

Amendment History
-----------------

Date		Author		Description
----		------		-----------

**********************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_MonthlyReportSSIS_0029ZurichBizProtIHTSellerListPart1]

AS

declare @Date as datetime
declare @NodeLevel int

create table #ChildNodes 
(      
       UniqueRowId          int identity(1,1),
       ParentID             uniqueidentifier,
       ChildID                    uniqueidentifier,
       NodeLevel            tinyint
)  
 
select @Date = isnull(@Date, getdate()),
              @NodeLevel = 1
 

insert into #ChildNodes
select HNL_ParentID,
              HNL_NodeID,
              @NodeLevel
from   sa_insight_HierarchyNodeLink HNL
              inner join sa_insight_Distributor D 
                                         on  D.DIST_ID = HNL.HNL_ParentID 
                                         and D.DIST_Category in (0, 1, 2, 3, 4, 5, 6, 7, 15, 16, 17, 18, 19, 20)   -- AG 20/02/2012
                                                                                  -- Distributor must be a firm
                                                                                  -- AG 15/11/2011 Include Category 0 as these have not yet been assigned in Insight 
                                         and @Date between HNL.HNL_DateFrom and isnull(HNL.HNL_DateTo, '9999-12-31')
                                         and isnull(D.DIST_ExternalID,'') <> ''   -- AG 15/11/2011. Only match if an External ID is set up.

while @@rowcount > 0
begin
      
       set @NodeLevel = @NodeLevel + 1

       insert into #ChildNodes
       select CN.ParentID,
                     HNL.HNL_NodeID,
                     @NodeLevel
       from   #ChildNodes CN
                     inner join sa_insight_HierarchyNodeLink HNL 
                                                on  HNL.HNL_ParentID = CN.ChildID 
                                                and HNL.HNL_Type = 0 
                                                and CN.NodeLevel = @NodeLevel - 1 
                                                and @Date between HNL.HNL_DateFrom and isnull(HNL.HNL_DateTo,'9999-12-31')
                     left join #ChildNodes CNCR 
                                                on  CNCR.ChildID = HNL.HNL_NodeID 
                                                and CNCR.NodeLevel < @NodeLevel - 1
       where  CNCR.ParentID is null

end

/***********************************************************************************************************************

Create a temporary table of branches that prioritises head office branches over non head office branches.
If a distributor has a head office branch, then discard all the distibutor's non-head office branches  
If a distributor does not have any head office branches, then keep all its normal branches.
Finally, dedupe the temporary table of branches so there is only one branch for each distributor
 
************************************************************************************************************************/

--Identify if each distributor has a Head Office set up
select	BRAN_ParentID, max(convert(tinyint,BRAN_IsHeadOffice)) as MaxIsHeadOffice
into	#Branch1
from	dbo.sa_insight_Branch
group	by BRAN_ParentID

--If a Head Office branch exists then take it over normal branches; but if not, then just take the normal branches
select	fullbranch.*
into	#Branch2
from	#Branch1 summbranch
		inner join dbo.sa_insight_Branch fullbranch
					on fullbranch.BRAN_ParentID = summbranch.BRAN_ParentID
					and fullbranch.BRAN_IsHeadOffice = summbranch.MaxIsHeadOffice

--Take one branch per distributor. 
select	BRAN_ParentID, max(convert(varchar(36),BRAN_ID)) as Max_ID
into	#Branch3
from	#Branch2
group	by BRAN_ParentID

/***********************************************************************************************************************

This is the main data extract

************************************************************************************************************************/

truncate table dbo.owt_MonthlyReport0029

insert into dbo.owt_MonthlyReport0029
(
	ScanDate,
	BizProt,
	IHT,
	SellerCode,
	SellerName,
	SellerTypeDescription,
	SellerCategoryDescription,
	StartDate,
	CorrespondenceAddress1,
	CorrespondenceAddress2,
	CorrespondenceAddress3,
	CorrespondenceAddress4,
	CorrespondenceAddress5,
	CorrespondencePostCode,
	EnterpriseName,
	EnterpriseType,
	EnterpriseTelephone,
	EnterpriseEmail,
	ASDName
)
select	distinct
		convert(nvarchar(10),getdate(),103) as Date,
		convert(nvarchar(255),BizProtLic.Prot_Description) as BizProt,
		convert(nvarchar(255),IHTLic.Inv_Description) as IHT,
		convert(nvarchar(25),ud.USR_ExternalID) as SellerCode,
		convert(nvarchar(255),ud.USR_Name) as SellerName,
		convert(nvarchar(255),ag.AgentTypeDescription) as SellerTypeDescription,
		convert(nvarchar(255),dbo.owf_CleanText(ag.AgentCategoryDescription)) as SellerCategoryDescription,
		convert(nvarchar(10), ag.OscarDateStarted, 103) as StartDate,
		convert(nvarchar(255),dbo.owf_CleanText(a.ADD_Line1)) as Address1,
		convert(nvarchar(255),dbo.owf_CleanText(a.ADD_Line2)) as Address2,
		convert(nvarchar(255),dbo.owf_CleanText(a.ADD_Line3)) as Address3,
		convert(nvarchar(255),dbo.owf_CleanText(a.ADD_Line4)) as Address4,
		convert(nvarchar(255),dbo.owf_CleanText(a.ADD_Line5)) as Address5,
		convert(nvarchar(255),dbo.owf_CleanText(a.ADD_Postcode)) as PostCode,
		convert(nvarchar(255),coalesce(d.DIST_TradingName, d.DIST_CompanyName)) as EnterpriseName,
		convert(nvarchar(100),ah.FirmFranchiseType) as EnterpriseType,
		convert(nvarchar(100),c.CD_Telephone) as Telephone,
		convert(nvarchar(100),c.CD_Email) as Email,
		convert(nvarchar(255),mgr4.Descn) as ASDName
from	#ChildNodes CN                                                       
		inner join sa_insight_HierarchyNodeLink hnl	
								  on  hnl.HNL_NodeID = CN.ChildID 
								  and hnl.HNL_Type = 5 --5=User Position
								  and getdate() between hnl.HNL_DateFrom and isnull(hnl.HNL_DateTo,'9999-12-31')
		inner join sa_insight_UserPosition up on up.UPS_ID = hnl.HNL_ParentID
		inner join SA_INSIGHT_UserDetails ud  on up.UPS_UserId = ud.USR_ID
		left join  (select	ulProt.ULIC_UserID as Prot_UserID, licProt.LIC_Description as Prot_Description
					from	sa_insight_UserLicence ulProt
							inner join sa_insight_Licence licProt on licProt.LIC_ID = ulProt.ULIC_LicenceID and licProt.LIC_Code = 'LIC50'	--Business Protection
					where	isnull(ulProt.ULIC_ValidTo,'9999-12-31') > convert(date,GETDATE())
					and		ulProt.ULIC_Status = 2 --Granted	
					) BizProtLic on BizProtLic.Prot_UserID = ud.USR_ID
		left join  (select	ulInv.ULIC_UserID as Inv_UserID, licInv.LIC_Description as Inv_Description
					from	sa_insight_UserLicence ulInv
							inner join sa_insight_Licence licInv on licInv.LIC_ID = ulInv.ULIC_LicenceID and licInv.LIC_Code = 'LIC10'	--IHT
					where	isnull(ulInv.ULIC_ValidTo,'9999-12-31') > convert(date,GETDATE())
					and		ulInv.ULIC_Status = 2 --Granted	
					) IHTLic on IHTLic.Inv_UserID = ud.USR_ID
		left join mstt_Agents ag on ag.code = ud.USR_ExternalID
		LEFT JOIN cscv_AgentsHierarchy ah ON ag.Code = ah.agentCode
		LEFT JOIN mstt_Agents AS mgr4 ON ag.Manager4CODE = mgr4.CODE
		inner join SA_INSIGHT_HierarchyNode hn on hn.HN_ID = hnl.HNL_NodeId	
		inner join SA_INSIGHT_Distributor d on  D.DIST_ID = CN.ParentID	
		inner join #Branch3 TmpB on TmpB.BRAN_ParentID =  d.DIST_ID		
		inner join SA_INSIGHT_Branch b on b.BRAN_ID = TmpB.Max_ID 
		inner join SA_INSIGHT_Address a on a.ADD_ParentID = b.BRAN_ID 
		left join SA_INSIGHT_ContactDetails c on c.CD_ParentID = b.BRAN_ID
where	ag.CompetentStatus = '1' --Active
AND		ag.GivesAdvice = 'Y'
AND		ah.firmtypedescription not in ('Directly Authorised')	
and		up.UPS_JobTitle in (4,52,61,62,63)










