/****** Object:  StoredProcedure [dbo].[owp_MortgageBrokerFees]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_MortgageBrokerFees
  	 					
	  Author:	Sarah Inglis - SQL (15/04/2016)
				A Groves - Stored procedure 

Date created:	15/04/2016
													
 Description:   This stored procedure calculates the retention amount that Openwork will retain
				from the fee that the client paid directly to their adviser as part of the client's
				mortgage application. This fee will have been declared on OWS. Once a month, a Logi 
				report will sum all the retention amounts on table "owt_MortgageBrokerFees" for each 
				enterprise and PSD will then create a standing order in Swift to retain that month's 
				retention amount for Openwork. This standing order can then be viewed by the 
				enterprise on their OpenAccess Account Statement. 
				
				Note:
				----
				1)	Just Mortgages Direct are subject to 3%. It was pre agreed that they would only have 
					a 3% retention. 1010902 and 10010900 are First Affinity and GHL and they are only 
					taking 5% from their sub firms.
				2)	Where commission splits occur, then we get a table row for each split. Thus it is
					possible to have multiple rows for a case - this is NOT a bug.
				
				It is called as follows:

				exec owp_MortgageBrokerFees 'Openwork', 'SecondaryTransformationPart3'
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
18/04/2016	S Inglis	Amendment to include the adviser split % in the Deduction, APE and 
						Elite point calculations.
18/04/2016	A Groves	Added config for the mortgage application start date.
19/04/2016	S Inglis	Amendment to include adviser split % in APE calculation as this didnt save.
05/05/2016	A Groves	SR433012. Join bug on table sa_ows_Policies. Was SaleID, changed to PolicyID.
08/07/2016	A Groves	1) SR441658. Current processing does not account for -ve clawbacks and 
							adjustments. Processing introduced to zero the following columns if
							the clawback/adj is not 100% of the original amount:
							1) Broker fee
							2) APE
							3) Elite points
							4) Deduction amount
							if the clawback/adj is 100% of the original amount then it is signed
							appropriately.
						2) Changed ProcFeeAmount from oal.APE to oal.TotalAmount as this the amount
							paid rather than a productivity measure.
						3) Changed sa_swift_S_AGENTS to mstt_Agents for efficiency.
						4) Added TransctionID to table owt_MortgageBrokerFees for efficiency.
						5) Removed BusinessCode from the join on msit_CommissionStatement because
							a split can go to another firm.
						6) Moved join on mstt_Agents to after the "oal" to ensure a split to another
							firm picks up the correct "agt" row (i.e. correct Manager2Code). 
10/07/2018	A Groves	SR510283/CH21939. Enhanced to show the partner's name if the policy owner
							is the partner. Client name is shown where the policy owner is either
							client or joint - as before.							
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_MortgageBrokerFees]
	@Client		varchar(50),
	@Module		varchar(50)
AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@JMDBusinessUID				varchar(7),
		@CreateDateTime				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @CreateDateTime	= getdate()

set @JMDBusinessUID = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'BusinessUID' and cde.Description = 'JMD')

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Populate the mortgage broker fees table

	****************************************************************************/
	
	insert into owt_MortgageBrokerFees
	(
		FirmUID,
		FirmName,
		AdviserUID,
		AdviserName,
		SaleID,
		PolicyID,
		TransactionID,			-- AG 08/07/2016 (4)
		CommissionType,
		PendingPaymentID,
		Month,
		MortgageNumber,
		MortgageCategory,
		ProcFeeAmount,
		AdviceFeeCharged,
		AdviceFeeAmount,
		AgentSplit,
		RetentionRate,
		DeductionAmount,
		ApplicationDate,
		SubmittedDate,
		PaymentMatchedDate,
		ClientName,
		APE,
		ElitePoints,
		StandingOrderID,
		DateInserted,
		DateLastUpdated
	)
	Select	oal.BusinessCode,
			oal.BusinessName,
			oal.SellerCode,
			oal.SellerForename + ' ' +oal.SellerSurname as SellerName,
			mdaf.SaleId,
			oal.CaseId,
			pt.ID as TransactionID,						-- AG 08/07/2016 (4)							
			comms.CommissionType,
			comms.PendingPaymentID,
			OAL.Month,
			oal.policy as MortgageNumber,
			inv.valuename as MortgageCategory,
			oal.TotalPayment as ProcFeeAmount,			-- AG 08/07/2016 (2)
			inv2.ValueName as AdviceFeeCharged,
			mdaf.BrokerFeeAmount as AdviceFeeAmount,	-- This will be signed correctly or potentially set to zero later
			oal.AgentSplit,
			case when agt.Manager2Code in ('1010902','1010900') then 5 when oal.BusinessCode = @JMDBusinessUID then 3 else (100 - oal.EnhancementRate) end as RetentionRate,
			0 as DeductionAmount,	-- Calculated later
			mdaf.MortgageApplicationDate as ApplicationDate,
			sale.DateSubmitted,
			oal.CreateDate,
			--pers.FirstName + ' ' + pers.LastName as ClientName,			  AG 10/07/2018
            case when pol.PolicyOwnerType = 2 --1=Client;2=Partner;3=Joint    AG 10/07/2018
				then partnr.FirstName + ' ' + partnr.LastName 
                else pers.FirstName + ' ' + pers.LastName 
            end as ClientName,
			0 as APE,				-- Calculated later
			0 as ElitePoints,		-- Calculated later
			NULL as StandingOrderID,
			@CreateDateTime as DateInserted,
			@CreateDateTime as DateLastUpdated
	--select COUNT(*)
	from	PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf
			inner join PolicyOneLink.sa_ows_MortgageProductSummary mps on mps.PolicyId = mdaf.PolicyId
			inner join StaticData.sa_ows_InputValues inv on inv.InputID = mps.MortgageCategoryId
			inner join StaticData.sa_ows_InputValues inv2 on inv2.InputID = HasBrokerFeeCharged
			inner join sa_ows_Sale sale on sale.SaleID = mdaf.SaleId
			inner join sa_ows_Policies pol on pol.PolicyID = mdaf.PolicyId		-- AG 05/05/2016
			inner join mstt_Policies p on p.PolicyRef = pol.PolicyID
			inner join mstt_PolicyTransactions pt on pt.PolicyID = p.POL_NUM 			
			inner join sa_ows_Person pers on pers.PersonID = sale.PersonID
            left join sa_ows_Person partnr on partnr.PersonID = pers.PartnerPersonID						-- AG 10/07/2018
			inner join msit_CommissionStatement comms on comms.TransactionID = convert(varchar(10),pt.ID)	-- AG 08/07/2016 (5)
			inner join msit_OpenworkAdviserListing oal 
						on oal.Source = 'Openwork 2006'
						and oal.SourceID = comms.ID
			inner join mstt_Agents agt on agt.CODE = oal.BusinessCode			-- AG 08/07/2016 (6)
			inner join owt_SelectionControl sc 
						on  sc.KeyValue = 'MortgageApplicationDate'
						and sc.KeyType = 'MortgageRetention'
						and sc.Process = 'owp_MortgageBrokerFees'
						and mdaf.MortgageApplicationDate between sc.EffectiveStartDate and sc.EffectiveEndDate
			left join owt_MortgageBrokerFees mbf on mbf.PendingPaymentID = comms.PendingPaymentID
	where	oal.CreateDate >= DATEADD(week,-2,getdate())
	and		mbf.PendingPaymentID is null

	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Update the sign sensitive columns.
		SR441658. AG 08/07/2016 (1).
																		
		Find the oldest "IC Initial" payment amount for the adviser within the transaction
		as this is the one that accrues APE. Any other payment for the same amount (i.e. 100%
		of the value of this payment - either positive or negative) will also get this APE 
		(correctly signed). Any other payments (i.e. not 100% - either positive or negative)
		are seen as partial adjustments and these should not get APE, so APE is set to zero.
	
	****************************************************************************/

	-- The join ensures that only the oldest IC Initial payment amount for the transaction and adviser is stored.
	
	select	mbf.PolicyID, mbf.TransactionID, mbf.AdviserUID, mbf.ProcFeeAmount
	into	#APE
	from	(select	mbf.PolicyID, mbf.TransactionID, mbf.AdviserUID, min(mbf.PendingPaymentID) as MinPendingPaymentID
			 from	owt_MortgageBrokerFees mbf
			 where	mbf.CommissionType = 1	-- IC Initial
			 group	by mbf.PolicyID, mbf.TransactionID, mbf.AdviserUID) as APEPayment
			inner join owt_MortgageBrokerFees mbf on mbf.PendingPaymentID = APEPayment.MinPendingPaymentID

	-- Now update the sign sensitive columns.
	
	update mbf
		set APE				=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0 
											then -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100))
											else abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100))
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,
			ElitePoints		=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0 
												then -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
												else abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,
			DeductionAmount	=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0	-- Deduction always has the opposite sign to the broker fee
												then abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
												else -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,										
			AdviceFeeAmount	=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0 
												then -abs(mbf.AdviceFeeAmount)
												else abs(mbf.AdviceFeeAmount)
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end
	from	owt_MortgageBrokerFees mbf
			left join #APE ape	on  ape.PolicyID = mbf.PolicyID
								and ape.TransactionID = mbf.TransactionID
								and ape.AdviserUID = mbf.AdviserUID
	where	mbf.AdviceFeeCharged = 'Yes'
	and		mbf.DateInserted = @CreateDateTime
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Update. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [dbo].[owp_MortgageBrokerFees_Backup20180711AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_MortgageBrokerFees
  	 					
	  Author:	Sarah Inglis - SQL (15/04/2016)
				A Groves - Stored procedure 

Date created:	15/04/2016
													
 Description:   This stored procedure calculates the retention amount that Openwork will retain
				from the fee that the client paid directly to their adviser as part of the client's
				mortgage application. This fee will have been declared on OWS. Once a month, a Logi 
				report will sum all the retention amounts on table "owt_MortgageBrokerFees" for each 
				enterprise and PSD will then create a standing order in Swift to retain that month's 
				retention amount for Openwork. This standing order can then be viewed by the 
				enterprise on their OpenAccess Account Statement. 
				
				Note:
				----
				1)	Just Mortgages Direct are subject to 3%. It was pre agreed that they would only have 
					a 3% retention. 1010902 and 10010900 are First Affinity and GHL and they are only 
					taking 5% from their sub firms.
				2)	Where commission splits occur, then we get a table row for each split. Thus it is
					possible to have multiple rows for a case - this is NOT a bug.
				
				It is called as follows:

				exec owp_MortgageBrokerFees 'Openwork', 'SecondaryTransformationPart3'
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
18/04/2016	S Inglis	Amendment to include the adviser split % in the Deduction, APE and 
						Elite point calculations.
18/04/2016	A Groves	Added config for the mortgage application start date.
19/04/2016	S Inglis	Amendment to include adviser split % in APE calculation as this didnt save.
05/05/2016	A Groves	SR433012. Join bug on table sa_ows_Policies. Was SaleID, changed to PolicyID.
08/07/2016	A Groves	1) SR441658. Current processing does not account for -ve clawbacks and 
							adjustments. Processing introduced to zero the following columns if
							the clawback/adj is not 100% of the original amount:
							1) Broker fee
							2) APE
							3) Elite points
							4) Deduction amount
							if the clawback/adj is 100% of the original amount then it is signed
							appropriately.
						2) Changed ProcFeeAmount from oal.APE to oal.TotalAmount as this the amount
							paid rather than a productivity measure.
						3) Changed sa_swift_S_AGENTS to mstt_Agents for efficiency.
						4) Added TransctionID to table owt_MortgageBrokerFees for efficiency.
						5) Removed BusinessCode from the join on msit_CommissionStatement because
							a split can go to another firm.
						6) Moved join on mstt_Agents to after the "oal" to ensure a split to another
							firm picks up the correct "agt" row (i.e. correct Manager2Code). 							
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_MortgageBrokerFees_Backup20180711AG]
	@Client		varchar(50),
	@Module		varchar(50)
AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@JMDBusinessUID				varchar(7),
		@CreateDateTime				datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @CreateDateTime	= getdate()

set @JMDBusinessUID = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'BusinessUID' and cde.Description = 'JMD')

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Populate the mortgage broker fees table

	****************************************************************************/
	
	insert into owt_MortgageBrokerFees
	(
		FirmUID,
		FirmName,
		AdviserUID,
		AdviserName,
		SaleID,
		PolicyID,
		TransactionID,			-- AG 08/07/2016 (4)
		CommissionType,
		PendingPaymentID,
		Month,
		MortgageNumber,
		MortgageCategory,
		ProcFeeAmount,
		AdviceFeeCharged,
		AdviceFeeAmount,
		AgentSplit,
		RetentionRate,
		DeductionAmount,
		ApplicationDate,
		SubmittedDate,
		PaymentMatchedDate,
		ClientName,
		APE,
		ElitePoints,
		StandingOrderID,
		DateInserted,
		DateLastUpdated
	)
	Select	oal.BusinessCode,
			oal.BusinessName,
			oal.SellerCode,
			oal.SellerForename + ' ' +oal.SellerSurname as SellerName,
			mdaf.SaleId,
			oal.CaseId,
			pt.ID as TransactionID,						-- AG 08/07/2016 (4)							
			comms.CommissionType,
			comms.PendingPaymentID,
			OAL.Month,
			oal.policy as MortgageNumber,
			inv.valuename as MortgageCategory,
			oal.TotalPayment as ProcFeeAmount,			-- AG 08/07/2016 (2)
			inv2.ValueName as AdviceFeeCharged,
			mdaf.BrokerFeeAmount as AdviceFeeAmount,	-- This will be signed correctly or potentially set to zero later
			oal.AgentSplit,
			case when agt.Manager2Code in ('1010902','1010900') then 5 when oal.BusinessCode = @JMDBusinessUID then 3 else (100 - oal.EnhancementRate) end as RetentionRate,
			0 as DeductionAmount,	-- Calculated later
			mdaf.MortgageApplicationDate as ApplicationDate,
			sale.DateSubmitted,
			oal.CreateDate,
			pers.FirstName + ' ' + pers.LastName as ClientName,
			0 as APE,				-- Calculated later
			0 as ElitePoints,		-- Calculated later
			NULL as StandingOrderID,
			@CreateDateTime as DateInserted,
			@CreateDateTime as DateLastUpdated
	--select COUNT(*)
	from	PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf
			inner join PolicyOneLink.sa_ows_MortgageProductSummary mps on mps.PolicyId = mdaf.PolicyId
			inner join StaticData.sa_ows_InputValues inv on inv.InputID = mps.MortgageCategoryId
			inner join StaticData.sa_ows_InputValues inv2 on inv2.InputID = HasBrokerFeeCharged
			inner join sa_ows_Sale sale on sale.SaleID = mdaf.SaleId
			inner join sa_ows_Policies pol on pol.PolicyID = mdaf.PolicyId		-- AG 05/05/2016
			inner join mstt_Policies p on p.PolicyRef = pol.PolicyID
			inner join mstt_PolicyTransactions pt on pt.PolicyID = p.POL_NUM 			
			inner join sa_ows_Person pers on pers.PersonID = sale.PersonID
			inner join msit_CommissionStatement comms on comms.TransactionID = convert(varchar(10),pt.ID)	-- AG 08/07/2016 (5)
			inner join msit_OpenworkAdviserListing oal 
						on oal.Source = 'Openwork 2006'
						and oal.SourceID = comms.ID
			inner join mstt_Agents agt on agt.CODE = oal.BusinessCode			-- AG 08/07/2016 (6)
			inner join owt_SelectionControl sc 
						on  sc.KeyValue = 'MortgageApplicationDate'
						and sc.KeyType = 'MortgageRetention'
						and sc.Process = 'owp_MortgageBrokerFees'
						and mdaf.MortgageApplicationDate between sc.EffectiveStartDate and sc.EffectiveEndDate
			left join owt_MortgageBrokerFees mbf on mbf.PendingPaymentID = comms.PendingPaymentID
	where	oal.CreateDate >= DATEADD(week,-2,getdate())
	and		mbf.PendingPaymentID is null

	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Update the sign sensitive columns.
		SR441658. AG 08/07/2016 (1).
																		
		Find the oldest "IC Initial" payment amount for the adviser within the transaction
		as this is the one that accrues APE. Any other payment for the same amount (i.e. 100%
		of the value of this payment - either positive or negative) will also get this APE 
		(correctly signed). Any other payments (i.e. not 100% - either positive or negative)
		are seen as partial adjustments and these should not get APE, so APE is set to zero.
	
	****************************************************************************/

	-- The join ensures that only the oldest IC Initial payment amount for the transaction and adviser is stored.
	
	select	mbf.PolicyID, mbf.TransactionID, mbf.AdviserUID, mbf.ProcFeeAmount
	into	#APE
	from	(select	mbf.PolicyID, mbf.TransactionID, mbf.AdviserUID, min(mbf.PendingPaymentID) as MinPendingPaymentID
			 from	owt_MortgageBrokerFees mbf
			 where	mbf.CommissionType = 1	-- IC Initial
			 group	by mbf.PolicyID, mbf.TransactionID, mbf.AdviserUID) as APEPayment
			inner join owt_MortgageBrokerFees mbf on mbf.PendingPaymentID = APEPayment.MinPendingPaymentID

	-- Now update the sign sensitive columns.
	
	update mbf
		set APE				=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0 
											then -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100))
											else abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100))
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,
			ElitePoints		=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0 
												then -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
												else abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,
			DeductionAmount	=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0	-- Deduction always has the opposite sign to the broker fee
												then abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
												else -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,										
			AdviceFeeAmount	=	case when abs(round(mbf.ProcFeeAmount,2)) = abs(round(ape.ProcFeeAmount,2))
									then case when mbf.ProcFeeAmount < 0 
												then -abs(mbf.AdviceFeeAmount)
												else abs(mbf.AdviceFeeAmount)
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end
	from	owt_MortgageBrokerFees mbf
			left join #APE ape	on  ape.PolicyID = mbf.PolicyID
								and ape.TransactionID = mbf.TransactionID
								and ape.AdviserUID = mbf.AdviserUID
	where	mbf.AdviceFeeCharged = 'Yes'
	and		mbf.DateInserted = @CreateDateTime
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Update. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
