			mdaf.BrokerFeeAmount as AdviceFeeAmount,	-- This will be signed correctly or potentially set to zero later
			oal.AgentSplit,
			case when agt.Manager2Code in ('1010902','1010900') then 5 when oal.BusinessCode = @JMDBusinessUID then 3 else (100 - oal.EnhancementRate) end as RetentionRate,
			0 as DeductionAmount,	-- Calculated later
			mdaf.MortgageApplicationDate as ApplicationDate,
			sale.DateSubmitted,
			oal.CreateDate,
			pers.FirstName + ' ' + pers.LastName as ClientName,
			0 as APE,				-- Calculated later
			0 as ElitePoints,		-- Calculated later
			NULL as StandingOrderID,
			@CreateDateTime as DateInserted,
			@CreateDateTime as DateLastUpdated
	--select COUNT(*)
	from	PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf
			inner join PolicyOneLink.sa_ows_MortgageProductSummary mps on mps.PolicyId = mdaf.PolicyId
			inner join StaticData.sa_ows_InputValues inv on inv.InputID = mps.MortgageCategoryId
			inner join StaticData.sa_ows_InputValues inv2 on inv2.InputID = HasBrokerFeeCharged
			inner join sa_ows_Sale sale on sale.SaleID = mdaf.SaleId
			inner join sa_ows_Policies pol on pol.PolicyID = mdaf.PolicyId		-- AG 05/05/2016
			inner join mstt_Policies p on p.PolicyRef = pol.PolicyID
			inner join mstt_PolicyTransactions pt on pt.PolicyID = p.POL_NUM 			
			inner join sa_ows_Person pers on pers.PersonID = sale.PersonID
			inner join msit_CommissionStatement comms on comms.TransactionID = convert(varchar(10),pt.ID)	-- AG 08/07/2016 (5)
			inner join msit_OpenworkAdviserListing oal 
						on oal.Source = 'Openwork 2006'
						and oal.SourceID = comms.ID
			inner join mstt_Agents agt on agt.CODE = oal.BusinessCode			-- AG 08/07/2016 (6)
			inner join owt_SelectionControl sc 
						on  sc.KeyValue = 'MortgageApplicationDate'
						and sc.KeyType = 'MortgageRetention'
						and sc.Process = 'owp_MortgageBrokerFees'
						and mdaf.MortgageApplicationDate between sc.EffectiveStartDate and sc.EffectiveEndDate
--			left join owt_MortgageBrokerFees_SR441658 mbf on mbf.PendingPaymentID = comms.PendingPaymentID
--	where	oal.CreateDate >= DATEADD(week,-2,getdate())
--	and		mbf.PendingPaymentID is null

	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Insert. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Update the sign sensitive columns.
		SR441658. AG 08/07/2016 (1).
																		
	****************************************************************************/

	-- Get the total unsplit procuration fee for each slice and commission type within that

	select	mbf.PolicyID, mbf.TransactionID, mbf.CommissionType, sum(mbf.ProcFeeAmount) as UnsplitTotalProcFeeAmount
	into	#APE
	from	owt_MortgageBrokerFees_SR441658 mbf
	group	by mbf.PolicyID, mbf.TransactionID, mbf.CommissionType

	-- Now update the sign sensitive columns
	-- Note that the only time the split percentages won't match is when a partial adjustment or clawback is
	-- processed i.e. where CommissionType = 2 or 17
	
	update mbf
		set APE				=	case when abs(round(((mbf.ProcFeeAmount / ape.UnsplitTotalProcFeeAmount) * 100),0)) = mbf.AgentSplit
									then case when mbf.ProcFeeAmount < 0 
											then -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100))
											else abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100))
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,
			ElitePoints		=	case when abs(round(((mbf.ProcFeeAmount / ape.UnsplitTotalProcFeeAmount) * 100),0)) = mbf.AgentSplit
									then case when mbf.ProcFeeAmount < 0 
												then -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
												else abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,
			DeductionAmount	=	case when abs(round(((mbf.ProcFeeAmount / ape.UnsplitTotalProcFeeAmount) * 100),0)) = mbf.AgentSplit
									then case when mbf.ProcFeeAmount < 0	-- Deduction always has the opposite sign to the broker fee
												then abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
												else -abs(mbf.AdviceFeeAmount * (mbf.AgentSplit/100) * (mbf.RetentionRate/100)) 
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end,										
			AdviceFeeAmount	=	case when abs(round(((mbf.ProcFeeAmount / ape.UnsplitTotalProcFeeAmount) * 100),0)) = mbf.AgentSplit
									then case when mbf.ProcFeeAmount < 0 
												then -abs(mbf.AdviceFeeAmount)
												else abs(mbf.AdviceFeeAmount)
										 end
									else 0	-- Partial adjustment/clawback so set to zero
								end
	from	owt_MortgageBrokerFees_SR441658 mbf
			inner join #APE ape 
						on  ape.PolicyID = mbf.PolicyID
						and ape.TransactionID = mbf.TransactionID
						and ape.CommissionType = 1	-- Get the original (IC) amount to enable partial 
													-- amount clawbacks and adjustments to be recognised 
	where	mbf.AdviceFeeCharged = 'Yes'
	and		mbf.DateInserted = @CreateDateTime
	
	set @RowCount = @@rowcount
	
	set @ProcessMessage = 'Table Update. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [dbo].[owp_OMS_APE_Extract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[owp_OMS_APE_Extract]
WITH RECOMPILE 
as

------------------------------------------------------------------------------------
-- Generates Production Adjustments for OMS Commission Payments with Turnover or DA 
------------------------------------------------------------------------------------

----------------------------------------------------------------------------------
-- Delete all existing OMS APE Adjustment rows on the Production Adjustments table
---------------------------------------------------------------------------------

delete from mstt_ProductionAdjustments 
where productcode like 'O_%' and transactionid = -9

select 
  BusinessCode,
  SellerCode,
  Client,
  Policy,
  ProdType,
  HierarchyProduct,
  pr.ProductID,
  CreateDate,
  Month,
  ProviderCode,
  isnull(DA,0) as DA,
  isnull(Turnover,0) as Turnover,
  isnull(APE,0) as APE,
  isnull(EnhancedNBI,0) as NBI,
  isnull(Margin,0) as Margin,
  (rtrim(Policy) 
   + '  :Product - ' + rtrim(ProdType) 
   + '  :Provider - ' + rtrim(ProviderCode) 
   + '  :Seller - ' + SellerCode 
   + '  :PayDate - ' + CAST(CONVERT(NVARCHAR, createdate, 103) AS varchar(10))
   + '  :Client - ' + rtrim(Client)) as Notes
into #OMS_APE
from omst_OMSCommissionPayments oms
left outer join msdt_products pr on pr.productcode = oms.hierarchyproduct
where oms.commtype in (1,2)
and (isnull(Turnover,0) <> 0 or isnull(DA,0) <> 0)

---------------------------------------------------------------------------------
-- insert OMS APE records into mstt_ProductionAdjustments
---------------------------------------------------------------------------------

Insert into mstt_ProductionAdjustments 
select
  -9,
  t1.BusinessCode, 
  -9,
  -99,
  (select AdviserID from msdt_Adviser where AgentCode = t1.BusinessCode),
  2,
  (case when t1.ProductID is not null then t1.ProductID else -99 end),
  -99,
  (select DateID from msdt_CalendarTime where DateTime = t1.Month and EntryTypeID = 2),
  (select DateID from msdt_CalendarTime where DateTime = t1.Month and EntryTypeID = 2),
  2,
  -99,
  isnull((select FranchiseSizeID from msdt_FranchiseSize where FranchiseSize = (select case when MIN(FranchiseSize) < 1000 then MIN(FranchiseSize) else 1000 end from mstt_Agents where CODE = t1.BusinessCode )), -1),
  -99,
  1,
  -99,
  -99,
  2,
  -99,
  cast(t1.Turnover as decimal(12,2)),
  cast(t1.APE as decimal(12,2)),
  cast(t1.NBI as decimal(12,2)),
  cast(t1.DA as decimal(12,2)),
  cast(t1.Margin as decimal(12,2)),
  case when t1.Turnover > 0 then 1 when t1.Turnover < 0 then -1 else 0 end,
  0,
  t1.HierarchyProduct,
  0,
  left(t1.Notes,255),
  'Y',
  (select c.Year from msit_CommissionStatementPeriods c where c.Month = t1.Month)

from #oms_ape t1

---------------------------------------------------------------------------------
-- clear down temp tables
---------------------------------------------------------------------------------
drop table #OMS_APE


GO
/****** Object:  StoredProcedure [dbo].[owp_OngoingRate]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_OngoingRate					
	  Author:	A Groves
Date created:	05/07/2018
		
 Description:   This proc populates (new) table "dbo.owt_OngoingRate". It is used by the
				VNB Recognition proc to look up the ongoing rate that was in place at the
				time that the transaction (slice) was created in Swift. The purpose is to 
				ensure that the OGS rate used on a transaction at any point in time remains 
				the same. This will then ensure that VNB points calculated in the past will 
				never later re-calculate to a different value, even if the average OGS rate 
				has changed over time - which is more than likely.  
				
				It is called as follows:

				exec owp_OngoingRate 'Openwork', 'Transform'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
23/11/2018	A Groves	SR519806: Multiple rows for the same client_num were being created due to 
						duplicate PersonIDs on OWS that link to the same ClientID on Swift. This 
						was causing the MERGE to fail in proc owp_RecognitionSwift. 
						1) GROUP BY introduced to use the earliest PersonID.
						2) Removed OWSPersonID from join to dbo.owt_OngoingRate as this could
							also cause dupes.
						3) Pulled in the partner from the Swift table where the policy is partner 
							only.
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_OngoingRate] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare	@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@DateLastUpdated			datetime,
		@ProcessMessage				varchar(100),
		@ProcessMessage1			varchar(100),
		@ProcessMessage2			varchar(100),
		@ProcessMessage3			varchar(100),
		@Yesterday					date,
		@DayBeforeYesterday			date,
		@DateNotEnded				date,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@RowCount					int			

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @DateLastUpdated	= getdate()
set @Yesterday			= dateadd(dd,-1,getdate())	--<-- NORMAL
--set @Yesterday			= '2017-01-01'
set @DayBeforeYesterday = dateadd(dd,-1,@Yesterday)
set @DateNotEnded		= '9999-12-31'

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		look up the OGS rates

	****************************************************************************/

	select	min(s.PersonID) as PersonID,		--AG 23/11/2018
			case when p.PolicyOwnerType = 2		--1=Client;2=Partner;3=Joint
				then case when swp.joint_num is not null then swp.joint_num else swp.Client_Num end 
				else swp.Client_Num
			end as Client_Num,
			p.InternalProductID, 
			swp.ProductCode 
	into	#SwiftOWSClientLink
	from	sa_ows_Sale s
			inner join sa_ows_Policies p on p.SaleID = s.SaleID
			inner join mstt_Policies swp on swp.PolicyRef = p.PolicyID
	where	s.DateSubmitted is not null
	--and		s.PersonID = 146030
	group	by	case when p.PolicyOwnerType = 2	--1=Client;2=Partner;3=Joint	AG 23/11/2018
					then case when swp.joint_num is not null then swp.joint_num else swp.Client_Num end 
					else swp.Client_Num
				end, 
				p.InternalProductID, 
				swp.ProductCode

	select @RowCount = @@rowcount
	set @ProcessMessage = '#SwiftOWSClientLink = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	-- The OGS rate is stored for the client/product combination
	select	link.Client_Num, 
			link.ProductCode, 
			min(case when ogs.OwnerID = 2 
					then cli.PartnerPersonID 
					else cli.PersonID 
				end) as OWSPersonID,
			max(ogs.OngoingServiceFee) as OngoingServiceFee
	into	#OGSLookUp
	from	#SwiftOWSClientLink link 
			inner join dbo.sa_ows_Person cli on cli.PersonID = link.PersonID
			inner join mstt_ProductHierarchy ph on ph.ProductCode = link.ProductCode
			inner join Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee ogs
							on ogs.PersonID = link.PersonID
							and ogs.InternalProductID = (case when ph.RDRType = 'ONPLAT' 
															then -2 
															else link.InternalProductID 
														 end)
	where	ogs.OngoingServiceFee > 0.0							--AG 26/04/2018
	group	by 	link.Client_Num, link.ProductCode

	select @RowCount = @@rowcount
	set @ProcessMessage = '#OGSLookUp Insert 1 = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
	
	-- The OGS rate is stored just for the client (dummy product code)
	insert into #OGSLookUp
	(
		Client_Num, 
		ProductCode, 
		OWSPersonID,
		OngoingServiceFee
	)
	select	Client_Num, 
			'(CLIENT)' as ProductCode,
			min(OWSPersonID) as OWSPersonID,
			max(OngoingServiceFee) as OngoingServiceFee
	from	#OGSLookUp
	group	by Client_Num
	
	select @RowCount = @@rowcount
	set @ProcessMessage = '#OGSLookUp Insert 2 = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
			
	/****************************************************************************
	
		Update the destination table for Client/Product pair

	****************************************************************************/

	insert into dbo.owt_OngoingRate
	(
		EffectiveStartDate,					
		EffectiveEndDate,					
		LatestRowInd,
		OWSPersonID,						
		Client_Num,
		ProductCode,
		OngoingServiceFee,
		DateLoaded,
		DateLastUpdated	
	)
		select	@Yesterday as EffectiveStartDate,	
				@DateNotEnded as EffectiveEndDate,	
				0 as LatestRowInd,					--Must be 0 here. Will be toggled to 1 later.
				lu.OWSPersonID,
				lu.Client_Num, 
				lu.ProductCode, 
				lu.OngoingServiceFee,
				@DateLastUpdated as DateInserted,
				@DateLastUpdated as DateLastUpdated
		from	#OGSLookUp lu
				left join dbo.owt_OngoingRate ogs 
							on  ogs.Client_Num = lu.Client_Num
							and ogs.ProductCode = lu.ProductCode
							and ogs.EffectiveEndDate = @DateNotEnded				--This will ensure just one row is joined
							and	ogs.LatestRowInd = 1								-- ...and this ensures no rows added by this proc run are picked up
		where	(ogs.ID is null)													--On the source table but not on the destination table so must be a new starter
		or		(isnull(ogs.OngoingServiceFee,0) <> isnull(lu.OngoingServiceFee,0))	--On both tables so check for a column change
		or		(isnull(ogs.OWSPersonID,-1) <> isnull(lu.OWSPersonID,-1))			--AG 23/11/2018
																		
	set @RowCount = @@rowcount
	set @ProcessMessage1 = 'New History Rows (New and Changes) - Rows Inserted = ' + convert(varchar(20),@RowCount)
																		
	/****************************************************************************

		Close the penultimate row (if there is one) for Client/Product pair
																		
	****************************************************************************/

	update	old
		set EffectiveEndDate = @DayBeforeYesterday,	-- Update the audit info
			LatestRowInd = 0,						-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated		-- Update the audit info
	from	dbo.owt_OngoingRate old
			inner join dbo.owt_OngoingRate new		
							on  new.Client_Num = old.Client_Num			
							and new.ProductCode = old.ProductCode
							and new.EffectiveEndDate = @DateNotEnded	-- This....
							and	new.LatestRowInd = 0					-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1										-- This is the penultimate row (if it exists)
 
	set @RowCount = @@rowcount
	set @ProcessMessage2 = 'Penultimate Rows Closed - Rows Updated = ' + convert(varchar(20),@RowCount)

	/****************************************************************************

		Set the latest row indicator on the latest row for Client/Product pair.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_OngoingRate new
	where	new.EffectiveEndDate = @DateNotEnded		
	and		new.LatestRowInd = 0

	set @RowCount = @@rowcount
	set @ProcessMessage3 = 'Latest Row Indicator - Rows Updated = ' + convert(varchar(20),@RowCount)

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION  

	exec msp_ProcessLog @PhaseLog, @ProcessMessage1, null, @Module, @Client
	exec msp_ProcessLog @PhaseLog, @ProcessMessage2, null, @Module, @Client
	exec msp_ProcessLog @PhaseLog, @ProcessMessage3, null, @Module, @Client
			 
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/






					
GO
/****** Object:  StoredProcedure [dbo].[owp_OngoingRate_Backup20181123AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_OngoingRate					
	  Author:	A Groves
Date created:	05/07/2018
		
 Description:   This proc populates (new) table "dbo.owt_OngoingRate". It is used by the
				VNB Recognition proc to look up the ongoing rate that was in place at the
				time that the transaction (slice) was created in Swift. The purpose is to 
				ensure that the OGS rate used on a transaction at any point in time remains 
				the same. This will then ensure that VNB points calculated in the past will 
				never later re-calculate to a different value, even if the average OGS rate 
				has changed over time - which is more than likely.  
				
				It is called as follows:

				exec owp_OngoingRate 'Openwork', 'Transform'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_OngoingRate_Backup20181123AG] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare	@PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@DateLastUpdated			datetime,
		@ProcessMessage				varchar(100),
		@ProcessMessage1			varchar(100),
		@ProcessMessage2			varchar(100),
		@ProcessMessage3			varchar(100),
		@Yesterday					date,
		@DayBeforeYesterday			date,
		@DateNotEnded				date,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@RowCount					int			

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @DateLastUpdated	= getdate()
set @Yesterday			= dateadd(dd,-1,getdate())	--<-- NORMAL
--set @Yesterday			= '2017-01-01'
set @DayBeforeYesterday = dateadd(dd,-1,@Yesterday)
set @DateNotEnded		= '9999-12-31'

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************
	
		look up the OGS rates

	****************************************************************************/

	select	distinct s.PersonID, swp.Client_Num, p.InternalProductID, swp.ProductCode 
	into	#SwiftOWSClientLink
	from	sa_ows_Sale s
			inner join sa_ows_Policies p on p.SaleID = s.SaleID
			inner join mstt_Policies swp on swp.PolicyRef = p.PolicyID
	where	s.DateSubmitted is not null
	--and		s.PersonID = 146030

	select @RowCount = @@rowcount
	set @ProcessMessage = '#SwiftOWSClientLink = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	-- The OGS rate is stored for the client/product combination
	select	link.Client_Num, 
			link.ProductCode, 
			min(case when ogs.OwnerID = 2 
					then cli.PartnerPersonID 
					else cli.PersonID 
				end) as OWSPersonID,
			max(ogs.OngoingServiceFee) as OngoingServiceFee
	into	#OGSLookUp
	from	#SwiftOWSClientLink link 
			inner join dbo.sa_ows_Person cli on cli.PersonID = link.PersonID
			inner join mstt_ProductHierarchy ph on ph.ProductCode = link.ProductCode
			inner join Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee ogs
							on ogs.PersonID = link.PersonID
							and ogs.InternalProductID = (case when ph.RDRType = 'ONPLAT' 
															then -2 
															else link.InternalProductID 
														 end)
	where	ogs.OngoingServiceFee > 0.0							--AG 26/04/2018
	group	by 	link.Client_Num, link.ProductCode

	select @RowCount = @@rowcount
	set @ProcessMessage = '#OGSLookUp Insert 1 = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
	
	-- The OGS rate is stored just for the client (dummy product code)
	insert into #OGSLookUp
	(
		Client_Num, 
		ProductCode, 
		OWSPersonID,
		OngoingServiceFee
	)
	select	Client_Num, 
			'(CLIENT)' as ProductCode,
			min(OWSPersonID) as OWSPersonID,
			max(OngoingServiceFee) as OngoingServiceFee
	from	#OGSLookUp
	group	by Client_Num
	
	select @RowCount = @@rowcount
	set @ProcessMessage = '#OGSLookUp Insert 2 = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
			
	/****************************************************************************
	
		Update the destination table for Client/Product pair

	****************************************************************************/

	insert into dbo.owt_OngoingRate
	(
		EffectiveStartDate,					
		EffectiveEndDate,					
		LatestRowInd,
		OWSPersonID,						
		Client_Num,
		ProductCode,
		OngoingServiceFee,
		DateLoaded,
		DateLastUpdated	
	)
		select	@Yesterday as EffectiveStartDate,	
				@DateNotEnded as EffectiveEndDate,	
				0 as LatestRowInd,					--Must be 0 here. Will be toggled to 1 later.
				lu.OWSPersonID,
				lu.Client_Num, 
				lu.ProductCode, 
				lu.OngoingServiceFee,
				@DateLastUpdated as DateInserted,
				@DateLastUpdated as DateLastUpdated
		from	#OGSLookUp lu
				left join dbo.owt_OngoingRate ogs 
							on  ogs.OWSPersonID = lu.OWSPersonID
							and ogs.Client_Num = lu.Client_Num
							and ogs.ProductCode = lu.ProductCode
							and ogs.EffectiveEndDate = @DateNotEnded				--This will ensure just one row is joined
							and	ogs.LatestRowInd = 1								-- ...and this ensures no rows added by this proc run are picked up
		where	(ogs.ID is null)													--On the source table but not on the destination table so must be a new starter
		or		(isnull(ogs.OngoingServiceFee,0) <> isnull(lu.OngoingServiceFee,0))	--On both tables so check for a column change
																		
	set @RowCount = @@rowcount
	set @ProcessMessage1 = 'New History Rows (New and Changes) - Rows Inserted = ' + convert(varchar(20),@RowCount)
																		
	/****************************************************************************

		Close the penultimate row (if there is one) for Client/Product pair
																		
	****************************************************************************/

	update	old
		set EffectiveEndDate = @DayBeforeYesterday,	-- Update the audit info
			LatestRowInd = 0,						-- This is no longer the latest row, so reset the indicator
			DateLastUpdated = @DateLastUpdated		-- Update the audit info
	from	dbo.owt_OngoingRate old
			inner join dbo.owt_OngoingRate new		
							on  new.OWSPersonID = old.OWSPersonID
							and new.Client_Num = old.Client_Num			
							and new.ProductCode = old.ProductCode
							and new.EffectiveEndDate = @DateNotEnded	-- This....
							and	new.LatestRowInd = 0					-- ...and this, gives the newly added row
	where	old.LatestRowInd = 1										-- This is the penultimate row (if it exists)
 
	set @RowCount = @@rowcount
	set @ProcessMessage2 = 'Penultimate Rows Closed - Rows Updated = ' + convert(varchar(20),@RowCount)

	/****************************************************************************

		Set the latest row indicator on the latest row for Client/Product pair.
		Note: DateLastUpdated is not updated here as this update is considered 
				part of the original insert.
																		
	****************************************************************************/

	update	new
		set LatestRowInd = 1
	from	dbo.owt_OngoingRate new
	where	new.EffectiveEndDate = @DateNotEnded		
	and		new.LatestRowInd = 0

	set @RowCount = @@rowcount
	set @ProcessMessage3 = 'Latest Row Indicator - Rows Updated = ' + convert(varchar(20),@RowCount)

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION  

	exec msp_ProcessLog @PhaseLog, @ProcessMessage1, null, @Module, @Client
	exec msp_ProcessLog @PhaseLog, @ProcessMessage2, null, @Module, @Client
	exec msp_ProcessLog @PhaseLog, @ProcessMessage3, null, @Module, @Client
			 
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/






					
GO
/****** Object:  StoredProcedure [dbo].[owp_OpenworkMetricPopulation]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Program:		owp_OpenworkMetricPopulation					
Author:			Alan Groves
Date created:	19/09/2018
											
Description:
===========

This proc populates the Openwork and Owl metrics that are displayed on the TV screens on each floor.
This stored proc is called by a MIDB overnight batch process.

Note that a SQL merge statement is used - so this proc IS re-runnable. For example, if the four rows 
on table "owt_OpenworkMetrics" don't exist for the metric date, then running this proc will create them.
But if the rows do exist, then running this proc will update the existing rows. 

This proc is called as follows:
	declare @rc int,
	@Dte date = getdate()-1
	select @Dte
	exec @rc = dbo.owp_OpenworkMetricPopulation 'Openwork', 'Metrics', @Dte
	select @rc
			
AMENDMENT HISTORY				
=================								

Date		Author		Description
----		------		-----------
28/09/2018	A Groves	1) Marcus identified that a first time buyer is any of the following:
							8900	MortgageTransactionType			First time buyer
							8905	MortgageTransactionType			Purchase
							9800	OneLinkMortgageTransactionType	First time purchase
							9804	OneLinkMortgageTransactionType	Second or subsequent purchase
							9805	OneLinkMortgageTransactionType	Unencumbered property
						2) Additional adviser headcount filter added to ensure that the @DateOfMetric 
							is witin the table effective dates. This makes the headcount re-runnable
							as it will count based on the headcount as at that date.
15/10/2018	A Groves	Changed Openwork headcount to a simplified version of Josh Bolton's headcount SQL.
*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_OpenworkMetricPopulation]
	@Client			varchar(50),
	@Module			varchar(50),
	@DateOfMetric	date
AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50),
			@ProcName				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@OALRowCount			int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int,
			@DateLastUpdated		datetime
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0	
set @DateLastUpdated	= getdate()

-- We want this logging irrespective of whether or not there is a rollback
exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Main processing																
																		
****************************************************************************/

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

BEGIN TRY

	/************************************************************************
	
		Create working temp table
	
	************************************************************************/
	
	CREATE TABLE #Metrics
	(
		DateOfMetric date NULL,
		Source varchar(50) NULL,
		Brand varchar(20) NULL,
		Headcount int NULL,
		OMNISInflows decimal(16,2) NULL,
		TotalCasesSubmitted int NULL,
		ProtectionCasesSubmitted int NULL,
		MortgageCasesSubmitted int NULL,
		MortgageFirstTimers int NULL,
		DateInserted datetime NULL,
		DateLastUpdated datetime NULL
	)

	/************************************************************************
	
		Daily Owl
	
	************************************************************************/

	insert into #Metrics
	(
		DateOfMetric,
		Source,
		Brand,
		Headcount,
		OMNISInflows,
		TotalCasesSubmitted,
		ProtectionCasesSubmitted,
		MortgageCasesSubmitted,
		MortgageFirstTimers,
		DateInserted,
		DateLastUpdated
	)
	select	@DateOfMetric as DateOfMetric,
			'Owl' as Source,
			'Owl' as Brand,
			COUNT(*) as Headcount,
			0 as OMNISInflows,
			0 as TotalCasesSubmitted,
			0 as ProtectionCasesSubmitted,
			0 as MortgageCasesSubmitted,
			0 as MortgageFirstTimers,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	mi_insight_UserHierarchyAllUsers uhau
	where   uhau.UserEmploymentStatuscode not in (2,5,6)	--Ignoring Left,NPW,Deceased
	and		uhau.UserContractStatuscode not in (2,3,4)		--Ignoring Out of Contract,Pre-contract,Vetting
	and		uhau.UserJobTitleCodeSeller = 52				--Selling agents only 
	and		uhau.ADUID = '4005013'							--Owl only. Not great to hard code Pat McKenna but it excludes test accounts not linked to Pat.
	and		@DateOfMetric between uhau.EffectiveStartDate and uhau.EffectiveEndDate
          
	/************************************************************************
	
		Year To Date Owl
	
	************************************************************************/

	insert into #Metrics
	(
		DateOfMetric,
		Source,
		Brand,
		Headcount,
		OMNISInflows,
		TotalCasesSubmitted,
		ProtectionCasesSubmitted,
		MortgageCasesSubmitted,
		MortgageFirstTimers,
		DateInserted,
		DateLastUpdated
	)
	select	@DateOfMetric as DateOfMetric,
			'Year to Date' as Source,
			'Owl' as Brand,
			COUNT(*) as Headcount,
			0 as OMNISInflows,
			0 as TotalCasesSubmitted,
			0 as ProtectionCasesSubmitted,
			0 as MortgageCasesSubmitted,
			0 as MortgageFirstTimers,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	mi_insight_UserHierarchyAllUsers uhau
	where   uhau.UserEmploymentStatuscode not in (2,5,6)	--Ignoring Left,NPW,Deceased
	and		uhau.UserContractStatuscode not in (2,3,4)		--Ignoring Out of Contract,Pre-contract,Vetting
	and		uhau.UserJobTitleCodeSeller = 52				--Selling agents only 
	and		uhau.ADUID = '4005013'							--Owl only. Not great to hard code Pat McKenna but it excludes test accounts not linked to Pat.
	and		@DateOfMetric between uhau.EffectiveStartDate and uhau.EffectiveEndDate

	/************************************************************************
	
		Daily Openwork
		AG 15/10/2018. Changed to a simplified version of Josh Bolton's 
		headcount SQL.
	
	************************************************************************/

	insert into #Metrics
	(
		DateOfMetric,
		Source,
		Brand,
		Headcount,
		OMNISInflows,
		TotalCasesSubmitted,
		ProtectionCasesSubmitted,
		MortgageCasesSubmitted,
		MortgageFirstTimers,
		DateInserted,
		DateLastUpdated
	)
	select	@DateOfMetric as DateOfMetric,
			'Openwork' as Source,
			'Openwork' as Brand,
			COUNT(*) as Headcount,
			0 as OMNISInflows,
			0 as TotalCasesSubmitted,
			0 as ProtectionCasesSubmitted,
			0 as MortgageCasesSubmitted,
			0 as MortgageFirstTimers,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated           
	from	dbo.mstt_Agents ag 
			left join mstt_Agents ag2 ON ag.Firm = ag2.code		
	where (ag.Manager2Code <> '1011671') -- ignore owl
	--manual exclusions
	and ag.Code not in
	(
	'4002872','1001025','4003785','4007961','4007959','1011677','4007963','4009489','4009488','4009375','4010182','4010455',
	'4010568','4010513','4010566','4010573','4010511','4010570','4011182','4006771','4011613','4011213','4012052','1011524',
	'4012843','4012821','4012820','1005260','2001539','1011607','1011608','1011609','2001815','2004327','2005603','2005605',
	'4007962','2005601','2005599','2007293','2007295','2007996','2008545','2008526','2008591','2008595','2008661','2008664',
	'2008666','2008670','2000873','2009072','2000686','2009397','1002915','2010370','1003227','2011284','2011287','2011312',
	'10003'
	)
	-- Actives only
	and case ag.CompetentStatusdescription when 'deceased' then 'Left' when 'n/a' then 'Active'	else ag.CompetentStatusdescription end = 'Active'
	and ag.AgentType <> 49 --Directly Authorised
	and ((case when (RIGHT(ag.SupervisorTypeCode, 2) = 'NA' AND ag.givesAdvice = 'Y') 
			or ag.Code = '1005202' 
				then 'N' 
				else ag.GivesAdvice 
		  end = 'Y') 
			or (case when left(ag2.AgentCategoryDescription, 4) = 'NASP' and ag.AgentType = 5 
					then 'NASP' 
					else null 
				end) is not null)
  
	/************************************************************************
	
		Year To Date Openwork
		AG 15/10/2018. Changed to a simplified version of Josh Bolton's 
		headcount SQL.
	
	************************************************************************/

	insert into #Metrics
	(
		DateOfMetric,
		Source,
		Brand,
		Headcount,
		OMNISInflows,
		TotalCasesSubmitted,
		ProtectionCasesSubmitted,
		MortgageCasesSubmitted,
		MortgageFirstTimers,
		DateInserted,
		DateLastUpdated
	)
	select	@DateOfMetric as DateOfMetric,
			'Year to Date' as Source,
			'Openwork' as Brand,
			COUNT(*) as Headcount,
			0 as OMNISInflows,
			0 as TotalCasesSubmitted,
			0 as ProtectionCasesSubmitted,
			0 as MortgageCasesSubmitted,
			0 as MortgageFirstTimers,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated           
	from	dbo.mstt_Agents ag 
			left join mstt_Agents ag2 ON ag.Firm = ag2.code		
	where (ag.Manager2Code <> '1011671') -- ignore owl
	--manual exclusions
	and ag.Code not in
	(
	'4002872','1001025','4003785','4007961','4007959','1011677','4007963','4009489','4009488','4009375','4010182','4010455',
	'4010568','4010513','4010566','4010573','4010511','4010570','4011182','4006771','4011613','4011213','4012052','1011524',
	'4012843','4012821','4012820','1005260','2001539','1011607','1011608','1011609','2001815','2004327','2005603','2005605',
	'4007962','2005601','2005599','2007293','2007295','2007996','2008545','2008526','2008591','2008595','2008661','2008664',
	'2008666','2008670','2000873','2009072','2000686','2009397','1002915','2010370','1003227','2011284','2011287','2011312',
	'10003'
	)
	-- Actives only
	and case ag.CompetentStatusdescription when 'deceased' then 'Left' when 'n/a' then 'Active'	else ag.CompetentStatusdescription end = 'Active'
	and ag.AgentType <> 49 --Directly Authorised
	and ((case when (RIGHT(ag.SupervisorTypeCode, 2) = 'NA' AND ag.givesAdvice = 'Y') 
			or ag.Code = '1005202' 
				then 'N' 
				else ag.GivesAdvice 
		  end = 'Y') 
			or (case when left(ag2.AgentCategoryDescription, 4) = 'NASP' and ag.AgentType = 5 
					then 'NASP' 
					else null 
				end) is not null)

	/************************************************************************
	
		Get Owl written business
	
	************************************************************************/
	
	select	min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
	into	#c
	FROM	dbo.mstt_Commissions co 
			INNER JOIN dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID 
			INNER JOIN dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID 
			LEFT OUTER JOIN dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode 
			LEFT OUTER JOIN dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE 
			LEFT OUTER JOIN dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode 
			LEFT OUTER JOIN dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID 
			LEFT OUTER JOIN cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	where	co.agent_code not in ('10002','1011542','10004')
	and		co.commissiontype = 1
	and		co.poltrantranstype = 39
	and		(ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and		(left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and		(left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and		(co.productcode like '%OWL%' or co.productcode is NULL)
	group	by po.policyref, po.cont_num, co.productcode

	--MONTH & YEAR
	SELECT	'Written' 'Type',
			convert(date,wr.writtendate) as Date,
			sum(case when wr.frequency = 'Single' then wr.ape * 10 else wr.ape end) as Premium, 
			sum(wr.ape) as APE, 
			sum(wr.NBcases) as NewPolicies,
			sum(wr.distributionallowance) as DA, 
			sum(wr.margin) as Margin
	into	#h
	from
	(
		SELECT  
		cast(co.AGENT_CODE as int) as Adviser,
		cast(pt.AGENTCODE as int) as PriAdviser,
		cast(min(isnull(s.DateSubmitted,pt.writtendate)) as date) as writtendate,
		round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
		round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
		when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, 
		round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
		when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin, 
		max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases", 
		max((co.agent_perc/100)) as "AllCases",
		min(pt.FrequencyDescription) as frequency,
		min(co.AdminMethodDescription) as adminmethoddescription,
		min(co.ProductCode) as productcode,
		min(ph.ProductSubGroupName) as productsubgroupname, 
		min(ph.productgroupname) as "ProductGroupName",
		min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G'))) then 'Non Advised' else 'Advised' end) as "Adminmethod"
		from	dbo.mstt_Commissions co 
				inner join dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID 
				inner join dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID 
				left join dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode 
				left join dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE 
				left join dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID 
				left join #c c on c.transactionid = co.transactionid 
				left join cscv_AgentsHierarchy ah ON ah.agentcode = pt.AgentCode 
				left join sa_ows_Policies p on p.PolicyID = po.PolicyRef 
				left join sa_ows_Sale s on s.SaleID = p.SaleID 
				left join mi_insight_userhierarchyallusers uh2 
								on uh2.useruid = pt.agentcode 
								and pt.writtendate between uh2.effectivestartdate and uh2.effectiveenddate 
		where	co.agent_code not in ('10002','1011542','10004')
		and		co.commissiontype = 1
		and		co.poltrantranstype = 39
		and		(co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
		and		(left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
		and		(left(ccs.description,2) <> 'UA' or ccs.description is NULL)
		and		(co.productcode like '%OWL%' or co.productcode is NULL)
		and		(rtrim(uh2.ADName) = 'Pat Mckenna' or co.agent_code in ('1011623','1011629','1011630','1011631','1011632','1011633','1011634','1011635'))---OWL POT ACCOUNT NOT COUNTED
		and		(po.PolicyRef not in ('500020430','500020431') or po.PolicyRef is null)
		and		year(isnull(s.DateSubmitted,pt.writtendate)) = year(@DateOfMetric)
		group by
				cast(co.AGENT_CODE as int),
				cast(pt.AGENTCODE as int),
				round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2),
				po.policyref,
				po.cont_num,
				ah.agentstartdate
	) wr
	group by
	wr.writtendate

	UNION all

	------------------------------------------------------------------- OWS L&G ASU Product Added 20/03/17

	select 
	'Written' as Type,
	cast(pol.ApplicationDate as date) as Date,
	sum(pps.PremiumAmount*12) as Premium,
	sum(pps.PremiumAmount*12) as APE,
	sum(1) AS NewPolicies,
	sum(pps.PremiumAmount*12*0.35) as DA,
	sum(pps.PremiumAmount*12*0.10) as Margin
	from sa_ows_Policies  pol 
	join policy.sa_ows_ProtectionProductSummary pps on pps.PolicyID = pol.PolicyID
	join sa_ows_sale sale on sale.SaleID = pol.SaleID
	join mi_insight_UserHierarchy uh on uh.UserUID = sale.AdviserUID
	join cscv_AgentsHierarchy ah on agentcode = sale.adviseruid
	where InternalProductID = 10000063
	and SaleStatusID = 2 and pol.Status = 2
	and sale.adviserUID <> '4006226' -- Excluding the test UID
	and year(pol.ApplicationDate) = year(@DateOfMetric)
	group by cast(pol.ApplicationDate as date)

	/************************************************************************
	
		Update Owl written business
	
	************************************************************************/
	
	update m
		set TotalCasesSubmitted = round(DailyAPE.APE,0),
			ProtectionCasesSubmitted = round(DailyAPE.APE,0)
	from	#Metrics m
			cross join (select sum(APE) as APE
						from #h h 
						where h.date = @DateOfMetric
						group by h.Date
						) DailyAPE
	where	m.DateOfMetric = @DateOfMetric
	and		m.Source = 'Owl'
	and		m.Brand = 'Owl'

	update m
		set TotalCasesSubmitted = round(YTD_APE.APE,0),
			ProtectionCasesSubmitted = round(YTD_APE.APE,0)
	from	#Metrics m
			cross join (select sum(APE) as APE
						from #h h 
						where year(h.date) = year(@DateOfMetric)
						group by year(h.date)
						) YTD_APE
	where	m.DateOfMetric = @DateOfMetric
	and		m.Source = 'Year To Date'
	and		m.Brand = 'Owl'

	drop table #c, #h

	/************************************************************************
	
		Get Openwork written business
	
	************************************************************************/

	IF OBJECT_ID('tempdb..#d') IS NOT NULL
		DROP TABLE #d

	select	min(transactionid) as transactionid, 
			po.policyref, 
			po.cont_num, 
			co.productcode,
			ph.productgroupname,
			COMP_CODE
	into	#d
	FROM	dbo.mstt_Commissions co 
			INNER JOIN dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID
			INNER JOIN dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID 
			LEFT OUTER JOIN dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode 
			LEFT OUTER JOIN dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE 
			LEFT OUTER JOIN dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode 
			LEFT OUTER JOIN dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID 
			LEFT OUTER JOIN cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	where	co.agent_code not in ('10002','1011542','10004')
	and		co.commissiontype = 1
	and		co.poltrantranstype = 39
	and		(ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and		(left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and		(left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and		(co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
	and		((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
	group	by po.policyref, po.cont_num, co.productcode, ph.productgroupname,COMP_CODE

	union all

	select	min(transactionid) as transactionid, 
			'' t1, 
			'' t2,
			'' t3,
			ph.productgroupname,
			COMP_CODE
	FROM	dbo.mstt_Commissions co 
			INNER JOIN dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID 
			INNER JOIN dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID
			LEFT OUTER JOIN dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode 
			LEFT OUTER JOIN dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE 
			LEFT OUTER JOIN dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode 
			LEFT OUTER JOIN dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID 
			LEFT OUTER JOIN cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	where	co.agent_code not in ('10002','1011542','10004')
	and		co.commissiontype = 1
	and		co.poltrantranstype = 39
	and		(ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and		(left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and		(left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and		(co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
	and		(left(ltrim(po.policyref),4) = '8000' and ph.productgroupname like 'Protection')
	group	by	co.CLIENT_NUM,
				po.comp_code,
				case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end,
				ph.productgroupname,COMP_CODE

	--MONTH & YEAR
	SELECT 'Written' as "Type", 
			CONVERT(date,wr.writtendate) as Date,
			sum(wr.ape) as APE_Total,
			sum(case when wr.productgroupname = 'Mortgage' then wr.ape else 0 end) as APE_Mortgage,
			sum(case when wr.productgroupname = 'Protection' then wr.ape else 0 end) as APE_Protection,
			sum(case when wr.productgroupname not in ('Protection','Mortgage') then wr.ape else 0 end) as APE_Other, 
			sum(wr.MortgageCaseFTB) as MortgageCaseFTB,
			sum(wr.MortgageCase) as MortgageCase,
			sum(wr.NBcases) as NewPolicies,
			sum(case when wr.frequency = 'Single' then wr.ape * 10 else wr.ape end) as Premium, 
			sum(wr.distributionallowance) as DA, 
			sum(wr.margin) as Margin
	into	#i
	from
	(	SELECT	cast(co.AGENT_CODE as int) as Adviser,
				min(coalesce(co.firm,co.agent_code)) as Firm,
				min(co.transactionid) as transactionid, 
				min(pt.writtendate) as writtendate,
				datepart(week,(pt.writtendate)) as writtenweek, 
				year(pt.writtendate) as writtenyear,
				Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
						then 0 
						else round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) 
				END as APE,
				Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
						then 0 
						else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
					 when (ph.productgroupname = 'Mortgage' and ccs.description is null) 
						then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) 
						else co.distributionallowance end),2)
				End as distributionallowance, 
				Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
						then 0 
						else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
					 when (ph.productgroupname = 'Mortgage' and ccs.description is null) 
						then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) 
						else (co.baseamount + co.upliftamount) end),2)
				End as NBI, 
				Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
						then 0 
						else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
					 when (ph.productgroupname = 'Mortgage' and ccs.description is null) 
						then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) 
						else (co.salesmargin) end),2)
				End as Margin, 
				min(po.PolicyRef) minpolref,
				co.agent_perc tst2,
				Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
					then 0 
					else max(case when co.transactionid = d.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)
				End as "NBCases", 
				Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
					then 0 
					else max((co.agent_perc/100))
				End as "AllCases", 
				min(pt.FrequencyDescription) as frequency, 
				min(po.PolicyRef) AS CaseID, 
				po.CONT_NUM AS Policy, 
				min(co.BusinessReason) as businessreason,
				min(co.AdminMethodDescription) as adminmethoddescription, 
				min(co.ProductCode) as productcode, 
				min(po.COMP_CODE) AS Provider, 
				min(rp.ReportingProductName) as reportingproductname, 
				min(ph.ProductSubGroupName) as productsubgroupname, 
				min(case when ph.productgroupname = 'Other' 
						then 'Pensions' 
						else ph.productgroupname 
					end) as "ProductGroupName",
				min(po.originatingsource) as originatingsource, 
				min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') 
						then 'Non Advised' 
						else 'Advised' 
					end) as "Adminmethod", 
				min(ccs.calculationcode) as calculationcode, 
				min(ccs.description) as description, 
				min(rtrim(ah.asdname)) as ASD,
				min(case when ph.productgroupname = 'Mortgage' 
						and (mrs.TransactionTypeID in (8900,8905) or mps.TransactionTypeId in (9800,9804,9805))
						and (pmps.MortgageCategoryId = 8865 or mps.MortgageCategoryId = 8865) then 1 else 0 end) as MortgageCaseFTB,
				min(case when ph.productgroupname = 'Mortgage' then 1 else 0 end) as MortgageCase
		FROM	dbo.mstt_Commissions co
				INNER JOIN dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID
				INNER JOIN dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID 
				LEFT OUTER JOIN dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode 
				LEFT OUTER JOIN dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE 
				LEFT OUTER JOIN dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode
				LEFT OUTER JOIN dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID
				LEFT OUTER JOIN #d d on d.transactionid = co.transactionid
				LEFT OUTER JOIN cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
				left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num
				left join Policy.sa_ows_MortgageRecommendedSolution mrs on mrs.PolicyID = po.PolicyRef
				left join PolicyOneLink.sa_ows_MortgageProductSummary mps on mps.PolicyId = po.PolicyRef 
				left join Policy.sa_ows_MortgageProductSummary pmps on pmps.PolicyID = po.PolicyRef  
		where	co.agent_code not in ('10002','1011542','10004','1011623')
		and		co.commissiontype = 1
		and		co.poltrantranstype = 39
		and		(co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
		and		(ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
		and		(left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
		and		(left(ccs.description,2) <> 'UA' or ccs.description is NULL)
		and		(co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
		and		po.COMP_CODE NOT LIKE '%Owl%'
		and		(rtrim(ah.ASDName) <> 'Pat Mckenna' or ah.ASDName is Null)
		----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
		and		(case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
		-----------------------------------------------------------------------
		group	by	cast(co.AGENT_CODE as int), 
					round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), 
					po.policyref, 
					po.cont_num, 
					datepart(week,(pt.writtendate)), 
					year(pt.writtendate), 
					ph.productgroupname,
					ph.productgroupname,
					co.agent_code,
					co.agent_perc
		having min(year(convert(date,pt.writtendate))) = year(@DateOfMetric)
		) wr
	where	year(convert(date,wr.writtendate)) = year(@DateOfMetric)
	and		(wr.caseid not in ('500020430','500020431') or wr.caseid is null)
	group	by CONVERT(date,wr.writtendate)

	/************************************************************************
	
		Update Openwork written business
	
	************************************************************************/

	update m
		set TotalCasesSubmitted = round(i.APE_Total,0),
			ProtectionCasesSubmitted = round(i.APE_Protection,0),
			MortgageCasesSubmitted = round(i.APE_Mortgage,0),
			MortgageFirstTimers = case when i.MortgageCase <> 0
									then round((convert(float,i.MortgageCaseFTB)/convert(float,i.MortgageCase))*100.0,0)
									else 0
								  end
	from	#Metrics m
			inner join #i i on i.date = @DateOfMetric
	where	m.DateOfMetric = @DateOfMetric
	and		m.Source = 'Openwork'
	and		m.Brand = 'Openwork'

	update m
		set TotalCasesSubmitted = round(YTD_APE.APE_Total,0),
			ProtectionCasesSubmitted = round(YTD_APE.APE_Protection,0),
			MortgageCasesSubmitted = round(YTD_APE.APE_Mortgage,0),
			MortgageFirstTimers = case when YTD_APE.MortgageCase <> 0 
									then round((convert(float,YTD_APE.MortgageCaseFTB)/convert(float,YTD_APE.MortgageCase))*100.0,0)
									else 0
								  end
	from	#Metrics m
			cross join (select	sum(APE_Total) as APE_Total,
								sum(APE_Protection) as APE_Protection,
								sum(APE_Mortgage) as APE_Mortgage,								
								sum(MortgageCaseFTB) as MortgageCaseFTB,
								sum(MortgageCase) as MortgageCase
						from	#i i 
						where	year(i.date) = year(@DateOfMetric)
						group	by year(i.date)
						) YTD_APE
	where	m.DateOfMetric = @DateOfMetric
	and		m.Source = 'Year To Date'
	and		m.Brand = 'Openwork'

	/************************************************************************
	
		Now merge the data (this makes this proc re-runnable)
	
	************************************************************************/

	drop table #d, #i

	BEGIN TRANSACTION

	declare @SummaryOfChanges table (Change varchar(20))
	
	merge	dbo.owt_OpenworkMetrics as trg
	using	#Metrics as src
	on		trg.DateOfMetric = src.DateOfMetric
	and		trg.Source = src.Source
	and		trg.Brand = src.Brand
	when	matched 
	and		(trg.Headcount <> src.Headcount
	or		trg.OMNISInflows <> src.OMNISInflows
	or		trg.TotalCasesSubmitted <> src.TotalCasesSubmitted
	or		trg.ProtectionCasesSubmitted <> src.ProtectionCasesSubmitted
	or		trg.MortgageCasesSubmitted <> src.MortgageCasesSubmitted
	or		trg.MortgageFirstTimers <> src.MortgageFirstTimers)
	then	update 
				set trg.Headcount = src.Headcount,
					trg.OMNISInflows = src.OMNISInflows,
					trg.TotalCasesSubmitted = src.TotalCasesSubmitted,
					trg.ProtectionCasesSubmitted = src.ProtectionCasesSubmitted,
					trg.MortgageCasesSubmitted = src.MortgageCasesSubmitted,
					trg.MortgageFirstTimers = src.MortgageFirstTimers,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	then	insert
			(
				DateOfMetric,
				Source,
				Brand,
				Headcount,
				OMNISInflows,
				TotalCasesSubmitted,
				ProtectionCasesSubmitted,
				MortgageCasesSubmitted,
				MortgageFirstTimers,
				DateInserted,
				DateLastUpdated
			)		
			values
			(
				src.DateOfMetric,
				src.Source,
				src.Brand,
				src.Headcount,
				src.OMNISInflows,
				src.TotalCasesSubmitted,
				src.ProtectionCasesSubmitted,
				src.MortgageCasesSubmitted,
				src.MortgageFirstTimers,
				src.DateInserted,
				src.DateLastUpdated
			)	
	output $action into @SummaryOfChanges;			--Merge statements must have a ;

	COMMIT TRANSACTION      

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @ProcessMessage = 'owt_OpenworkMetrics (insert) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @ProcessMessage = 'owt_OpenworkMetrics (update) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		T H E   E N D
																		
	****************************************************************************/
	
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

return @ErrNum



GO
/****** Object:  StoredProcedure [dbo].[owp_OSCARLedgerExtractScan]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


---------------------------------------------------------------------------------
-- exec owp_OSCARLedgerExtractScan '2007/01/01', '2007/03/01'
---------------------------------------------------------------------------------

CREATE procedure [dbo].[owp_OSCARLedgerExtractScan]
 @StartDate datetime,
 @EndDate datetime
WITH RECOMPILE 
as

---------------------------------------------------------------------------
--- Mike Cawood Dec 2007
--  Use unique PolicyID and TransactionID of -9 for all Warehouse generated adjustments
---------------------------------------------------------------------------


---------------------------------------------------------------------------
---  Set dates if parms are blank
---------------------------------------------------------------------------
if @EndDate = ''
begin
  set @EndDate = getdate()
end
----------------------------------------------------------------------------------
-- Delete all existing OSCAR Ledger Adjustment rows on the Production Adjustments table
---------------------------------------------------------------------------------

delete from mstt_ProductionAdjustments 
where ProductCode like 'LDG_%' and TransactionID = -9   --MPC: Dec2007


select
  opd.BusinessCode,
  case
    when opd.Description like '%ZIWM%' then 'LDG_ZIWM'
    when opd.Description like 'Procuration Fee%' then 'LDG_MTG'
    else 'LDG_DBGA' 
  end as 'LEDGER_TYPE',
  opd.Amount as 'Amount',
  opd.[Month]
into #OSCAR
from msit_OpenworkBankDetails opd
where 
  opd.Month between @StartDate and @EndDate        
--  opd.Month between '1 Jan 2001' and '1 Mar 2006'
  and opd.Source = 'Openwork 2005'
  and opd.PaymentType = 1
  and 
     ((left(opd.Description,15) = 'Procuration Fee' and Len(opd.Description) > 15) or 
       opd.Description like '%ZIWM%' or 
             opd.Description like '%Dunbar Bank Guaranteed Account%')
order by opd.BusinessCode

---------------------------------------------------------------------------------
-- create temporary table #OSCAR_LEDGER
---------------------------------------------------------------------------------

select BusinessCode,LEDGER_TYPE,[Month],Sum(Amount) as 'AMOUNT', COUNT(*) as 'COUNT'
into #OSCAR_LEDGER
from #OSCAR
GROUP BY BusinessCode,LEDGER_TYPE, [Month]
order by BusinessCode,LEDGER_TYPE, [Month]

---------------------------------------------------------------------------------
-- insert records into mstt_ProductionAdjustments
---------------------------------------------------------------------------------

Insert into mstt_ProductionAdjustments 
select
  -9,       --MPC: Dec2007
  ol.BusinessCode, 
  -9,       --MPC: Dec2007
  -99,
  (select AdviserID from msdt_Adviser where AgentCode = ol.BusinessCode),
  2,
  (select ProductID from msdt_Products where ProductCode = ol.LEDGER_TYPE),
  -99,
  (select DateID from msdt_CalendarTime where DateTime = ol.Month and EntryTypeID = 2),
  (select DateID from msdt_CalendarTime where DateTime = ol.Month and EntryTypeID = 2),
  2,
  -99,
  isnull((select FranchiseSizeID from msdt_FranchiseSize where FranchiseSize = (select case when MIN(FranchiseSize) < 1000 then MIN(FranchiseSize) else 1000 end from mstt_Agents where CODE = ol.BusinessCode )), -1),
  -99,
  1,
  -99,
  -99,
  2,
  -99,
  cast(ol.AMOUNT as decimal(12,2)),
  cast(ol.AMOUNT as decimal(12,2)),
  cast(ol.AMOUNT as decimal(12,2)),
  NULL,
  NULL,
  ol.COUNT,
  NULL,
  ol.LEDGER_TYPE,
  0,
  'Applied as OSCAR Ledger',
  'Y',
  (select Year(OSCARStartDate) from msit_CommissionStatementPeriods c where c.Month = ol.Month)

from #OSCAR_LEDGER ol
--inner join mstt_Agents a on a.CODE = ol.BusinessCode

---------------------------------------------------------------------------------
-- clear down temp tables
---------------------------------------------------------------------------------

drop table #OSCAR
drop table #OSCAR_LEDGER



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentMarginSplits]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[owp_PaymentMarginSplits] -- WITH RECOMPILE,ENCRYPTION
  @Client   varchar(50),            --MPC:25/01/2010
  @Module   varchar(50),            --MPC:25/01/2010
  @Mode   varchar(4)    --'FULL' or 'MOVE'  --MPC:25/01/2010

AS

/******************************************************************************

Module:     owp_PaymentMarginSplits

Created:    26/01/2010
Created By:   Mike Cawood

-----------    EXECUTION DETAILS  ---------------------------------------

Call as 
  owp_PaymentMarginSplits 'Openwork', 'BI','MOVE'
 OR
  owp_PaymentMarginSplits 'Openwork', 'BI','FULL'

-----------    Mike Cawood 26 Jan 2010  ---------------------------------------

Description 
===========
This procedure calculates the proportion of the Margin associated with an initial 
commission payment that can be associated with each agent linked to the transaction.
Currently, Openwork does not deduct a margin from Trail Fees (types 10, 16 and 19) 
or Renewal Commission (types 4, 15, 18) payments.

The derived margin amount (plus the agent split used to derive it) are applied to
the mstt_PaymentsPending table (which is refreshed by the mstp_PaymentsPending
procedure). This processing is executed as a separate procedure to enable this 
module to be scheduled after the Open Access system has been made available for use.
Please note that the values derived here are not required for use in Open Access.

The commission types covered by this process are 1 (IC), 2 (IC Clawback) and 17 
(IC Adjustment). The latter two types are always negative though their AMOUNT_REC  
values on the sa_swift_S_PACC table are always positive. Each S_PACC payment 
holds the gross commission matched to the linked Transaction. When the owning 
Statement is processed each S_PACC payment is split according to the transaction 
agent splits for that commission type. These are held on the sa_swif_S_AGTCOM table
under commissiontype 1 (IC).

Each S_PACC initial commission payment is split into one or more entries on the 
sa_swift_S_AGMFIL table, one for each agent defined in the transaction agent splits. 
Each S_AGMFIL row holds the ID of the linked transaction plus the owning agent code.
The component reserved as Margin is held under the Openwork '10002' agent code. The 
proportion of this Margin that accrues to a non-Margin S_AGMFIL entry is derived as
follows:

  Margin Amt =  [ (Agent_Split_%/100) * (S_PACC.AMOUNT_REC) ] -  S_AGMFIL.AMOUNT

The Agent_Split_% is derived by matching the S_AGMFIL row to the relevant 
sa_swift_AgentSplitMovements row (based on the S_AGMFIL agent code, commission type 
and row creation date) and sa_swift_S_AGTCOM row (based on the agent code and 
commission type). the % used in the above derivation is taken from the 
AgentSplitMovements entry (if found), then the S_AGMFIL row and lastly S_AGTCOM.

AMENDMENT HISTORY
=================
Date    Author    Description
====    ======    ===========
08/02/2010  A Groves  Removed unnecessary ORDER BY clauses on temp table inserts.
            Changed writes to mst_ProcessLog to use @ProgressModule.
14/04/2010  A Groves  Use owt_TransformationMovements.PendingPayments flag to
            correctly minimise the number of rows updated in MOVE mode.
*******************************************************************************/

-- PROCEDURE BODY GOES HERE

declare   @PhaseStart     varchar(50),
      @PhaseEnd     varchar(50),
      @ProcName     varchar(100),
      @ProgressModule   varchar(50),
      @RowCount     int,
      @ProcessMessage   varchar(100)

set @ProcName   = object_name(@@procid) + ' - ' + @Mode
set @PhaseStart   = 'START'
set @PhaseEnd   = 'END'
set @ProgressModule = 'PMS'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

CREATE TABLE #AGMFILChanges (ID int)
CREATE INDEX #X ON #AGMFILCHANGES (ID)

IF @Mode = 'FULL' --FULL Reload of Table
BEGIN

  Insert INTO #AGMFILCHANGES
  Select Distinct ID 
  from sa_swift_S_AGMFIL 

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGMFIL Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END --@Mode = 'FULL'

IF @Mode = 'MOVE' --Process Movements only
BEGIN

  Insert  INTO #AGMFILCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_S_AGMFIL'
  and   PendingPayments = 'Y'             -- AG 14/04/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGMFIL Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END   --@Mode = 'MOVE'

Select distinct policyid into #SplitPols from sa_swift_BACJobpolicy

Create INDEX #SP ON #SplitPols (PolicyID)

select UP.ID,UP.CreateDateTime,max(ASM.ID) as ASMID
into #SplitMoves
from sa_swift_S_AGMFIL UP
inner join #AGMFILCHANGES X ON X.ID = UP.ID
left outer join sa_swift_AgentSplitMovements ASM 
ON ASM.CommissionType = 1 and ASM.AgentCode = UP.Agent_Code and ASM.TransactionId = UP.TransactionId
Where UP.Type in (1,2,17) AND Cast(UP.AMOUNT as decimal(28,2)) <> 0
AND ASM.ID is not NULL
AND ASM.MovementDate <= UP.CreateDateTime
Group by UP.ID,UP.CreateDateTime
--Order by UP.ID  AG 08/02/2010

Create INDEX #ASM ON #SplitMoves (ID)

Select A.PACC_ID,A.AGENT_CODE,A.FirstID,UP.AMOUNT,UP.TYPE
Into #FirstSplit
FROM (
Select UP.PACC_ID,UP.AGENT_CODE,Min(UP.ID) as FirstID
From sa_swift_S_AGMFIL UP
--Inner Join (Select Distinct PP.PACC_ID From sa_swift_S_AGMFIL PP
--      inner join #AGMFILCHANGES X ON X.ID = PP.ID) B ON UP.PACC_ID = B.PACC_ID
Where Type in (1,2,17) and Agent_Code <> 10002
Group by UP.PACC_ID,UP.AGENT_CODE 
) A
Inner Join sa_swift_S_AGMFIL UP on UP.ID = A.FirstId
--Order by 1,2    AG 08/02/2010

CREATE INDEX #FS on #FirstSplit (PACC_ID,AGENT_CODE)

Select UP.ID,UP.PACC_ID,UP.TransactionId,UP.AGENT_CODE,UP.CreateDateTime,UP.AMOUNT,EX.DATE_RECV,
Case WHEN EX.TYPE in (2,17) THEN -1*ABS(EX.AMOUNT_REC) ELSE EX.AMOUNT_REC END as AMOUNT_REC,
UP.AGENT_PERC as Payment_AgPct,CO.AGENT_PERC as Split_AgPct,ASM.AgentPercent,
isnull(isnull(UP.AGENT_PERC,isnull(ASM.AgentPercent,CO.AGENT_PERC)),100) as DerivedSplit,
CASE WHEN isnull(isnull(UP.AGENT_PERC,isnull(ASM.AgentPercent,CO.AGENT_PERC)),100) <= 0 THEN 0
WHEN UP.AMOUNT < 0 THEN (-0.01*ABS(EX.Amount_REC)*isnull(isnull(UP.AGENT_PERC,isnull(ASM.AgentPercent,CO.AGENT_PERC)),100)) - UP.AMOUNT
ELSE (0.01*ABS(EX.Amount_REC)*isnull(isnull(UP.AGENT_PERC,isnull(ASM.AgentPercent,CO.AGENT_PERC)),100)) - UP.AMOUNT END as DerivedMargin
into #Margins
from sa_swift_S_AGMFIL UP
inner join #AGMFILCHANGES X ON X.ID = UP.ID
inner join sa_swift_S_PACC EX ON EX.ID = UP.PACC_ID
inner join sa_swift_Policytransactions PT on PT.ID = UP.TransactionId
left outer join #splitpols T1 ON T1.policyid = PT.policyid
left outer join #SplitMoves T2 ON T2.ID = UP.ID
left outer join sa_swift_AgentSplitMovements ASM on ASM.ID = T2.ASMID
left outer join sa_swift_S_AGTCOM CO 
ON CO.CommissionType = 1 and CO.Agent_Code = UP.Agent_Code and CO.TransactionId = UP.TransactionId
Where UP.Type in (1,2,17) AND Cast(UP.AMOUNT as decimal(28,2)) <> 0
and UP.AGENT_CODE not in (10002)
--Order by 2,1    AG 08/02/2010

select @RowCount = @@rowcount
set @ProcessMessage = @Mode + ' - Select Payments : Count = ' + convert(varchar(10), @RowCount)   
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

Create INDEX #MG1 ON #Margins (ID)
Create INDEX #MG2 ON #Margins (PACC_ID)

Select T2.*,T1.DerivedSplit as OrigSplit,T1.DerivedMargin as OrigMargin
into #FirstSplit2
from #Margins T1
inner join #FirstSplit T2 on T1.ID = T2.FirstId
--order by T2.PACC_ID,T2.AGENT_CODE   AG 08/02/2010

CREATE INDEX #FS2 on #FirstSplit2 (PACC_ID,AGENT_CODE)

Update #Margins
Set DerivedMargin = CASE WHEN t1.Amount < 0 then -1 * ABS(T2.OrigMargin) ELSE ABS(T2.OrigMargin) END
From #Margins T1
inner join #FirstSplit2 T2 on T2.PACC_ID = T1.PACC_ID AND T2.AGENT_CODE = T1.AGENT_CODE
Where T1.ID > T2.FIRSTID and ABS(T1.AMOUNT) = ABS(T2.AMOUNT) and T1.AMOUNT <> 0
AND T1.DerivedSplit <> T2.OrigSplit

Select PACC_ID
into #SingleSplits
from sa_swift_S_AGMFIL
where agent_code <> 10002
Group by PACC_ID
Having Count(*) = 1
--Order by 1  AG 08/02/2010

CREATE INDEX #SS on #SingleSplits (PACC_ID)

Update #Margins
Set DerivedMargin = Cast(T1.Amount_Rec - T1.Amount as decimal(28,2))
--Select T1.Amount_Rec,T1.Amount,round(T1.DerivedMargin,2) as Margin,T1.Amount_Rec - T1.Amount as NewMargin,T1.DerivedSplit,T2.FirstId,*
From #Margins T1
inner join #FirstSplit2 T2 on T2.FirstID = T1.ID 
inner join #SingleSplits T3 on T3.PACC_ID = T1.PACC_ID
where CAST(T1.Amount+round(T1.DerivedMargin,2) as decimal(28,2)) <> CAST(T1.Amount_Rec as decimal(28,2))
and ((t1.amount < 0 and t1.amount_rec < 0) OR (t1.amount > 0 and t1.amount_rec > 0))

Select EX.ID,
Case WHEN EX.TYPE in (2,17) THEN -1*ABS(EX.AMOUNT_REC) ELSE EX.AMOUNT_REC END as AMOUNT_REC,
SUM(CASE WHEN UP.AGENT_CODE = '10002' THEN UP.AMOUNT ELSE 0 END) as Margin,
SUM(CASE WHEN UP.AGENT_CODE <> '10002' THEN UP.AMOUNT ELSE 0 END) as NBI
into #PACCAmounts
from sa_swift_S_PACC EX
inner join sa_swift_S_AGMFIL UP ON EX.ID = UP.PACC_ID
Where EX.Type in (1,2,17)
Group By EX.ID,Case WHEN EX.TYPE in (2,17) THEN -1*ABS(EX.AMOUNT_REC) ELSE EX.AMOUNT_REC END 
--Order by 1    AG 08/02/2010

Create INDEX #PACC ON #PACCAmounts (ID)

Select DISTINCT A.PACC_ID 
INTO #DIFFID 
FROM (
Select T1.PACC_ID,T2.Amount_Rec,T2.NBI,T2.Margin,
Sum(T1.Amount) AS NBI2,Round(Sum(T1.DerivedMargin),2) as Margin2
,(T2.Margin-Round(Sum(T1.DerivedMargin),2)) as NetDiffMgn
,ABS(T2.Margin-Round(Sum(T1.DerivedMargin),2)) as ABSDiffMgn
From #Margins T1
Inner Join #PACCAmounts T2 on T2.ID = T1.PACC_ID
Group By T1.PACC_ID,T2.Amount_Rec,T2.NBI,T2.Margin
having CAST(Sum(T1.Amount)+Round(Sum(T1.DerivedMargin),2) as decimal(15,2)) <> CAST(T2.Amount_Rec as decimal(15,2))
  ) A
--Order by 1    AG 08/02/2010

UPDATE #Margins 
Set DerivedMargin = A.Margin
FROM #Margins T3
Inner Join (
Select DISTINCT T2.ID,-1*T1.DerivedMargin as Margin
from #Margins T2
inner join #Margins T1 ON T1.PACC_ID = T2.PACC_ID AND T2.ID > T1.ID 
AND cast((T1.AMOUNT + T2.AMOUNT) as decimal(28,2)) = 0 
AND cast(ABS(T1.DerivedMargin) as decimal(28,2)) <> cast(ABS(T2.DerivedMargin) as decimal(28,2))
where T2.pacc_id in (select pacc_id from #diffid) and T2.Amount < 0 
      ) A ON A.ID = T3.ID

--Select * from #Margins

/************************************************************************************************
  PERFORM DATABASE UPDATES
************************************************************************************************/

UPDATE mstt_PaymentsPending
SET DerivedAgentSplit = T1.DerivedSplit,
  DerivedMarginAmount = T1.DerivedMargin
FROM mstt_PaymentsPending PP
Inner Join #Margins T1 ON T1.ID = PP.ID

select @RowCount = @@rowcount
set @ProcessMessage = @Mode + ' - UPDATE mstt_PaymentsPending : Count = ' + convert(varchar(10), @RowCount)   
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/

Drop Table #SplitPols
Drop Table #SplitMoves
Drop Table #FirstSplit
Drop Table #FirstSplit2
Drop table #Margins
Drop table #SingleSplits
Drop table #PACCAmounts
Drop table #DIFFID

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client


GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldAdviserListingExtract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_PaymentshieldAdviserListingExtract]
with recompile
as
/********************************************************************************

Object      : procedure
Name        : owp_PaymentshieldAdviserListingExtract
Created By  : Paul Robathan
Created     : 25/09/2007

Amendment History
-----------------
Date        Author      Description
----        ------      -----------
15/05/2008  P Robathan  Add null values for ABCValue and ABC Rate

16/03/2009  P Robathan  Add Scheme and ProductGroup

23/09/2010  M Cawood    Use the new owt_PaymentshieldImportControl table to 
                        define which data should be selected from the  
                        owt_PaymentshieldCommissionPayments table. Note that no
                        msit_OpenworkAdviserListing rows are now deleted.

11/03/2013  M Cawood	SR207107 - Add Elite Points to Table

25/04/2015	A Groves	SR371343. New ELITE points calculation based on margin instead
						of adviser payment. Also, new ELITE rounding implemented.

02/05/2018	A Groves 	SR504834/CH21153/CR630.
						This amendment makes no functional/logical change to this proc. 
						It has been carried out to enable the new column 
						"msit_OpenworkAdviserListing.VNB_Points" to be introduced without 
						having to change and deploy this proc simultaneously. It is all 
						part of the work to separate VNB from the legacy batch procs to 
						protect them as VNB is likely to be subject to many tweaks as was 
						the case with ELITE.
						The change is as follows:
						 1) Introduction of listed columns in the INSERT statement. When 
							the "msit_OpenworkAdviserListing.VNB_Points" column is 
							introduced, this proc will default the column to null.					
***********************************************************************************/

--delete from dbo.msit_OpenworkAdviserListing                             --MPC: 23/09/2010
--where Source = 'Payshield'                                              --MPC: 23/09/2010
--  and [Month] in (select [Month] from owt_PaymentshieldImportPeriods)   --MPC: 23/09/2010

---------------------------------------------------------------------------
-- For each owt_PaymentshieldCommissionPayments record create an msit_OpenWorkAdviserListing
-- record
---------------------------------------------------------------------------

insert into msit_OpenworkAdviserListing		--AG 02/05/2018
(
	BusinessCode,
	BusinessName,
	SellerCode,
	SellerName,
	SellerForename,
	SellerSurname,
	Client,
	ClientForename,
	ClientSurname,
	BACSDate,
	Policy,
	CaseId,
	ProdType,
	StartDate,
	PaymentDate,
	Frequency,
	Premium,
	APE,
	CommRate,
	InitialPeriod,
	PayBasis,
	Sacrifice,
	AgentSplit,
	FeeType,
	Remarks,
	Provider,
	ProviderCode,
	SourceID,
	ListPosition,
	Month,
	Source,
	TotDue_Base,
	Accrued_Base,
	StillToAccr_Base,
	ITAdvanced_Base,
	EnhancementRate,
	TotDue_Enhd,
	Accrued_Enhd,
	StillToAccr_Enhd,
	ITAdvanced_Enhd,
	TotalPayment,
	DistributorRef,
	CreateDate,
	TransactionID,
	ABCValue,
	ABCRate,
	SchemeNum,
	ProductGroup,
	ELITE_Points
) 
Select	BusinessCode,
		BusinessName,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		Client,
		ClientForename,
		ClientSurname,
		convert(datetime,convert(varchar(10),BACSDate,103),103) as BACSDate, 
		Policy,
		NULL as CaseId,
		ProdType ,
		convert(datetime,convert(varchar(10),StartDate ,103),103) as StartDate, 
		convert(datetime,convert(varchar(10),PaymentDate,103),103) as PaymentDate, 
		Frequency,
		Premium,
		Turnover as APE,
		CommRate,
		InitialPeriod,
		PayBasis,
		NULL as Sacrifice,
		AgentSplit,
		FeeType ,
		OrigStatus as Remarks,
		Provider,
		ProviderCode,
		ID as SourceID,
		NULL as ListPosition,
		convert(datetime,convert(varchar(10),Month,103),103) as Month, 
		Source,

		case 
			when UpliftRate > 0 then EnhancedNBI/UpliftRate 
			else 0
		end as TotDue_Base,

		case
			when PayBasisCode = 'T' then 0
			when PayBasisCode <> 'T' and UpliftRate IS NULL then PaymentAmount
			when PayBasisCode <> 'T' and UpliftRate = 0 then PaymentAmount
			else case when UpliftRate > 0 then PaymentAmount/UpliftRate else 0 end
		end as Accrued_Base,

		case 
			when UpliftRate > 0 then StillToAccrue/UpliftRate 
			else 0 
		end as StillToAccr_Base,

		case
			when PayBasisCode <> 'T' then 0
			when PayBasisCode = 'T' and UpliftRate IS NULL then PaymentAmount
			when PayBasisCode = 'T' and UpliftRate = 0 then PaymentAmount
			else case when UpliftRate > 0 then PaymentAmount/UpliftRate else 0 end
		end as ITAdvanced_Base,

		case
			when UpliftRate IS NULL then 1
			when UpliftRate = 0 then 1
			else UpliftRate * 100
		end as EnhancementRate,

		EnhancedNBI as TotDue_Enhd,

		case
		when PayBasisCode <> 'T' then PaymentAmount
		else 0
		end as Accrued_Enhd,

		StillToAccrue as StillToAccr_Enhd,

		case
			when PayBasisCode = 'T' then PaymentAmount
			else 0
		end as ITAdvanced_Enhd,

		PaymentAmount as TotalPayment,
		NULL as DistributorRef,
		CreateDate,
		NULL as TransactionID,

		case 
			when UpliftRate > 0 then EnhancedNBI/UpliftRate 
			else 0
		end as ABCValue,			-- PR 15/05/08

		NULL as ABCRate,			-- PR 15/05/08    
		NULL as SchemeNum,			-- PR 16/03/09    
		'GI' as ProductGroup,		-- PR 16/03/09 
		   
		case when month >= '2015-02-01'							-- AG 25/04/2015
		then													-- AG 25/04/2015
			case when isnull(ELITE_Initial,0) < 0				-- AG 25/04/2015
				then -ceiling(ABS(isnull(ELITE_Initial,0)))		-- AG 25/04/2015
				else ceiling(isnull(ELITE_Initial,0))			-- AG 25/04/2015
			end													-- AG 25/04/2015
		else													-- AG 25/04/2015
			ELITE_Initial										--as ElitePoints --SR207107: MPC - 11/03/2013
		end as ELITE_Points
																-- AG 25/04/2015
from	owt_PaymentshieldCommissionPayments
		inner join (select max(FileID) as FileID                                      --MPC: 23/09/2010
					from owt_PaymentshieldImportControl) X on CreateDate = X.FileID   --MPC: 23/09/2010
where	PaymentAmount <> 0 and SalesMoveFlag <> 'N'





GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldAdviserListingExtract_Backup20180504AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_PaymentshieldAdviserListingExtract_Backup20180504AG]
with recompile
as

/********************************************************************************

Object      : procedure
Name        : owp_PaymentshieldAdviserListingExtract
Created By  : Paul Robathan
Created     : 25/09/2007

Amendment History
-----------------
Date        Author      Description
----        ------      -----------
15/05/2008  P Robathan  Add null values for ABCValue and ABC Rate

16/03/2009  P Robathan  Add Scheme and ProductGroup

23/09/2010  M Cawood    Use the new owt_PaymentshieldImportControl table to 
                        define which data should be selected from the  
                        owt_PaymentshieldCommissionPayments table. Note that no
                        msit_OpenworkAdviserListing rows are now deleted.

11/03/2013  M Cawood	SR207107 - Add Elite Points to Table

25/04/2015	A Groves	SR371343. New ELITE points calculation based on margin instead
						of adviser payment. Also, new ELITE rounding implemented.

***********************************************************************************/

--delete from dbo.msit_OpenworkAdviserListing                             --MPC: 23/09/2010
--where Source = 'Payshield'                                              --MPC: 23/09/2010
--  and [Month] in (select [Month] from owt_PaymentshieldImportPeriods)   --MPC: 23/09/2010

---------------------------------------------------------------------------
-- For each owt_PaymentshieldCommissionPayments record create an msit_OpenWorkAdviserListing
-- record
---------------------------------------------------------------------------

insert into msit_OpenworkAdviserListing 
Select
BusinessCode,
BusinessName,
SellerCode,
SellerName,
SellerForename,
SellerSurname,
Client,
ClientForename,
ClientSurname,
convert(datetime,convert(varchar(10),BACSDate,103),103), 
Policy ,
NULL,
ProdType ,
convert(datetime,convert(varchar(10),StartDate ,103),103), 
convert(datetime,convert(varchar(10),PaymentDate,103),103), 
Frequency ,
Premium ,
Turnover ,
CommRate,
InitialPeriod,
PayBasis,
NULL,
AgentSplit,
FeeType ,
OrigStatus,
Provider,
ProviderCode,
ID,
NULL,
convert(datetime,convert(varchar(10),Month,103),103), 
Source,
case when UpliftRate > 0 then EnhancedNBI/UpliftRate else 0 end,
case
when PayBasisCode = 'T' then 0
when PayBasisCode <> 'T' and UpliftRate IS NULL then PaymentAmount
when PayBasisCode <> 'T' and UpliftRate = 0 then PaymentAmount
else case when UpliftRate > 0 then PaymentAmount/UpliftRate else 0 end
end,

case when UpliftRate > 0 then StillToAccrue/UpliftRate else 0 end,

case
when PayBasisCode <> 'T' then 0
when PayBasisCode = 'T' and UpliftRate IS NULL then PaymentAmount
when PayBasisCode = 'T' and UpliftRate = 0 then PaymentAmount
else case when UpliftRate > 0 then PaymentAmount/UpliftRate else 0 end
end,

case
when UpliftRate IS NULL then 1
when UpliftRate = 0 then 1
else UpliftRate * 100
end,

EnhancedNBI,

case
when PayBasisCode <> 'T' then PaymentAmount
else 0
end,

StillToAccrue,

case
when PayBasisCode = 'T' then PaymentAmount
else 0
end,

PaymentAmount,
NULL,
CreateDate,
NULL,
case when UpliftRate > 0 then EnhancedNBI/UpliftRate else 0 end,  -- PR 15/05/08
NULL,				-- PR 15/05/08    
NULL,				-- PR 16/03/09    
'GI',				-- PR 16/03/09    
case when month >= '2015-02-01'							-- AG 25/04/2015
then													-- AG 25/04/2015
	case when isnull(ELITE_Initial,0) < 0				-- AG 25/04/2015
		then -ceiling(ABS(isnull(ELITE_Initial,0)))		-- AG 25/04/2015
		else ceiling(isnull(ELITE_Initial,0))			-- AG 25/04/2015
	end													-- AG 25/04/2015
else													-- AG 25/04/2015
	ELITE_Initial	--as ElitePoints --SR207107: MPC - 11/03/2013
end														-- AG 25/04/2015
from owt_PaymentshieldCommissionPayments
inner join (select max(FileID) as FileID                                      --MPC: 23/09/2010
            from owt_PaymentshieldImportControl) X on CreateDate = X.FileID   --MPC: 23/09/2010
where PaymentAmount <> 0 and SalesMoveFlag <> 'N';
GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldBankDetailsExtract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


create procedure [dbo].[owp_PaymentshieldBankDetailsExtract]
with recompile
as

set dateformat ymd

--########################################################################
--
-- Object  : procedure
-- Name    : owp_PaymentshieldBankDetailsExtract
-- Owner   : PR
-- Created : 20/09/2007
--
--########################################################################


-----------------------------------------------------
-- Delete Paymentshield rows from msit_OpenworkBankDetails
-----------------------------------------------------
delete from msit_OpenworkBankDetails where Source = 'Payshield'

---------------------------------
--- Create temporary table #Group
---------------------------------
Select
  BusinessCode,
  BusinessName,
  BusinessECode,
  [Month],
  ProviderCode,
  Provider,
  Sum(Round(PaymentAmount,2)) as 'GroupAmount',
  Count(*) as 'GroupCount'
into
 #Group
from owt_PaymentshieldCommissionPayments 
where PaymentAmount <> 0 and SalesMoveFlag <> 'N'
Group by 
  BusinessCode,
  BusinessName,
  BusinessECode,
  Month,
  ProviderCode,
  Provider

insert into msit_OpenworkBankDetails
select
  BusinessCode,
  BusinessName,
  BusinessECode,
  [Month],
  'Payshield',
  GroupAmount,
  (select case when convert(datetime,getdate(), 112) > c.PeriodEndDate then c.PeriodEndDate else CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME)  end from msit_CommissionStatementPeriods c where c.[Month] = G.[Month]),
  '90',
  'Commission Accrual',
  'Commission Accural - ' + Provider,
  case
    when GroupCount = 1 then '1 entry'
    else LTrim(Str(GroupCount) + ' entries')
        end,
  NULL,
  case when GroupAmount >= 0 then 2 else 1 end ,
  1,
  ProviderCode

from #Group G
where GroupCount > 0

drop table #Group

Select
  BusinessCode,
  BusinessName,
  BusinessECode,
  BACSDate,
  Sum(Round(PaymentAmount,2)) as 'GroupAmount',
  Count(*) as 'GroupCount'
into
 #Group1
from owt_PaymentshieldCommissionPayments
where PaymentAmount <> 0 and SalesMoveFlag <> 'N' and BACSDate is not NULL
Group by 
  BusinessCode,
  BusinessName,
  BusinessECode,
  BACSDate


insert into msit_OpenworkBankDetails
select
    BusinessCode,
    BusinessName,
    BusinessECode = BusinessECode,
    (select [Month] from msit_CommissionStatementPeriods c where convert(datetime,BACSDate, 112) between c.PeriodStartDate and c.PeriodEndDate),
    'Payshield',
    -1 * GroupAmount,
    BACSDate,
    '2',
    'Payments to Bank',
    'Payments to Bank',
    NULL,
    NULL,
    3,
    1,
    NULL
from #Group1
where GroupAmount <> 0

drop table #Group1


---------------------------------------------------------------------------------------
--- Create various temporary tables to hold opening/closing balances and monthly totals
---------------------------------------------------------------------------------------

select BusinessCode,BusinessName,BusinessEcode,Month,sum(PaymentAmount) as Amount,count(*) as Count
into #MonthTotals
from owt_PaymentshieldCommissionPayments
group by BusinessCode,BusinessName,BusinessEcode,Month
order by BusinessCode,Month

select t1.BusinessCode,t1.Month,sum(t2.Amount) as Amount,sum(t2.Count) as Count
into #PrevMonth
from #Monthtotals t1
left outer join #Monthtotals t2 on t1.Businesscode = t2.BusinessCode and t1.Month > t2.Month
group by t1.BusinessCode,t1.Month
order by t1.BusinessCode,t1.Month

select t1.BusinessCode,t1.BusinessName,t1.BusinessEcode,t1.Month,
isnull(t2.Amount,0) as Amount,isnull(t2.Count,0) as Count
into #OpenBalances
from #Monthtotals t1
left outer join #PrevMonth t2 on t1.BusinessCode = t2.BusinessCode and t1.Month = t2.Month

--select * from #OpenBalances

select t1.BusinessCode,t1.BusinessName,t1.BusinessEcode,t1.Month,
t1.Amount+isnull(t2.Amount,0) as Amount,t1.Count+isnull(t2.Count,0) as Count
into #ClosingBalances
from #MonthTotals t1
left outer join #PrevMonth t2 on t1.BusinessCode = t2.BusinessCode and t1.Month = t2.Month

--select * from #ClosingBalances
drop table #PrevMonth

select csp.Month,csp.PeriodStartDate,owt.BusinessCode,owt.BusinessName,owt.BusinessEcode
into #MonthList
from owt_PaymentshieldCommissionPayments owt,msit_CommissionStatementPeriods csp
group by csp.Month,csp.PeriodStartDate,owt.BusinessCode,owt.BusinessName,owt.BusinessEcode
order by 3,1

select t1.*,t5.Amount as OpeningBalance,t2.Amount as ClosingBalance,coalesce(t3.Amount,0) as Amount,coalesce(max(t4.Month),dateadd(mm,-1,t1.Month)) as PrevMonth
into #BalanceList
from #MonthList t1
left outer join #OpenBalances t5 on t5.Businesscode = t1.BusinessCode and t5.Month = t1.Month
left outer join #ClosingBalances t2 on t2.Businesscode = t1.BusinessCode and t2.Month = t1.Month
left outer join #MonthTotals t3 on t3.Businesscode = t1.BusinessCode and t3.Month = t1.Month
left outer join #ClosingBalances t4 on t4.Businesscode = t1.BusinessCode and t4.Month < t1.Month
group by t1.Month,t1.PeriodStartDate,t1.BusinessCode,t1.BusinessName,t1.BusinessEcode,t5.Amount,t2.Amount,t3.Amount
order by 2,1

drop table #MonthTotals
drop table #OpenBalances
drop table #MonthList


update #BalanceList
set ClosingBalance = t2.Amount,
    OpeningBalance = t2.Amount
from #BalanceList t1
inner join #ClosingBalances t2 on t1.BusinessCode = t2.BusinessCode and t1.PrevMonth = t2.Month
where t1.ClosingBalance is null and t1.PrevMonth is not NULL

drop table #ClosingBalances
--select * from #BalanceList order by BusinessCode,Month

delete from #Balancelist
where ClosingBalance is NULL --and Amount is NULL and PrevMonth is NULL

----------------------------------------------------------------------------
-- Use #Balancelist table to Create OB/CB rows for each Month setting values
-- where Amount is NULL and ClosingBalance is not NULL
----------------------------------------------------------------------------
insert into msit_OpenworkBankDetails 
select
  BusinessCode,
  BusinessName,
  BusinessECode,
  [Month],
  'Payshield',
  OpeningBalance,
  PeriodStartDate,
  '0',
  'Opening Balance',
  'Opening Balance',
  NULL,
  NULL,
  0,
  0,
  NULL
from #Balancelist 
where ClosingBalance is not null --and Amount is null

insert into msit_OpenworkBankDetails 
select
  BusinessCode,
  BusinessName,
  BusinessECode,
  [Month],
  'Payshield',
  ClosingBalance,
  PeriodStartDate,
  '99',
  'Closing Balance',
  'Closing Balance',
  NULL,
  NULL,
  9,
  2,
  NULL
from #Balancelist
where ClosingBalance is not null --and Amount is null

drop table #BalanceList



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommission]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_PaymentshieldCommission]
	@debug  varchar(1) = 'N'
with recompile
as

/********************************************************************************

Object  	  : procedure
Name    	  : owp_PaymentshieldCommission
Created By	  : Paul Robathan
Created 	  : 22/09/2007

Amendment History
-----------------
Date		  Author	  Description
----		  ------      -----------
05/10/2009	A Groves	  1) Added debug lines to identify UAT perf prob
						  2) Deleted _BYO from BranchNo
10/11/2009  A Harrison		Create index on temporary #currtotals table
03/03/2010	A Groves		Enhancement to Paul Robathan's fix of a year
  						    ago to include another condition for leap year.
23/09/2010  M Cawood    1) To allow more than one GI file to be loaded in a month 
                           (e.g. GHL) the new owt_PaymentShieldImportControl table
                           holds the FileID to be held as CreateDate on each row
                           loaded onto the owt_PaymentshieldCommissionPayments table. 
                        2) The FileID is then used by the procedure
                           owp_PaymentshieldAdviserListingExtract to select the 
                           data to be extracted from the
                           owt_PaymentshieldCommissionPayments table.
                        3) No data is now deleted by this procedure. The data held
                           on the owt_PaymentShieldImport table is now appended to
                           the owt_PaymentshieldCommissionPayments table.
25/10/2010  M Cawood    Move Month forward one month. For example, if data loaded
                        with [Period] = 'April, 2010' then derive the Month and Period
                        End Date for May 2010 (i.e. 2010/06/01 and 2010/06/09 resp).
25/09/2012	A Groves	1) Break-fix: Take 1st 65 characters only from column
							owt_PaymentshieldImport.ClientName.
22/02/2013	A Groves	1) All these suffixes found in the Paymentshield file:
							_BYO, _BYO2, _BYO_BYO, _BYO2_BYO, BYO3, _BYO_BYO_BYO
							They also appear in the Seller Log.  All variations of BYO
							are now removed from both the Paymentshield file and the
							Seller Log to improve the match rate.
						2) DACommRate changed from 32.5 to 35.0 if look up fails.
08/03/2013	Mike Cawood	SR207107 - Calculate new metric ELITE Points
08/04/2013	A Groves	Changes required to load new Paymentshield Panel file.
18/04/2013	A Groves	Changes for new values of CommType and Status.
22/04/2013	A Groves	Openwork DA increased from 35% to 39% so a further tweak
						was required when calculatin DARate, CommRate & UpliftRate. 
23/04/2013	A Groves	Additional tweaks to the above change required for double indemnity. 
						ELITE_Initial calculation corrected.
30/04/2013	A Groves	SR224597 - Processing previously assumed title was present. When 
						not present as with adviser Alison Herbert, then her Seller Name
						was changed to Herbert rather than left as Alison Herbert.
26/06/2013	A Groves	SR227174. Populate the seller code using fuzzy matching techniques.
						This is required to enable recognition to be counted correctly
						for each adviser. 
						This change includes a bug fix to ensure that the post table load
						updates operate on just the file being loaded and not every
						row for the commission period which could have included data loaded 
						by previous runs of this proc on other files.
05/07/2013	A Groves	Improve selection of unique match keys by using Code rather
						than Descn as Descn often changes over time causing a seller
						to dupe with themselves - leading them to be excluded from matching. 
22/11/2013	A Groves	Paymentshield have used _BY0 (zero) instead of BYO (oh) so matching
						has been amended to cope.
19/06/2014	A Groves	Improved coding to strip unwanted characters after either an 
						underscore or a hyphen. This improves matching between the
						Paymentshield Branch Number and the Openwork Business UID.
25/04/2015	A Groves	SR371343. New ELITE points calculation based on margin instead
						of adviser payment.
06/11/2015	A Groves	SR380390 - Load Paymentshield Owl payments. New column SourceID
						added to table owt_PaymentshieldCommissionPayments but set to NULL
						in this proc because the source table gets cleared down. However,
						the Owl table doesn't get cleared down because it sources the
						data for the ASM Override Statements.
05/09/2017	A Groves	SR464996. Replace DTS with SSIS. Comma in column "Period" was
						originally removed by the DTS script. The SSIS replacement does
						not do this to keep it simple. Instead it is done in this proc.
30/06/2021  P Reed      Addition to capture sellercode and PESN fields and save in a new unmatched table - 
						[dbo].[owt_PaymentshieldImportUnmatched]
22/08/2023  P Reed      Removed Month table from fuzzy table check as causing step 15 to never finish
17/09/2024  P Reed      Openwork DA increased from 39% to 42.25% so a further tweak
						was required when calculatin DARate, CommRate & UpliftRate. (R248924)
***********************************************************************************/

declare	@RowCount		int,			-- AG 26/06/2013
		@Process		nvarchar(100),	-- AG 26/06/2013
		@ProviderOrig	varchar(30),	-- AG 26/06/2013
		@ProviderPanel	varchar(30),	-- AG 26/06/2013
		@Provider		varchar(30),    -- AG 26/06/2013
		@Panelfile     varchar(10)      -- Pr 30/06/2021

set @Panelfile='no';
exec msp_ProcessLog 'START', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

if @debug = 'Y' exec msp_ProcessLog 'START', '00) Remove _BYO from BranchNo', null, 'PaymentShield', 'Openwork'

-- AG 22/02/2013 Start

-- Strip out all text that includes and follows "_BYO". 
--update owhot_PaymentshieldSwiftAgentXRef
--		set PayshieldAgent = stuff(PayshieldAgent,patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')),50,'')	-- AG 22/11/2013
--where patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')) > 0													-- AG 22/11/2013

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update dbo.owhot_PaymentshieldSwiftAgentXref
	set PayshieldAgent = stuff(PayshieldAgent,patindex('%[-_]%',PayshieldAgent),100,'')
where patindex('%[-_]%',PayshieldAgent) > 0
-- AG 19/06/2014 End.

-- Since stripping out the _BYO derivatives, there are now dupes in the table. This step removes the dupes.
select	Xref.*
into	#owhot_PayshieldSwiftAgentXref
from	owhot_PaymentshieldSwiftAgentXref Xref
		inner join	(select PayshieldAgent, max(ID) as MaxID
						from owhot_PaymentshieldSwiftAgentXref
						group by PayshieldAgent) as DedupedPayshieldAgent
					on DedupedPayshieldAgent.MaxID = Xref.ID

-- AG 05/10/2009 Start

--update owt_paymentshieldimport
--		set BranchNo = stuff(BranchNo,patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')),50,'')		-- AG 22/11/2013
--where patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')) > 0										-- AG 22/11/2013

-- AG 05/10/2009 End
-- AG 22/02/2013 End

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update owt_paymentshieldimport
	set BranchNo = stuff(BranchNo,patindex('%[-_]%',BranchNo),100,'')
where patindex('%[-_]%',BranchNo) > 0
-- AG 19/06/2014 End.

--AG 05/09/2017 Start
--Remove comma in the Period field to enable it to be matched to the commission statement periods.
update owt_paymentshieldimport
	set Period = REPLACE(Period,',','')
--AG 05/09/2017 End

if @debug = 'Y' exec msp_ProcessLog 'START', '01) @PeriodCount derived', null, 'PaymentShield', 'Openwork'

select 
	distinct [Period] as 'Periods',
	convert (datetime, NULL,103) as 'PeriodMonth',
	convert (datetime, NULL,103) as 'BACSDate'
into #Months
from owt_PaymentshieldImport

-- AG 26/06/2013 Start

set @ProviderOrig	= 'Payment Shield'
set @ProviderPanel	= 'Payment Shield Panel'

if (select count(*) from owt_PaymentshieldImportPanel) > 1
	set @Provider = @ProviderPanel
else
	set @Provider = @ProviderOrig		

-- AG 26/06/2013 End

declare @PeriodCount  int
set @PeriodCount = (select Count(*) from #Months)

if @PeriodCount > 0 
begin

	if @debug = 'Y' exec msp_ProcessLog 'START', '02) Update #Months', null, 'PaymentShield', 'Openwork'

	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.MonthName = m.Periods 

--MPC: 25/10/2010 Move PeriodMonth and BACSDate forward one month
	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.Month = dateadd(mm,1,m.PeriodMonth) 
	
	declare @MonthCount  int
	set @MonthCount  = (select Count(*) from #Months where PeriodMonth is NOT NULL)

	if @debug = 'Y' exec msp_ProcessLog 'START', '03) @MonthCount derived', null, 'PaymentShield', 'Openwork'

	if @MonthCount  > 0 
	begin

		if @debug = 'Y' exec msp_ProcessLog 'START', '04) Delete from #Months', null, 'PaymentShield', 'Openwork'

		delete from #Months where PeriodMonth is NULL

			--PFR NEW 22082023
			declare @maxMonth datetime;
			set @maxMonth=(select MAX(periodmonth) from #Months)

		if @debug = 'Y' exec msp_ProcessLog 'START', '05) Delete from owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		--Derive unique FileID to be recorded against each row inserted --MPC: 23/09/2010
		declare @FileID datetime;                                       --MPC: 23/09/2010
		set @FileID = getdate();                                        --MPC: 23/09/2010

		--delete from owt_PaymentshieldCommissionPayments               --MPC: 23/09/2010
		--where [Month] in (select PeriodMonth from #Months)            --MPC: 23/09/2010

		--Maintain table that controls msit_OpenworkAdviserListing      --MPC: 23/09/2010
		truncate table dbo.owt_PaymentshieldImportControl;              --MPC: 23/09/2010
    
		insert into dbo.owt_PaymentshieldImportControl                  --MPC: 23/09/2010
		Select [FileID] = @FileID;                                      --MPC: 23/09/2010

		if @debug = 'Y' exec msp_ProcessLog 'START', '06) insert into owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		insert into owt_PaymentshieldCommissionPayments 
		select
		x.AgentCode,
		Rtrim(isnull(a.TradingName,a.DESCN)),
		a.OscarAgentPrefix + a.OscarAgentSerial + a.OscarAgentSuffix,
		PSI.BranchNo,
		NULL,
--		AG 30/04/2013 Start
--		case when charindex(' ', RTrim(PSI.SellerName)) = 0 then PSI.SellerName
--			else Rtrim(Substring(RTrim(PSI.SellerName), charindex(' ', RTrim(PSI.SellerName)) + 1, Len(RTrim(PSI.SellerName)) - charindex(' ', RTrim(PSI.SellerName))))
--			end,
		case when MICodes.Code is null	-- No match on person title so title assumed not present
			then ltrim(rtrim(PSI.SellerName))												-- AG 26/06/2013
			else ltrim(rtrim(stuff(replace(PSI.SellerName,'.',''),1,len(MICodes.Code),''))) 
		end as SellerName,
--		AG 30/04/2013 End
		NULL,
		NULL,
		NULL,
		substring(Rtrim(PSI.ClientName),1,65),						-- AG 25/09/2012
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Substring(RTrim(PSI.ClientName), charindex(' ', RTrim(PSI.ClientName))+1,1))
			end,
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Right(RTrim(PSI.ClientName),charindex(' ', Reverse(RTrim(PSI.ClientName)))-1))
			end,
		NULL,
		PSI.PolicyReference,
		Left(PSI.Product,8),
		'PY_' + Left(PSI.Product,5),
		PSI.StartDate,
	 	m.PeriodMonth,
		case 
			when PSI.StartDate >= convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) then PSI.StartDate
			when PSI.StartDate < convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) and Month(PSI.StartDate) < Month(PSI.Period) then 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then 
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period) as varchar(4)),103)
					 else
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period) as varchar(4)),103)
				end			
			else 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then					-- AG 03/03/2010
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)	-- AG 03/03/2010
					 else																			-- AG 03/03/2010
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)
				end
		end,
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then 'M'
			else case when left(Panel.TermOfContract,6) = 'ANNUAL'
					then 'A'
					else 'M'
				 end
		end as Frequency, 
		case when Panel.UniqueRowID is null
			then Abs(PSI.Premium) * 12
			else case when left(Panel.TermOfContract,6) = 'ANNUAL' 
						then 1 
						else 12 
				 end * abs(PSI.Premium)
		end as Premium,		
		-- AG 08/04/2013 End
		0,
		isnull ((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(PSI.Product,5)),'N'),
		0,
		0,
		case when PSI.Margin > 0 then PSI.Margin 
			 when PSI.Premium <> 0 then Abs((PSI.Fee*100)/(PSI.Premium *	case												-- AG 18/04/2013
																				when left(Panel.TermOfContract,6) = 'ANNUAL'	-- AG 18/04/2013
																				then 1											-- AG 18/04/2013
																				else 12											-- AG 18/04/2013
																			end))												-- AG 18/04/2013
			 else 7.5 
		end,
		isnull((select cast(Description as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),35.0),		-- AG 22/02/2013	Old value = 32.5
		isnull((select cast(LongDescription as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),27.5),
		1,
		0,
		0,
		NULL,
		0,
		0,
		0,
		0,
		0,
		PSI.Fee,
		0,
		case when PSI.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end,								-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end,			-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end,	-- AG 18/04/2013
		100,
		case when PSI.CommType in ('Adjustment','Awaiting Start') or PSI.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end,	-- AG 18/04/2013
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then @ProviderOrig					-- AG 26/06/2013
			else @ProviderPanel					-- AG 26/06/2013
		end as Provider,
		-- AG 08/04/2013 End
		'PYMTSHLD',
		m.PeriodMonth,
		'Payshield',
		--getdate(),      --MPC: 23/09/2010
		@FileID,          --MPC: 23/09/2010
		PSI.CommType,
		PSI.Status,
		NULL as ELITE_Initial,			--MPC: 20/02/2013 SR207107
		NULL as ELITE_Category,			--MPC: 20/02/2013 SR207107
		ltrim(rtrim(PSI.SellerName)),	-- AG 26/06/2013
		psi.UniqueRowID as SourceID				-- AG 06/11/2015   --PR 30/06/2021 CHANGED FROM NULL TO THE IMPORT RECORDID (NOTE THIS WILL LATER BE SET BACK TO NULL FOR SAFETY REASONS)
		from owt_PaymentshieldImport PSI
--		inner join owhot_PaymentshieldSwiftAgentXRef x on x.PayshieldAgent = PSI.BranchNo			AG 22/02/2012
		inner join #owhot_PayshieldSwiftAgentXref x on x.PayshieldAgent = PSI.BranchNo				-- AG 22/02/2012
		inner join mstt_Agents a on a.CODE = x.AgentCode
		inner join #Months m on m.Periods = PSI.Period
		left join owt_PaymentshieldImportPanel Panel on Panel.UniqueRowID = PSI.UniqueRowID			-- AG 08/04/2013
		left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes									-- AG 30/04/2013
						on  MICodes.ColumnName = 'PersonTitle' 
						and ltrim(rtrim(replace(PSI.SellerName,'.',''))) like MICodes.Code + ' %'	-- AG 26/06/2013
		where x.Deleted <> 'Y'

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '06) insert into owt_PaymentshieldCommissionPayments. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- AG 08/04/2013. Truncate Panel table to ensure it is not incorrectly
		-- used during a non-Panel File load. 
		---------------------------------------------------------------------------
		select @panelfile='Yes' from owt_PaymentshieldImportPanel where UniqueRowID is not null; --if there is a pesn then the last file loaded must be a panel file --PR 30/06/2021
		truncate table owt_PaymentshieldImportPanel	

		---------------------------------------------------------------------------
		-- Update Sales Measures #1		AG 22/04/2013 & 23/04/2013
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '07) Update Sales Measures #1', null, 'PaymentShield', 'Openwork'

		--2024 change R248924--4 in the 3 lines below changes from 4 to 7.25
		update	owt_PaymentshieldCommissionPayments 
			set	DACommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 7.25 else 0.0 end + PCP.DACommRate,
				CommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 7.25 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate),
				UpliftRate	= (case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 7.25 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate))/PCP.BaseCommRate
		from	owt_PaymentshieldCommissionPayments PCP
				INNER JOIN #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '07) Update Sales Measures #1. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #2
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '08) Update Sales Measures #2', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
                        set PaymentAmount = case	  
						  when PCP.MarginCommRate > 0 then PCP.Margin * (PCP.CommRate/PCP.MarginCommRate)
						  else PCP.PaymentAmount
				  	    end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '08) Update Sales Measures #2. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update incomplete data
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '09) Update incomplete data', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set PayBasisCode = isnull((select	top 1 PayBasisCode 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth
										order by o.Month Desc), PCP.PayBasisCode),
			    PayBasis = isnull((select	top 1 PayBasis 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.PayBasis),
			    Premium = isnull((select	top 1 Premium 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.Premium),
			    InitialPeriod = isnull((select	top 1 InitialPeriod 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth 
										order by o.Month Desc), PCP.InitialPeriod) 	
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where  PCP.CreateDate = @FileID														-- AG 26/06/2013
		and	   (PCP.OrigCommType in ('Clawback','Adjustment','Cancelled','Cancelled Case')	-- AG 18/04/2013 
		or		PCP.Premium = 0
		or		PCP.OrigStatus in ('CANCELLATION','CANCELLED','MTA'))						-- AG 18/04/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '09) Update incomplete data. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- create temporary table to hold current totals 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '10) Populate #currtotals', null, 'PaymentShield', 'Openwork'

		select	isnull(SUM(b.PaymentAmount),0) as 'CURR_FEE',a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month], Count(*) as 'CURR_COUNT'
		into	#currtotals
		from	owt_PaymentshieldCommissionPayments a 
				inner join owt_PaymentshieldCommissionPayments b 
						on a.BusinessCode = b.BusinessCode 
						and a.Policy = b.Policy 
						and a.LatestAnniversary = b.LatestAnniversary 
						and a.Provider = b.Provider					-- AG 26/06/2013
		where	a.OrigCommType not in ('Awaiting Start','Earn Off')
		and		a.Provider = @Provider								-- AG 26/06/2013
		group	by a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month]

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '10) Populate #currtotals. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------
		-- Create index on temporary table
		---------------------------------------------

		CREATE  INDEX [idx_BusinessCode] ON [dbo].[#currtotals]([BusinessCode],[Policy],[LatestAnniversary],[Month]) 

		---------------------------------------------------------------------------
		-- Update SalesMoveFlag 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '11) Update SalesMoveFlag', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set SalesMoveFlag = case 
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary > PCP.StartDate and ct.CURR_COUNT = 1 then 'Y'
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary = PCP.StartDate and ct.CURR_COUNT = 1 then 'Y' 
					when PCP.PayBasisCode = 'T' and PCP.Margin > 0 then 'Y' 
					when PCP.OrigCommType in ('Cancelled','Clawback','Cancelled Case') or PCP.OrigStatus in ('CANCELLATION','CANCELLED') then case when ct.CURR_FEE = 0 then 'Y' else 'X' end	-- AG 18/04/2013
					when PCP.OrigCommType in ('Awaiting Start','Earn Off') then 'N'
					else 'X'
				    end 
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
											and ct.[Month] = PCP.[Month] 
		where  PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '11) Update SalesMoveFlag. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #3
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '12) Update Sales Measures #3', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set TotalFeeDue = case 
								when PCP.SalesMoveFlag  = 'N' then PCP.TotalFeeDue
								else case	  
										when PCP.PaymentAmount < 0 or PCP.PayBasis = 'IT' then PCP.PaymentAmount 
										else PCP.PaymentAmount * case when PCP.Frequency = 'A' then 1 else 12 end	-- AG 18/04/2013
									 end	  
				  			   end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '12) Update Sales Measures #3. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- now use current table to update ICPaidToDate and StilltoAccrue 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '13) Update ICPaidToDate and StilltoAccrue', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set ICPaidToDate = CURR_FEE,
			    StilltoAccrue = PCP.TotalFeeDue - CURR_FEE
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
							                and ct.[Month] = PCP.[Month] 
		where	PCP.PaymentAmount > 0 
		and		PCP.PayBasisCode = 'F'
		and		PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '13) Update ICPaidToDate and StilltoAccrue. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #4
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '14) Update Sales Measures #4', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set 
				DA = Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
	    		EnhancedNBI = Abs(PCP.TotalFeeDue) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	BaseNBI = (Abs(PCP.TotalFeeDue)/PCP.UpliftRate) *  case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	Turnover =	case
			 	  				when PCP.APEFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 	  				else Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate)  * case when PCP.PaymentAmount < 0 then -1 else 1 end
							end,
		    	APE =	case
			 				when PCP.APEFlag = 'Y' and PCP.SalesMoveFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 				else PCP.APE  
						end,
				ELITE_Initial = 
					case when PCP.Month >= '2015-02-01'									--AG 25/04/2015
					then case															--AG 25/04/2015
							when PCP.PaymentAmount < 0									--AG 25/04/2015
							then round(isnull(-ABS(PCP.Margin * ELF.Multiplier),0),4)	--AG 25/04/2015
							else round(isnull(PCP.Margin * ELF.Multiplier,0),4)			--AG 25/04/2015
						  end															--AG 25/04/2015
					else																--AG 25/04/2015
						round( ELF.Factor * ELF.Multiplier *							--MPC: 20/02/2013 SR207107
						( ( Abs(PCP.TotalFeeDue)/PCP.UpliftRate )						--MPC: 20/02/2013 SR207107
						* case when PCP.PaymentAmount < 0 then -1 else 1 end ),2)		--MPC: 20/02/2013 SR207107
					end,																--AG 25/04/2015
				ELITE_Category = ELF.Category											--MPC: 20/02/2013 SR207107
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join msit_CommissionStatementPeriods CSP on m.PeriodMonth = CSP.Month	--MPC: 20/02/2013 SR207107
				left join owt_ELITEFactors ELF on ELF.FeeType = 'Initial' and ELF.Category = 'GI' and CSP.Year between ELF.StartYear and ELF.EndYear		--MPC: 20/02/2013 SR207107
		where	PCP.SalesMoveFlag  = 'Y'
		and		PCP.CreateDate = @FileID										-- AG 26/06/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '14) Update Sales Measures #4. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		----------------------------------------------------------------------------------
		-- Populate temporary table with exact and fuzzy matched sellers for current month
		----------------------------------------------------------------------------------

		-- AG 26/06/2013 Start

		if @debug = 'Y' exec msp_ProcessLog 'START', '15) Populate #FuzzyMatchedSellers', null, 'PaymentShield', 'Openwork'

		select	distinct	-- joins are to all rows on AgentsHistory to match to past
							-- employers.  This will create a lot of duplicate rows 
							-- hence distinct to remove them.
				PCP.BusinessCode as PaymentshieldBusinessCode,
				PCP.SellerName as PaymentshieldSellerName, 
				coalesce(AgHist.Code,FuzzyNotExact.Code) as SwiftSellerUID, 
				coalesce(ltrim(rtrim(AgHist.DESCN)),FuzzyNotExact.descn) as SwiftSellerName
		into	#FuzzyMatchedSellers
		From	owt_PaymentshieldCommissionPayments PCP
				--inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join	mstt_AgentsHistory AgHist	-- Exact match of this seller in this business either now or in the past 
								on ltrim(rtrim(AgHist.DESCN)) = ltrim(rtrim(PCP.SellerName))
								and AgHist.AgentType in (4,43,46,49,51)
								and AgHist.Firm = PCP.BusinessCode
				left join	(	select	advisers.code, advisers.Firm, 
										ltrim(rtrim(advisers.Descn)) as descn, 
										dbo.owf_Soundex(advisers.descn,'F') as SoundexDescnForename,
										dbo.owf_Soundex(advisers.descn,'L') as SoundexDescnSurname
								from	mstt_AgentsHistory advisers
										inner join	(					
														select	a.Firm, a.SoundexDescnSurname, a.FirstInitial
														from	
																(
																	select	distinct -- Unique permutations of sellers and their fuzzy match key hence distinct
																			sellers.Firm, 
																			--ltrim(rtrim(sellers.Descn)) as Descn,	-- AG 05/07/2013
																			Sellers.Code,							-- AG 05/07/2013 
																			dbo.owf_Soundex(sellers.descn,'L') As SoundexDescnSurname,
																			substring(sellers.descn,1,1) as FirstInitial 
																	from mstt_AgentsHistory sellers		-- Use Agent History to exclude anyone who has ever swapped businesses
																	where sellers.AgentType in (4,43,46,49,51)
																	and isnull(sellers.Firm,'') <> ''
																) a 
														group	by a.Firm, a.SoundexDescnSurname, a.FirstInitial
														having	count(*) = 1	-- We only want one occurrence of a fuzzy match key to avoid over-matching
													)	Fuzzy   on  Fuzzy.Firm = advisers.Firm 
																and Fuzzy.SoundexDescnSurname = dbo.owf_Soundex(advisers.descn,'L')
																and	Fuzzy.FirstInitial = substring(advisers.descn,1,1)
								where	advisers.AgentType in (4,43,46,49,51)
								and		isnull(advisers.Firm,'') <> ''	
							) FuzzyNotExact on FuzzyNotExact.Firm = PCP.BusinessCode
											and FuzzyNotExact.Descn <> PCP.SellerName
											-- First two characters of forename soundex must be the same
											-- Thus Michael and Mike match but Michael and Matthew don't match
											and (substring(FuzzyNotExact.SoundexDescnForename,1,2) = substring(dbo.owf_Soundex(PCP.SellerName,'F'),1,2)	
											or	 dbo.owf_AbbreviatedMatch(FuzzyNotExact.descn,PCP.SellerName) = 1)
											and FuzzyNotExact.SoundexDescnSurname = dbo.owf_Soundex(PCP.SellerName,'L')		-- Soundex of surname must match
		where	(FuzzyNotExact.Code is not null or AgHist.Code is not null)
		and		PCP.CreateDate = @FileID	
		and pcp.Month=@maxMonth    --PFR NEW 22082023

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '15) Populate #FuzzyMatchedSellers. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the exact and fuzzy matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '16) Update SellerCode with UID matches', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerCode		= FMS.SwiftSellerUID,
				SellerName		= FMS.SwiftSellerName + ' - ' + FMS.SwiftSellerUID,
				SellerForename	= dbo.owf_FirstWord(FMS.SwiftSellerName),
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(FMS.SwiftSellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #FuzzyMatchedSellers FMS 
							on  FMS.PaymentshieldBusinessCode = PCP.BusinessCode
							and FMS.PaymentshieldSellerName = PCP.SellerName
		where	PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '16) Update SellerCode with UID matches. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the non-matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '17) Update Forename and Surname with unmatched names', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerForename	= dbo.owf_FirstWord(PCP.SellerName),				-- SellerName unchanged from Paymentshield
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(PCP.SellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID											-- AG 26/06/2013
		and		PCP.SellerCode is null		-- non-matched sellers

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17) Update Forename and Surname with unmatched names. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		-- AG 26/06/2013 End

		----------------------------- PR 30/06/2021 --START PR CHANGE 30/06/2021 (also some code above)
		--STORED UNMATCHED UID'S
		----------------------------
		if @debug = 'Y' exec msp_ProcessLog 'START', '17A) Store unmatched UIDs', null, 'PaymentShield', 'Openwork'

		--select @panelfile='Yes' from owt_PaymentshieldImport where pesn is not null; --if there is a pesn then the last file loaded must be a panel file
	
insert into [dbo].[owt_PaymentshieldImportUnmatched]
(     
	[UniqueRowID] ,
	[Period] ,
	[PolicyReference] ,
	[OWPolicyRef],
	[ClientName] ,
	[StartDate] ,
	[Source] ,
	[Product] ,
	[CommType] ,
	[Status] ,
	[Premium] ,
	[Margin] ,
	[Fee] ,
	[BranchName],
	[BranchNo] ,
	[SellerName] ,
	[OWFirmRef] ,
	[OW_Sellerref] ,
	[PESN] ,
	[comm_id] ,
	[comm_SellerCode],
	[comm_SellerName] ,
	[comm_SellerForename] ,
	[comm_SellerSurname] ,
	[panelfile] ,
	[provider] ,
	[DateLoaded] ,
	[ImportConvertsellerref],
	[sourceid])

--Selects them on the basis they are at the same policy and branch
select 
ii.[UniqueRowID] ,
	ii.[Period] ,
	ii.[PolicyReference] ,
	ii.[OWPolicyRef],
	ii.[ClientName] ,
	ii.[StartDate] ,
	ii.[Source] ,
	ii.[Product] ,
	ii.[CommType] ,
	ii.[Status] ,
	ii.[Premium] ,
	ii.[Margin] ,
	ii.[Fee] ,
	ii.[BranchName],
	ii.[BranchNo] ,
	ii.[SellerName] ,
	ii.[OWFirmRef] ,
	ii.[OW_Sellerref] ,
	ii.[PESN] ,
	owt.id,
	owt.SellerCode,
	owt.SellerName,
	owt.SellerForename,
	owt.SellerSurname,
	@panelfile ,
	owt.provider,
	getdate() ,
	CASE WHEN LEN(dbo.CleanAndTrimString(ii.OW_Sellerref)) =7
             THEN dbo.CleanAndTrimString(ii.OW_Sellerref)
             ELSE ''
        END ,
		owt.sourceid
from owt_PaymentshieldCommissionPayments owt 
inner join #Months m on m.PeriodMonth = owt.[Month]
join owt_PaymentshieldImport ii on ii.UniqueRowID=owt.sourceid
--and ii.margin=owt.MarginCommRate
where ((owt.provider ='payment shield panel' and @panelfile='Yes')  or (owt.provider ='payment shield' and @panelfile='no'))
and owt.sellercode is null 

set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17A) Insert records unmatched UIDS. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		if @debug = 'Y' exec msp_ProcessLog 'START', '17B) Update sourceids back to null', null, 'PaymentShield', 'Openwork'

		Update owt_PaymentshieldCommissionPayments set sourceid=null where sourceid is not null and provider in ('payment shield panel','payment shield'); --PR 30/06/2021 SET SOURCEID BACK TO NULL - SAFEGUARD UNLESS THIS IS BEING USED

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17B) SourceIDs set back to null. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		--END PR CHANGE 30/06/2021
		---------------------------------------------------------------------------
		-- Delete temporary tables
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

		drop table #currtotals
		drop table #FuzzyMatchedSellers		-- AG 26/06/2013
 
		if @debug = 'Y' exec msp_ProcessLog 'END', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

	end
end

drop table #Months;

exec msp_ProcessLog 'END', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommission_backupPFR_17_09_2024]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owp_PaymentshieldCommission_backupPFR_17_09_2024]
	@debug  varchar(1) = 'N'
with recompile
as

/********************************************************************************

Object  	  : procedure
Name    	  : owp_PaymentshieldCommission
Created By	  : Paul Robathan
Created 	  : 22/09/2007

Amendment History
-----------------
Date		  Author	  Description
----		  ------      -----------
05/10/2009	A Groves	  1) Added debug lines to identify UAT perf prob
						  2) Deleted _BYO from BranchNo
10/11/2009  A Harrison		Create index on temporary #currtotals table
03/03/2010	A Groves		Enhancement to Paul Robathan's fix of a year
  						    ago to include another condition for leap year.
23/09/2010  M Cawood    1) To allow more than one GI file to be loaded in a month 
                           (e.g. GHL) the new owt_PaymentShieldImportControl table
                           holds the FileID to be held as CreateDate on each row
                           loaded onto the owt_PaymentshieldCommissionPayments table. 
                        2) The FileID is then used by the procedure
                           owp_PaymentshieldAdviserListingExtract to select the 
                           data to be extracted from the
                           owt_PaymentshieldCommissionPayments table.
                        3) No data is now deleted by this procedure. The data held
                           on the owt_PaymentShieldImport table is now appended to
                           the owt_PaymentshieldCommissionPayments table.
25/10/2010  M Cawood    Move Month forward one month. For example, if data loaded
                        with [Period] = 'April, 2010' then derive the Month and Period
                        End Date for May 2010 (i.e. 2010/06/01 and 2010/06/09 resp).
25/09/2012	A Groves	1) Break-fix: Take 1st 65 characters only from column
							owt_PaymentshieldImport.ClientName.
22/02/2013	A Groves	1) All these suffixes found in the Paymentshield file:
							_BYO, _BYO2, _BYO_BYO, _BYO2_BYO, BYO3, _BYO_BYO_BYO
							They also appear in the Seller Log.  All variations of BYO
							are now removed from both the Paymentshield file and the
							Seller Log to improve the match rate.
						2) DACommRate changed from 32.5 to 35.0 if look up fails.
08/03/2013	Mike Cawood	SR207107 - Calculate new metric ELITE Points
08/04/2013	A Groves	Changes required to load new Paymentshield Panel file.
18/04/2013	A Groves	Changes for new values of CommType and Status.
22/04/2013	A Groves	Openwork DA increased from 35% to 39% so a further tweak
						was required when calculatin DARate, CommRate & UpliftRate. 
23/04/2013	A Groves	Additional tweaks to the above change required for double indemnity. 
						ELITE_Initial calculation corrected.
30/04/2013	A Groves	SR224597 - Processing previously assumed title was present. When 
						not present as with adviser Alison Herbert, then her Seller Name
						was changed to Herbert rather than left as Alison Herbert.
26/06/2013	A Groves	SR227174. Populate the seller code using fuzzy matching techniques.
						This is required to enable recognition to be counted correctly
						for each adviser. 
						This change includes a bug fix to ensure that the post table load
						updates operate on just the file being loaded and not every
						row for the commission period which could have included data loaded 
						by previous runs of this proc on other files.
05/07/2013	A Groves	Improve selection of unique match keys by using Code rather
						than Descn as Descn often changes over time causing a seller
						to dupe with themselves - leading them to be excluded from matching. 
22/11/2013	A Groves	Paymentshield have used _BY0 (zero) instead of BYO (oh) so matching
						has been amended to cope.
19/06/2014	A Groves	Improved coding to strip unwanted characters after either an 
						underscore or a hyphen. This improves matching between the
						Paymentshield Branch Number and the Openwork Business UID.
25/04/2015	A Groves	SR371343. New ELITE points calculation based on margin instead
						of adviser payment.
06/11/2015	A Groves	SR380390 - Load Paymentshield Owl payments. New column SourceID
						added to table owt_PaymentshieldCommissionPayments but set to NULL
						in this proc because the source table gets cleared down. However,
						the Owl table doesn't get cleared down because it sources the
						data for the ASM Override Statements.
05/09/2017	A Groves	SR464996. Replace DTS with SSIS. Comma in column "Period" was
						originally removed by the DTS script. The SSIS replacement does
						not do this to keep it simple. Instead it is done in this proc.
30/06/2021  P Reed      Addition to capture sellercode and PESN fields and save in a new unmatched table - 
						[dbo].[owt_PaymentshieldImportUnmatched]
22/08/2023  P Reed      Removed Month table from fuzzy table check as causing step 15 to never finish
***********************************************************************************/

declare	@RowCount		int,			-- AG 26/06/2013
		@Process		nvarchar(100),	-- AG 26/06/2013
		@ProviderOrig	varchar(30),	-- AG 26/06/2013
		@ProviderPanel	varchar(30),	-- AG 26/06/2013
		@Provider		varchar(30),    -- AG 26/06/2013
		@Panelfile     varchar(10)      -- Pr 30/06/2021

set @Panelfile='no';
exec msp_ProcessLog 'START', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

if @debug = 'Y' exec msp_ProcessLog 'START', '00) Remove _BYO from BranchNo', null, 'PaymentShield', 'Openwork'

-- AG 22/02/2013 Start

-- Strip out all text that includes and follows "_BYO". 
--update owhot_PaymentshieldSwiftAgentXRef
--		set PayshieldAgent = stuff(PayshieldAgent,patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')),50,'')	-- AG 22/11/2013
--where patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')) > 0													-- AG 22/11/2013

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update dbo.owhot_PaymentshieldSwiftAgentXref
	set PayshieldAgent = stuff(PayshieldAgent,patindex('%[-_]%',PayshieldAgent),100,'')
where patindex('%[-_]%',PayshieldAgent) > 0
-- AG 19/06/2014 End.

-- Since stripping out the _BYO derivatives, there are now dupes in the table. This step removes the dupes.
select	Xref.*
into	#owhot_PayshieldSwiftAgentXref
from	owhot_PaymentshieldSwiftAgentXref Xref
		inner join	(select PayshieldAgent, max(ID) as MaxID
						from owhot_PaymentshieldSwiftAgentXref
						group by PayshieldAgent) as DedupedPayshieldAgent
					on DedupedPayshieldAgent.MaxID = Xref.ID

-- AG 05/10/2009 Start

--update owt_paymentshieldimport
--		set BranchNo = stuff(BranchNo,patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')),50,'')		-- AG 22/11/2013
--where patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')) > 0										-- AG 22/11/2013

-- AG 05/10/2009 End
-- AG 22/02/2013 End

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update owt_paymentshieldimport
	set BranchNo = stuff(BranchNo,patindex('%[-_]%',BranchNo),100,'')
where patindex('%[-_]%',BranchNo) > 0
-- AG 19/06/2014 End.

--AG 05/09/2017 Start
--Remove comma in the Period field to enable it to be matched to the commission statement periods.
update owt_paymentshieldimport
	set Period = REPLACE(Period,',','')
--AG 05/09/2017 End

if @debug = 'Y' exec msp_ProcessLog 'START', '01) @PeriodCount derived', null, 'PaymentShield', 'Openwork'

select 
	distinct [Period] as 'Periods',
	convert (datetime, NULL,103) as 'PeriodMonth',
	convert (datetime, NULL,103) as 'BACSDate'
into #Months
from owt_PaymentshieldImport

-- AG 26/06/2013 Start

set @ProviderOrig	= 'Payment Shield'
set @ProviderPanel	= 'Payment Shield Panel'

if (select count(*) from owt_PaymentshieldImportPanel) > 1
	set @Provider = @ProviderPanel
else
	set @Provider = @ProviderOrig		

-- AG 26/06/2013 End

declare @PeriodCount  int
set @PeriodCount = (select Count(*) from #Months)

if @PeriodCount > 0 
begin

	if @debug = 'Y' exec msp_ProcessLog 'START', '02) Update #Months', null, 'PaymentShield', 'Openwork'

	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.MonthName = m.Periods 

--MPC: 25/10/2010 Move PeriodMonth and BACSDate forward one month
	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.Month = dateadd(mm,1,m.PeriodMonth) 
	
	declare @MonthCount  int
	set @MonthCount  = (select Count(*) from #Months where PeriodMonth is NOT NULL)

	if @debug = 'Y' exec msp_ProcessLog 'START', '03) @MonthCount derived', null, 'PaymentShield', 'Openwork'

	if @MonthCount  > 0 
	begin

		if @debug = 'Y' exec msp_ProcessLog 'START', '04) Delete from #Months', null, 'PaymentShield', 'Openwork'

		delete from #Months where PeriodMonth is NULL

			--PFR NEW 22082023
			declare @maxMonth datetime;
			set @maxMonth=(select MAX(periodmonth) from #Months)

		if @debug = 'Y' exec msp_ProcessLog 'START', '05) Delete from owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		--Derive unique FileID to be recorded against each row inserted --MPC: 23/09/2010
		declare @FileID datetime;                                       --MPC: 23/09/2010
		set @FileID = getdate();                                        --MPC: 23/09/2010

		--delete from owt_PaymentshieldCommissionPayments               --MPC: 23/09/2010
		--where [Month] in (select PeriodMonth from #Months)            --MPC: 23/09/2010

		--Maintain table that controls msit_OpenworkAdviserListing      --MPC: 23/09/2010
		truncate table dbo.owt_PaymentshieldImportControl;              --MPC: 23/09/2010
    
		insert into dbo.owt_PaymentshieldImportControl                  --MPC: 23/09/2010
		Select [FileID] = @FileID;                                      --MPC: 23/09/2010

		if @debug = 'Y' exec msp_ProcessLog 'START', '06) insert into owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		insert into owt_PaymentshieldCommissionPayments 
		select
		x.AgentCode,
		Rtrim(isnull(a.TradingName,a.DESCN)),
		a.OscarAgentPrefix + a.OscarAgentSerial + a.OscarAgentSuffix,
		PSI.BranchNo,
		NULL,
--		AG 30/04/2013 Start
--		case when charindex(' ', RTrim(PSI.SellerName)) = 0 then PSI.SellerName
--			else Rtrim(Substring(RTrim(PSI.SellerName), charindex(' ', RTrim(PSI.SellerName)) + 1, Len(RTrim(PSI.SellerName)) - charindex(' ', RTrim(PSI.SellerName))))
--			end,
		case when MICodes.Code is null	-- No match on person title so title assumed not present
			then ltrim(rtrim(PSI.SellerName))												-- AG 26/06/2013
			else ltrim(rtrim(stuff(replace(PSI.SellerName,'.',''),1,len(MICodes.Code),''))) 
		end as SellerName,
--		AG 30/04/2013 End
		NULL,
		NULL,
		NULL,
		substring(Rtrim(PSI.ClientName),1,65),						-- AG 25/09/2012
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Substring(RTrim(PSI.ClientName), charindex(' ', RTrim(PSI.ClientName))+1,1))
			end,
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Right(RTrim(PSI.ClientName),charindex(' ', Reverse(RTrim(PSI.ClientName)))-1))
			end,
		NULL,
		PSI.PolicyReference,
		Left(PSI.Product,8),
		'PY_' + Left(PSI.Product,5),
		PSI.StartDate,
	 	m.PeriodMonth,
		case 
			when PSI.StartDate >= convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) then PSI.StartDate
			when PSI.StartDate < convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) and Month(PSI.StartDate) < Month(PSI.Period) then 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then 
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period) as varchar(4)),103)
					 else
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period) as varchar(4)),103)
				end			
			else 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then					-- AG 03/03/2010
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)	-- AG 03/03/2010
					 else																			-- AG 03/03/2010
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)
				end
		end,
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then 'M'
			else case when left(Panel.TermOfContract,6) = 'ANNUAL'
					then 'A'
					else 'M'
				 end
		end as Frequency, 
		case when Panel.UniqueRowID is null
			then Abs(PSI.Premium) * 12
			else case when left(Panel.TermOfContract,6) = 'ANNUAL' 
						then 1 
						else 12 
				 end * abs(PSI.Premium)
		end as Premium,		
		-- AG 08/04/2013 End
		0,
		isnull ((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(PSI.Product,5)),'N'),
		0,
		0,
		case when PSI.Margin > 0 then PSI.Margin 
			 when PSI.Premium <> 0 then Abs((PSI.Fee*100)/(PSI.Premium *	case												-- AG 18/04/2013
																				when left(Panel.TermOfContract,6) = 'ANNUAL'	-- AG 18/04/2013
																				then 1											-- AG 18/04/2013
																				else 12											-- AG 18/04/2013
																			end))												-- AG 18/04/2013
			 else 7.5 
		end,
		isnull((select cast(Description as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),35.0),		-- AG 22/02/2013	Old value = 32.5
		isnull((select cast(LongDescription as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),27.5),
		1,
		0,
		0,
		NULL,
		0,
		0,
		0,
		0,
		0,
		PSI.Fee,
		0,
		case when PSI.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end,								-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end,			-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end,	-- AG 18/04/2013
		100,
		case when PSI.CommType in ('Adjustment','Awaiting Start') or PSI.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end,	-- AG 18/04/2013
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then @ProviderOrig					-- AG 26/06/2013
			else @ProviderPanel					-- AG 26/06/2013
		end as Provider,
		-- AG 08/04/2013 End
		'PYMTSHLD',
		m.PeriodMonth,
		'Payshield',
		--getdate(),      --MPC: 23/09/2010
		@FileID,          --MPC: 23/09/2010
		PSI.CommType,
		PSI.Status,
		NULL as ELITE_Initial,			--MPC: 20/02/2013 SR207107
		NULL as ELITE_Category,			--MPC: 20/02/2013 SR207107
		ltrim(rtrim(PSI.SellerName)),	-- AG 26/06/2013
		psi.UniqueRowID as SourceID				-- AG 06/11/2015   --PR 30/06/2021 CHANGED FROM NULL TO THE IMPORT RECORDID (NOTE THIS WILL LATER BE SET BACK TO NULL FOR SAFETY REASONS)
		from owt_PaymentshieldImport PSI
--		inner join owhot_PaymentshieldSwiftAgentXRef x on x.PayshieldAgent = PSI.BranchNo			AG 22/02/2012
		inner join #owhot_PayshieldSwiftAgentXref x on x.PayshieldAgent = PSI.BranchNo				-- AG 22/02/2012
		inner join mstt_Agents a on a.CODE = x.AgentCode
		inner join #Months m on m.Periods = PSI.Period
		left join owt_PaymentshieldImportPanel Panel on Panel.UniqueRowID = PSI.UniqueRowID			-- AG 08/04/2013
		left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes									-- AG 30/04/2013
						on  MICodes.ColumnName = 'PersonTitle' 
						and ltrim(rtrim(replace(PSI.SellerName,'.',''))) like MICodes.Code + ' %'	-- AG 26/06/2013
		where x.Deleted <> 'Y'

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '06) insert into owt_PaymentshieldCommissionPayments. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- AG 08/04/2013. Truncate Panel table to ensure it is not incorrectly
		-- used during a non-Panel File load. 
		---------------------------------------------------------------------------
		select @panelfile='Yes' from owt_PaymentshieldImportPanel where UniqueRowID is not null; --if there is a pesn then the last file loaded must be a panel file --PR 30/06/2021
		truncate table owt_PaymentshieldImportPanel	

		---------------------------------------------------------------------------
		-- Update Sales Measures #1		AG 22/04/2013 & 23/04/2013
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '07) Update Sales Measures #1', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set	DACommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate,
				CommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate),
				UpliftRate	= (case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate))/PCP.BaseCommRate
		from	owt_PaymentshieldCommissionPayments PCP
				INNER JOIN #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '07) Update Sales Measures #1. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #2
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '08) Update Sales Measures #2', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
                        set PaymentAmount = case	  
						  when PCP.MarginCommRate > 0 then PCP.Margin * (PCP.CommRate/PCP.MarginCommRate)
						  else PCP.PaymentAmount
				  	    end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '08) Update Sales Measures #2. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update incomplete data
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '09) Update incomplete data', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set PayBasisCode = isnull((select	top 1 PayBasisCode 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth
										order by o.Month Desc), PCP.PayBasisCode),
			    PayBasis = isnull((select	top 1 PayBasis 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.PayBasis),
			    Premium = isnull((select	top 1 Premium 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.Premium),
			    InitialPeriod = isnull((select	top 1 InitialPeriod 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth 
										order by o.Month Desc), PCP.InitialPeriod) 	
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where  PCP.CreateDate = @FileID														-- AG 26/06/2013
		and	   (PCP.OrigCommType in ('Clawback','Adjustment','Cancelled','Cancelled Case')	-- AG 18/04/2013 
		or		PCP.Premium = 0
		or		PCP.OrigStatus in ('CANCELLATION','CANCELLED','MTA'))						-- AG 18/04/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '09) Update incomplete data. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- create temporary table to hold current totals 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '10) Populate #currtotals', null, 'PaymentShield', 'Openwork'

		select	isnull(SUM(b.PaymentAmount),0) as 'CURR_FEE',a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month], Count(*) as 'CURR_COUNT'
		into	#currtotals
		from	owt_PaymentshieldCommissionPayments a 
				inner join owt_PaymentshieldCommissionPayments b 
						on a.BusinessCode = b.BusinessCode 
						and a.Policy = b.Policy 
						and a.LatestAnniversary = b.LatestAnniversary 
						and a.Provider = b.Provider					-- AG 26/06/2013
		where	a.OrigCommType not in ('Awaiting Start','Earn Off')
		and		a.Provider = @Provider								-- AG 26/06/2013
		group	by a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month]

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '10) Populate #currtotals. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------
		-- Create index on temporary table
		---------------------------------------------

		CREATE  INDEX [idx_BusinessCode] ON [dbo].[#currtotals]([BusinessCode],[Policy],[LatestAnniversary],[Month]) 

		---------------------------------------------------------------------------
		-- Update SalesMoveFlag 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '11) Update SalesMoveFlag', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set SalesMoveFlag = case 
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary > PCP.StartDate and ct.CURR_COUNT = 1 then 'Y'
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary = PCP.StartDate and ct.CURR_COUNT = 1 then 'Y' 
					when PCP.PayBasisCode = 'T' and PCP.Margin > 0 then 'Y' 
					when PCP.OrigCommType in ('Cancelled','Clawback','Cancelled Case') or PCP.OrigStatus in ('CANCELLATION','CANCELLED') then case when ct.CURR_FEE = 0 then 'Y' else 'X' end	-- AG 18/04/2013
					when PCP.OrigCommType in ('Awaiting Start','Earn Off') then 'N'
					else 'X'
				    end 
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
											and ct.[Month] = PCP.[Month] 
		where  PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '11) Update SalesMoveFlag. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #3
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '12) Update Sales Measures #3', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set TotalFeeDue = case 
								when PCP.SalesMoveFlag  = 'N' then PCP.TotalFeeDue
								else case	  
										when PCP.PaymentAmount < 0 or PCP.PayBasis = 'IT' then PCP.PaymentAmount 
										else PCP.PaymentAmount * case when PCP.Frequency = 'A' then 1 else 12 end	-- AG 18/04/2013
									 end	  
				  			   end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '12) Update Sales Measures #3. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- now use current table to update ICPaidToDate and StilltoAccrue 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '13) Update ICPaidToDate and StilltoAccrue', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set ICPaidToDate = CURR_FEE,
			    StilltoAccrue = PCP.TotalFeeDue - CURR_FEE
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
							                and ct.[Month] = PCP.[Month] 
		where	PCP.PaymentAmount > 0 
		and		PCP.PayBasisCode = 'F'
		and		PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '13) Update ICPaidToDate and StilltoAccrue. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #4
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '14) Update Sales Measures #4', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set 
				DA = Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
	    		EnhancedNBI = Abs(PCP.TotalFeeDue) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	BaseNBI = (Abs(PCP.TotalFeeDue)/PCP.UpliftRate) *  case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	Turnover =	case
			 	  				when PCP.APEFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 	  				else Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate)  * case when PCP.PaymentAmount < 0 then -1 else 1 end
							end,
		    	APE =	case
			 				when PCP.APEFlag = 'Y' and PCP.SalesMoveFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 				else PCP.APE  
						end,
				ELITE_Initial = 
					case when PCP.Month >= '2015-02-01'									--AG 25/04/2015
					then case															--AG 25/04/2015
							when PCP.PaymentAmount < 0									--AG 25/04/2015
							then round(isnull(-ABS(PCP.Margin * ELF.Multiplier),0),4)	--AG 25/04/2015
							else round(isnull(PCP.Margin * ELF.Multiplier,0),4)			--AG 25/04/2015
						  end															--AG 25/04/2015
					else																--AG 25/04/2015
						round( ELF.Factor * ELF.Multiplier *							--MPC: 20/02/2013 SR207107
						( ( Abs(PCP.TotalFeeDue)/PCP.UpliftRate )						--MPC: 20/02/2013 SR207107
						* case when PCP.PaymentAmount < 0 then -1 else 1 end ),2)		--MPC: 20/02/2013 SR207107
					end,																--AG 25/04/2015
				ELITE_Category = ELF.Category											--MPC: 20/02/2013 SR207107
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join msit_CommissionStatementPeriods CSP on m.PeriodMonth = CSP.Month	--MPC: 20/02/2013 SR207107
				left join owt_ELITEFactors ELF on ELF.FeeType = 'Initial' and ELF.Category = 'GI' and CSP.Year between ELF.StartYear and ELF.EndYear		--MPC: 20/02/2013 SR207107
		where	PCP.SalesMoveFlag  = 'Y'
		and		PCP.CreateDate = @FileID										-- AG 26/06/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '14) Update Sales Measures #4. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		----------------------------------------------------------------------------------
		-- Populate temporary table with exact and fuzzy matched sellers for current month
		----------------------------------------------------------------------------------

		-- AG 26/06/2013 Start

		if @debug = 'Y' exec msp_ProcessLog 'START', '15) Populate #FuzzyMatchedSellers', null, 'PaymentShield', 'Openwork'

		select	distinct	-- joins are to all rows on AgentsHistory to match to past
							-- employers.  This will create a lot of duplicate rows 
							-- hence distinct to remove them.
				PCP.BusinessCode as PaymentshieldBusinessCode,
				PCP.SellerName as PaymentshieldSellerName, 
				coalesce(AgHist.Code,FuzzyNotExact.Code) as SwiftSellerUID, 
				coalesce(ltrim(rtrim(AgHist.DESCN)),FuzzyNotExact.descn) as SwiftSellerName
		into	#FuzzyMatchedSellers
		From	owt_PaymentshieldCommissionPayments PCP
				--inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join	mstt_AgentsHistory AgHist	-- Exact match of this seller in this business either now or in the past 
								on ltrim(rtrim(AgHist.DESCN)) = ltrim(rtrim(PCP.SellerName))
								and AgHist.AgentType in (4,43,46,49,51)
								and AgHist.Firm = PCP.BusinessCode
				left join	(	select	advisers.code, advisers.Firm, 
										ltrim(rtrim(advisers.Descn)) as descn, 
										dbo.owf_Soundex(advisers.descn,'F') as SoundexDescnForename,
										dbo.owf_Soundex(advisers.descn,'L') as SoundexDescnSurname
								from	mstt_AgentsHistory advisers
										inner join	(					
														select	a.Firm, a.SoundexDescnSurname, a.FirstInitial
														from	
																(
																	select	distinct -- Unique permutations of sellers and their fuzzy match key hence distinct
																			sellers.Firm, 
																			--ltrim(rtrim(sellers.Descn)) as Descn,	-- AG 05/07/2013
																			Sellers.Code,							-- AG 05/07/2013 
																			dbo.owf_Soundex(sellers.descn,'L') As SoundexDescnSurname,
																			substring(sellers.descn,1,1) as FirstInitial 
																	from mstt_AgentsHistory sellers		-- Use Agent History to exclude anyone who has ever swapped businesses
																	where sellers.AgentType in (4,43,46,49,51)
																	and isnull(sellers.Firm,'') <> ''
																) a 
														group	by a.Firm, a.SoundexDescnSurname, a.FirstInitial
														having	count(*) = 1	-- We only want one occurrence of a fuzzy match key to avoid over-matching
													)	Fuzzy   on  Fuzzy.Firm = advisers.Firm 
																and Fuzzy.SoundexDescnSurname = dbo.owf_Soundex(advisers.descn,'L')
																and	Fuzzy.FirstInitial = substring(advisers.descn,1,1)
								where	advisers.AgentType in (4,43,46,49,51)
								and		isnull(advisers.Firm,'') <> ''	
							) FuzzyNotExact on FuzzyNotExact.Firm = PCP.BusinessCode
											and FuzzyNotExact.Descn <> PCP.SellerName
											-- First two characters of forename soundex must be the same
											-- Thus Michael and Mike match but Michael and Matthew don't match
											and (substring(FuzzyNotExact.SoundexDescnForename,1,2) = substring(dbo.owf_Soundex(PCP.SellerName,'F'),1,2)	
											or	 dbo.owf_AbbreviatedMatch(FuzzyNotExact.descn,PCP.SellerName) = 1)
											and FuzzyNotExact.SoundexDescnSurname = dbo.owf_Soundex(PCP.SellerName,'L')		-- Soundex of surname must match
		where	(FuzzyNotExact.Code is not null or AgHist.Code is not null)
		and		PCP.CreateDate = @FileID	
		and pcp.Month=@maxMonth    --PFR NEW 22082023

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '15) Populate #FuzzyMatchedSellers. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the exact and fuzzy matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '16) Update SellerCode with UID matches', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerCode		= FMS.SwiftSellerUID,
				SellerName		= FMS.SwiftSellerName + ' - ' + FMS.SwiftSellerUID,
				SellerForename	= dbo.owf_FirstWord(FMS.SwiftSellerName),
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(FMS.SwiftSellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #FuzzyMatchedSellers FMS 
							on  FMS.PaymentshieldBusinessCode = PCP.BusinessCode
							and FMS.PaymentshieldSellerName = PCP.SellerName
		where	PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '16) Update SellerCode with UID matches. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the non-matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '17) Update Forename and Surname with unmatched names', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerForename	= dbo.owf_FirstWord(PCP.SellerName),				-- SellerName unchanged from Paymentshield
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(PCP.SellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID											-- AG 26/06/2013
		and		PCP.SellerCode is null		-- non-matched sellers

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17) Update Forename and Surname with unmatched names. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		-- AG 26/06/2013 End

		----------------------------- PR 30/06/2021 --START PR CHANGE 30/06/2021 (also some code above)
		--STORED UNMATCHED UID'S
		----------------------------
		if @debug = 'Y' exec msp_ProcessLog 'START', '17A) Store unmatched UIDs', null, 'PaymentShield', 'Openwork'

		--select @panelfile='Yes' from owt_PaymentshieldImport where pesn is not null; --if there is a pesn then the last file loaded must be a panel file
	
insert into [dbo].[owt_PaymentshieldImportUnmatched]
(     
	[UniqueRowID] ,
	[Period] ,
	[PolicyReference] ,
	[OWPolicyRef],
	[ClientName] ,
	[StartDate] ,
	[Source] ,
	[Product] ,
	[CommType] ,
	[Status] ,
	[Premium] ,
	[Margin] ,
	[Fee] ,
	[BranchName],
	[BranchNo] ,
	[SellerName] ,
	[OWFirmRef] ,
	[OW_Sellerref] ,
	[PESN] ,
	[comm_id] ,
	[comm_SellerCode],
	[comm_SellerName] ,
	[comm_SellerForename] ,
	[comm_SellerSurname] ,
	[panelfile] ,
	[provider] ,
	[DateLoaded] ,
	[ImportConvertsellerref],
	[sourceid])

--Selects them on the basis they are at the same policy and branch
select 
ii.[UniqueRowID] ,
	ii.[Period] ,
	ii.[PolicyReference] ,
	ii.[OWPolicyRef],
	ii.[ClientName] ,
	ii.[StartDate] ,
	ii.[Source] ,
	ii.[Product] ,
	ii.[CommType] ,
	ii.[Status] ,
	ii.[Premium] ,
	ii.[Margin] ,
	ii.[Fee] ,
	ii.[BranchName],
	ii.[BranchNo] ,
	ii.[SellerName] ,
	ii.[OWFirmRef] ,
	ii.[OW_Sellerref] ,
	ii.[PESN] ,
	owt.id,
	owt.SellerCode,
	owt.SellerName,
	owt.SellerForename,
	owt.SellerSurname,
	@panelfile ,
	owt.provider,
	getdate() ,
	CASE WHEN LEN(dbo.CleanAndTrimString(ii.OW_Sellerref)) =7
             THEN dbo.CleanAndTrimString(ii.OW_Sellerref)
             ELSE ''
        END ,
		owt.sourceid
from owt_PaymentshieldCommissionPayments owt 
inner join #Months m on m.PeriodMonth = owt.[Month]
join owt_PaymentshieldImport ii on ii.UniqueRowID=owt.sourceid
--and ii.margin=owt.MarginCommRate
where ((owt.provider ='payment shield panel' and @panelfile='Yes')  or (owt.provider ='payment shield' and @panelfile='no'))
and owt.sellercode is null 

set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17A) Insert records unmatched UIDS. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		if @debug = 'Y' exec msp_ProcessLog 'START', '17B) Update sourceids back to null', null, 'PaymentShield', 'Openwork'

		Update owt_PaymentshieldCommissionPayments set sourceid=null where sourceid is not null and provider in ('payment shield panel','payment shield'); --PR 30/06/2021 SET SOURCEID BACK TO NULL - SAFEGUARD UNLESS THIS IS BEING USED

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17B) SourceIDs set back to null. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		--END PR CHANGE 30/06/2021
		---------------------------------------------------------------------------
		-- Delete temporary tables
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

		drop table #currtotals
		drop table #FuzzyMatchedSellers		-- AG 26/06/2013
 
		if @debug = 'Y' exec msp_ProcessLog 'END', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

	end
end

drop table #Months;

exec msp_ProcessLog 'END', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommission_BACKUPPR01_07_21]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create procedure [dbo].[owp_PaymentshieldCommission_BACKUPPR01_07_21]
	@debug  varchar(1) = 'N'
with recompile
as

/********************************************************************************

Object  	  : procedure
Name    	  : owp_PaymentshieldCommission
Created By	  : Paul Robathan
Created 	  : 22/09/2007

Amendment History
-----------------
Date		  Author	  Description
----		  ------      -----------
05/10/2009	A Groves	  1) Added debug lines to identify UAT perf prob
						  2) Deleted _BYO from BranchNo
10/11/2009  A Harrison		Create index on temporary #currtotals table
03/03/2010	A Groves		Enhancement to Paul Robathan's fix of a year
  						    ago to include another condition for leap year.
23/09/2010  M Cawood    1) To allow more than one GI file to be loaded in a month 
                           (e.g. GHL) the new owt_PaymentShieldImportControl table
                           holds the FileID to be held as CreateDate on each row
                           loaded onto the owt_PaymentshieldCommissionPayments table. 
                        2) The FileID is then used by the procedure
                           owp_PaymentshieldAdviserListingExtract to select the 
                           data to be extracted from the
                           owt_PaymentshieldCommissionPayments table.
                        3) No data is now deleted by this procedure. The data held
                           on the owt_PaymentShieldImport table is now appended to
                           the owt_PaymentshieldCommissionPayments table.
25/10/2010  M Cawood    Move Month forward one month. For example, if data loaded
                        with [Period] = 'April, 2010' then derive the Month and Period
                        End Date for May 2010 (i.e. 2010/06/01 and 2010/06/09 resp).
25/09/2012	A Groves	1) Break-fix: Take 1st 65 characters only from column
							owt_PaymentshieldImport.ClientName.
22/02/2013	A Groves	1) All these suffixes found in the Paymentshield file:
							_BYO, _BYO2, _BYO_BYO, _BYO2_BYO, BYO3, _BYO_BYO_BYO
							They also appear in the Seller Log.  All variations of BYO
							are now removed from both the Paymentshield file and the
							Seller Log to improve the match rate.
						2) DACommRate changed from 32.5 to 35.0 if look up fails.
08/03/2013	Mike Cawood	SR207107 - Calculate new metric ELITE Points
08/04/2013	A Groves	Changes required to load new Paymentshield Panel file.
18/04/2013	A Groves	Changes for new values of CommType and Status.
22/04/2013	A Groves	Openwork DA increased from 35% to 39% so a further tweak
						was required when calculatin DARate, CommRate & UpliftRate. 
23/04/2013	A Groves	Additional tweaks to the above change required for double indemnity. 
						ELITE_Initial calculation corrected.
30/04/2013	A Groves	SR224597 - Processing previously assumed title was present. When 
						not present as with adviser Alison Herbert, then her Seller Name
						was changed to Herbert rather than left as Alison Herbert.
26/06/2013	A Groves	SR227174. Populate the seller code using fuzzy matching techniques.
						This is required to enable recognition to be counted correctly
						for each adviser. 
						This change includes a bug fix to ensure that the post table load
						updates operate on just the file being loaded and not every
						row for the commission period which could have included data loaded 
						by previous runs of this proc on other files.
05/07/2013	A Groves	Improve selection of unique match keys by using Code rather
						than Descn as Descn often changes over time causing a seller
						to dupe with themselves - leading them to be excluded from matching. 
22/11/2013	A Groves	Paymentshield have used _BY0 (zero) instead of BYO (oh) so matching
						has been amended to cope.
19/06/2014	A Groves	Improved coding to strip unwanted characters after either an 
						underscore or a hyphen. This improves matching between the
						Paymentshield Branch Number and the Openwork Business UID.
25/04/2015	A Groves	SR371343. New ELITE points calculation based on margin instead
						of adviser payment.
06/11/2015	A Groves	SR380390 - Load Paymentshield Owl payments. New column SourceID
						added to table owt_PaymentshieldCommissionPayments but set to NULL
						in this proc because the source table gets cleared down. However,
						the Owl table doesn't get cleared down because it sources the
						data for the ASM Override Statements.
05/09/2017	A Groves	SR464996. Replace DTS with SSIS. Comma in column "Period" was
						originally removed by the DTS script. The SSIS replacement does
						not do this to keep it simple. Instead it is done in this proc.
***********************************************************************************/

declare	@RowCount		int,			-- AG 26/06/2013
		@Process		nvarchar(100),	-- AG 26/06/2013
		@ProviderOrig	varchar(30),	-- AG 26/06/2013
		@ProviderPanel	varchar(30),	-- AG 26/06/2013
		@Provider		varchar(30)		-- AG 26/06/2013

exec msp_ProcessLog 'START', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

if @debug = 'Y' exec msp_ProcessLog 'START', '00) Remove _BYO from BranchNo', null, 'PaymentShield', 'Openwork'

-- AG 22/02/2013 Start

-- Strip out all text that includes and follows "_BYO". 
--update owhot_PaymentshieldSwiftAgentXRef
--		set PayshieldAgent = stuff(PayshieldAgent,patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')),50,'')	-- AG 22/11/2013
--where patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')) > 0													-- AG 22/11/2013

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update dbo.owhot_PaymentshieldSwiftAgentXref
	set PayshieldAgent = stuff(PayshieldAgent,patindex('%[-_]%',PayshieldAgent),100,'')
where patindex('%[-_]%',PayshieldAgent) > 0
-- AG 19/06/2014 End.

-- Since stripping out the _BYO derivatives, there are now dupes in the table. This step removes the dupes.
select	Xref.*
into	#owhot_PayshieldSwiftAgentXref
from	owhot_PaymentshieldSwiftAgentXref Xref
		inner join	(select PayshieldAgent, max(ID) as MaxID
						from owhot_PaymentshieldSwiftAgentXref
						group by PayshieldAgent) as DedupedPayshieldAgent
					on DedupedPayshieldAgent.MaxID = Xref.ID

-- AG 05/10/2009 Start

--update owt_paymentshieldimport
--		set BranchNo = stuff(BranchNo,patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')),50,'')		-- AG 22/11/2013
--where patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')) > 0										-- AG 22/11/2013

-- AG 05/10/2009 End
-- AG 22/02/2013 End

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update owt_paymentshieldimport
	set BranchNo = stuff(BranchNo,patindex('%[-_]%',BranchNo),100,'')
where patindex('%[-_]%',BranchNo) > 0
-- AG 19/06/2014 End.

--AG 05/09/2017 Start
--Remove comma in the Period field to enable it to be matched to the commission statement periods.
update owt_paymentshieldimport
	set Period = REPLACE(Period,',','')
--AG 05/09/2017 End

if @debug = 'Y' exec msp_ProcessLog 'START', '01) @PeriodCount derived', null, 'PaymentShield', 'Openwork'

select 
	distinct [Period] as 'Periods',
	convert (datetime, NULL,103) as 'PeriodMonth',
	convert (datetime, NULL,103) as 'BACSDate'
into #Months
from owt_PaymentshieldImport

-- AG 26/06/2013 Start

set @ProviderOrig	= 'Payment Shield'
set @ProviderPanel	= 'Payment Shield Panel'

if (select count(*) from owt_PaymentshieldImportPanel) > 1
	set @Provider = @ProviderPanel
else
	set @Provider = @ProviderOrig		

-- AG 26/06/2013 End

declare @PeriodCount  int
set @PeriodCount = (select Count(*) from #Months)

if @PeriodCount > 0 
begin

	if @debug = 'Y' exec msp_ProcessLog 'START', '02) Update #Months', null, 'PaymentShield', 'Openwork'

	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.MonthName = m.Periods 

--MPC: 25/10/2010 Move PeriodMonth and BACSDate forward one month
	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.Month = dateadd(mm,1,m.PeriodMonth) 
	
	declare @MonthCount  int
	set @MonthCount  = (select Count(*) from #Months where PeriodMonth is NOT NULL)

	if @debug = 'Y' exec msp_ProcessLog 'START', '03) @MonthCount derived', null, 'PaymentShield', 'Openwork'

	if @MonthCount  > 0 
	begin

		if @debug = 'Y' exec msp_ProcessLog 'START', '04) Delete from #Months', null, 'PaymentShield', 'Openwork'

		delete from #Months where PeriodMonth is NULL

		if @debug = 'Y' exec msp_ProcessLog 'START', '05) Delete from owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		--Derive unique FileID to be recorded against each row inserted --MPC: 23/09/2010
		declare @FileID datetime;                                       --MPC: 23/09/2010
		set @FileID = getdate();                                        --MPC: 23/09/2010

		--delete from owt_PaymentshieldCommissionPayments               --MPC: 23/09/2010
		--where [Month] in (select PeriodMonth from #Months)            --MPC: 23/09/2010

		--Maintain table that controls msit_OpenworkAdviserListing      --MPC: 23/09/2010
		truncate table dbo.owt_PaymentshieldImportControl;              --MPC: 23/09/2010
    
		insert into dbo.owt_PaymentshieldImportControl                  --MPC: 23/09/2010
		Select [FileID] = @FileID;                                      --MPC: 23/09/2010

		if @debug = 'Y' exec msp_ProcessLog 'START', '06) insert into owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		insert into owt_PaymentshieldCommissionPayments 
		select
		x.AgentCode,
		Rtrim(isnull(a.TradingName,a.DESCN)),
		a.OscarAgentPrefix + a.OscarAgentSerial + a.OscarAgentSuffix,
		PSI.BranchNo,
		NULL,
--		AG 30/04/2013 Start
--		case when charindex(' ', RTrim(PSI.SellerName)) = 0 then PSI.SellerName
--			else Rtrim(Substring(RTrim(PSI.SellerName), charindex(' ', RTrim(PSI.SellerName)) + 1, Len(RTrim(PSI.SellerName)) - charindex(' ', RTrim(PSI.SellerName))))
--			end,
		case when MICodes.Code is null	-- No match on person title so title assumed not present
			then ltrim(rtrim(PSI.SellerName))												-- AG 26/06/2013
			else ltrim(rtrim(stuff(replace(PSI.SellerName,'.',''),1,len(MICodes.Code),''))) 
		end as SellerName,
--		AG 30/04/2013 End
		NULL,
		NULL,
		NULL,
		substring(Rtrim(PSI.ClientName),1,65),						-- AG 25/09/2012
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Substring(RTrim(PSI.ClientName), charindex(' ', RTrim(PSI.ClientName))+1,1))
			end,
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Right(RTrim(PSI.ClientName),charindex(' ', Reverse(RTrim(PSI.ClientName)))-1))
			end,
		NULL,
		PSI.PolicyReference,
		Left(PSI.Product,8),
		'PY_' + Left(PSI.Product,5),
		PSI.StartDate,
	 	m.PeriodMonth,
		case 
			when PSI.StartDate >= convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) then PSI.StartDate
			when PSI.StartDate < convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) and Month(PSI.StartDate) < Month(PSI.Period) then 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then 
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period) as varchar(4)),103)
					 else
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period) as varchar(4)),103)
				end			
			else 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then					-- AG 03/03/2010
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)	-- AG 03/03/2010
					 else																			-- AG 03/03/2010
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)
				end
		end,
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then 'M'
			else case when left(Panel.TermOfContract,6) = 'ANNUAL'
					then 'A'
					else 'M'
				 end
		end as Frequency, 
		case when Panel.UniqueRowID is null
			then Abs(PSI.Premium) * 12
			else case when left(Panel.TermOfContract,6) = 'ANNUAL' 
						then 1 
						else 12 
				 end * abs(PSI.Premium)
		end as Premium,		
		-- AG 08/04/2013 End
		0,
		isnull ((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(PSI.Product,5)),'N'),
		0,
		0,
		case when PSI.Margin > 0 then PSI.Margin 
			 when PSI.Premium <> 0 then Abs((PSI.Fee*100)/(PSI.Premium *	case												-- AG 18/04/2013
																				when left(Panel.TermOfContract,6) = 'ANNUAL'	-- AG 18/04/2013
																				then 1											-- AG 18/04/2013
																				else 12											-- AG 18/04/2013
																			end))												-- AG 18/04/2013
			 else 7.5 
		end,
		isnull((select cast(Description as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),35.0),		-- AG 22/02/2013	Old value = 32.5
		isnull((select cast(LongDescription as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),27.5),
		1,
		0,
		0,
		NULL,
		0,
		0,
		0,
		0,
		0,
		PSI.Fee,
		0,
		case when PSI.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end,								-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end,			-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end,	-- AG 18/04/2013
		100,
		case when PSI.CommType in ('Adjustment','Awaiting Start') or PSI.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end,	-- AG 18/04/2013
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then @ProviderOrig					-- AG 26/06/2013
			else @ProviderPanel					-- AG 26/06/2013
		end as Provider,
		-- AG 08/04/2013 End
		'PYMTSHLD',
		m.PeriodMonth,
		'Payshield',
		--getdate(),      --MPC: 23/09/2010
		@FileID,          --MPC: 23/09/2010
		PSI.CommType,
		PSI.Status,
		NULL as ELITE_Initial,			--MPC: 20/02/2013 SR207107
		NULL as ELITE_Category,			--MPC: 20/02/2013 SR207107
		ltrim(rtrim(PSI.SellerName)),	-- AG 26/06/2013
		NULL as SourceID				-- AG 06/11/2015
		from owt_PaymentshieldImport PSI
--		inner join owhot_PaymentshieldSwiftAgentXRef x on x.PayshieldAgent = PSI.BranchNo			AG 22/02/2012
		inner join #owhot_PayshieldSwiftAgentXref x on x.PayshieldAgent = PSI.BranchNo				-- AG 22/02/2012
		inner join mstt_Agents a on a.CODE = x.AgentCode
		inner join #Months m on m.Periods = PSI.Period
		left join owt_PaymentshieldImportPanel Panel on Panel.UniqueRowID = PSI.UniqueRowID			-- AG 08/04/2013
		left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes									-- AG 30/04/2013
						on  MICodes.ColumnName = 'PersonTitle' 
						and ltrim(rtrim(replace(PSI.SellerName,'.',''))) like MICodes.Code + ' %'	-- AG 26/06/2013
		where x.Deleted <> 'Y'

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '06) insert into owt_PaymentshieldCommissionPayments. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- AG 08/04/2013. Truncate Panel table to ensure it is not incorrectly
		-- used during a non-Panel File load. 
		---------------------------------------------------------------------------

		truncate table owt_PaymentshieldImportPanel	

		---------------------------------------------------------------------------
		-- Update Sales Measures #1		AG 22/04/2013 & 23/04/2013
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '07) Update Sales Measures #1', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set	DACommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate,
				CommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate),
				UpliftRate	= (case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate))/PCP.BaseCommRate
		from	owt_PaymentshieldCommissionPayments PCP
				INNER JOIN #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '07) Update Sales Measures #1. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #2
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '08) Update Sales Measures #2', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
                        set PaymentAmount = case	  
						  when PCP.MarginCommRate > 0 then PCP.Margin * (PCP.CommRate/PCP.MarginCommRate)
						  else PCP.PaymentAmount
				  	    end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '08) Update Sales Measures #2. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update incomplete data
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '09) Update incomplete data', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set PayBasisCode = isnull((select	top 1 PayBasisCode 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth
										order by o.Month Desc), PCP.PayBasisCode),
			    PayBasis = isnull((select	top 1 PayBasis 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.PayBasis),
			    Premium = isnull((select	top 1 Premium 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.Premium),
			    InitialPeriod = isnull((select	top 1 InitialPeriod 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth 
										order by o.Month Desc), PCP.InitialPeriod) 	
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where  PCP.CreateDate = @FileID														-- AG 26/06/2013
		and	   (PCP.OrigCommType in ('Clawback','Adjustment','Cancelled','Cancelled Case')	-- AG 18/04/2013 
		or		PCP.Premium = 0
		or		PCP.OrigStatus in ('CANCELLATION','CANCELLED','MTA'))						-- AG 18/04/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '09) Update incomplete data. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- create temporary table to hold current totals 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '10) Populate #currtotals', null, 'PaymentShield', 'Openwork'

		select	isnull(SUM(b.PaymentAmount),0) as 'CURR_FEE',a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month], Count(*) as 'CURR_COUNT'
		into	#currtotals
		from	owt_PaymentshieldCommissionPayments a 
				inner join owt_PaymentshieldCommissionPayments b 
						on a.BusinessCode = b.BusinessCode 
						and a.Policy = b.Policy 
						and a.LatestAnniversary = b.LatestAnniversary 
						and a.Provider = b.Provider					-- AG 26/06/2013
		where	a.OrigCommType not in ('Awaiting Start','Earn Off')
		and		a.Provider = @Provider								-- AG 26/06/2013
		group	by a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month]

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '10) Populate #currtotals. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------
		-- Create index on temporary table
		---------------------------------------------

		CREATE  INDEX [idx_BusinessCode] ON [dbo].[#currtotals]([BusinessCode],[Policy],[LatestAnniversary],[Month]) 

		---------------------------------------------------------------------------
		-- Update SalesMoveFlag 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '11) Update SalesMoveFlag', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set SalesMoveFlag = case 
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary > PCP.StartDate and ct.CURR_COUNT = 1 then 'Y'
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary = PCP.StartDate and ct.CURR_COUNT = 1 then 'Y' 
					when PCP.PayBasisCode = 'T' and PCP.Margin > 0 then 'Y' 
					when PCP.OrigCommType in ('Cancelled','Clawback','Cancelled Case') or PCP.OrigStatus in ('CANCELLATION','CANCELLED') then case when ct.CURR_FEE = 0 then 'Y' else 'X' end	-- AG 18/04/2013
					when PCP.OrigCommType in ('Awaiting Start','Earn Off') then 'N'
					else 'X'
				    end 
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
											and ct.[Month] = PCP.[Month] 
		where  PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '11) Update SalesMoveFlag. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #3
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '12) Update Sales Measures #3', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set TotalFeeDue = case 
								when PCP.SalesMoveFlag  = 'N' then PCP.TotalFeeDue
								else case	  
										when PCP.PaymentAmount < 0 or PCP.PayBasis = 'IT' then PCP.PaymentAmount 
										else PCP.PaymentAmount * case when PCP.Frequency = 'A' then 1 else 12 end	-- AG 18/04/2013
									 end	  
				  			   end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '12) Update Sales Measures #3. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- now use current table to update ICPaidToDate and StilltoAccrue 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '13) Update ICPaidToDate and StilltoAccrue', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set ICPaidToDate = CURR_FEE,
			    StilltoAccrue = PCP.TotalFeeDue - CURR_FEE
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
							                and ct.[Month] = PCP.[Month] 
		where	PCP.PaymentAmount > 0 
		and		PCP.PayBasisCode = 'F'
		and		PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '13) Update ICPaidToDate and StilltoAccrue. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #4
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '14) Update Sales Measures #4', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set 
				DA = Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
	    		EnhancedNBI = Abs(PCP.TotalFeeDue) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	BaseNBI = (Abs(PCP.TotalFeeDue)/PCP.UpliftRate) *  case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	Turnover =	case
			 	  				when PCP.APEFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 	  				else Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate)  * case when PCP.PaymentAmount < 0 then -1 else 1 end
							end,
		    	APE =	case
			 				when PCP.APEFlag = 'Y' and PCP.SalesMoveFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 				else PCP.APE  
						end,
				ELITE_Initial = 
					case when PCP.Month >= '2015-02-01'									--AG 25/04/2015
					then case															--AG 25/04/2015
							when PCP.PaymentAmount < 0									--AG 25/04/2015
							then round(isnull(-ABS(PCP.Margin * ELF.Multiplier),0),4)	--AG 25/04/2015
							else round(isnull(PCP.Margin * ELF.Multiplier,0),4)			--AG 25/04/2015
						  end															--AG 25/04/2015
					else																--AG 25/04/2015
						round( ELF.Factor * ELF.Multiplier *							--MPC: 20/02/2013 SR207107
						( ( Abs(PCP.TotalFeeDue)/PCP.UpliftRate )						--MPC: 20/02/2013 SR207107
						* case when PCP.PaymentAmount < 0 then -1 else 1 end ),2)		--MPC: 20/02/2013 SR207107
					end,																--AG 25/04/2015
				ELITE_Category = ELF.Category											--MPC: 20/02/2013 SR207107
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join msit_CommissionStatementPeriods CSP on m.PeriodMonth = CSP.Month	--MPC: 20/02/2013 SR207107
				left join owt_ELITEFactors ELF on ELF.FeeType = 'Initial' and ELF.Category = 'GI' and CSP.Year between ELF.StartYear and ELF.EndYear		--MPC: 20/02/2013 SR207107
		where	PCP.SalesMoveFlag  = 'Y'
		and		PCP.CreateDate = @FileID										-- AG 26/06/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '14) Update Sales Measures #4. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		----------------------------------------------------------------------------------
		-- Populate temporary table with exact and fuzzy matched sellers for current month
		----------------------------------------------------------------------------------

		-- AG 26/06/2013 Start

		if @debug = 'Y' exec msp_ProcessLog 'START', '15) Populate #FuzzyMatchedSellers', null, 'PaymentShield', 'Openwork'

		select	distinct	-- joins are to all rows on AgentsHistory to match to past
							-- employers.  This will create a lot of duplicate rows 
							-- hence distinct to remove them.
				PCP.BusinessCode as PaymentshieldBusinessCode,
				PCP.SellerName as PaymentshieldSellerName, 
				coalesce(AgHist.Code,FuzzyNotExact.Code) as SwiftSellerUID, 
				coalesce(ltrim(rtrim(AgHist.DESCN)),FuzzyNotExact.descn) as SwiftSellerName
		into	#FuzzyMatchedSellers
		From	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join	mstt_AgentsHistory AgHist	-- Exact match of this seller in this business either now or in the past 
								on ltrim(rtrim(AgHist.DESCN)) = ltrim(rtrim(PCP.SellerName))
								and AgHist.AgentType in (4,43,46,49,51)
								and AgHist.Firm = PCP.BusinessCode
				left join	(	select	advisers.code, advisers.Firm, 
										ltrim(rtrim(advisers.Descn)) as descn, 
										dbo.owf_Soundex(advisers.descn,'F') as SoundexDescnForename,
										dbo.owf_Soundex(advisers.descn,'L') as SoundexDescnSurname
								from	mstt_AgentsHistory advisers
										inner join	(					
														select	a.Firm, a.SoundexDescnSurname, a.FirstInitial
														from	
																(
																	select	distinct -- Unique permutations of sellers and their fuzzy match key hence distinct
																			sellers.Firm, 
																			--ltrim(rtrim(sellers.Descn)) as Descn,	-- AG 05/07/2013
																			Sellers.Code,							-- AG 05/07/2013 
																			dbo.owf_Soundex(sellers.descn,'L') As SoundexDescnSurname,
																			substring(sellers.descn,1,1) as FirstInitial 
																	from mstt_AgentsHistory sellers		-- Use Agent History to exclude anyone who has ever swapped businesses
																	where sellers.AgentType in (4,43,46,49,51)
																	and isnull(sellers.Firm,'') <> ''
																) a 
														group	by a.Firm, a.SoundexDescnSurname, a.FirstInitial
														having	count(*) = 1	-- We only want one occurrence of a fuzzy match key to avoid over-matching
													)	Fuzzy   on  Fuzzy.Firm = advisers.Firm 
																and Fuzzy.SoundexDescnSurname = dbo.owf_Soundex(advisers.descn,'L')
																and	Fuzzy.FirstInitial = substring(advisers.descn,1,1)
								where	advisers.AgentType in (4,43,46,49,51)
								and		isnull(advisers.Firm,'') <> ''	
							) FuzzyNotExact on FuzzyNotExact.Firm = PCP.BusinessCode
											and FuzzyNotExact.Descn <> PCP.SellerName
											-- First two characters of forename soundex must be the same
											-- Thus Michael and Mike match but Michael and Matthew don't match
											and (substring(FuzzyNotExact.SoundexDescnForename,1,2) = substring(dbo.owf_Soundex(PCP.SellerName,'F'),1,2)	
											or	 dbo.owf_AbbreviatedMatch(FuzzyNotExact.descn,PCP.SellerName) = 1)
											and FuzzyNotExact.SoundexDescnSurname = dbo.owf_Soundex(PCP.SellerName,'L')		-- Soundex of surname must match
		where	(FuzzyNotExact.Code is not null or AgHist.Code is not null)
		and		PCP.CreateDate = @FileID	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '15) Populate #FuzzyMatchedSellers. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the exact and fuzzy matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '16) Update SellerCode with UID matches', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerCode		= FMS.SwiftSellerUID,
				SellerName		= FMS.SwiftSellerName + ' - ' + FMS.SwiftSellerUID,
				SellerForename	= dbo.owf_FirstWord(FMS.SwiftSellerName),
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(FMS.SwiftSellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #FuzzyMatchedSellers FMS 
							on  FMS.PaymentshieldBusinessCode = PCP.BusinessCode
							and FMS.PaymentshieldSellerName = PCP.SellerName
		where	PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '16) Update SellerCode with UID matches. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the non-matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '17) Update Forename and Surname with unmatched names', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerForename	= dbo.owf_FirstWord(PCP.SellerName),				-- SellerName unchanged from Paymentshield
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(PCP.SellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID											-- AG 26/06/2013
		and		PCP.SellerCode is null		-- non-matched sellers

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17) Update Forename and Surname with unmatched names. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		-- AG 26/06/2013 End

		---------------------------------------------------------------------------
		-- Delete temporary tables
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

		drop table #currtotals
		drop table #FuzzyMatchedSellers		-- AG 26/06/2013
 
		if @debug = 'Y' exec msp_ProcessLog 'END', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

	end
end

drop table #Months;

exec msp_ProcessLog 'END', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

GO

